window.HADITH_CACHE["darimi_1"] = {"501":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ وَحَدَّثَنَاهُ عَنْ يُونُسَ أَيْضًا عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ أَنَّهَا أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لَهَا لَمْ يَبْلُغْ أَنْ يَأْكُلَ الطَّعَامَ فَأَجْلَسَتْهُ فِي حِجْرِهِ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَنَضَحَهُ وَلَمْ يَغْسِلْهُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Malik bin Anas] dan kami menceritakannya juga, dari [Yunus] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin 'Utbah] dari [Ummu Qais binti Mihshan] ia pernah menemui Nabi shallallahu 'alaihi wasallam dengan membawa seorang anak kecil yang belum makan (selain minum air susu ibu), kemudian beliau memangkunya. Ia mengencingi beliau, (ummu Qais) berkata: 'Kemudian beliau meminta air dan beliau percikkan (ke bagian yang terkena kencing) tanpa mencucinya.\""},"502":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ مُحَمَّدِ بْنِ عُمَارَةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أُمِّ وَلَدٍ لِإِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهَا سَأَلَتْ أُمَّ سَلَمَةَ فَقَالَتْ إِنِّي امْرَأَةٌ أُطِيلُ ذَيْلِي فَأَمْشِي فِي الْمَكَانِ الْقَذِرِ فَقَالَتْ أُمُّ سَلَمَةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطَهِّرُهُ مَا بَعْدَهُ قِيلَ لِأَبِي مُحَمَّدٍ تَأْخُذُ بِهَذَا قَالَ لَا أَدْرِي","id":"Telah mengabarkan kepadda kami [Yahya bin Hassan] telah meceritakan kepada kami [Malik bin Anas] dari [Muhammad bin 'Umarah] dari [Muhammad bin Ibrahim At Taimi] dari [ummu walad nya Ibrahim bin Abdur Rahman bin 'Auf] ia bertanya kepada Ummu Salamah radliallahu 'anha: \"Aku seorang wanita yang memanjangkan bajuku, kemudian aku berjalan di tempat yang kotor,? ', [Ummu Salamah] radliallahu 'anha berkata: Rasulullah shallallahu 'alaihi wasallam pernah bersabda: 'Tanah selanjutnya yang akan mensucikannya'. Ditanyakan kepada Abu Muhammad: 'Apakah kamu mengambilnya (menjadi hujjah)?\", ia menjawab: 'Aku tidak tahu' \"."},"503":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عَوْفٌ حَدَّثَنِي أَبُو رَجَاءٍ الْعُطَارِدِيُّ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ ثُمَّ نَزَلَ فَدَعَا بِوَضُوءٍ فَتَوَضَّأَ ثُمَّ نُودِيَ بِالصَّلَاةِ فَصَلَّى بِالنَّاسِ فَلَمَّا انْفَتَلَ مِنْ صَلَاتِهِ إِذَا هُوَ بِرَجُلٍ مُعْتَزِلٍ لَمْ يُصَلِّ فِي الْقَوْمِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ يَا فُلَانُ أَنْ تُصَلِّيَ فِي الْقَوْمِ فَقَالَ يَا رَسُولَ اللَّهِ أَصَابَتْنِي جَنَابَةٌ وَلَا مَاءَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكَ بِالصَّعِيدِ فَإِنَّهُ يَكْفِيكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Auf] ia berkata: telah menceritakan kepadaku [Abu Raja` Al 'Utharidi] dari [Imran bin Hushain] ia berkata: ia berkata: \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam satu perjalanan jauh, lalu beliau turun dan meminta diambilkan air wudhu, kemudian beliau berwudhu, selanjutnya dikumandangkan adzan, lalu beliau shalat bersama orang-orang, Selesai menunaikan shalat, beliau mendapati seseorang yang tidak ikut shalat berjamaah bersama orang-orang, beliau bertanya: 'Apa yang menghalangi kamu untuk shalat berjamaah bersama orang-orang? ', ia menjawab: 'Wahai Rasulullah, aku sedang junub dan tidak ada air', maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Gunakanlah debu (untuk bertayammum), hal yang demikian mencukupimu' \"."},"504":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ خَرَجَ رَجُلَانِ فِي سَفَرٍ فَحَضَرَتْهُمَا الصَّلَاةُ وَلَيْسَ مَعَهُمَا مَاءٌ فَتَيَمَّمَا صَعِيدًا طَيِّبًا فَصَلَّيَا ثُمَّ وَجَدَا الْمَاءَ بَعْدُ فِي الْوَقْتِ فَأَعَادَ أَحَدُهُمَا الصَّلَاةَ بِوُضُوءٍ وَلَمْ يُعِدْ الْآخَرُ ثُمَّ أَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَا ذَلِكَ فَقَالَ لِلَّذِي لَمْ يُعِدْ أَصَبْتَ السُّنَّةَ وَأَجْزَتْكَ صَلَاتُكَ وَقَالَ لِلَّذِي تَوَضَّأَ وَأَعَادَ لَكَ الْأَجْرُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ishak] telah meneritakan kepadaku [Abdullah bin Nafi'] dari [Al Laits bin Sa'ad] dari [Bakar bin Sawadah] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] radliallahu 'anhu ia berkata: \"Pernah ada dua orang bepergian dalam sebuah perjalanan jauh dan waktu shalat telah tiba, sedang mereka tidak membawa air, lalu mereka berdua bertayamum dengan debu yang bersih dan melakukan shalat, kemudian keduanya mendapati air (dan waktu shalat masih ada), lalu salah seorang dari keduanya mengulangi shalatnya dengan air wudhu dan yang satunya tidak mengulangi. Mereka menemui Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal itu. Maka beliau berkata kepada orang yang tidak mengulangi shalatnya: 'Kamu sesuai dengan sunnah dan shalatmu sudah cukup'. Dan beliau juga berkata kepada yang berwudhu dan mengulangi shalatnya: 'Bagimu pahala dua kali' \"."},"505":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ حَدَّثَنَا قَتَادَةُ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ عَمَّارِ بْنِ يَاسِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي التَّيَمُّمِ ضَرْبَةٌ لِلْوَجْهِ وَالْكَفَّيْنِ قَالَ عَبْد اللَّهِ صَحَّ إِسْنَادُهُ","id":"Telah mengahabarkan kepada kami ['Affan] telah menceritakan kepada kami [Aban bin Yazid Al 'Athar] telah menceritaan kepada kami [Qatadah] dari ['Azrah] dari [Sa'id bin Abdur Rahman bin `Abza] dari [ayahnya] dari ['Ammar bin Yasir] radliallahu 'anhu Nabi shallallahu 'alaihi wasallam pernah bersabda dalam hal tayammum: \"Sekali tepukan untuk (diusapkan) ke wajah dan kedua telapak tangannya (bagian luarnya). Abu Abdullah berkata: \"Sanadnya shahih\"."},"506":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا اسْتَعَارَتْ قِلَادَةً مِنْ أَسْمَاءَ فَهَلَكَتْ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسًا مِنْ أَصْحَابِهِ فِي طَلَبِهَا فَأَدْرَكَتْهُمْ الصَّلَاةُ فَصَلَّوْا مِنْ غَيْرِ وُضُوءٍ فَلَمَّا أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَكَوْا ذَلِكَ إِلَيْهِ فَنَزَلَتْ آيَةُ التَّيَمُّمِ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ جَزَاكِ اللَّهُ خَيْرًا فَوَاللَّهِ مَا نَزَلَ بِكِ أَمْرٌ قَطُّ إِلَّا جَعَلَ اللَّهُ لَكِ مِنْهُ مَخْرَجًا وَجَعَلَ لِلْمُسْلِمِينَ فِيهِ بَرَكَةً","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha \" ia meminjam seuntai kalung dari Asma` radliallahu 'anha kemudian kalung itu hilang. Rasulullah shallallahu 'alaihi wasallam mengutus beberapa orang sahabatnya untuk mencarinya, tetapi tibalah waktu shalat, lalu mereka shalat tanpa dengan wudhu, tatkala mereka menemui Nabi shallallahu 'alaihi wasallam, mereka mengadukan hal itu kepada beliau, maka turunlah ayat tayammum, Usaid bin Hudhair berkata: 'Semoga Allah subhanallahu wa ta'ala membalas kebaikanmu dengan balasan yang lebih baik, demi Allah subhanallahu wa ta'ala, tidak ada satupun ayat yang turun berkenaan dengan dirimu kecuali Allah subhanallahu wa ta'ala jadikan untukmu jalan keluar bagi permasalahanmu dan menjadi keberkahan bagi kaum muslimin' \"."},"507":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا زَائِدَةُ عَنْ سُلَيْمَانَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ قَالَتْ وَضَعْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاءً فَأَفْرَغَ عَلَى يَدَيْهِ فَجَعَلَ يَغْسِلُ بِهَا فَرْجَهُ فَلَمَّا فَرَغَ مَسَحَهَا بِالْأَرْضِ أَوْ بِحَائِطٍ شَكَّ سُلَيْمَانُ ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ فَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ وَصَبَّ عَلَى رَأْسِهِ وَجَسَدِهِ فَلَمَّا فَرَغَ تَنَحَّى فَغَسَلَ رِجْلَيْهِ فَأَعْطَيْتُهُ مِلْحَفَةً فَأَبَى وَجَعَلَ يَنْفُضُ بِيَدِهِ قَالَتْ فَسَتَرْتُهُ حَتَّى اغْتَسَلَ قَالَ سُلَيْمَانُ فَذَكَرَ سَالِمٌ أَنَّ غُسْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا كَانَ مِنْ جَنَابَةٍ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Za`idah] dari [Sulaiman] dari [Salim bin Abu Al Ja'd] dari [Kuraib] dari [Ibnu Abbas] radliallahu 'anhu dari [Maimunah] radliallahu 'anha ia berkata: \"Aku pernah menyediakan air untuk Nabi shallallahu 'alaihi wasallam, beliau mengambil air dengan kedua tangannya dan membasuh kemaluannya, setelah selesai beliau menggosokkan tangannya di tanah atau di dinding--Sulaiman di sini ragu perihal tanah atau dinding--, kemudian beliau berkumur-kumur, beristinsyaq (menghisap air ke hidung), membasuh wajah dan dua lengannya, beliau menyiramkan air ke kepala dan seluruh badannya. Tatkala semua sudah selesai beliau bergeser dan mencuci kedua kakinya, lalu aku memberikan kain selimut kepada beliau, tetapi beliau menolak, saat itu beliau mengibaskan dengan tangannya. Aku menutupi beliau hingga beliau selesai mandi'. Sulaiman berkata: 'Salim menyebutkan mandi Nabi shallallahu 'alaihi wasallam yang seperti ini adalah mandi junub' \". "},"508":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْدَأُ فَيَغْسِلُ يَدَيْهِ ثُمَّ يَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يُدْخِلُ كَفَّهُ فِي الْمَاءِ فَيُخَلِّلُ بِهَا أُصُولَ شَعْرِهِ حَتَّى إِذَا خُيِّلَ إِلَيْهِ أَنَّهُ قَدْ اسْتَبْرَأَ الْبَشَرَةَ غَرَفَ بِيَدِهِ ثَلَاثَ غَرَفَاتٍ فَصَبَّهَا عَلَى رَأْسِهِ ثُمَّ اغْتَسَلَ قَالَ أَبُو مُحَمَّد هَذَا أَحَبُّ إِلَيَّ مِنْ حَدِيثِ سَالِمِ بْنِ أَبِي الْجَعْدِ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha ia berkata: \"Rasulullah shallallahu 'alaihi wasallam memulai mandinya dengan mencuci kedua telapak tangannya sebagaimana wudhu untuk shalat, kemudian beliau memasukkan telapak tangannya di air kemudian beliau menyela-nyela pangkal rambutnya dengan air tersebut, setelah yakin mengenai kulit beliau mengambil air dan diguyurkan ke kepalanya sebanyak tiga kali, kemudian beliau mandi\". Abu Ahmad berkata: \"Hadits ini lebih aku sukai dibandingkan hadits riwayat Salim bin Abu Al Ja'd\"."},"509":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ مِنْ الْجَنَابَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha ia berkata: \"Aku pernah mandi junub bersama Nabi shallallahu 'alaihi wasallam dengan satu bejana\"."},"510":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا جَعْفَرُ بْنُ بُرْقَانَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ وَهُوَ الْفَرَقُ","id":"Telah mengabarkan kepada kami [Ja'far bn 'Aun] telah mengabarkan kepada kami [Ja'far bin burqan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha ia berkata: \"Aku pernah mandi bersama Rasulullah shallallahu 'alaihi wasallam dengan satu bejana, (yang di maksud adalah) al faraq (wadah yang menampung enam belas rithl) \". "},"511":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ زَاذَانَ عَنْ عَلِيٍّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ مَوْضِعَ شَعْرَةٍ مِنْ جَنَابَةٍ لَمْ يُصِبْهَا الْمَاءُ فُعِلَ بِهَا كَذَا وَكَذَا مِنْ النَّارِ قَالَ عَلِيٌّ فَمِنْ ثَمَّ عَادَيْتُ رَأْسِي وَكَانَ يَجُزُّ شَعْرَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Fadhl] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Atha` bin As Sa`ib] dari [Zadzan] dari [Ali] radhiallallahu 'anhu. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan (dari anggota badan) sebesar sehelai rambut ketika mandi junub, hingga tidak terkena air, ia terkena api neraka\". Ali radliallahu 'anhu berkata: \"Karena itu, aku mengulangi kembali membasuh kepala\". Saat itu, kepalanya sudah kering."},"512":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ بَلَغَنِي أَنَّ عَطَاءَ بْنَ أَبِي رَبَاحٍ قَالَ إِنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يُخْبِرُ أَنَّ رَجُلًا أَصَابَهُ جُرْحٌ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَصَابَهُ احْتِلَامٌ فَأُمِرَ بِالِاغْتِسَالِ فَمَاتَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَتَلُوهُ قَتَلَهُمْ اللَّهُ أَلَمْ يَكُنْ شِفَاءَ الْعِيِّ السُّؤَالُ وَقَالَ عَطَاءٌ بَلَغَنِي أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ بَعْدَ ذَلِكَ فَقَالَ لَوْ غَسَلَ جَسَدَهُ وَتَرَكَ رَأْسَهُ حَيْثُ أَصَابَهُ الْجُرْحُ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al 'Auza'i] ia berkata: [Telah sampai kepadaku] bahwa ['Atha` bin Abu Rabah] berkata: ia pernah mendengar [Ibnu Abbas] radliallahu 'anhu mengabarkan: \"Ada seseorang yang terluka pada zaman Nabi shallallahu 'alaihi wasallam kemudian ia mimpi basah, maka ia disuruh untuk mandi, dan akhirnya meninggal dunia. Kabar tersebut sampai kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: 'Mereka telah membunuhnya, semoga Allah subhanallahu wa ta'ala membinasakan mereka, bukankah obat kebodohan itu bertanya? ', ['Atha`] berkata: 'Telah sampai kepadaku kabar bahwa Nabi shallallahu 'alaihi wasallam ditanya setelah kejadian itu, lalu beliau bersabda: 'Seharusnya ia cukup mengguyur seluruh anggota badannya yang tidak terluka dan membiarkan kepalanya yang terluka' \"."},"513":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ عَلَى نِسَائِهِ فِي يَوْمٍ وَاحِدٍ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] radliallahu 'anhu Rasulullah shallallahu 'alaihi wasallam pernah menggilir para isteri beliau dengan hanya sekali mandi\"."},"514":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ عَلَى نِسَائِهِ فِي لَيْلَةٍ وَاحِدَةٍ جُمَعَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] radliallahu 'anhu Rasulullah shallallahu 'alaihi wasallam menggilir para isteri beliau dalam satu malam\"."},"515":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي يَعْقُوبَ عَنْ الْحَسَنِ بْنِ سَعْدٍ مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ أَرْدَفَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ خَلْفَهُ فَأَسَرَّ إِلَيَّ حَدِيثًا لَا أُحَدِّثُ بِهِ أَحَدًا مِنْ النَّاسِ وَكَانَ أَحَبَّ مَا اسْتَتَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَتِهِ هَدَفٌ أَوْ حَائِشُ نَخْلٍ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [mahdi bin Maimun] telah menceritakan kepada kami [Muhammad bin Abdullah bin Abu Ya'qub] dari [Al Hasan bin Sa'ad] -bekas budak bagi Al Hasan bin Ali-, dari [Abdullah bin Ja'far] ia berkata: \"Suatu hari Rasulullah shallallahu 'alaihi wasallam memerintahkanku untuk membonceng di belakang beliau, lalu beliau membisikkan kepadaku satu hadits yang tidak akan aku ceritakan kepada seorang pun, dan diantara penutup yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam untuk buang hajat adalah rerimbunan pohon yang jaraknya rapat\". "},"516":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ سَأَلَ عُمَرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تُصِيبُنِي الْجَنَابَةُ مِنْ اللَّيْلِ فَأَمَرَهُ أَنْ يَغْسِلَ ذَكَرَهُ وَيَتَوَضَّأَ ثُمَّ يَرْقُدَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhu ia berkata: \"Umar radliallahu 'anhu pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata: 'Aku junub pada malam hari', lalu beliau memerintahkannya mencuci kemaluannya dan berwudhu dan tidur\"."},"517":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ قَالَ سَأَلْتُ عَائِشَةَ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ إِذَا أَرَادَ أَنْ يَنَامَ وَهُوَ جُنُبٌ فَقَالَتْ كَانَ يَتَوَضَّأُ وُضُوءَهُ لِلصَّلَاةِ ثُمَّ يَنَامُ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishak] dari [Abdur Rahman bin Al Aswad] dari [ayahnya] ia berkata: \"Aku pernah bertanya [Aisyah] radliallahu 'anha tentang bagaimana cara Rasulullah shallallahu 'alaihi wasallam apabila hendak tidur di saat beliau junub?, lalu ia menjawab: 'Beliau berwudhu sebagaimana wudhu untuk shalat, kemudian tidur' \"."},"518":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ السَّائِبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سُعَادٍ وَكَانَ مَرْضِيًّا مِنْ أَهْلِ الْمَدِينَةِ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَاءُ مِنْ الْمَاءِ","id":"Telah mengabarkan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Abdur Razzaq] telah mengabarkan kepada kami [Ibnu Juraij] ia berkata: telah mengabarkan kepada kami ['Amr bin Dinar] dari [Abdur rahman bin As Sa`ib] dari [Abdur rahman bin Su'ad] -ia disukai oleh penduduk Madinah-, dari [Abu Ayyub Al Anshari] radliallahu 'anhu Nabi shallallahu 'alaihi wasallam bersabda: \"Keluar mani mewajibkan mandi\". "},"519":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعَ مِنْهُ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ سَنَةً حِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ أَنَّ الْفُتْيَا الَّتِي كَانُوا يُفْتَوْنَ بِهَا فِي قَوْلِهِ الْمَاءُ مِنْ الْمَاءِ رُخْصَةٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِيهَا فِي أَوَّلِ الْإِسْلَامِ ثُمَّ أَمَرَ بِالِاغْتِسَالِ بَعْدُ قَالَ عَبْد اللَّهِ و قَالَ غَيْرُهُ قَالَ الزُّهْرِيُّ حَدَّثَنِي بَعْضُ مَنْ أَرْضَى عَنْ سَهْلِ بْنِ سَعْدٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata: telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [ibnu Syihab] dari [Sahl bin Sa'ad As Saidi] radliallahu 'anhu -beliau mendapati masa Nabi shallallahu 'alaihi wasallam, ia mendengar hadits dari beliau sewaktu berumur lima belas tahun ketika Rasulullah shallallahu 'alaihi wasallam wafat-, ia berkata: Telah menceritakan kepadaku [Ubai bin Ka'ab]: ' fatwa yang mereka sampaikan berdasarkan sabda beliau 'AL MAA`U MINAL MAA`I' (Keluarnya mani mewajibkan mandi) adalah rukhshah (keringanan) yang Rasulullah shallallahu 'alaihi wasallam berikan di awal Islam, setelah itu barulah fatwa kewajiban mandi', Abdullah dan yang lainnya berkata: Az Zuhri berkata: 'telah menceritakan kepadaku sebagian orang yang aku percaya menceritakan kepada kami dari Sahl bin Sa'ad' \"."},"520":{"ar":" أَخْبَرَنَا أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ مِهْرَانَ الْجَمَّالُ حَدَّثَنَا مُبَشِّرٌ الْحَلَبِيُّ عَنْ مُحَمَّدٍ أَبِي غَسَّانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ حَدَّثَنِي أُبَيٌّ أَنَّ الْفُتْيَا الَّتِي كَانُوا يُفْتَوْنَ بِهَا الْمَاءُ مِنْ الْمَاءِ كَانَتْ رُخْصَةً رَخَّصَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَوَّلِ الْإِسْلَامِ أَوْ الزَّمَانِ ثُمَّ اغْتَسَلَ بَعْدُ","id":"Telah mengabarkan kepada kami [Abu Ja'far Muhammad bin Mihran Al Jammal], telah menceritakan kepada kami [Mubasyir Al Halabi] dari [Muhammad Abu Ghassan] dari [Abu Hazim] dari [Sahl bin Sa'ad] ia berkata: [Ubay] menceritakan kepadaku: \"Fatwa yang mereka sampaikan berdasarkan sabda beliau: 'AL MAA`U MINAL MAA`I' (Keluarnya mani mewajibkan mandi), adalah rukhshah (keringanan) yang Rasulullah shallallahu 'alaihi wasallam berikan di awal Islam, setelah itu barulah datang fatwa kewajiban mandi' \"."},"521":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَلَسَ بَيْنَ شُعَبِهَا الْأَرْبَعِ ثُمَّ جَهَدَهَا فَقَدْ وَجَبَ الْغُسْلُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Al Hasan] dari [Abu Rafi'] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seorang laki-laki duduk diantara empat bagian tubuh isterinya lalu menyetubuhinya, wajiblah mandi\". "},"522":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءٍ الْخُرَاسَانِيِّ قَالَ سَمِعْتُ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ سَأَلَتْ خَالَتِي خَوْلَةُ بِنْتُ حَكِيمٍ الْسُلَمِيَّةُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمَرْأَةِ تَحْتَلِمُ فَأَمَرَهَا أَنْ تَغْتَسِلَ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari ['Atha` Al Khurrasani] ia berkata: \"Aku pernah mendengar [Sa'id bin Al Musayyib] berkata: 'Bibiku - [Khaulah binti Hakim As Sulamiyyah] -, pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang seorang wanita yang mimpi basah, lalu beliau memerintahkannya (orang yang bermimpi) untuk mandi\". "},"523":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ ��لزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا أَخْبَرَتْهُ أَنَّ أُمَّ سُلَيْمٍ أُمَّ بَنِي أَبِي طَلْحَةَ دَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ أَرَأَيْتَ الْمَرْأَةَ تَرَى فِي النَّوْمِ مَا يَرَى الرَّجُلُ أَتَغْتَسِلُ قَالَ نَعَمْ فَقَالَتْ عَائِشَةُ فَقُلْتُ أُفٍّ لَكِ أَتَرَى الْمَرْأَةُ ذَلِكَ فَالْتَفَتَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَرِبَتْ يَمِينُكِ فَمِنْ أَيْنَ يَكُونُ الشَّبَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] ia berkata: telah mengabarkan kepadaku ['Uqail] dari [Ibnu Syihab] ia berkata: Telah menceritakan kepadaku ['urwah bin Az Zubair] dari [Aisyah] -isteri Nabi shallallahu 'alaihi wasallam-, ia mengabarkannya: \"Bahwa Ummu Sulaim-Ummu Bani Thalhah- menemui Rasulullah shallallahu 'alaihi wasallam, lalu bertanya: 'Wahai Rasulullah shallallahu 'alaihi wasallam, Allah subhanallahu wa ta'ala tidak malu mengungkapkan yang baik, bagaimana menurutmu apabila seorang wanita melihat dalam tidurnya (bermimpi) sebagaimana orang laki-laki bermimpi, apakah ia wajib mandi? ', beliau menjawab: 'Ya, wajib', lalu Aisyah radliallahu 'anha berkata: 'Ah kamu ini, apakah seorang wanita bermimpi seperti itu? ', lalu Rasulullah shallallahu 'alaihi wasallam menoleh ke arahnya (Aisyah radliallahu 'anha) dan berkata: 'Kamu ini bagaimana, jika tidak mimpi, bagaimana mungkin ada kemiripan (antara anak dengan ibunya)? ' \"."},"524":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَ دَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمُّ سُلَيْمٍ وَعِنْدَهُ أُمُّ سَلَمَةَ فَقَالَتْ الْمَرْأَةُ تَرَى فِي مَنَامِهَا مَا يَرَى الرَّجُلُ فَقَالَتْ أُمُّ سَلَمَةَ تَرِبَتْ يَدَاكِ يَا أُمَّ سُلَيْمٍ فَضَحْتِ النِّسَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْتَصِرًا لِأُمِّ سُلَيْمٍ بَلْ أَنْتِ تَرِبَتْ يَدَاكِ إِنَّ خَيْرَكُنَّ الَّتِي تَسْأَلُ عَمَّا يَعْنِيهَا إِذَا رَأَتْ الْمَاءَ فَلْتَغْتَسِلْ قَالَتْ أُمُّ سَلَمَةَ وَلِلنِّسَاءِ مَاءٌ قَالَ نَعَمْ فَأَنَّى يُشْبِهُهُنَّ الْوَلَدُ إِنَّمَا هُنَّ شَقَائِقُ الرِّجَالِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] radliallahu 'anhu ia berkata: \"Ummu Sulaim menemui Rasulullah shallallahu 'alaihi wasallam dan di samping beliau ada Ummu Salamah, ia bertanya: 'Apakah seorang wanita bermimpi dalam tidurnya sebagaimana yang diimpikan oleh orang laki-laki (mimpi basah)? ', lalu ummu Salamah berkata: 'Beruntunglah kamu, wahai ummu Sulaim, kamu sudah membuka rahasia wanita', lalu Rasulullah shallallahu 'alaihi wasallam berkata sambil mendukung Ummu Sulaim: 'Bahkan kamulah yang beruntung, karena sebaik-baik dari kalian adalah yang mau bertanya tentang permasalahannya, apabila ia melihat air (mani), hendaklah ia mandi', Ummu Salamah bertanya: 'Apakah pada wanita juga ada air (mani)? ', beliau menjawab: 'Ya, lalu bagaimana bisa ada kemiripan antara anak dengan mereka (para ibu)?, mereka (wanita) adalah saudara kaum laki-laki' \". "},"525":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَوْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَسْتَيْقِظُ فَيَرَى بَلَلًا وَلَمْ يَذْكُرْ احْتِلَامًا قَالَ لِيَغْتَسِلْ فَإِنْ رَأَى احْتِلَامًا وَلَمْ يَرَ بَلَلًا فَلَا غُسْلَ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Abdur razzaq] dari [Abdillah bin Umar] atau [Ubaidullah bin Umar] dari [Al Qasim] dari [Aisyah] radliallahu 'anha dari Nabi shallallahu 'alaihi wasallam, tentang seorang laki-laki yang bangun tidur dan ia melihat basah (di pakaiannya) tetapi ia tidak ingat mimpinya (ia bermimpi atau tidak), beliau bersabda: 'Dia harus mandi, jika ia bermimpi tetapi tidak melihat ada yang basah, ia tidak wajib mandi'\"."},"526":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَيْقَظَ أَحَدُكُمْ مِنْ نَوْمِهِ فَلَا يَغْمِسْ يَدَهُ فِي الْوَضُوءِ حَتَّى يَغْسِلَهَا ثَلَاثًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu ia berkata: Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Apabila seseorang diantara kalian bangun tidur, janganlah ia langsung memasukkan tangannya ke dalam bejana, hingga ia mencucinya sebanyak tiga kali\". "},"527":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ الْحُوَيْرِثِ عَنْ ابْنِ عَبَّاسٍ قَالَ كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ الْغَائِطَ ثُمَّ خَرَجَ فَأُتِيَ بِطَعَامٍ فَقِيلَ أَلَا تَتَوَضَّأُ فَقَالَ أُصَلِّي فَأَتَوَضَّأُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amr bin Dinar] dari [Sa'id bin Al Huwairits] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam, lalu beliau masuk ke tempat buang hajat dan keluar, kemudian beliau disuguh makanan, beliau ditanya: 'apakah kamu tidak berwudhu? ', beliau menjawab: '(Jika aku mau) shalat, aku berwudhu' \"."},"528":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ اسْتُحِيضَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ وَهِيَ تَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ سَبْعَ سِنِينَ فَشَكَتْ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذِهِ لَيْسَتْ بِالْحَيْضَةِ وَإِنَّمَا هِيَ عِرْقٌ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي ثُمَّ صَلِّي قَالَتْ عَائِشَةُ فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍ ثُمَّ تُصَلِّي وَكَانَتْ تَقْعُدُ فِي مِرْكَنٍ لِأُخْتِهَا زَيْنَبَ بِنْتِ جَحْشٍ حَتَّى إِنَّ حُمْرَةَ الدَّمِ لَتَعْلُو الْمَاءَ","id":"Telah mengabarkan kepadakami [Abu Al Mughirah] dari [Al 'Auza'i] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dan ['Amrah binti Abdur Rahman bin Sa'ad bin Zurarah] dari [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata: \"Ummu Habibah binti Jahsy mengalami istihadhah saat menjadi isteri Abdur Rahman bin 'Auf selama tujuh tahun, lalu ia mengadukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, Nabi shallallahu 'alaihi wasallam bersabda: 'Ini bukanlah darah haidh akan tetapi 'irq (hentakan rahim), maka apabila kamu mendapati haidh, tinggalkanlah shalat. Dan apabila sudah lewat, hendaklah kamu mandi dan shalatlah', Aisyah radliallahu 'anha berkata: 'Lalu ia (Ummu Habibah) mandi untuk setiap waktu shalat kemudian ia shalat, dan ketika ia sedang duduk di sebuah sudut rumah saudaranya Zainab binti jahsy, darah merah terlihat seperti air (mengalir) ' \"."},"529":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ هِشَامٍ صَاحِبِ الدَّسْتَوَائِيِّ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَاشِرُ وَهُوَ صَائِمٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Hisyam] -shahabat Ad Dastawa`i-, dari [Hammad] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha ia berkata: \"Nabi shallallahu 'alaihi wasallam penah mencumbui (para isteri beliau) saat beliau sedang puasa\"."},"530":{"ar":" أَخْبَرَنَا أَبُو حَاتِمٍ الْبَصْرِيُّ رَوْحُ بْنُ أَسْلَمَ حَدَّثَنَا زَائِدَةُ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُبَاشِرُ وَهُوَ صَائِمٌ","id":"Telah mengabarkan kepada kami [Abu Hatim Al Bashri Rauh bin `Aslam], telah menceritakan kepada kami [Za`idah] dari [Sulaiman] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha. Rasulullah shallallahu 'alaihi wasallam pernah mencumbui (para isteri beliau) saat beliau sedang puasa\"."},"531":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ سُلَيْمَانُ أَخْبَرَنِي عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا نَاوِلِينِي الْخُمْرَةَ قَالَتْ إِنِّي حَائِضٌ قَالَ إِنَّهَا لَيْسَتْ فِي يَدِكِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalitsi] telah menceritakan kepada kami [Syu'bah] ia berkata: [Sulaiman] telah mengabarkan kepadaku dari [Tsabit bin 'Ubaid] dari [Al Qasim] dari [Aisyah] radliallahu 'anha Nabi shallallahu 'alaihi wasallam pernah berkata kepadanya: 'Berikanlah untukku khimar (penutup kepala) itu', ia berkata: ' aku sedang haidh', beliau bersabda: ' ia tidak terjadi di tanganmu' \"."},"532":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ جَدَّتِهَا أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْ سَمِعْتُ امْرَأَةً وَهِيَ تَسْأَلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ تَصْنَعُ بِثَوْبِهَا إِذَا طَهُرَتْ مِنْ مَحِيضِهَا قَالَ إِنْ رَأَيْتِ فِيهِ دَمًا فَحُكِّيهِ ثُمَّ اقْرُصِيهِ ثُمَّ انْضَحِي فِي سَائِرِ ثَوْبِكِ ثُمَّ صَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Fathimah binti Al Mundzir] dari neneknya - [`Asma` binti Abu Bakar] -, ia berkata: \"Aku pernah mendengar seorang wanita ia bertanya kepada Rasulullah shallallahu 'alaihi wasallam apa yang kamu lakukan terhadap pakaiannya (isteri beliau) apabila sudah suci dari haidhnya? ', beliau menjawab: 'Jika kamu melihat darah pada pakaianmu, hendaklah kamu menyikatnya, lalu bilaslah, dan siramlah ke seluruh ruas pakaianmu, kemudian shalatlah dengan mengenakannya' \". "},"533":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ بْنِ عُثْمَانَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْ سَأَلَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَيْضِ قَالَ خُذِي مَاءَكِ وَسِدْرَكِ ثُمَّ اغْتَسِلِي وَأَنْقِي ثُمَّ صُبِّي عَلَى رَأْسِكِ حَتَّى تَبْلُغِي شُؤُونَ الرَّأْسِ ثُمَّ خُذِي فِرْصَةً مُمَسَّكَةً قَالَتْ كَيْفَ أَصْنَعُ بِهَا يَا رَسُولَ اللَّهِ فَسَكَتَ قَالَتْ فَكَيْفَ أَصْنَعُ بِهَا يَا رَسُولَ اللَّهِ فَسَكَتَ فَقَالَتْ عَائِشَةُ خُذِي فِرْصَةً مُمَسَّكَةً فَتَتَبَّعِي بِهَا آثَارَ الدَّمِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْمَعُ فَمَا أَنْكَرَ عَلَيْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Isra`il] dari [Ibrahim bin Muhajir] dari [Shafiyah binti Syaibah bin Utsman] dari [Aisyah] radliallahu 'anha-ummul mu`minin-, ia berkata: \"Seorang wanita dari Anshar bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang haidh, beliau menjawab: 'Ambilah air dan dan daun bidara kemudian mandi dan bersihkanlah, kemudian guyurkan ke atas kepalamu hingga sampai ke pangkal kepala, lalu ambilah kain (yang bisa meresap) ', ia bertanya: 'Apa yang harus lakukan dengan kain tersebut, wahai Rasulullah shallallahu 'alaihi wasallam? ', lalu beliau diam, kemudian Aisyah radliallahu 'anha berkata: 'Ambilah kain tersebut dan bersihkanlah dengannya bekas-bekas darahmu', dan Rasulullah shallallahu 'alaihi wasallam mendengar (hal itu) tetapi tidak mengingkarinya' \"."},"534":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَ��ْ جَاءَتْ فَاطِمَةُ بِنْتُ أَبِي حُبَيْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ أُسْتَحَاضُ فَلَا أَطْهُرُ أَفَأَدَعُ الصَّلَاةَ قَالَ لَا إِنَّمَا ذَلِكِ عِرْقٌ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْسِلِي عَنْكِ الدَّمَ وَصَلِّي","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha ia berkata: \"Fatimah binti Abu Hubaisy datang menemui Rasulullah shallallahu 'alaihi wasallam, ia bertanya: 'Wahai Rasulullah, aku seorang wanita yang sedang mengalami istihadhah, maka aku tidak bersuci, apakah aku boleh meninggalkan shalat? ', beliau menjawab: 'Tidak boleh', itu hanyalah (darah) penyakit, sebaliknya apabila haid datang, tinggalkanlah shalat, lalu apabila ia sudah usai, maka bersihkanlah darah itu (mandilah) dan shalatlah' \"."},"535":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ ابْنَةَ جَحْشٍ اسْتُحِيضَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْغُسْلِ لِكُلِّ صَلَاةٍ فَإِنْ كَانَتْ لَتَدْخُلُ الْمِرْكَنَ وَإِنَّهُ لَمَمْلُوءٌ مَاءً فَتَنْغَمِسُ فِيهِ ثُمَّ تَخْرُجُ مِنْهُ وَإِنَّ الدَّمَ لَعَالِيهِ فَتُصَلِّي","id":"Telah mengabarkan kepada kami [Yazid] telah menberitakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha; Putri Jahsy pernah mengalami istihadhah pada zaman Rasulullah shallallahu 'alaihi wasallam, lalu beliau menyuruhnya untuk mandi pada setiap shalat, dan jika ia berada di tempat mencuci pakaian, maka tempat itu seperti penuh dengan air yang mengalir darinya dengan deras, dan darah yang keluar sangatlah banyak, (namun kemudian) iapun (tetap) mengerjakan shalat\"."},"536":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ قَالَ سَأَلْتُ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ عَنْ الْمُسْتَحَاضَةِ فَأَخْبَرَنِي عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ امْرَأَةً اسْتُحِيضَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُمِرَتْ قَالَ قُلْتُ لِعَبْدِ الرَّحْمَنِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا قَالَ لَا أُحَدِّثُكَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَأُمِرَتْ أَنْ تُؤَخِّرَ الظُّهْرَ وَتُعَجِّلَ الْعَصْرَ وَتَغْتَسِلَ لَهُمَا غُسْلًا وَتُؤَخِّرَ الْمَغْرِبَ وَتُعَجِّلَ الْعِشَاءَ وَتَغْتَسِلَ لَهُمَا غُسْلًا وَتَغْتَسِلَ لِلصُّبْحِ غُسْلًا","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] ia berkata: \"Aku pernah bertanya kepada [Abdur Rahman bin Al Qasim] tentang darah istihadhah, lalu ia mengabarkan kepadaku dari [ayahnya] dari [Aisyah] radliallahu 'anha. Bahwa pada zaman Rasulullah shallallahu 'alaihi wasallam ada seorang wanita yang mengalami istihadhah, lalu ia diperintahkan, ia (Syu'bah) berkata: Aku berkata kepada Abdur Rahman: 'Nabi shallallahu 'alaihi wasallam telah memerintahkannya? ', ia menjawab: 'Aku tidak akan menceritakan sesuatupun dari Nabi shallallahu 'alaihi wasallam. Ia berkata: 'Ia telah diperintah untuk mengakhirkan shalat dhuhur dan menyegerakan shalat ashr dan (memerintahkan) mandi untuk kedua waktu itu dengan sekali mandi, serta mengakhirkan shalat maghrib dan menyegerakan shalat isya' dan (memerintahkan) mandi untuk kedua waktu itu dengan sekali mandi, serta (memerintahkan) untuk mandi guna shalat subuh\"."},"537":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ اسْتُحِيضَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ سَبْعَ سِنِينَ وَهِيَ تَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ فَاشْتَكَتْ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَيْسَتْ بِحِيضَةٍ إِنَّمَا هُوَ عِرْقٌ فَإِذَا أَقْبَلَتْ الْحَيْضَةُ فَدَعِي الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَاغْتَسِلِي وَصَلِّي قَالَتْ عَائِشَةُ فَكَانَتْ تَغْتَسِلُ لِكُلِّ صَلَاةٍ ثُمَّ تُصَلِّي قَالَتْ وَكَانَتْ تَقْعُدُ فِي مِرْكَنٍ لِأُخْتِهَا زَيْنَبَ بِنْتِ جَحْشٍ حَتَّى إِنَّ حُمْرَةَ الدَّمِ لَتَعْلُو الْمَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepadaku [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha ia berkata: \"Ummu Habibah binti Jahsy mengalami istihadhah selama tujuh tahun, sewaktu menjadi isteri Abdur Rahman bin 'Auf, ia mengadu kepada Rasulullah shallallahu 'alaihi wasallam (tentang hal itu), kemudian beliau berkata kepadanya: ' itu bukan darah haid, tetapi ia itu penyakit, maka apabila haid datang, hendaklah kamu tinggalkan shalat, dan jika telah usai, mandilah serta shalatlah\". Aisyah radliallahu 'anha berkata: \"Maka ia (Ummu Habibah) mandi untuk setiap shalatnya kemudian ia shalat, (ia berkata): 'Dan ia duduk di tempat mencuci saudarinya-Zainab binti Jahsy-, hingga sungguh dan darah merahnya pun mengalir mengungguli aliran air\"."},"538":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّ رَجُلًا أَخْبَرَهُ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ امْرَأَةً كَانَتْ تُهَرَاقُ الدَّمَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَتْ أُمُّ سَلَمَةَ لَهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ لِتَنْظُرْ عَدَدَ اللَّيَالِي وَالْأَيَّامِ الَّتِي كَانَتْ تَحِيضُهُنَّ قَبْلَ أَنْ يَكُونَ بِهَا الَّذِي كَانَ وَقَدْرَهُنَّ مِنْ الشَّهْرِ فَتَتْرُكْ الصَّلَاةَ لِذَلِكَ فَإِذَا خَلَفَتْ ذَلِكَ وَحَضَرَتْ الصَّلَاةُ فَلْتَغْتَسِلْ وَلْتَسْتَثْفِرْ بِثَوْبٍ ثُمَّ تُصَلِّي","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Nafi'] dari [Sulaiman bin Yasar] \"Bahwa [seorang laki-laki] mengabarkan kepadanya dari [Ummu Salamah] radliallahu 'anha -isteri Nabi shallallahu 'alahi wa sallam-, ada seorang wanita pernah bercucuran darah pada zaman Rasulullah shallallahu 'alaihi wasallam, lalu Ummu Salamah meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam untuknya (wanita tersebut), kemudian beliau berkata kepadanya: 'Hendaklah wanita tersebut memperhatikan jumlah malam dan siang yang biasa terjadi padanya haid sebelum ia mengalami hal tersebut, dan (perkirakan) berapa hitungannya dalam satu bulan, maka hendaklah ia meninggalkan shalat berdasar (hitungan) tersebut, dan apabila ia telah lewat, dan tiba waktu shalat, hendaklah ia mandi dan berbalutlah dengan kain kemudian shalatlah' \"."},"539":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ أُمِّ حَبِيبَةَ قَالَتْ يَا رَسُولَ اللَّهِ غَلَبَنِي الدَّمُ قَالَ اغْتَسِلِي وَصَلِّي","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['urwah] dari [Aisyah] radliallahu 'anha Bahwa [Ummu Habibah] radliallahu 'anha pernah berkata: \"Wahai Rasulullah shallallahu 'alaihi wasallam, darah (istihadhah) itu betul-betul terkadang menjadikanku kewalahan (sering aku alami) \", beliau menjawab: \"Mandi dan shalatlah\". "},"540":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ أَنَّهَا سَمِعَتْ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ جَاءَتْ أُمُّ حَبِيبَةَ بِنْتُ جَحْشٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ اسْتُحِيضَتْ سَبْعَ سِنِينَ فَاشْتَكَتْ ذَلِكَ إِلَيْهِ وَاسْتَفْتَتْهُ فِيهِ فَقَالَ لَهَا إِنَّ هَذَا لَيْسَ بِالْحِيضَةِ إِنَّمَا هَذَا عِرْقٌ فَاغْتَسِلِي ثُمَّ صَلِّي قَالَتْ عَائِشَةُ وَكَانَتْ أُمُّ حَبِيبَةَ تَغْتَسِلُ لِكُلِّ صَلَاةٍ وَتُصَلِّي وَكَانَتْ تَجْلِسُ فِي الْمِرْكَنِ فَتَعْلُو حُمْرَةُ الدَّمِ الْمَاءَ ثُمَّ تُصَلِّي","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud Al Hasyimi] telah mengabarkan kepada kami [Ibrahim yaitu Ibnu Sa'ad], dari [Az Zuhri] dari ['Amrah binti Abdurrahman bin Sa'ad bin Zurarah] ia pernah mendengar [Aisyah] radliallahu 'anha -isteri Nabi shallallahu 'alaihi wasallam-, berkata: \"Ummu Habibah binti Jahsy radliallahu 'anha datang menemui Nabi shallahu 'alaihi wa sallam, ia mengalami istihadhah selama tujuh tahun, lalu ia mengadu tentang hal itu dan meminta fatwa tentangnya, maka beliau berkata kepadanya: 'Ini bukanlah haid, tetapi penyakit, mandilah dan shalatlah', Aisyah radliallahu 'anha berkata: 'Dan Ummu Habibah radliallahu 'anha telah mandi untuk setiap waktu dan ia shalat, dan ia pernah duduk di tempat cucian, lalu darah merah yang mengalir melebihi aliran air, kemudian ia shalat' \"."},"541":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى أَنَّ الْقَعْقَاعَ بْنَ حَكِيمٍ أَخْبَرَهُ أَنَّهُ سَأَلَ سَعِيدًا عَنْ الْمُسْتَحَاضَةِ فَقَالَ يَا ابْنَ أَخِي مَا بَقِيَ أَحَدٌ أَعْلَمُ بِهَذَا مِنِّي إِذَا أَقْبَلَتْ الْحَيْضَةُ فَلْتَدَعْ الصَّلَاةَ وَإِذَا أَدْبَرَتْ فَلْتَغْتَسِلْ وَلْتُصَلِّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya] bahwa [Al Qa'qa'] telah mengabarkannya: \"Ia telah bertanya kepada [Sa'id] tentang istihadhah, lalu ia menjawab: 'Wahai keponakanku, tidak tersisa seorang pun yang lebih tahu dalam masalah ini selain aku, apabila datang haid, tinggalkanlah shalat, dan jika sudah lewat (haidnya), mandi dan shalatlah\"."},"542":{"ar":" أَخْبَرَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمَّارٍ مَوْلَى بَنِي هَاشِمٍ عَنْ ابْنِ عَبَّاسٍ فِي الْمُسْتَحَاضَةِ تَدَعُ الصَّلَاةَ أَيَّامَ أَقْرَائِهَا ثُمَّ تَغْتَسِلُ ثُمَّ تَحْتَشِي وَتَسْتَثْفِرُ ثُمَّ تُصَلِّي فَقَالَ الرَّجُلُ وَإِنْ كَانَ يَسِيلُ قَالَ وَإِنْ كَانَ يَسِيلُ مِثْلَ هَذَا الْمَثْعَبِ","id":"Telah mengabarkan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Syu'bah] dari ['Amar] -bekas budak Bani Hasyim-, dari [Ibnu Abbas] radliallahu 'anhu tentang istihadhah: \"Hendaknya orang yang mengalami istihadhah meninggalkan shalat pada hari-hari (saat haid), kemudian mandilah (setelah suci), kemudian sumbatlah (kemaluannya) dan balutlah dan kenakanlah kain lalu shalatlah\". Seorang laki-laki bertanya: \"Meskipun darahnya mengalir terus?\", ia menjawab: \"Meskipun darahnya mengalir seperti saluran air ini\". "},"543":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سُمَيٍّ قَالَ سَأَلْتُ سَعِيدَ بْنَ الْمُسَيَّبِ عَنْ الْمُسْتَحَاضَةِ فَقَالَ تَجْلِسُ أَيَّامَ أَقْرَائِهَا وَتَغْتَسِلُ مِنْ الظُّهْرِ إِلَى الظُّهْرِ وَتَسْتَذْفِرُ بِثَوْبٍ وَيَأْتِيهَا زَوْجُهَا وَتَصُومُ فَقُلْتُ عَمَّنْ هَذَا فَأَخَذَ الْحَصَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yunus] telah menceritakan kepada kami [Sufyan] dari [Sumay] ia berkata; \"Aku pernah bertanya kepada [Sa'id bin Al Musayyab] tentang wanita yang mengalami istihadhah, ia menjawab: 'Hendaknya ia duduk berdiam (tidak mengerjakan shalat) dalam masa haidnya, lalu ia dapat mandi (dalam satu hari) dari dhuhur sampai dhuhur berikutnya, dan ia membalut (kemaluannya) dengan sehelai kain, dan suaminya (boleh) menggaulinya, ia juga boleh berpuasa', aku bertanya: 'Dari siapa kamu dapatkan (hukum) ini? ', lalu ia (Sa'id) mengambil tongkat' \"."},"544":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ تَغْتَسِلُ مِنْ ظُهْرٍ إِلَى ظُهْرٍ وَتَتَوَضَّأُ لِكُلِّ صَلَاةٍ فَإِنْ غَلَبَهَا الدَّمُ اسْتَثْفَرَتْ وَكَانَ الْحَسَنُ يَقُولُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id bin Al Musayyib] radliallahu 'anhu ia berkata: \"Hendaknya (wanita yang mengalami istihadhah) mandi dari waktu dhuhur hingga waktu dhuhur (hari berikutnya), dan ia berwudhu untuk setiap kali hendak shalat, dan jika darah mengalahkannya (darah mengalir terus), hendaknya ia membalutnya (dengan kain) ' \". Dan [Al Hasan] mengatakan hal itu juga."},"545":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى أَنَّ سُمَيًّا مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَخْبَرَهُ أَنَّ الْقَعْقَاعَ بْنَ حَكِيمٍ وَزَيْدَ بْنَ أَسْلَمَ أَرْسَلَاهُ إِلَى سَعِيدِ بْنِ الْمُسَيَّبِ يَسْأَلُهُ كَيْفَ تَغْتَسِلُ الْمُسْتَحَاضَةُ فَقَالَ سَعِيدٌ تَغْتَسِلُ مِنْ الظُّهْرِ إِلَى مِثْلِهَا مِنْ الْغَدِ لِصَلَاةِ الظُّهْرِ فَإِنْ غَلَبَهَا الدَّمُ اسْتَثْفَرَتْ وَتَوَضَّأَتْ لِكُلِّ صَلَاةٍ وَصَلَّتْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah meneritakan kepada kami [Yahya], bahwa [Sumayyah] -bekas budak bagi Abu Bakar bin Abdur Rahman bin Al Harits bin Hisyam- telah mengabarkan kepadanya: \"Al Qa'qa' bin Hakim dan Zaid bin Aslam mengutusnya kepada Sa'id bin Al Musayyib, ia bertanya kepadanya: 'Bagaimana cara mandi wanita yang mengalami istihadhah? ', [Sa'id] menjawab: 'Ia mandi dari waktu dhuhur sampai dhuhur berikutnya untuk mengerjakan shalat dhuhur, dan jika darah mengalahkannya (darah mengalir terus), hendaknya ia membalut (dengan kain), dan berwudhu untuk setiap waktu shalat, (baru kemudian) boleh mengerjakan shalat' \". "},"546":{"ar":" حَدَّثَنَا مُوسَى بْنُ خَالِدٍ عَنْ مُعْتَمِرٍ عَنْ أَبِيهِ عَنْ الْحَسَنِ فِي الْمُسْتَحَاضَةِ تَغْتَسِلُ مِنْ صَلَاةِ الظُّهْرِ إِلَى صَلَاةِ الظُّهْرِ مِنْ الْغَدِ","id":"Telah mengabarkan kepada kami [Musa bin Khalid] dari [Mu'tamir] dari [ayahnya] dari [Al Hasan] dalam hal istihadhah: \"Ia (wanita yang mengalami istihadhah) mandi dari waktu shalat dhuhur hingga shalat dhuhur keesokan harinya.\""},"547":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ قَالَ الْمُسْتَحَاضَةُ تَدَعُ الصَّلَاةَ أَيَّامَ حَيْضِهَا مِنْ الشَّهْرِ ثُمَّ تَغْتَسِلُ مِنْ الظُّهْرِ إِلَى الظُّهْرِ وَتَوَضَّأُ عِنْدَ كُلِّ صَلَاةٍ وَتَصُومُ وَتُصَلِّي وَيَأْتِيهَا زَوْجُهَا حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ عَبَّادِ بْنِ مَنْصُورٍ عَنْ الْحَسَنِ وَعَطَاءٍ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Al Hasan] ia berkata: \"Wanita yang mengalami istihadhah (hendaknya ia) meninggalkan shalat di hari-hari haidnya pada setiap bulannya, kemudian ia mandi dari dhuhur hingga dhuhur berikutnya, dan ia berwudhu ketika hendak shalat, ia dapat berpuasa dan shalat, dan boleh bagi suaminya menggaulinya\". Telah mengabarkan kapada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [hammad] dari ['Abbad bin Manshur] dari [Al Hasan] dan ['Atha`] dengan pernyataan semisal itu."},"548":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ دَاوُدَ عَنْ الشَّعْبِيِّ عَنْ قَمِيرَ امْرَأَةِ مَسْرُوقٍ أَنَّ عَائِشَةَ قَالَتْ فِي الْمُسْتَحَاضَةِ تَغْتَسِلُ كُلَّ يَوْمٍ مَرَّةً","id":"Telah mengabarkan kepada kami [Hajaj] telah menceritakan kepada kami [Hammad] dari [Daud] dari [As Sya'bi] dari [Qamir] -isteri Masruq-, Bahwa [Aisyah] radliallahu 'anha berkata tentang wanita yang mengalami istihadhah: \"Ia mandi sekali dalam sehari.\""},"549":{"ar":" أَخْبَرَنَا مَرْوَانُ عَنْ بُكَيْرِ بْنِ مَعْرُوفٍ عَنْ مُقَاتِلِ بْنِ حَيَّانَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ كَانَ يَقُولُ فِي الْمُسْتَحَاضَةِ تَغْتَسِلُ مِنْ ظُهْرٍ إِلَى ظُهْرٍ قَالَ مَرْوَانُ وَهُوَ قَوْلُ الْأَوْزَاعِيِّ","id":"Telah mengabarkan kepada kami [Marwan] dari [Bukair bin Ma'ruf] dari [Muqatil bin Hayyan] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu Bahwasanya ia berkata: \"Seorang wanita yang mengalami istihadhah, ia mandi dari waktu dhuhur hingga waktu dhuhur berikutnya (sekali dalam sehari) '. Marwan berkata: 'Pendapat itu juga merupakan pendapat Al 'Auza'i' \""},"550":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ الْمُسْتَحَاضَةُ تَغْتَسِلُ كُلَّ يَوْمٍ عِنْدَ صَلَاةِ الْأُولَى","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] dari [ubaidullah bin 'Amr] dari [Abdul Karim] dari [Sa'id bin Al Musayyib] radliallahu 'anhu ia berkata: \"Seorang wanita yang mengalami istihadhah, ia mandi setiap hari ketika hendak mengerjakan shalat pertamanya, namun pendapat ini bukanlah yang layak diikuti\"."},"551":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَتَّابٌ هُوَ ابْنُ بَشِيرٍ الْجَزَرِيُّ عَنْ خُصَيْفٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ فِي الْمُسْتَحَاضَةِ لَمْ يَرَ بَأْسًا أَنْ يَأْتِيَهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami ['Attab Ibnu Basyir Al Jazari], dari [Khushaif] dari ['Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu tentang wanita yang mengalami istihadhah: ia berpendapat bahwa tidak mengapa suaminya mendatanginya (menggauilinya) \"."},"552":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سَالِمٍ الْأَفْطَسِ قَالَ سُئِلَ سَعِيدُ بْنُ جُبَيْرٍ أَتُجَامَعُ الْمُسْتَحَاضَةُ فَقَالَ الصَّلَاةُ أَعْظَمُ مِنْ الْجِمَاعِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Salim Al `Afthas] ia berkata: \" [Sa'id bin Jubair] radliallahu 'anhu pernah ditanya, apakah wanita yang sedang mengalami istihadhah boleh digauli? ', ia menjawab: 'Shalat bahkan lebih agung daripada sekedar bersetubuh\"."},"553":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سُمَيٍّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَ يَأْتِيهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Sumay] dari [Sa'id bin Al Musayyib] radliallahu 'anhu ia berkata: \"Wanita yang tengah mengalami istihadhah, suaminya boleh mendatanginya (menggaulinya) \"."},"554":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ فِي الْمُسْتَحَاضَةِ قَالَ يَغْشَاهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Yunus] dari [Al Hasan] tentang wanita yang mengalami istihadhah, ia berkata: \"(wanita yang mengalami istihadhah), suami boleh menggaulinya\"."},"555":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ فِي الْمُسْتَحَاضَةِ يَغْشَاهَا زَوْجُهَا وَإِنْ قَطَرَ الدَّمُ عَلَى الْحَصِيرِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Abdullah bin Muslim] dari [Sa'id bin Jubair] ia berkata tentang wanita yang mengalami istihadhah: \"Suaminya boleh menggaulinya meskipun darah mengucur di atas tikarnya\"."},"556":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ قَالَ قِيلَ لِبَكْرِ بْنِ عَبْدِ اللَّهِ إِنَّ الْحَجَّاجَ بْنَ يُوسُفَ يَقُولُ إِنَّ الْمُسْتَحَاضَةَ لَا يَغْشَاهَا زَوْجُهَا قَالَ بَكْرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ الصَّلَاةُ أَعْظَمُ حُرْمَةً يَغْشَاهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Humaid] ia berkata: \"Pernah dikatakan kepada Bakar bin Abdullah: Al Hajjaj bin Yusuf berkata: 'Wanita yang mengalami istihadhah tidak boleh menggauli isterinya', [Bakar bin Abdullah Al muzani] pernah berkata: 'Shalat itu lebih agung kemuliaannya daripada sekedar suaminya menggaulinya\"."},"557":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ قَالَ يَأْتِيهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Zaid] dari [Humaid] dari [Al Hasan] ia berkata: \"Suami (wanita yang tengah mengalami istihadhah) boleh menggaulinya\"."},"558":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَطَاءٍ قَالَ فِي الْمُسْتَحَاضَةِ يُجَامِعُهَا زَوْجُهَا تَدَعُ الصَّلَاةَ أَيَّامَ حَيْضِهَا فَإِذَا حَلَّتْ لَهَا الصَّلَاةُ فَلْيَطَأْهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari ['Atha` bin As Sa`ib] dari ['Atha`] ia berkata tentang wanita yang masih mengalami istihadhah kemudian suaminya menggaulinya: 'Hendaknya ia meninggalkan shalat selama masa haidnya, dan apabila ia sudah boleh mengerjakan shalat, maka boleh (bagi suaminya) menggaulinya\"."},"559":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عُمَرُ بْنُ زُرْعَةَ الْخَارِفِيُّ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ عَنْ عَلِيٍّ قَالَ الْمُسْتَحَاضَةُ يُجَامِعُهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah meneritakan kepada kami [Umar bin Zur'ah Al Kharifi] dari [Muhammad bin Salim] dari [As Sya'bi] dari [Ali] ia berkata: \"Wanita yang mengalami istihadhah boleh digauli oleh suaminya\"."},"560":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَالْحَسَنِ وَعَطَاءٍ قَالُوا فِي الْمُسْتَحَاضَةِ تَغْتَسِلُ وَتُصَلِّي وَتَصُومُ رَمَضَانَ وَيَغْشَاهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah meneritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Sa'id bin Al Musayyib], [Al Hasan] dan ['Atha`] mereka berkata tentang wanita yang sedang mengalami istihadhah: \"Ia mandi dan boleh mengerjakan shalat, berpuasa ramadhan, dan suami boleh menggaulinya\"."},"561":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ حَفْصٍ عَنْ الْحَسَنِ قَالَ كَانَ يَقُولُ الْمُسْتَحَاضَةُ لَا يَغْشَاهَا زَوْجُهَا قَالَ أَبُو النُّعْمَانِ قَالَ لِي يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ لَا أَعْلَمُ أَحَدًا قَالَ هَذَا عَنْ الْحَسَنِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Hafsh] dari [Al Hasan] ia berkata: \"Wanita yang mengalami istihadhah tidak boleh suaminya menggaulinya', Abu An Nu'man berkata: 'Yahya bin Sa'id Al Qatthan berkata: 'Aku tidak tahu seorang pun yang mengutip perkataan ini dari Al Hasan\". "},"562":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ قَالَ كَانَ مُحَمَّدٌ يَكْرَهُ أَنْ يَغْشَى الرَّجُلُ امْرَأَتَهُ وَهِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] dari [Khalid] ia berkata: \" [Muhammad] tidak menyukai jika seorang suami menggauli isterinya sedang ia tengah mengalami istihadhah\"."},"563":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ الْمُسْتَحَاضَةُ لَا يَأْتِيهَا زَوْجُهَا وَلَا تَصُومُ وَلَا تَمَسُّ الْمُصْحَفَ","id":"Telah mengahabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [ibrahim] ia berkata: \"Seorang wanita yang sedang mengalami istihadhah, suaminya tidak boleh menggaulinya, ia tidak boleh berpuasa dan tidak boleh menyentuh mushaf (Al Qur`an) \"."},"564":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا حَجَّاجٌ الْأَعْوَرُ عَنْ شُعْبَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ الشَّعْبِيِّ عَنْ قَمِيرَ عَنْ عَائِشَةَ قَالَتْ الْمُسْتَحَاضَةُ لَا يَأْتِيهَا زَوْجُهَا","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Hajjaj Al `A'war] dari [Syu'bah] dari [Abdul Malik bin Maisarah] dari [As Sya'bi] dari [Qamir] dari [Aisyah] radliallahu 'anha ia berkata: \"Seorang wanita yang sedang mengalami istihadhah, suaminya tidak boleh menggaulinya\"."},"565":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ جَعْفَرِ بْنِ الْحَارِثِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ كَانَ يُقَالُ الْمُسْتَحَاضَةُ لَا تُجَامَعُ وَلَا تَصُومُ وَلَا تَمَسُّ الْمُصْحَفَ إِنَّمَا رُخِّصَ لَهَا فِي الصَّلَاةِ قَالَ يَزِيدُ يُجَامِعُهَا زَوْجُهَا وَيَحِلُّ لَهَا مَا يَحِلُّ لِلطَّاهِرِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ja'far bin Al Harits] dari [Manshur] dari [Ibrahim] ia berkata: \"Pernah dikatakan, bahwa seorang wanita yang mengalami istihadhah, tidak boleh digauli, tidak boleh puasa dan tidak boleh menyentuh mushhaf (Al Quran), hanyasanya diringankan dalam (mengerjakan) shalat', Yazid berkata: 'Suami (wanita yang sedang mengalami istihadhah) boleh menggaulinya, dan halal bagi wanita tersebut (untuk melakukan) apapun yang dihalalkan bagi orang yang suci\". "},"566":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ قَالَ تُمْسِكُ الْمَرْأَةُ عَنْ الصَّلَاةِ فِي حَيْضِهَا سَبْعًا فَإِنْ طَهُرَتْ فَذَاكَ وَإِلَّا أَمْسَكَتْ مَا بَيْنَهَا وَبَيْنَ الْعَشْرِ فَإِنْ طَهُرَتْ فَذَاكَ وَإِلَّا اغْتَسَلَتْ وَصَلَّتْ وَهِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Yunus] dari [Al Hasan] ia berkata: \"Seorang wanita harus menghentikan shalatnya saat haid selama tujuh hari, jika telah suci (dari haid), ia boleh kembali mengerjakannya, (andai ia tidak segera suci), ia boleh menghentikan shalatnya hingga sepuluh hari, dan jika ia telah suci (dari haid), ia boleh mengerjakannya, dan jika (tidak segera selesai), hendaknya ia mandi dan shalat, sedang ia dalam keadaan istihadhah\". "},"567":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الرَّبِيعِ عَنْ الْحَسَنِ قَالَ الْحَيْضُ عَشْرٌ فَمَا زَادَ فَهِيَ مُسْتَحَاضَةٌ و قَالَ عَطَاءٌ الْحَيْضُ خَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ar Rabi'] dari [Al Hasan] ia berkata: \"(Masa) haid itu sepuluh hari, apabila lebih dari itu, itu adalah (darah) istihadhah', ['Atha`] berkata: '(Masa) haid itu lima belas hari' \". "},"568":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْجَلْدِ بْنِ أَيُّوبَ عَنْ أَبِي إِيَاسٍ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ الْحَيْضُ عَشْرَةٌ فَمَا زَادَ فَهِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al Jald bin Ayyub] dari [Abu `Iyas Mu'awiyah bin Qurrah], dari [Anas bin Malik] radliallahu 'anhu ia berkata: \"(Masa) haid itu sepuluh hari, dan yang lebih dari itu adalah (darah) istihadhah\"."},"569":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ ثَابِتٍ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ الْحَيْضُ إِلَى ثَلَاثَ عَشْرَةَ فَمَا زَادَ فَهِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Tsabit] dari [Muhammad bin Zaid] dari [Sa'id bin Jubair] radliallahu 'anhu ia berkata: \"(Masa) haid itu sampai tiga belas hari, dan yang lebih dari itu adalah (darah) istihadhah\"."},"570":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ الْجَلْدِ بْنِ أَيُّوبَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ الْحَيْضُ عَشْرَةُ أَيَّامٍ ثُمَّ هِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Jald bin Ayyub] dari [Mu'awiyah bin Qurrah] dari [Anas bin Malik] radliallahu 'anhu ia berkata: \"(Masa) haid itu sepuluh hari, kemudian (setelah itu) adalah darah istihadhah\"."},"571":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ ثَابِتٍ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ الْحَيْضُ إِلَى ثَلَاثَةَ عَشَرَ يَوْمًا فَمَا سِوَى ذَلِكَ فَهِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Hajjaj] telah meneritakan kepada kami [Hammad] dari [Ali bin Tsabit] dari [Muhammad bin Zaid] dari [Sa'id bin Jubair] ia berkata: \"(Masa) haid itu adalah tiga belas hari, dan selain itu (lebih dari itu) adalah darah istihadhah\"."},"572":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ إِذَا رَأَتْ الدَّمَ فَإِنَّهَا تُمْسِكُ عَنْ الصَّلَاةِ بَعْدَ أَيَّامِ حَيْضِهَا يَوْمًا أَوْ يَوْمَيْنِ ثُمَّ هِيَ بَعْدَ ذَلِكَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan keapada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Yunus] dari [Al Hasan] ia berkata: \"Apabila (wanita) melihat darah, maka ia menahan (tidak mengerjakan) shalat setelah hari-hari masa haidnya (kira-kira) sehari atau dua hari, kemudian setelah itu berarti ia mengalami istihadhah\"."},"573":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْجَلْدِ بْنِ أَيُّوبَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَنَسٍ قَالَ الْمُسْتَحَاضَةُ تَنْتَظِرُ ثَلَاثًا أَرْبَعًا خَمْسًا سِتًّا سَبْعًا ثَمَانِيًا تِسْعًا عَشْرًا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Jald bin Ayyub] dari [Mu'awiyah bin Qurrah] dari [Anas] radliallahu 'anhu ia berkata: \"Seorang wanita yang mengalami istihadhah dapat menunggu tiga, empat, lima, enam, tujuh, delapan, sembilan, atau sepuluh hari\". "},"574":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ بَلَغَنَا أَنَّ الْمُسْتَحَاضَةَ تَنْتَظِرُ أَعْلَى أَقْرَائِهَا بِيَوْمٍ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Ibnu Juraij] dari ['Atha`] ia berkata: \"Telah sampai berita kepada kami bahwa wanita yang mengalami istihadhah dapat menunggu sehari paling banyak dari masa haidnya\"."},"575":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُفَضَّلِ بْنِ مُهَلْهَلٍ عَنْ سُفْيَانَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ أَقْصَى الْحَيْضِ خَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Abdullah bin Idris] dari [Mufadhdhal bin Muhalhal] dari [Sufyan] dari [ibnu Juraij] dari ['Atha`] ia berkata: \"(Masa) haid paling panjang adalah lima belas hari\"."},"576":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ قَالَ سُفْيَانُ بَلَغَنِي عَنْ أَنَسٍ أَنَّهُ قَالَ أَدْنَى الْحَيْضِ ثَلَاثَةُ أَيَّامٍ سُئِلَ عَبْدُ اللَّهِ الدَّارِمِيُّ تَأْخُذُ بِهَذَا قَالَ نَعَمْ إِذَا كَانَ عَادَتَهَا وَسَأَلْتُهُ أَيْضًا عَنْ هَذَا قَالَ أَقَلُّ الْحَيْضِ يَوْمٌ وَلَيْلَةٌ وَأَكْثَرُهُ خَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] ia berkata: [Sufyan] berkata: [Telah sampai berita kepadaku] dari [Anas] radliallahu 'anhu Bahwa ia berkata: \"(Masa) haid tercepat adalah tiga hari\", Abdullah Ad Darimi pernah ditanya: 'Apakah kamu mengambil pendapat ini? ', ia menjawab: 'Ya, jika hal itu kebiasaannya', dan aku pernah bertanya kepadanya juga tentang hal ini, ia menjawab: '(masa) haid paling sedikit adalah sehari semalam dan paling lama adalah lima belas hari' \"."},"577":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مُحَمَّدُ بْنُ أَبِي زَكَرِيَّا قَالَ أَبُو مُحَمَّد هُوَ أَبُو سَعْدٍ الصَّغَّانِيُّ عَنْ سُفْيَانَ عَنْ الرَّبِيعِ عَنْ الْحَسَنِ قَالَ أَدْنَى الْحَيْضِ ثَلَاثٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] Telah mengabarkan kepada kami [Muhammad bin Abu Zakaria] -Abu Muhammad berkata: Dia adalah Abu Sa'ad As Shaghani-, dari [Sufyan] dari [Ar Rabi'] dari [Al Hasan] ia berkata: \"(Masa) haid terpendek adalah tiga hari\"."},"578":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ مَعْقِلِ بْنِ عُبَيْدِ اللَّهِ عَنْ عَطَاءٍ قَالَ أَدْنَى الْحَيْضِ يَوْمٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Makhlad bin Yazid] dari [Ma'qil bin Ubaidullah] dari ['Atha`] ia berkata: \"(Masa) haid terbanyak adalah sehari\"."},"579":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ قَالَ إِذَا رَأَتْ الدَّمَ قَبْلَ حَيْضِهَا يَوْمًا أَوْ يَوْمَيْنِ فَهُوَ مِنْ الْحَيْضِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Wuhaib] telah meneritakan kepada kami [Yunus] dari [Al Hasan] ia berkata: \"Apabila seorang wanita melihat darah sebelum (masa haid biasanya) sehari atau dua hari, itu adalah adalah darah haid\"."},"580":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ وَقَيْسِ بْنِ سَعْدٍ عَنْ عَطَاءٍ أَنَّهُمَا قَالَا فِي الْبِكْرِ إِذَا نَفِسَتْ فَاسْتُحِيضَتْ قَالَا تُمْسِكُ عَنْ الصَّلَاةِ مِثْلَ مَا تُمْسِكُ الْمَرْأَةُ مِنْ نِسَائِهَا","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Qatadah] dan [Qais bin Sa'ad] dari ['Atha`]; Bahwa keduanya pernah berkata tentang perawan jika mengalami nifas, lalu mengalami istihadhah, keduanya berkata: \"Ia harus menahan (tidak mengerjakan) shalat seperti wanita dewasa melakukannya\"."},"581":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ قَالَ سُفْيَانُ إِذَا كَانَتْ الْمَرْأَةُ أَوَّلَ مَا تَحِيضُ تَجْلِسُ فِي الْحَيْضِ مِنْ نَحْوِ نِسَائِهَا سُئِلَ عَبْد اللَّهِ عَنْ هَذَا فَقَالَ هُوَ أَشْبَهُ الْأَشْيَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] ia berkata: [Sufyan] pernah berkata: \"Apabila seorang wanita mengalami haid pertama kali, ia diposisikan seperti wanita dewasa yang telah mengalaminya\". Hal ini kemudian ditanyakan kepada Abdullah, lalu ia menjawab: \"Itu (baik wanita yang baru pertama kali mengalami haid maupun wanita dewasa yang sudah mengalami haid) adalah kasus yang sama\". "},"582":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ عَطَاءٍ فِي الْكَبِيرَةِ تَرَى الدَّمَ قَالَ لَا نَرَاهُ حَيْضًا","id":"Telah menghabrkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Laits] dari ['Atha`] tentang seorang wanita tua yang melihat (dari kemaluannya) darah, ia berkata: \"Itu bukan darah haid\"."},"583":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنِيهِ ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ فِي امْرَأَةٍ تَرَكَهَا الْحَيْضُ ثَلَاثِينَ سَنَةً ثُمَّ رَأَتْ الدَّمَ فَأَمَرَ فِيهَا بِشَأْنِ الْمُسْتَحَاضَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan riwayat itu kepadaku [Ibnu Juraij] dari ['Atha`] dalam hal seorang wanita yang sudah tidak mengalami haid selama tiga puluh tahun, kemudian ia melihat darah (dari kemaluannya), maka ia memerintahkan (untuk menghukumi) nya sebagaimana kasus istihadhah\". "},"584":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ فِي الْكَبِيرَةِ تَرَى الدَّمَ قَالَ هِيَ بِمَنْزِلَةِ الْمُسْتَحَاضَةِ تَفْعَلُ كَمَا تَفْعَلُ الْمُسْتَحَاضَةُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha`] tentang seorang wanita tua yang melihat darah (dari kemaluannya), ia berkata: \"Kondisinya seperti wanita yang mengalami istihadhah, ia melakukan apa yang (mesti) dilakukan oleh wanita yang mengalami istihadhah\". "},"585":{"ar":" حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ وَالْحَكَمِ بْنِ عُتَيْبَةَ فِي الَّتِي قَعَدَتْ مِنْ الْمَحِيضِ إِذَا رَأَتْ الدَّمَ تَوَضَّأَتْ وَصَلَّتْ وَلَا تَغْتَسِلُ سُئِلَ عَبْد اللَّهِ عَنْ الْكَبِيرَةِ قَالَ تَوَضَّأُ وَتُصَلِّي وَإِذَا طُلِّقَتْ تَعْتَدُّ بِالْأَشْهُرِ","id":"Telah menceritakan kepada kami [Hajjaj] telah meneritakan kepada kami [Hammad] dari [Hajjaj] dari ['Atha`] dan [Al Hakam bin 'Utaibah] tentang seorang wanita yang berhenti mengalami haid (lantas mendapati darah lagi): \"Apabila ia melihat darah (lagi), hendaknya ia berwudhu dan shalat tanpa harus mandi\". Abdullah pernah ditanya tentang wanita tua (yang mendapati darah dari kemaluannya), ia menjawab: \"Hendaknya ia berwudhu dan shalat, dan apabila ia dithalaq (dicerai), ia harus menjalani 'iddah beberapa bulan\". "},"586":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ قَالَ سُفْيَانُ الطُّهْرُ خَمْسُ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] ia berkata: [Sufyan] pernah berkata: \"(Masa) suci itu selama lima belas hari\"."},"587":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْمُغِيرَةِ عَنْ إِبْرَاهِيمَ قَالَ إِذَا حَاضَتْ الْمَرْأَةُ فِي شَهْرٍ أَوْ فِي أَرْبَعِينَ لَيْلَةً ثَلَاثَ حِيَضٍ فَإِذَا شَهِدَ لَهَا الشُّهُودُ الْعُدُولُ مِنْ النِّسَاءِ أَنَّهَا رَأَتْ مَا يُحَرِّمُ عَلَيْهَا الصَّلَاةَ مِنْ طُمُوثِ النِّسَاءِ الَّذِي هُوَ الطَّمْثُ الْمَعْرُوفُ فَقَدْ خَلَا أَجَلُهَا قَالَ أَبُو مُحَمَّد سَمِعْت يَزِيدَ بْنَ هَارُونَ يَقُولُ أَسْتَحِبُّ الطُّهْرَ خَمْسَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin `Asad] telah menceritakan kepada kami [Abu 'Awanah] dari [Al Mughirah] dari [Ibrahim] ia berkata: \"Apabila seorang wanita mengalami tiga kali haid selama satu bulan atau empat puluh malam (hari), ia berkata: 'Apabila ada beberapa saksi yang adil dari kalangan wanita, bahwa ia melihat darah yang menyebabkan haramnya si wanita tersebut untuk mengerjakan shalat berdasarkan kebiasaan haid yang dialami para wanita, maka si wanita yang mengalaminya terlepas dari tanggungan (tidak wajib untuk mengerjakan shalat) \". Abu Muhammad berkata: \"Aku pernah mendengar Yazid bin Harun berkata: 'Aku lebih suka (menjadikan masa) suci (yang layak bagi wanita) adalah lima belas hari' \". "},"588":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ عَامِرٍ قَالَ جَاءَتْ امْرَأَةٌ إِلَى عَلِيٍّ تُخَاصِمُ زَوْجَهَا طَلَّقَهَا فَقَالَتْ قَدْ حِضْتُ فِي شَهْرٍ ثَلَاثَ حِيَضٍ فَقَالَ عَلِيٌّ لِشُرَيْحٍ اقْضِ بَيْنَهُمَا قَالَ يَا أَمِيرَ الْمُؤْمِنِينَ وَأَنْتَ هَا هُنَا قَالَ اقْضِ بَيْنَهُمَا قَالَ يَا أَمِيرَ الْمُؤْمِنِينَ وَأَنْتَ هَا هُنَا قَالَ اقْضِ بَيْنَهُمَا قَالَ إِنْ جَاءَتْ مِنْ بِطَانَةِ أَهْلِهَا مِمَّنْ يُرْضَى دِينُهُ وَأَمَانَتُهُ تَزْعُمُ أَنَّهَا حَاضَتْ ثَلَاثَ حِيَضٍ تَطْهُرُ عِنْدَ كُلِّ قُرْءٍ وَتُصَلِّي جَازَ لَهَا وَإِلَّا فَلَا فَقَالَ عَلِيٌّ قَالُونُ وَقَالُونُ بِلِسَانِ الرُّومِ أَحْسَنْتَ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari ['Amir] ia berkata: \"Pernah seorang wanita datang kepada Ali untuk mengadukan suaminya yang telah menceraikannya, ia berkata: 'Aku telah mengalami haid dalam sebulan sebanyak tiga kali, maka [Ali] berkata kepada [Syuraih]: 'Putuskanlah masalah antara keduanya', ia berkata: 'Wahai amirul mu`minin, (mengapa kamu memerintahkanku sedang) kamu masih di sini? ', ia berkata: 'Putuskanlah masalah antara keduanya', ia berkata: 'Wahai amirul mu`minin, kamu masih di sini? ', ia berkata: 'Putuskanlah masalah antara keduanya', ia berkata: 'Jika ada seorang wanita dari kalangan keluarga yang agama dan amanahnya baik lalu menyatakan bahwa wanita ini telah mengalami haid tiga kali dalam sebulan, lalu ia bersuci setiap kali masa sucinya itu lalu ia mengerjakan shalat, maka itu tidak mengapa baginya (untuk dicerai), namun jika tidak, maka tidak boleh (ia cerai) ', Ali berkata: 'Qaaluun'. Qaaluun dalam bahasa Ramawi artinya 'Kamu sungguh benar' \"."},"589":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ { وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ } قَالَ الْحَيْضُ قِيلَ لِأَبِي مُحَمَّدٍ أَتَقُولُ بِهَذَا قَالَ لَا سُئِلَ عَبْد اللَّهِ عَنْ حَدِيثِ شُرَيْحٍ تَقُولُ بِهِ قَالَ لَا وَقَالَ ثَلَاثُ حِيَضٍ فِي الشَّهْرِ كَيْفَ يَكُونُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [khalid bin Abdullah] dari [Khalid Al Hadzdza`] dari ['Ikrimah] (dalam penafsiran ayat) \"WA LAA YAHILLU LAHUNNA AN YAKTUMNA MAA KHALAQALLAHU FII ARHAAMIHINNA\" (Dan tidak boleh mereka menyembunyikan apa yang diciptakan Allah subhanallahu wa ta'ala dalam rahimnya) -Qs. Al Baqarah: 228-,: 'Maksudnya adalah haid', Dikatakan kepada Abu Muhammad: 'Apakah kamu mengatakan hal itu juga? ', ia menjawab: 'Tidak', dan Abdullah ditanya perihal tentang hadits Syuraih, apakah kamu mengatakan hal itu? ', ia menjawab: 'Tidak', dan ia berkata: 'Bagaimana bisa terjadi tiga kali haid dalam satu bulan? ' \"."},"590":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ قَالَتْ كَانَتْ عَائِشَةُ تَنْهَى النِّسَاءَ أَنْ يَنْظُرْنَ لَيْلًا فِي الْمَحِيضِ وَتَقُولُ إِنَّهُ قَدْ يَكُونُ الصُّفْرَةَ وَالْكُدْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Abdur Rahman bin Ishaq] dari [Abdullah bin Abu Bakar] dari ['Amrah] ia berkata: \" [Aisyah] radliallahu 'anha melarang para wanita untuk melihat darah haid pada malam hari, ia juga berkata: \"Terkadang ia (darah itu) terlihat kekuning-kuningan atau kehitam-hitaman (keruh) \". "},"591":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مَوْلَاةِ عَمْرَةَ قَالَتْ كَانَتْ عَمْرَةُ تَأْمُرُ النِّسَاءَ أَنْ لَا يَغْتَسِلْنَ حَتَّى تَخْرُجَ الْقُطْنَةُ بَيْضَاءَ","id":"Telah mengabarkan kepadda kami [Muhammad bin Isa] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [budaknya 'Amrah] ia berkata: \" ['Amrah] memerintahkan para wanita agar tidak mandi hingga kapas (yang digunakan untuk membalut kemaluan) terlihat putih\". "},"592":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ قَالَ سُفْيَانُ الْكُدْرَةُ وَالصُّفْرَةُ فِي أَيَّامِ الْحَيْضِ حَيْضٌ وَكُلُّ شَيْءٍ رَأَتْهُ بَعْدَ أَيَّامِ الْحَيْضِ مِنْ دَمٍ أَوْ كُدْرَةٍ أَوْ صُفْرَةٍ فَهِيَ مُسْتَحَاضَةٌ سُئِلَ تَأْخُذُ بِقَوْلِ سُفْيَانَ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] ia berkata: [Sufyan] berkata: \"Warna kehitam-hitaman (keruh) dan warna kekuning-kuningan pada hari-hari masa haid itu merupakan darah haid. Dan segala sesuatu yang ia lihat setelah hari-hari masa haid, baik berupa darah, atau bercak kehitam-hitaman atau bercak kekuning-kuningan, maka darah ia sedang mengalami istihadhah\". Abdullah pernah ditanya: \"Apakah kamu sepakat dengan pendapat Sufyan?\", ia menjawab: \"Ya\" \". "},"593":{"ar":" أَخْبَرَنَا يَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ صَاحِبَتِهِ فَاطِمَةَ بِنْتِ مُحَمَّدٍ وَكَانَتْ فِي حِجْرِ عَمْرَةَ قَالَتْ أَرْسَلَتْ امْرَأَةٌ مِنْ قُرَيْشٍ إِلَى عَمْرَةَ بِكُرْسُفَةِ قُطْنٍ فِيهَا كَالصُّفْرَةِ تَسْأَلُهَا هَلْ تَرَى إِذَا لَمْ تَرَ الْمَرْأَةُ مِنْ الْحِيضَةِ إِلَّا هَذَا أَنْ قَدْ طَهُرَتْ فَقَالَتْ لَا حَتَّى تَرَى الْبَيَاضَ خَالِصًا","id":"Telah mengabarkan kepada kami [Ya'la] dari [Muhammad bin Ishaq] dari [Abdullah bin Abu Bakar] dari isterinya - [Fatimah binti Muhammad] -, yang waktu itu berada dalam pemeliharaan 'Amrah, ia berkata: \"Seorang wanita dari suku Quraisy pernah mengirim sehelai kain katun yang ada bercak kekuning-kuningan, ['Amrah] bertanya kepadanya: 'Apa menurut pendapatmu jika yang terlihat ketika haid hanya darah berwarna seperti ini, apakah sudah dianggap suci? ', ia menjawab: 'Tidak, hingga kamu melihat benar-benar putih bersih' \". "},"594":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ عَنْ يَزِيدَ بْنِ زُرَيْعٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ قَالَ حَدَّثَتْنِي فَاطِمَةُ عَنْ أَسْمَاءَ قَالَتْ كُنَّا نَكُونُ فِي حِجْرِهَا فَكَانَتْ إِحْدَانَا تَحِيضُ ثُمَّ تَطْهُرُ فَتَغْتَسِلُ وَتُصَلِّي ثُمَّ تَنْكُسُهَا الصُّفْرَةُ الْيَسِيرَةُ فَتَأْمُرُنَا أَنْ نَعْتَزِلَ الصَّلَاةَ حَتَّى لَا نَرَى إِلَّا الْبَيَاضَ خَالِصًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] dari [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad bin Ishaq] ia berkata: Telah menceritakan kepadaku [Fathimah] dari [Asma`] ia berkata: 'Kami dahulu pernah tinggal bersamanya, lalu salah seorang dari kami mengalami haid kemudian suci, lalu ia mandi dan mengerjakan shalat, kemudian terlihat bercak kekuning-kuningan, maka ia (Asma`) memerintahkan kepada kami agar kami (jika mengalami haid) meninggalkan shalat hingga kami tidak melihat (dari kemaluan kami) kecuali bercak putih bersih\"."},"595":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ الْكُدْرَةُ وَالصُّفْرَةُ وَالدَّمُ فِي أَيَّامِ الْحَيْضِ بِمَنْزِلَةِ الْحَيْضِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Ibnu Juraij] dari ['Atha`] ia berkata: \"Bercak warnah keruh, kekuning-kuningan dan darah (yang keluar) pada hari-hari masa haid adalah termasuk darah haid\"."},"596":{"ar":" أَخْبَرَنَا زَيْدُ بْنُ يَحْيَى بْنِ عُبَيْدٍ الدِّمَشْقِيُّ عَنْ مُحَمَّدِ بْنِ رَاشِدٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَائِشَةَ أَنَّهَا قَالَتْ إِذَا رَأَتْ الدَّمَ فَلْتُمْسِكْ عَنْ الصَّلَاةِ حَتَّى تَرَى الطُّهْرَ أَبْيَضَ كَالْقَصَّةِ ثُمَّ لِتَغْتَسِلْ وَتُصَلِّي","id":"Telah mengabarkan kepada kami [Zaid bin yahya bin Ubaid Ad Dimasyqi] dari [Muhammad bin Rasyid] dari [Sulaiman bin Musa] dari ['Atha` bin Abu Rabah] dari [Aisyah] radliallahu 'anha Bahwa ia pernah berkata: \"Apabila ia (seorang wanita) melihat darah (keluar dari kemaluannya), hendaknya ia menahan dari mengerjakan shalat hingga ia melihat (tanda) suci, bercak putih seperti kapas, kemudian ia mandi dan shalat\"."},"597":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَامِرٍ الْأَحْوَلِ قَالَ كَانَ الْحَسَنُ لَا يَعُدُّ الصُّفْرَةَ وَالْكُدْرَةَ وَلَا مِثْلَ غُسَالَةِ اللَّحْمِ شَيْئًا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim Al `Ahwal] ia berkata: \" [Al Hasan] tidak menganggap bercak kekuning-kuningan, warna keruh kehitam-hitaman, serta darah yang seperti hasil bersihan (cucian) daging sebagai sesuatu apapun (bukan dari darah haid) \". "},"598":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْ كُنَّا لَا نَعُدُّ الصُّفْرَةَ وَالْكُدْرَةَ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu Ulayyah] dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] ia berkata: \"Kami tidak menganggap bercak kekuning-kuningan dan warna keruh kehitam-hitaman sebagai sesuatu apapun (bukan darah haid) \"."},"599":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَبْدِ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ الْحَنَفِيَّةِ فِي الْمَرْأَةِ تَرَى الصُّفْرَةَ بَعْدَ الطُّهْرِ قَالَ تِلْكَ التَّرِيَّةُ تَغْسِلُهُ وَتَوَضَّأُ وَتُصَلِّي","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Isra`il] dari [Abdul A'la] dari [Muhammad bin Al Hanafiyyah] tentang seorang wanita yang melihat bercak kekuning-kuningan setelah masa sucinya, ia berkata: \"Bercak kekuning-kuningan yang mendekati kehitam-hitaman itu harus dicuci dan wanita itu harus berwudhu lantas mengerjakan shalat\"."},"600":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ وَحَجَّاجٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ يُونُسَ وَحُمَيْدٍ عَنْ الْحَسَنِ قَالَ لَيْسَ فِي التَّرِيَّةِ شَيْءٌ بَعْدَ الْغُسْلِ إِلَّا الطُّهُورُ قَالَ عَبْد اللَّهِ التَّرِيَّةُ الصُّفْرَةُ وَالْكُدْرَةُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] dan [Hajjaj] dari [Hammad bin Salamah] dari [Yunus] dan [Humaid] dari [Al Hasan] ia berkata: \"Tidaklah dalam at tariyyah dianggap sebagai apapun setelah yang mengalaminya mandi kecuali kesucian\". Abdullah berkata: \"At tariyyah adalah bercak kekuning-kuningan dan kehitam-hitaman (keruh) \". "},"601":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَيْسٍ عَنْ عَطَاءٍ قَالَ لَيْسَ فِي التَّرِيَّةِ بَعْدَ الْغُسْلِ إِلَّا الطُّهُورُ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad bin Salamah] dari [Qais] dari ['Atha`] ia berkata: \"Tidak ada pada at tariyyah setelah mandi sehabis haid kecuali kesucian\"."},"602":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ قَتَادَةَ عَنْ أُمِّ الْهُذَيْلِ عَنْ أُمِّ عَطِيَّةَ وَكَانَتْ قَدْ بَايَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْ كُنَّا لَا نَعْتَدُّ بِالْكُدْرَةِ وَالصُّفْرَةِ بَعْدَ الْغُسْلِ شَيْئًا","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Qatadah] dari [Ummu Al Hudzail] dari [Ummu 'Athiyyah] -dan saat itu ia telah membai'at Nabi shallallahu 'alaihi wasallam-, ia berkata: \"Kami tidak menganggap bercak warna keruh kehitam-hitaman dan bercak kekuning-kuningan setelah mandi besar sebagai sesuatu apapun\"."},"603":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ إِذَا رَأَتْ الْحَائِضُ دَمًا عَبِيطًا بَعْدَ الْغُسْلِ بِيَوْمٍ أَوْ يَوْمَيْنِ فَإِنَّهَا تُمْسِكُ عَنْ الصَّلَاةِ يَوْمًا ثُمَّ هِيَ بَعْدَ ذَلِكَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Yunus] dari [Al Hasan] ia berkata: \"Apabila seorang wanita yang sedang haid melihat darah segar (yang mengalir) sehari atau dua hari setelah ia mandi hadats, maka ia harus menahan (tidak mengerjakan) shalat selama sehari, kemudian setelah itu (ia menjadi) wanita yang mengalami istihadhah\"."},"604":{"ar":" قَالَ أَبُو مُحَمَّد سَمِعْتُ يَزِيدَ بْنَ هَارُونَ يَقُولُ إِذَا كَانَ أَيَّامُ الْمَرْأَةِ سَبْعَةً فَرَأَتْ الطُّهْرَ بَيَاضًا فَتَزَوَّجَتْ ثُمَّ رَأَتْ الدَّمَ مَا بَيْنَهَا وَبَيْنَ الْعَشْرِ فَالنِّكَاحُ جَائِزٌ صَحِيحٌ فَإِنْ رَأَتْ الطُّهْرَ دُونَ السَّبْعِ فَتَزَوَّجَتْ ثُمَّ رَأَتْ الدَّمَ فَلَا يَجُوزُ وَهُوَ حَيْضٌ و سُئِلَ عَبْد اللَّهِ تَقُولُ بِهِ قَالَ نَعَمْ","id":"Abu Muhammad berkata: \"Aku pernah mendengar [Yazid bin Harun] berkata: \"Apabila (biasanya) hari-hari masa haid seorang wanita adalah tujuh hari, lalu ia melihat (tanda) suci bercak putih, lalu ia menikah, kemudian ia melihat darah (yang kembali keluar) pada masa (biasanya) hingga sepuluh hari, maka pernikahan itu boleh dan sah, dan jika ia melihat (tanda) suci sebelum genap tujuh hari, lalu ia menikah, dan kemudian ia melihat darah, maka nikahnya itu tidak boleh ketika ia sedang haid\". Abdullah pernah ditanya: \"Apakah kamu mengambil pendapat itu?\", ia menjawab: \"Ya\". "},"605":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ شَرِيكٍ عَنْ أَبِي إِسْحَقَ عَنْ الْحَارِثِ عَنْ عَلِيٍّ فِي الْمَرْأَةِ يَكُونُ حَيْضُهَا سِتَّةَ أَيَّامٍ أَوْ سَبْعَةَ أَيَّامٍ ثُمَّ تَرَى كُدْرَةً أَوْ صُفْرَةً أَوْ تَرَى الْقَطْرَةَ أَوْ الْقَطْرَتَيْنِ مِنْ الدَّمِ أَنَّ ذَلِكَ بَاطِلٌ وَلَا يَضُرُّهَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Syarik] dari [Abu Ishaq] dari [Al Harits] dari [Ali] radliallahu 'anhu tentang seorang wanita yang (biasanya) masa haidnya adalah enam atau tujuh hari, kemudian ia melihat bercak kehitam-hitaman (keruh) atau bercak kekuning-kuningan atau ia melihat satu tetes atau dua tetes darah, maka semua darah itu bathil (tidak termasuk haid) dan tidak memberi madharat padanya (untuk bisa mengerjakan shalat) \"."},"606":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الْمُسْتَحَاضَةِ قَالَ تَدَعُ الصَّلَاةَ فِي قُرُوئِهَا ذَلِكَ يَوْمًا أَوْ يَوْمَيْنِ ثُمَّ تَغْتَسِلُ فَإِذَا كَانَ عِنْدَ الْأُولَى نَظَرَتْ فَإِنْ كَانَتْ تَرِيَّةً تَوَضَّأَتْ وَصَلَّتْ وَإِنْ كَانَ دَمًا أَخَّرَتْ الظُّهْرَ وَعَجَّلَتْ الْعَصْرَ ثُمَّ صَلَّتْهُمَا بِغُسْلٍ وَاحِدٍ فَإِذَا غَابَتْ الشَّمْسُ نَظَرَتْ فَإِنْ كَانَتْ تَرِيَّةً تَوَضَّأَتْ وَصَلَّتْ وَإِنْ كَانَ دَمًا أَخَّرَتْ الْمَغْرِبَ وَعَجَّلَتْ الْعِشَاءَ ثُمَّ صَلَّتْهُمَا بِغُسْلٍ وَاحِدٍ فَإِذَا طَلَعَ الْفَجْرُ نَظَرَتْ فَإِنْ كَانَتْ تَرِيَّةً تَوَضَّأَتْ وَصَلَّتْ وَإِنْ كَانَ دَمًا اغْتَسَلَتْ وَصَلَّتْ الْغَدَاةَ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ ثَلَاثَ مَرَّاتٍ قَالَ أَبُو مُحَمَّد الْأَقْرَاءُ عِنْدِي الْحَيْضُ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] tentang seorang wanita yang mengalami istihadhah, ia berkata: \"(Hendaknya) ia meninggalkan shalat sehari atau dua hari (setelah) kebiasaan haidnya, kemudian ia (haruslah) mandi, apabila pada waktu yang pertama (dhuhur) ia melihat sesuatu berupa at tariyyah, hendaknya ia berwudhu dan shalat, tetapi jika ia melihat darah, hendaknya ia mengakhirkan waktu dhuhur dan menyegerakan ashr, kemudian ia shalat dua waktu tersebut dengan satu kali mandi, dan apabila matahari tenggelam, hendaknya ia periksa kembali, jika ia melihat at tariyyah, hendaknya ia berwudhu dan shalat, tetapi jika ia melihat darah, hendaknya ia mengakhirkan waktu maghrib dan menyegerakan isya, kemudian ia shalat dua waktu tersebut dengan satu kali mandi, dan apabila fajar telah terbit, hendaknya ia memeriksa kembali, jika ia melihat at tariyyah, hendaknya berwudhu dan shalat, dan apabila ia melihat darah, hendaknya ia mandi dan shalat subuh. Ia mengucapkannya secara berulang tiga kali\". Abu Muhammad berkata: \"Panjang masa yang biasa seorang wanita mengalami haid, aku anggap itu adalah masa haid\"."},"607":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ يَحْيَى حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَكَفَ وَاعْتَكَفَ مَعَهُ بَعْضُ نِسَائِهِ وَهِيَ مُسْتَحَاضَةٌ تَرَى الدَّمَ فَرُبَّمَا وَضَعَتْ الطَّسْتَ تَحْتَهَا مِنْ الدَّمِ وَزَعَمَ أَنَّ عَائِشَةَ رَأَتْ مَاءَ الْعُصْفُرِ فَقَالَتْ كَانَ هَذَا شَيْئًا كَانَتْ فُلَانَةُ تَجِدُهُ","id":"Telah mengabarkan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Khalid Al Hadzdza`] dari ['Ikrimah] dari [Aisyah] radliallahu 'anha; Bahwa Nabi shallallahu 'alaihi wasallam pernah beri'tikaf, turut beri'tikaf bersama beliau sebagian isteri beliau, dan (salah satu dari mereka) ia mengalami istihadhah dan melihat darah (keluar dari kemaluannya), dan terkadang ia meletakkan wadah (yang terbuat dari perunggu) untuk menghindari ceceran darah. Aisyah radliallahu 'anha merasa telah melihat airnya berwarna kekuning-kuningan. Aisyah radliallahu 'anha pun berkata: \"Kejadian ini sungguh telah dialami oleh si fulanah\"."},"608":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ الْحَجَّاجِ قَالَ سَأَلْتُ عَطَاءً عَنْ الْمَرْأَةِ تَطْهُرُ مِنْ الْمَحِيضِ ثُمَّ تَرَى الصُّفْرَةَ قَالَ تَوَضَّأُ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah meneritkana kepada kami [Abdul Wahid] dari [Al Hajjaj] ia berkata: \"Aku pernah bertanya kepada ['Atha`] tentang seorang wanita yang suci dari haid (nya) kemudian ia melihat bercak kekuning-kuningan, ia menjawab: \"Ia harus berwudhu\"."},"609":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبَّادُ بْنُ عَوَّامٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ إِذَا طَهُرَتْ الْمَرْأَةُ فِي وَقْتِ صَلَاةٍ فَلَمْ تَغْتَسِلْ وَهِيَ قَادِرَةٌ عَلَى أَنْ تَغْتَسِلَ قَضَتْ تِلْكَ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami ['Abbad bin 'Awwam] dari [Hisyam] dari [Al Hasan] ia berkata: \"Apabila seorang wanita mengalami suci (dari istihadhah) pada waktu shalat, lantas ia tidak mandi padahal ia mampu, ia harus mengqadha shalatnya itu\". "},"610":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَمْرٍو عَنْ الْحَسَنِ قَالَ إِذَا صَلَّتْ الْمَرْأَةُ رَكْعَتَيْنِ ثُمَّ حَاضَتْ فَلَا تَقْضِي إِذَا طَهُرَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abdul Warits] dari ['Amr] dari [Al Hasan] ia berkata: \"Apabila seorang wanita mengerjakan shalat dua raka`at kemudian ia mengalami haid, ia tidak harus mengqadha (shalat tersebut) jika ia suci nanti\"."},"611":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ عَنْ الْحَسَنِ وَمُغِيرَةُ عَنْ عَامِرٍ وَعُبَيْدَةُ عَنْ إِبْرَاهِيمَ فِي الْمَرْأَةِ تُفَرِّطُ فِي الصَّلَاةِ حَتَّى يُدْرِكَهَا الْحَيْضُ قَالُوا تُعِيدُ تِلْكَ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Yunus] dari [Al Hasan] dan [Mughirah] dari ['Amir] dan ['Ubaidah] dari [Ibrahim] Tentang seorang wanita yang menunda-nunda shalatnya hingga ia mengalami haid, mereka berkata: \"Wanita itu harus mengulangi shalatnya\"."},"612":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حَمَّادِ بْنِ أَبِي سُلَيْمَانَ وَيُونُسَ عَنْ الْحَسَنِ فِي امْرَأَةٍ حَضَرَتْ الصَّلَاةُ فَفَرَّطَتْ حَتَّى حَاضَتْ قَالَا تَقْضِي تِلْكَ الصَّلَاةَ إِذَا اغْتَسَلَتْ","id":"Telah menghabrkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Hammad bin Abu Sulaiman] dan [Yunus] dari [Al Hasan] Tentang seorang wanita (yang mengetahui) tibanya waktu shalat, tetapi ia merasa berat mengerjakannya (tidak segera mengerjakannya) hingga ia mengalami haid, mereka berdua berkata: \"Ia harus mengqadha shalat jika ia sudah mandi (setelah suci) \"."},"613":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ الزَّهْرَانِيُّ حَدَّثَنَا أَبُو شِهَابٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ وَقَتَادَةَ قَالَا إِذَا ضَيَّعَتْ الْمَرْأَةُ الصَّلَاةَ حَتَّى تَحِيضَ فَعَلَيْهَا الْقَضَاءُ إِذَا طَهُرَتْ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud Az Zahrani] telah menceritakan kepada kami [Abu Syihab] dari [Hisyam] dari [Al Hasan] dan [Qatadah] Keduanya berkata: \"Apabila seorang wanita menyia-nyiakan shalat (tidak segera mengerjakannya), hingga ia mengalami haid, ia harus mengqadha` shalat tersebut saat ia suci kelak\"."},"614":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ قَالَ ابْنُ الْمُبَارَكِ حَدَّثَنَا عَنْ يَعْقُوبَ عَنْ أَبِي يُوسُفَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ إِذَا حَاضَتْ الْمَرْأَةُ فِي وَقْتِ الصَّلَاةِ فَلَيْسَ عَلَيْهَا الْقَضَاءُ قَالَ أَبُو مُحَمَّد يَعْقُوبُ هُوَ ابْنُ الْقَعْقَاعِ قَاضِي مَرْوٍ وَأَبُو يُوسُفَ شَيْخٌ مَكِّيٌّ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah], berkata [Ibnu Al Mubarak]; telah menceritakan kepada kami dari [Ya'qub] dari [Abu Yusuf] dari [Sa'id bin Jubair] ia berkata: \"Jika seorang wanita mengalami haid saat ia tengah mengerjakan shalat, ia tidak harus mengqadha shalatnya.\" Abu Muhammad berkata: \"Ya'qub adalah Ibnu Al Qa'qa', ia adalah seorang qadhi wilayah Maru, Abu Yusuf adalah seorang Syeikh di Makkah\"."},"615":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حَجَّاجٍ وَقَيْسٍ عَنْ عَطَاءٍ قَالَ إِذَا طَهُرَتْ قَبْلَ الْمَغْرِبِ صَلَّتْ الظُّهْرَ وَالْعَصْرَ وَإِذَا طَهُرَتْ قَبْلَ الْفَجْرِ صَلَّتْ الْمَغْرِبَ وَالْعِشَاءَ أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ مِثْلَهُ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ مِثْلَهُ","id":"Telah mengabarkan kepada [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Hajjaj] dan [Qais] dari [Atha'] ia berkata: \"Jika seorang wanita suci sebelum maghrib, ia harus mengerjakan shalat Zhuhur dan Ashar. Dan jika ia suci sebelum Fajar, ia harus mengerjakan shalat Maghrib dan Isya`\". Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid] dari [Sa'id bin Al Musayyib] meriwayatkan hadits serupa.\" Telah mengabarkan kepada kami [Abdullah bin Muhammad] dari [Abu Bakar bin 'Ayyasy] dari [Yazid bin Abu Ziyad] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu meriwayatkan hadits yang serupa\"."},"616":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ وَطَاوُسٍ وَمُجَاهِدٍ قَالُوا إِذَا طَهُرَتْ الْحَائِضُ قَبْلَ الْفَجْرِ صَلَّتْ الْمَغْرِبَ وَالْعِشَاءَ وَإِذَا طَهُرَتْ قَبْلَ غُرُوبِ الشَّمْسِ صَلَّتْ الظُّهْرَ وَالْعَصْرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ibnu Abu Najih] dari ['Atha`], [Thawus] dan [Mujahid] mereka berkata: \"Apabila seorang wanita yang mengalami haid telah suci sebelum fajar, ia harus mengerjakan shalat maghrib dan isya`, dan apabila ia suci sebelum terbenam matahari, ia harus mengerjakan shalat dhuhur dan ashr, apabila ia suci pada akhir malam, ia harus mengerjakan shalat maghrib dan isya`\"."},"617":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ فِي الْحَائِضِ إِذَا رَأَتْ الطُّهْرَ آخِرَ النَّهَارِ صَلَّتْ الظُّهْرَ وَالْعَصْرَ وَإِذَا طَهُرَتْ آخِرَ اللَّيْلِ صَلَّتْ الْمَغْرِبَ وَالْعِشَاءَ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ لَيْثٍ عَنْ طَاوُسٍ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [al Hakam] Tentang seorang wanita yang mengalami haid apabila ia melihat (tanda-tanda) kesucian pada akhir siang, ia harus mengerjakan shalat dhuhur dan `ashr, dan apabila ia suci pada akhir malam, ia harus mengerjakan shalat maghrib dan isya`\". Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Laits] dari [thawus] dengan redaksi yang sama."},"618":{"ar":" أَخْبَرَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ مُغِيرَةَ قَالَ كَانَ إِبْرَاهِيمُ يَقُولُ إِذَا طَهُرَتْ عِنْدَ الْعَصْرِ صَلَّتْ الظُّهْرَ وَالْعَصْرَ","id":"Telah mengabarkan kepada kami [Abu Zaid Sa'id bin Ar Rabi'], telah menceritakan kepada kami [Syu'bah] dari [Mughirah] ia berkata: \" [Ibrahim] berkata: 'Apabila seorang wanita (yang mengalami haid) suci (dari haidnya) pada waktu ashr, ia harus mengerjakan shalat dhuhur dan ashr\"."},"619":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ أَوْ عِكْرِمَةُ قَالَ كَانَتْ زَيْنَبُ تَعْتَكِفُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ تُرِيقُ الدَّمَ فَأَمَرَهَا أَنْ تَغْتَسِلَ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] dari [Yahya bin Abu Katsir] ia berkata: Telah menceritakan kepadaku [Abu Salamah] dan ['Ikrimah] ia berkata: \"Zainab pernah beri'tikaf bersama Nabi shallallahu 'alaihi wasallam dan ia mengeluarkan darah, lalu beliau memerintahkannya untuk mandi setiap kali hendak mengerjakan shalat\". "},"620":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ أَنَّ عَلِيًّا وَابْنَ مَسْعُودٍ كَانَا يَقُولَانِ الْمُسْتَحَاضَةُ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] dari [Yahya bin Abu Katsir] Bahwa [Ali] dan [Ibnu Mas'ud] radliallahu 'anhuma keduanya pernah berkata: \"Wanita yang mengalami istihadhah ia harus mandi setiap hendak mengerjakan shalat\"."},"621":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ سَمِعْتُ عَطَاءَ بْنَ أَبِي رَبَاحٍ يَقُولُ تَغْتَسِلُ بَيْنَ كُلِّ صَلَاتَيْنِ غُسْلًا وَاحِدًا وَتَغْتَسِلُ لِلْفَجْرِ غُسْلًا وَاحِدًا قَالَ الْأَوْزَاعِيُّ وَكَانَ الزُّهْرِيُّ وَمَكْحُولٌ يَقُولَانِ تَغْتَسِلُ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] ia berkata: \"Aku pernah mendengar ['Atha` bin Rabah] berkata: 'Hendaknya ia mandi untuk setiap dua kali shalat dengan sekali mandi, dan untuk shalat subuh juga sekali mandi', Al 'Auza'i pernah berkata: ['Az Zuhri] dan [Mak-hul], keduanya berkata: 'Ia harus mandi untuk setiap kali hendak shalat' \"."},"622":{"ar":" أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو بِشْرٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ كَتَبَتْ امْرَأَةٌ إِلَى ابْنِ عَبَّاسٍ وَابْنِ الزُّبَيْرِ إِنِّي أُسْتَحَاضُ فَلَا أَطْهُرُ وَإِنِّي أُذَكِّرُكُمَا اللَّهَ إِلَّا أَفْتَيْتُمَانِي وَإِنِّي سَأَلْتُ عَنْ ذَلِكَ فَقَالُوا كَانَ عَلِيٌّ يَقُولُ تَغْتَسِلُ لِكُلِّ صَلَاةٍ فَقَرَأْتُ وَكَتَبْتُ الْجَوَابَ بِيَدِي مَا أَجِدُ لَهَا إِلَّا مَا قَالَ عَلِيٌّ فَقِيلَ إِنَّ الْكُوفَةَ أَرْضٌ بَارِدَةٌ فَقَالَ لَوْ شَاءَ اللَّهُ لَابْتَلَاهَا بِأَشَدَّ مِنْ ذَلِكَ أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسٍ عَنْ مُجَاهِدٍ قَالَ قِيلَ لِابْنِ عَبَّاسٍ إِنَّ أَرْضَهَا أَرْضٌ بَارِدَةٌ فَقَالَ تُؤَخِّرُ الظُّهْرَ وَتُعَجِّلُ الْعَصْرَ وَتَغْتَسِلُ غُسْلًا وَتُؤَخِّرُ الْمَغْرِبَ وَتُعَجِّلُ الْعِشَاءَ وَتَغْتَسِلُ غُسْلًا وَتَغْتَسِلُ لِلْفَجْرِ غُسْلًا","id":"Telah mengabarkan kepada kami [Abdus Shamad bin Abdul Warits] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Bisyr] ia berkata: \"Aku pernah mendengar [Sa'id bin Jubair] berkata: 'Ada [seorang wanita] menulis surat kepada [Ibnu Abbas] dan [Ibnu Az Zubair] radliallahu 'anhuma, 'Aku mengalami istihadhah dan tidak segera suci, dan aku ungkapkan hal ini kepada kalian berdua agar kalian memfatwakan kepadaku, sebenarnya aku telah bertanya hal ini, dan mereka menjawab bahwa [Ali] radliallahu 'anhu berkata: 'Ia harus mandi untuk setiap kali hendak mengerjakan shalat', aku membaca dan menulis jawaban itu dengan tulisan tangan', tidak kudapatkan pendapat lain kecuali seperti apa yang dikatakan oleh Ali radliallahu 'anhu'. Kemudian diberitakan bahwa kota Kufah itu tanah yang sangat dingin. Ibnu Abbas berkata: 'Kalau Allah subhanallahu wa ta'ala menghendaki, niscaya Ali akan menyiksa wanita ini dengan yang lebih dari itu' \". Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Qais] dari [Mujahid] ia berkata: \"Diberitakan kepada [Ibnu Abbas] radliallahu 'anhu: 'Tanahnya adalah tanah yang sangat dingin', lalu ia berkata: 'Hendaknya ia mengakhirkan shalat dhuhur dan menyegerakan shalat ashr dengan sekali mandi, ia juga mengakhirkan shalat maghrib dan menyegerakan shalat isya` dengan sekali mandi, dan ia harus mandi untuk shalat subuh' \". "},"623":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ أَنَّ ابْنَةَ جَحْشٍ كَانَتْ تَحْتَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَكَانَتْ تُسْتَحَاضُ فَكَانَتْ تَخْرُجُ مِنْ مِرْكَنِهَا وَإِنَّهُ لَعَالِيهِ الدَّمُ فَتُصَلِّي","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Zainab binti Ummu Salamah] Bahwa putri Jahsy saat menjadi isteri Abdur Rahman bin 'Auf ia pernah mengalami istihadhah, ia pernah keluar dari baskom pemandiannya sedang (warna) darahnya mengungguli (warna airnya), lalu ia tetap mengerjakan shalat\". "},"624":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ سَعِيدٍ الدِّمَشْقِيُّ عَنْ شُعَيْبِ بْنِ إِسْحَقَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ سَمِعْتُ الزُّهْرِيَّ وَيَحْيَى بْنَ أَبِي كَثِيرٍ يَقُولَانِ تُفْرِدُ لِكُلِّ صَلَاةٍ اغْتِسَالَةً قَالَ الْأَوْزَاعِيُّ وَبَلَغَنِي عَنْ مَكْحُولٍ مِثْلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Wahab bin Sa'id Ad Dimasyqi] dari [Syu'aib bin Ishaq] telah menceritakan kepada kami [Al 'Auza'i] ia berkata: Aku pernah mendengar [Az Zuhri] dan [Yahya bin Abu Katsir] keduanya berkata: \"Dikhususkan untuk setiap shalat sekali mandi\". Al 'Auza'I berkata: \"Dan [telah sampai kabar kepadaku] (riwayat) dari [Mak-hul] dengan redaksi yang sama.\""},"625":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حَمَّادٍ الْكُوفِيِّ أَنَّ امْرَأَةً سَأَلَتْ إِبْرَاهِيمَ فَقَالَتْ إِنِّي أُسْتَحَاضُ فَقَالَ عَلَيْكِ بِالْمَاءِ فَانْضَحِيهِ فَإِنَّهُ يَقْطَعُ الدَّمَ عَنْكِ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Hammad Al Kufi] Bahwa seorang wanita pernah bertanya kepada [Ibrahim] dengan berkata: 'aku mengalami istihadhah', ia berkata: 'Kamu harus mandi, siramlah badanmu, karena itu menghentikan darah' \"."},"626":{"ar":" أَخْبَرَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ دِينَارٍ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ فِي الْمُطَلَّقَةِ الَّتِي ارْتِيبَ بِهَا تَرَبَّصُ سَنَةً فَإِنْ حَاضَتْ وَإِلَّا تَرَبَّصَتْ بَعْدَ انْقِضَاءِ السَّنَةِ ثَلَاثَةَ أَشْهُرٍ فَإِنْ حَاضَتْ وَإِلَّا فَقَدْ انْقَضَتْ عِدَّتُهَا","id":"Telah mengabarkan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Muhammad bin Dinar] telah menceritakan kepada kami [Yunus] dari [Al Hasan] dalam (masalah) wanita yang di cerai, tetapi diragukan kesuciannya, maka ia menunggu setahun siapa tahu mengalami haid, dan jika belum juga haid, ia menunggu lagi tiga bulan setelah satu tahun siapa tahu mengalami haid, dan jika belum juga haid, masa 'iddah nya dianggap selesai."},"627":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ سُئِلَ مَالِكٌ عَنْ عِدَّةِ الْمُسْتَحَاضَةِ إِذَا طُلِّقَتْ فَحَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ قَالَ عِدَّتُهَا سَنَةٌ قَالَ أَبُو مُحَمَّد هُوَ قَوْلُ مَالِكٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] ia berkata: \"Malik pernah ditanya tentang 'iddah wanita yang mengalami istihadhah apabila ia dicerai\", telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyib] Bahwa ia berkata: \"'Iddah nya satu tahun\". Abu Muhammad berkata: \"Itu pendapat Malik'."},"628":{"ar":" أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ إِذَا طَلَّقَ الرَّجُلُ امْرَأَتَهُ فَحَاضَتْ حَيْضَةً أَوْ حَيْضَتَيْنِ ثُمَّ ارْتَفَعَتْ حَيْضَتُهَا إِنْ كَانَ ذَلِكَ مِنْ كِبَرٍ اعْتَدَّتْ ثَلَاثَةَ أَشْهُرٍ وَإِنْ كَانَتْ شَابَّةً وَارْتَابَتْ اعْتَدَّتْ سَنَةً بَعْدَ الرِّيبَةِ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] ia berkata: \"Apabila seorang laki-laki mencerai isterinya, kemudian ia mengalami sekali atau dua kali haid, kemudian haidnya terus meningkat, jika hal itu terjadi pada seorang wanita tua, ia menunggu 'iddah nya selama tiga bulan, dan jika ia adalah wanita belia dan ia ragu, maka 'iddah nya adalah setahun semenjak masa keraguannya\"."},"629":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ قَالَ سَأَلْتُ الزُّهْرِيَّ عَنْ الْحَامِلِ تَرَى الدَّمَ فَقَالَ تَدَعُ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami telah menceritakan kepada kami [Malik bin Anas] ia berkata: \"Aku pernah bertanya kepada [Az Zuhri] tentang seorang yang hamil dan melihat darah (keluar dari kemaluannya), ia menjawab: \" (wanita tersebut) harus meninggalkan shalat\". "},"630":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ قَالَ سَأَلْتُ مُجَاهِدًا عَنْ امْرَأَتِي رَأَتْ دَمًا وَأَنَا أُرَاهَا حَامِلًا قَالَ ذَلِكَ غَيْضُ الْأَرْحَامِ { اللَّهُ يَعْلَمُ مَا تَحْمِلُ كُلُّ أُنْثَى وَمَا تَغِيضُ الْأَرْحَامُ وَمَا تَزْدَادُ } فَمَا غَاضَتْ مِنْ شَيْءٍ رَأَتْ مِثْلَهُ فِي الْحَمْلِ","id":"Telah menghbarkan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al `Aswad] ia berkata: \"Aku pernah bertanya kepada [Mujahid] tentang isteriku, ia melihat darah (keluar dari kemaluannya) sedang aku berpendapat ia tengah hamil\", ia menjawab: \"Itu adalah penyakit rahim. (Sebagaimana firman Allah: \"(Allah subhanallahu wa ta'ala Maha mengetahui apa yang dikandung oleh setiap wanita, dan kandungan rahim yang kurang sempurna dan yang bertambah) -Qs. Ar Ra'ad: 8-, Maka segala keganjilan sesuatu, akan dilihat pula oleh wanita dalam hal kehamilan.\" "},"631":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عِكْرِمَةَ فِي هَذِهِ الْآيَةِ { اللَّهُ يَعْلَمُ مَا تَحْمِلُ كُلُّ أُنْثَى وَمَا تَغِيضُ الْأَرْحَامُ وَمَا تَزْدَادُ وَكُلُّ شَيْءٍ عِنْدَهُ بِمِقْدَارٍ } قَالَ ذَلِكَ الْحَيْضُ عَلَى الْحَبَلِ لَا تَحِيضُ يَوْمًا فِي الْحَبَلِ إِلَّا زَادَتْهُ طَاهِرًا فِي حَبَلِهَا","id":"Telah mengabarkan kepada kami [Hajjaj] telah mengabarkan kepada kami [Hammad bin Salamah] dari ['Ashim Al `Ahwal] dari ['Ikrimah] tentang ayat ini: \"(Allah subhanallahu wa ta'ala maha mengetahui apa yang dikandung oleh setiap wanita, dan kandungan rahim yang kurang sempurna dan bertambah dan segala sesuatu pada sisiNya ada ukurannya) -Qs. Ar Ra'ad: 8): \"Itu adalah haid pada masa kehamilan, tidaklah seorang wanita mengalami haid sehari dalam masa kehamilan, kecuali akan menambah masa kesucian pada kehamilannya.\" "},"632":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ عَنْ عِكْرِمَةَ { وَمَا تَغِيضُ الْأَرْحَامُ } قَالَ هُوَ الْحَيْضُ عَلَى الْحَبَلِ { وَمَا تَزْدَادُ } قَالَ فَلَهَا بِكُلِّ يَوْمٍ حَاضَتْ فِي حَمْلِهَا يَوْمًا تَزْدَادُ فِي طُهْرِهَا حَتَّى تَسْتَكْمِلَ تِسْعَةَ أَشْهُرٍ طَاهِرًا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] dari ['Ikrimah] (maksud kalimat dalam ayat): \"WA MAA TAGHIIDHUL `ARHAAMU\" (dan kandungan rahim yang kurang sempurna) -Qs. Ar Ra'ad: 8-, Maksudnya adalah haid saat hamil 'WAMAA TAZDAAD 'kandungan rahim yang bertambah', ia berkata: \"Maksudnya semakin bertambah sehari ia mengalami haid dalam masa kehamilannya, semakin pula bertambah sehari masa sucinya, hingga sempurna sembilan bulan masa sucinya\". "},"633":{"ar":" ىأَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ مُجَاهِدٍ { وَمَا تَغِيضُ الْأَرْحَامُ } قَالَ إِذَا حَاضَتْ الْمَرْأَةُ وَهِيَ حَامِلٌ قَالَ يَكُونُ ذَلِكَ نُقْصَانًا مِنْ الْوَلَدِ فَإِذَا زَادَتْ عَلَى تِسْعَةِ أَشْهُرٍ كَانَ تَمَامًا لِمَا نَقَصَ مِنْ وَلَدِهَا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Mujahid] (maksud kalimat dalam ayat) \"WA MAA TAGHIIDHUL `ARHAAMU\" (dan kandungani yang kurang sempurna) -Qs. Ar Ra'ad: 8-, ia berkata: \"(Ayat itu mengulas) jika seorang wanita mengalami haid sedang ia hamil\", ia berkata lagi: \"Hal itu merupakan kekurang sempurnaan pada janin, maka jika (masa kehamilan) melebihi sembilan bulan hal itu menjadi penyempurna bagi kekurangan janin tersebut\". "},"634":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَائِشَةَ أَنَّهَا قَالَتْ إِذَا رَأَتْ الْحُبْلَى الدَّمَ فَلْتُمْسِكْ عَنْ الصَّلَاةِ فَإِنَّهُ حَيْضٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ أَنَّهُ بَلَغَهُ عَنْ عَائِشَةَ مِثْلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [yahya bin Sa'id] dari [Aisyah] radliallahu 'anha Bahwa ia pernah berkata: \"Apabila seorang wanita yang sedang hamil melihat darah (keluar dari kemaluannya), ia harus menahan (tidak mengerjakan) shalat, karena itu adalah haid\". Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] Bahwa telah sampai kepadanya riwayat Aisyah radliallahu 'anha semisal itu\"."},"635":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ لَيْثٍ عَنْ الشَّعْبِيِّ فِي الْحَامِلِ تَرَى الدَّمَ إِنْ كَانَ الدَّمُ عَبِيطًا اغْتَسَلَتْ وَصَلَّتْ وَإِنْ كَانَتْ تَرِيَّةً تَوَضَّأَتْ وَصَلَّتْ أَخْبَرَنَا أَبُو الْمُغِيرَةِ عَنْ الْأَوْزَاعِيِّ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Ibnu Idris] dari [Laits] dari [As Sya'bi] Tentang seorang wanita hamil yang melihat darah (keluar dari kemaluannya): \"Jika darah tersebut segar, ia harus mandi dan shalat, tetapi jika darah tersebut berbentuk bercak kuning kehitam-hitaman, ia (hanya perlu) berwudhu dan boleh shalat\". Telah mengabarkan kepada kami [Abu Al Mughirah] dari [Al 'Auza'i] dengan redaksi yang sama. "},"636":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبَّادُ هُوَ ابْنُ الْعَوَّامِ عَنْ هِشَامٍ عَنْ الْحَسَنِ قَالَ إِنْ كَانَتْ تَرَاهُ كَمَا كَانَتْ تَرَاهُ قَبْلَ ذَلِكَ فِي أَقْرَائِهَا تَرَكَتْ الصَّلَاةَ وَإِنْ كَانَ إِنَّمَا هُوَ فِي الْيَوْمِ أَوْ الْيَوْمَيْنِ لَمْ تَدَعْ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami ['Abbad Ibnu Al 'Awwam], dari [Hisyam] dari [Al Hasan] ia berkata: \"Jika ia melihat (darah) sama seperti apa yang ia lihat sebelumnya dalam kebiasaan (masa haid), ia harus meninggalkan shalat, akan tetapi jika itu (hanya terjadi) sehari atau dua hari, ia tidak harus meninggalkan shalat\""},"637":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هَمَّامٌ عَنْ مَطَرٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ فِي الْحَامِلِ تَرَى الدَّمَ قَالَتْ تَغْتَسِلُ وَتُصَلِّي قَالَ يَزِيدُ لَا تَغْتَسِلُ قَالَ عَبْد اللَّهِ أَقُولُ بِقَوْلِ يَزِيدَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hammam] dari [Mathar] dari ['Atha`] dari [Aisyah] radliallahu 'anha Tentang seorang yang hamil bila ia melihat darah (keluar dari kemaluannya), ia ('Atha`) berkata: \"Ia harus mandi dan shalat\", Yazid berkata: \"Ia tidak perlu mandi\", Abdullah berkata: \"Aku berkata (berpendapat) seperti pendapat Yazid\"."},"638":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ يُونُسَ عَنْ الْحَسَنِ فِي الْحَامِلِ تَرَى الدَّمَ قَالَ هِيَ بِمَنْزِلَةِ الْمُسْتَحَاضَةِ غَيْرَ أَنَّهَا لَا تَدَعُ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Yunus] dari [Al Hasan] Tentang seorang wanita yang hamil bila melihat darah (keluar dari kemaluannya), ia berkata: \"Ia seperti wanita yang mengalami istihadhah, hanya ia tidak meninggalkan shalat\"."},"639":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو سُفْيَانَ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ فِي النُّفَسَاءِ كَطُهْرِ امْرَأَةٍ مِنْ نِسَائِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Sufyan] dari [Ma'mar] dari [Qatadah] Tentang para wanita yang sedang mengalami nifas, (ia berkata): \"Seperti sucinya wanita dewasa (dari haidnya) \"."},"640":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ فِي النُّفَسَاءِ تُمْسِكُ عَنْ الصَّلَاةِ أَرْبَعِينَ يَوْمًا فَإِنْ رَأَتْ الطُّهْرَ فَذَاكَ وَإِنْ لَمْ تَرَ الطُّهْرَ أَمْسَكَتْ عَنْ الصَّلَاةِ أَيَّامًا خَمْسًا سِتًّا فَإِنْ طَهُرَتْ فَذَاكَ وَإِلَّا أَمْسَكَتْ عَنْ الصَّلَاةِ مَا بَيْنَهَا وَبَيْنَ الْخَمْسِينَ فَإِنْ طَهُرَتْ فَذَاكَ وَإِلَّا فَهِيَ مُسْتَحَاضَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Yunus] dari [Al Hasan] tentang para wanita yang mengalami nifas, hendaknya ia menahan (tidak mengerjakan) shalat selama empat puluh hari, jika ia melihat tanda suci, itulah waktu sucinya, tetapi jika ia tidak melihat tanda suci, ia harus menahan shalat beberapa hari (sekitar) lima atau enam hari, jika kemudian ia melihat tanda suci, itulah waktu sucinya, tetapi jika tidak (melihat), ia harus menghentikan shalat mulai hitungan tersebut hingga lima puluh hari, dan jika ia melihat tanda suci, itulah waktu sucinya, dan jika tidak (melihat), berarti ia mengalami istihadhah\"."},"641":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ مُسْلِمٍ عَنْ الْحَسَنِ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَ وَقْتُ النُّفَسَاءِ أَرْبَعِينَ يَوْمًا فَإِنْ طَهُرَتْ وَإِلَّا فَلَا تُجَاوِزْهُ حَتَّى تُصَلِّيَ","id":"Telah mengabarkan kepada kami [ja'far bin 'Aun] telah mengabarkan kepada kami [Isma'il bin Muslim] dari [Al Hasan] dari [Utsman bin Abu Al 'Ash] ia berkata: \"Waktu (suci) para wanita yang mengalami nifas, adalah empat puluh hari, jika ia suci (sebelum empat puluh hari, itulah waktunya) dan jika tidak, ia tidak boleh melampauinya (waktu empat puluh hari), dan ia harus shalat."},"642":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَشْعَثَ عَنْ عَطَاءٍ قَالَ إِنْ كَانَ لِلنُّفَسَاءِ عَادَةٌ وَإِلَّا جَلَسَتْ أَرْبَعِينَ لَيْلَةً","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Asy'ats] dari ['Atha`] ia berkata: \"Jika bagi para wanita yang mengalami nifas ada kebiasaan waktu tertentu (maka itulah waktu sucinya), tetapi jika tidak ada, ia harus duduk (tidak mengerjakan shalat) selama empat puluh hari\". "},"643":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ النِّفَاسُ حَيْضٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha`] ia berkata: \"Nifas adalah haid\"."},"644":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا أَبُو خَيْثَمَةَ حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ الْأَعْلَى عَنْ أَبِي سَهْلٍ الْبَصْرِيِّ عَنْ مُسَّةَ عَنْ أُمِّ سَلَمَةَ قَالَتْ كَانَتْ النُّفَسَاءُ تَجْلِسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ يَوْمًا أَوْ أَرْبَعِينَ لَيْلَةً وَكَانَتْ إِحْدَانَا تَطْلِي الْوَرْسَ عَلَى وَجْهِهَا مِنْ الْكَلَفِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Abu Khaitsamah] telah menceritakan kepada kami [Ali bin Abdul A'la] dari [Abu Sahl Al Bashri] dari [Mussah] dari [Ummu Salamah] radliallahu 'anha ia berkata: \"Dahulu para wanita yang mengalami nifas pada masa Rasulullah shallallahu 'alaihi wasallam (mereka) duduk (tidak mengerjakan shalat) selama empat puluh hari atau empat puluh malam, dan salah seorang dari kami (biasanya) mengolesi wajahnya dengan al waras (tumbuhan berwarna kuning dan beraroma wangi) untuk menutupi bercak hitam di wajahnya\"."},"645":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ جَلْدٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ أَنَّ امْرَأَةً لِعَائِذِ بْنِ عَمْرٍو نُفِسَتْ فَجَاءَتْ بَعْدَمَا مَضَتْ عِشْرُونَ لَيْلَةً فَدَخَلَتْ فِي لِحَافِهِ فَقَالَ مَنْ هَذِهِ قَالَتْ أَنَا فُلَانَةُ إِنِّي قَدْ تَطَهَّرْتُ فَرَكَضَهَا بِرِجْلِهِ فَقَالَ لَا تُغَرِّنِي عَنْ دِينِي حَتَّى تَمْضِيَ أَرْبَعُونَ لَيْلَةً","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Hisyam] dari [Jald] dari [Mu'awiyah bin Qurrah] Bahwa isteri 'A`idz bin 'Amr mengalami nifas, ia mendatangi (suaminya) ketika baru lewat dua puluh malam (masa nifasnya), ia masuk ke dalam selimutnya. ['A`idz] bertanya: \"Ini siapa?\", ia menjawab: \"Aku isterimu, aku sudah suci\", lalu 'A`idz menendangnya dengan kakinya, lantas ia berkata: \"Jangan kamu cemarkan agamaku hingga kamu melewati (masa nifas) empat puluh malam\"."},"646":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ ابْنِ عَبَّاسٍ قَالَ النُّفَسَاءُ تَنْتَظِرُ نَحْوًا مِنْ أَرْبَعِينَ يَوْمًا","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Yusuf bin Mahak] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Para wanita yang mengalami nifas, ia menunggu empat puluh hari\"."},"647":{"ar":" أَخْبَرَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ أَنَّ الْحَسَنَ قَالَ فِي النُّفَسَاءِ الَّتِي تَرَى الدَّمَ تَرَبَّصُ أَرْبَعِينَ لَيْلَةً ثُمَّ تُصَلِّي وَقَالَ الشَّعْبِيُّ شَهْرَيْنِ ثُمَّ هِيَ بِمَنْزِلَةِ الْمُسْتَحَاضَةِ","id":"Telah mengabarkan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] Bahwa [Al hasan] pernah berkata tentang para wanita yang mengalami nifas sedang ia melihat darah (keluar dari kemaluannya): \"Ia harus menunggu (masa sucinya) empat puluh malam, kemudian (ia boleh) shalat\". [As Sya'bi] pernah berkata: \"(Wanita itu harus menunggu selama) dua bulan, kemudian (jika melebihi batas itu) berarti ia mengalami istihadhah\"."},"648":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سُلَيْمَانَ الْأَفْطَسُ قَالَ سَمِعْتُ الْعَلَاءَ بْنَ الْحَارِثِ عَنْ مَكْحُولٍ قَالَ الْمَرْأَةُ تَنْتَظِرُ مِنْ الْغُلَامِ ثَلَاثِينَ يَوْمًا وَمِنْ الْجَارِيَةِ أَرْبَعِينَ يَوْمًا يَعْنِي النُّفَسَاءَ قَالَ مَرْوَانُ هُوَ قَوْلُ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ و قَالَ الْأَوْزَاعِيُّ هُمَا سَوَاءٌ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Muhammad bin Syu'aib] telah menceritakan kepada kami [Ibrahim bin Sulaiman Al `Afthas] ia berkata: Aku pernah mendengar [Al 'Ala` bin Al Harits] dari [Makhul] ia berkata: \"Seorang wanita harus menunggu selama tiga puluh hari (selepas melahirkan) anak laki-laki, dan menunggu selama empat puluh hari (selepas melahirkan) anak perempuan, yaitu para wanita yang mengalami nifas\". Marwan mengatakan: \"Itu juga pendapat Sa'id bin Abdul Aziz\". Al 'Auza'i pernah berkata: \"Keduanya (laki-laki dan perempuan) adalah sama\"."},"649":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ فِي الْمَرْأَةِ تُجْنِبُ ثُمَّ تَحِيضُ قَالَ تَغْتَسِلُ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ الْحَسَنِ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Mughirah] dari [Ibrahim] tentang seorang wanita yang junub kemudian haid, ia berkata: \"Wanita itu harus mandi\". Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [sufyan] dari [Hisyam] dari [Al Hasan] dengan redaksi yang sama."},"650":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ عَطَاءٍ قَالَ الْحَيْضُ أَكْبَرُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al 'Ala`bin Al Musayyib] dari ['Atha`] ia berkata: \"Haid itu lebih besar (dari pada junub) \". "},"651":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ فِي رَجُلٍ غَشِيَ امْرَأَتَهُ فَحَاضَتْ فَقَالَ تَغْتَسِلُ أَحَبُّ إِلَيَّ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Mughirah] dari [Ibrahim] Tentang seorang laki-laki yang menggauli isterinya, kemudian ia mengalami haid, ia berkata: \"(Jika) segera mandi itu lebih aku sukai\"."},"652":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ وَالنَّخَعِيِّ قَالَا لِتَغْتَسِلْ مِنْ الْجَنَابَةِ حَدَّثَنَا حَجَّاجٌ عَنْ حَمَّادٍ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ الْحَسَنِ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Hajjaj] dari ['Atha`] dan [An Nakha'i] Keduanya berkata: \"Hendaknya (wanita yang junub lalu haid), ia mandi karena junub\". Telah mengabarkan kepada kami [Hajjaj] dari [Hammad] dari ['Amir Al `Ahwal] dari [Al Hasan] dengan riwayat yang semisal itu."},"653":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْمُسَيَّبِ قَالَ سُئِلَ عَنْهَا حَمَّادٌ فَقَالَ قَالَ إِبْرَاهِيمُ تَغْتَسِلُ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin `Asad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Al 'Ala` bin Al Musayyib] ia berkata: \" [Hammad] ditanya tentang hal tersebut, maka ia menjawab: \" [Ibrahim] pernah mengatakan: '(Wanita yang mengalaminya) harus mandi' \". "},"654":{"ar":" حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ ابْنِ فُضَيْلٍ عَنْ مُحَمَّدِ بْنِ سَالِمٍ عَنْ الشَّعْبِيِّ قَالَ تَغْتَسِلُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] dari [Ibnu Fudhail] dari [Muhammad bin Salim] dari [As Sya'bi] ia berkata: \"(Wanita yang mengalaminya) harus mandi\"."},"655":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ قَالَ سَمِعْتُ الْحَكَمَ بْنَ عُتَيْبَةَ يَقُولُ كَانَ يُعْجِبُهُمْ فِي الْمَرْأَةِ الْحَائِضِ أَنْ تَوَضَّأَ وُضُوءَهَا لِلصَّلَاةِ ثُمَّ تُسَبِّحَ اللَّهَ وَتُكَبِّرَهُ فِي وَقْتِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Yahya bin Ayyub] ia berkata: \"Aku pernah mendengar [Al Hakam bin 'Utaibah] berkata: 'Mereka sangat takjub terhadap seorang wanita yang mengalami haid, ia berwudhu sebagaimana wudhunya untuk shalat kemudian ia bertasbih serta bertakbir kepada-Nya pada waktu shalat\"."},"656":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ التَّيْمِيِّ قَالَ قُلْتُ لِأَبِي قِلَابَةَ الْحَائِضُ تَتَوَضَّأُ عِنْدَ وَقْتِ كُلِّ صَلَاةٍ وَتَذْكُرُ اللَّهَ فَقَالَ مَا وَجَدْتُ لِهَذَا أَصْلًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Sulaiman At Taimi] ia berkata: Aku bertanya: kepada [Abu Qilabah]: \"(Bagaimana tentang) seorang wanita yang mengalami haid yang berwudhu pada setiap waktu shalat, lalu ia berdzikir kepada Allah subhanallahu wa ta'ala?\", ia menjawab: \"Aku sama sekali tidak pernah mendapatkan (dasar) untuk masalah seperti ini\"."},"657":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ حَدَّثَنِي خَالِدُ بْنُ يَزِيدَ الصَّدَفِيُّ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ أَنَّهُ كَانَ يَأْمُرُ الْمَرْأَةَ الْحَائِضَ عِنْدَ أَوَانِ الصَّلَاةِ أَنْ تَوَضَّأَ وَتَجْلِسَ بِفِنَاءِ مَسْجِدِهَا فَتَذْكُرَ اللَّهَ وَتُسَبِّحَ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] ia berkata: Telah menceritakan kepada kami [Khalid bin Yazid Ash Shadafi] dari [ayahnya] dari ['Uqbah bin 'Amir Al Juhani] Bahwa ia memerintahkan wanita yang mengalami haid ketika tiba waktu shalat untuk berwudhu dan duduk di teras masjidnya sambil berdzikir dan bertasbih kepada Allah subhanallahu wa ta'ala."},"658":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الْمَرْأَةِ الْحَائِضِ أَتَقْرَأُ قَالَ لَا إِلَّا طَرَفَ الْآيَةِ وَلَكِنْ تَوَضَّأُ عِنْدَ وَقْتِ كُلِّ صَلَاةٍ ثُمَّ تَسْتَقْبِلُ الْقِبْلَةَ وَتُسَبِّحُ وَتُكَبِّرُ وَتَدْعُو اللَّهَ ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] Tentang seorang wanita yang mengalami haid, apakah ia (boleh) membaca (Al Qur`an)?, ia menjawab: \"Tidak, kecuali (kalimat pada) ujung ayat, akan tetapi ia dapat berwudhu pada setiap waktu shalat, kemudian ia menghadap qiblat, bertasbih, bertakbir dan berdo`a kepada Allah subhanallahu wa ta'ala\"."},"659":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا ضَمْرَةُ حَدَّثَنَا السَّيْبَانِيُّ وَهُوَ يَحْيَى بْنُ أَبِي عَمْرٍو مِنْ أَهْلِ الرَّمْلَةِ حَدَّثَنَا مَكْحُولٌ قَالَ تُؤْمَرُ الْحَائِضُ تَتَوَضَّأُ عِنْدَ مَوَاقِيتِ الصَّلَاةِ وَتَسْتَقْبِلُ الْقِبْلَةَ وَتَذْكُرُ اللَّهَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid] telah meneritakan kepada kami [Dhamrah] telah menceritakan kepada kami [As Saibani Yahya bin Abu 'Amr] dari penduduk Ramlah-, telah menceritakan kepada kami [Makhul] ia berkata: \"Seorang wanita yang mengalami haid ia diperintahkan untuk berwudhu di setiap waktu shalat, kemudian menghadap qiblat dan berdzikir kepada Allah subhanallahu wa ta'ala\". "},"660":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ قَالَ إِذَا سَمِعَ الْحَائِضُ وَالْجُنُبُ السَّجْدَةَ يَغْتَسِلُ الْجُنُبُ وَيَسْجُدُ وَلَا تَقْضِي الْحَائِضُ لِأَنَّهَا لَا تُصَلِّي","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hammad] dari [Ibrahim] ia berkata: \"Apabila seorang wanita haid dan junub mendengar (bacaan ayat) sajdah, hendaknya yang junub mandi dan bersujud, sedang yang haid tidak perlu melakukannya, karena ia tidak wajib shalat (saat itu) \"."},"661":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ فِي الْحَائِضِ تَسْمَعُ السَّجْدَةَ قَالَ لَا تَقْضِي","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Mughirah] dari [Ibrahim] tentang wanita haid yang mendengar (bacaan ayat) sajdah, ia berkata: \"Ia tidak perlu melakukan (sujud) \"."},"662":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ وَجَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ قَالَ لَيْسَ عَلَيْهَا شَيْءٌ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dan [Ja'far bin 'Aun] dari [Sa'id] dari [Abu Ma'syar] dari [Ibrahim] ia berkata: \"(Wanita haid yang mendengar ayat sajdah) tidak ada keharusan apa-apa\"."},"663":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عُبَيْدَةُ بْنُ مُعَتِّبٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ كُنَّا نَحِيضُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا يَأْمُرُ امْرَأَةً مِنَّا بِرَدِّ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada Kami ['Ubaidah bin Mu'attib] dari [Ibrahim] dari [Al `Aswad] dari [Aisyah] raddhiallahu 'anha berkata: \"Dahulu kami pernah mengalami haid pada masa Rasulullah shallallahu 'alaihi wasallam, beliau tidak memerintahkan seorang (wanita pun) diantara kami untuk mengerjakan shalat (yang tertinggal ketika masa haid) \"."},"664":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ مُعَاذَةَ أَنَّ امْرَأَةً سَأَلَتْ عَائِشَةَ أَتَقْضِي إِحْدَانَا صَلَاةَ أَيَّامِ حَيْضِهَا فَقَالَتْ أَحَرُورِيَّةٌ أَنْتِ قَدْ كَانَتْ إِحْدَانَا تَحِيضُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تُؤْمَرُ بِقَضَاءٍ أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ يَزِيدَ الرِّشْكِ عَنْ مُعَاذَةَ قَالَ أَبُو النُّعْمَانِ كَأَنَّ حَمَّادًا فَرِقَ حَدِيثَ أَيُّوبَ فَجَاءَ بِهَذَا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Mu'adzah]: Ada seorang wanita bertanya kepada [Aisyah] radliallahu 'anha: \"Apakah salah seorang dari kami wajib mengqadha` shalatnya pada hari-hari haid?\", ia menjawab: \"Apakah kamu orang Haruriyah?, sungguh salah seorang dari kami pernah mengalami haid pada zaman Rasulullah shallallahu 'alaihi wasallam, beliau tidak memerintahkannya untuk mengqadha` (shalatnya) \". Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad] dari [Yazid Ar Rasyk] dari [Mu'adzah]. Abu An Nu'man berkata: \"Sepertinya Hammad memisahkan antara hadits Ayyub dan lebih memilih hadits ini\". "},"665":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَامِرٍ قَالَ إِذَا سَمِعَتْ الْحَائِضُ السَّجْدَةَ فَلَا تَسْجُدْ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari ['Atha` bin As Sa`ib] dari ['Amir] ia berkata: \"Apabila seorang wanita haid mendengar (bacaan ayat) sajdah, tidak perlu sujud\"."},"666":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ قَالَ لَا تَسْجُدُ الْمَرْأَةُ الْحَائِضُ إِذَا سَمِعَتْ السَّجْدَةَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] ia berkata: \"Seorang wanita yang sedang haid tidak perlu sujud ketika mendengar (bacaan ayat) sajdah\"."},"667":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدٍ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ أَنَّهُ كَانَ يَكْرَهُ لِلْحَائِضِ أَنْ تَسْجُدَ إِذَا سَمِعَتْ السَّجْدَةَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid] dari [Al Hasan bin Ubaidullah] dari [Ibrahim]: ia membenci seorang wanita haid untuk sujud ketika ia mendengar (bacaan ayat) sajdah."},"668":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ لَيْثٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ قَالَ أَتَتْ امْرَأَةٌ إِلَى عَائِشَةَ فَقَالَتْ أَقْضِي مَا تَرَكْتُ مِنْ صَلَوَاتِي فِي الْحَيْضِ عِنْدَ الطُّهْرِ فَقَالَتْ عَائِشَةُ أَحَرُورِيَّةٌ أَنْتِ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَتْ إِحْدَانَا تَحِيضُ وَتَطْهُرُ فَلَا يَأْمُرُنَا بِالْقَضَاءِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Khalid] dari [Laits] dari [Abdur Rahman bin Al Qasim] dari [ayahnya] ia berkata: \"Ada seorang wanita datang menemui Aisyah radliallahu 'anha, ia bertanya: 'Apakah aku harus mengqadha` shalat yang aku tinggalkan selama masa haid ketika suci nanti? ', [Aisyah] radliallahu 'anha menjawab: 'Apakah kamu kelompok Haruriyah?, dahulu kami bersama Rasulullah shallallahu 'alaihi wasallam, salah seorang dari kami mengalami haid dan (kemudian) suci, tetapi beliau tidak memerintahkan kami untuk mengqadha`' \"."},"669":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا شَرِيكٌ عَنْ كَثِيرٍ أَبِي إِسْمَعِيلَ قَالَ قُلْتُ لِفَاطِمَةَ يَعْنِي بِنْتَ عَلِيٍّ أَتَقْضِينَ صَلَاةَ أَيَّامِ حَيْضِكِ قَالَتْ لَا","id":"Telah mengabarkan kepada kami [Ishaq bin Isa] telah menceritakan kepada kami [Syarik] dari [Katsir bin Isma'il] ia berkata: \"Aku pernah bertanya kepada [Fathimah] radliallahu 'anha-yaitu putrinya Ali radliallahu 'anhu-, Apakah kamu mengqadha` shalat kamu (yang tidak kamu lakukan) pada hari haid?\", ia menjawab: \"Tidak\"."},"670":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ الْحَائِضُ وَالْجُنُبُ يَذْكُرَانِ اللَّهَ وَيُسَمِّيَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Mughirah] dari [Ibrahim] ia berkata: \"Orang yang haid dan orang yang sedang junub keduanya boleh berdzikir dan menyebut nama Allah subhanallahu wa ta'ala\"."},"671":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ قَالَ بَلَغَنِي عَنْ إِبْرَاهِيمَ وَسَعِيدِ بْنِ جُبَيْرٍ أَنَّهُمَا قَالَا لَا يَقْرَأْ الْجُنُبُ وَالْحَائِضُ آيَةً تَامَّةً يَقْرَأَانِ الْحَرْفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] ia berkata: [Telah sampai kabar kepadaku] dari [Ibrahim] dan [Sa'id bin Jubair], keduanya pernah berkata: \"Wanita haid dan orang yang junub tidak boleh membaca ayat (Al Qur`an) secara lengkap, tetapi keduanya boleh membaca satu huruf\". "},"672":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْبَزَّازُ حَدَّثَنَا شَرِيكٌ عَنْ فِرَاسٍ عَنْ عَامِرٍ الْجُنُبُ وَالْحَائِضُ لَا يَقْرَأَانِ الْقُرْآنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Bazzaz] telah menceritakan kepada kami [Syarik] dari [Firas] dari ['Amir]: Orang yang junub dan yang haid tidak boleh membaca Al Qur`an."},"673":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ قَالَ كَانَ عُمَرُ يَكْرَهُ أَوْ يَنْهَى أَنْ يَقْرَأَ الْجُنُبُ قَالَ شُعْبَةُ وَجَدْتُ فِي الْكِتَابِ وَالْحَائِضُ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] ia berkata: \" [Umar] radliallahu 'anhu membenci atau melarang seorang yang junub membaca (Al Qur`an) \", Syu'bah berkata: \"Dalam sebuah kitab aku temukan: dan wanita yang mengalami haid\". "},"674":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ قَالَ أَرْبَعَةٌ لَا يَقْرَءُونَ الْقُرْآنَ عِنْدَ الْخَلَاءِ وَفِي الْحَمَّامِ وَالْجُنُبُ وَالْحَائِضُ إِلَّا الْآيَةَ وَنَحْوَهَا لِلْجُنُبِ وَالْحَائِضِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Hisyam Ad Dastawa`i] dari [Hammad] dari [Ibrahim] ia berkata: \"Ada empat (orang) yang tidak boleh membaca Al Qur`an: \"Seseorang yang berada di khala` (tempat buang hajat), orang yang sedang ada di kamar mandi, orang yang junub, dan wanita haid, kecuali satu ayat atau sejenisnya, hal itu boleh bagi orang yang junub dan wanita yang sedang haid\". "},"675":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ وَحَمَّادٍ عَنْ إِبْرَاهِيمَ وَسَعِيدِ بْنِ جُبَيْرٍ قَالُوا الْحَائِضُ وَالْجُنُبُ يَسْتَفْتِحُونَ الْآيَةَ وَلَا يُتِمُّونَ آخِرَهَا","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid Al `Ahmar] dari [Hajjaj] dari ['Atha`] dan [Hammad] dari [Ibrahim] dan [Sa'id bin Jubair] mereka berkata: \"Wanita haid dan orang junub boleh mengawalmulai bacaan ayat tetapi mereka tidak boleh menyelesaikan akhirnya\". "},"676":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى وَأَبُو نُعَيْمٍ قَالَا أَخْبَرَنَا السَّائِبُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَنَّ عَائِشَةَ كَانَتْ تَرْقِي أَسْمَاءَ وَهِيَ عَارِكٌ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dan [Abu Nu'aim] keduanya berkata: Telah mengabarkan kepada kami [As Sa`ib bin Umar] dari [Ibnu Abu Mulaikah]: [Aisyah] radliallahu 'anha pernah meruqyah Asma` radliallahu 'anha, sedang ia (dalam keadaan) haid\"."},"677":{"ar":" أَخْبَرَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ قَالَ الْجُنُبُ يَذْكُرُ اسْمَ اللَّهِ","id":"Telah mengabarkan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] ia berkata: \"Orang junub (dibolehkan) menyebut nama Allah subhanallahu wa ta'ala\"."},"678":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ عَنْ أَبِي وَائِلٍ قَالَ كَانَ يُقَالُ لَا يَقْرَأُ الْجُنُبُ وَلَا الْحَائِضُ وَلَا يُقْرَأُ فِي الْحَمَّامِ وَحَالَانِ لَا يَذْكُرُ الْعَبْدُ فِيهِمَا اللَّهَ عِنْدَ الْخَلَاءِ وَعِنْدَ الْجِمَاعِ إِلَّا أَنَّ الرَّجُلَ إِذَا أَتَى أَهْلَهُ بَدَأَ فَسَمَّى اللَّهَ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Sayyar] dari [Abu Wa`il] ia berkata: \"Pernah dikatakan bahwa orang junub dan wanita yang sedang haid tidak boleh membaca (Al Qur`an) dan Al Qur`an tidak boleh dibaca dalam kamar mandi, dan ada dua kondisi yang seorang hamba tidak boleh menyebut nama Allah subhanallahu wa ta'ala: ketika berada di khala` (tempat buang hajat) dan ketika sedang bersenggama, kecuali seorang laki-laki yang hendak menggauli isterinya, maka ia memulai dengan menyebut nama Allah subhanallahu wa ta'ala\"."},"679":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي عَطَّافٍ عَنْ أَبِي هُرَيْرَةَ قَالَ أَرْبَعٌ لَا يَحْرُمْنَ عَلَى جُنُبٍ وَلَا حَائِضٍ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ ��َكْبَرُ سُئِلَ أَبُو مُحَمَّد عَبْد اللَّهِ يَقْرَأُ الْجُنُبُ آيَةً آيَةً قَالَ لَا يُعْجِبُنِي","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Al Jurairi] dari [Abu 'Aththaf] dari [Abu Hurairah] radliallahu 'anhu ia berkata: \"Empat (bacaan) yang tidak diharamkan atas orang yang junub dan yang sedang haid: Subhanallahu (Maha Suci Allah), Alhamdu lillahi (Segala Puji bagi Allah), Lailaaha illa Allah (tidak ada Tuhan yang patut disembah kecuali Allah), dan Allahu Akbar) (Allah Maha Besar) \"."},"680":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ حَدَّثَنَا الْحَسَنُ بْنُ عُبَيْدِ اللَّهِ عَنْ مُسْلِمِ بْنِ صُبَيْحٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ سُئِلَ عَنْ الْحَائِضِ تَسْمَعُ السَّجْدَةَ قَالَ لَا تَسْجُدُ لِأَنَّهَا صَلَاةٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Abdur Rahim bin Sulaiman] telah menceritakan kepada kami [Al Hasan bin Ubaidullah] dari [Muslim bin Shubaih] dari [Ibnu Abbas] radliallahu 'anhu: Ia ditanya tentang wanita yang haid dan mendengar (bacaan ayat) sajdah, ia berkata: \"Ia tidak perlu sujud, karena hal itu terhitung shalat\". "},"681":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ وَأَبِي الضُّحَى قَالَا لَا تَسْجُدُ","id":"Telah mengabarkan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Hafsh Ibnu Ghiyats], dari [Al Hasan bin Ubaidullah] dari [Ibrahim] dan [Abu Adh Dhuha] keduanya berkata: \" (wanita haid) Tidak perlu sujud\"."},"682":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ حَجَّاجٍ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ وَسَعِيدِ بْنِ جُبَيْرٍ قَالَا لَيْسَ عَلَيْهَا ذَاكَ الصَّلَاةُ أَكْبَرُ مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Ibnu Numair] dari [Hajjaj] dari [Hammad] dari [Ibrahim] dan [Sa'id bin Jubair] keduanya berkata: 'Wanita tidak ada keharusan sujud dalam ayat sajdah, sedang shalat lebih besar dari hal itu\"."},"683":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ مُنِعَتْ خَيْرًا مِنْ ذَلِكَ الصَّلَاةَ الْمَكْتُوبَةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Ibnu Juraij] dari ['Atha`] ia berkata: \"Wanita haidh dilarang mengerjakan suatu hal yang lebih baik dari sujud tilawah, yaitu shalat wajib\". "},"684":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ حُمَيْدٍ حَدَّثَنَا غُنْدَرٌ عَنْ أَشْعَثَ عَنْ الْحَسَنِ قَالَ لَا تَسْجُدُ","id":"Telah mengabarkan kepada kami [Ahmad bin Humaid] telah menceritakan kepada kami [Ghundar] dari [`Asy'ats] dari [Al Hasan] ia berkata: \"Wanita haidh tidak perlu sujud (tilawah) \"."},"685":{"ar":" أَخْبَرَنَا أَحْمَدُ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ فِي الْمَرْأَةِ تَرَى الطُّهْرَ فَتَسْمَعُ السَّجْدَةَ قَالَ لَا تَسْجُدُ حَتَّى تَغْتَسِلَ","id":"Telah mengabarkan kepada kami [Ahmad] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yunus] dari [Az Zuhri] Tentang seorang wanita yang melihat (tanda-tanda) suci, kemudian ia mendengar (bacaan ayat) sajdah, ia berkata: \"Tidak boleh sujud hingga mandi (terlebih dahulu) \"."},"686":{"ar":" أَخْبَرَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ ذَرًّا عَنْ وَائِلِ بْنِ مُهَانَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لِلنِّسَاءِ تَصَدَّقْنَ فَإِنَّكُنَّ أَكْثَرُ أَهْلِ النَّارِ فَقَالَتْ امْرَأَةٌ لَيْسَتْ مِنْ عِلْيَةِ النِّسَاءِ لِمَ أَوْ بِمَ أَوْ فِيمَ قَالَ إِنَّكُنَّ تُكْثِرْنَ اللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ قَالَ وَقَالَ عَبْدُ اللَّهِ مَا مِنْ نَاقِصِي الدِّينِ وَالْعَقْلِ أَغْلَبَ لِلرِّجَالِ ذَوِي الْأَمْرِ عَلَى أَمْرِهِمْ مِنْ النِّسَاءِ قَالَ رَجُلٌ لِعَبْدِ اللَّهِ مَا نُقْصَانُ عَقْلِهَا قَالَ جُعِلَتْ شَهَادَةُ امْرَأَتَيْنِ بِشَهَادَةِ رَجُلٍ قَالَ سُئِلَ مَا نُقْصَانُ دِينِهَا قَالَ تَمْكُثُ كَذَا وَكَذَا مِنْ يَوْمٍ وَلَيْلَةٍ لَا تُصَلِّي لِلَّهِ صَلَاةً","id":"Telah mengabarkan kepada kami [Abu Zaid Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata: Aku pernah mendengar [Dzar] (berkata) dari [Wa'il bin Muhanah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Bersedekahlah kalian (wahai para wanita), karena kalian yang terbanyak dari penghuni neraka\", lalu seorang wanita yang bukan dari kalangan bangsawan bertanya: \"Mengapa demikian?\", atau \"dengan penyebab apa?\", atau \"lantaran apa?\", beliau menjawab: \"Karena kalian sering melaknat dan (sering) tidak menghargai kebaikan suami\", perawi berkata: \"Abdullah berkata: 'Tidak ada manusia yang kurang agama dan akalnya bisa menguasai laki-laki yang mewenangi urusan daripada kaum wanita\". Seorang laki-laki sontak bertanya kepada Abdullah: \"Apa kekurangan akal wanita?\", ia menjawab: \"Dijadikannya kesaksian dua orang wanita sama dengan kesaksian satu orang laki-laki, lalu ia ditanya 'apa kekurangan agama (pada) wanita?\", ia menjawab: \"Ia melewati beberapa hari (siang dan malam) tanpa mengerjakan shalat apapun (baca; saat haidh) \". "},"687":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ إِذَا طَهُرَتْ الْمَرْأَةُ مِنْ الْحَيْضِ فَلْتَتَّبِعْ ثَوْبَهَا الَّذِي يَلِي جِلْدَهَا فَلْتَغْسِلْ مَا أَصَابَهُ مِنْ الْأَذَى ثُمَّ تُصَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] dari [Abdur Rahman bin Al Qasim] dari [ayahnya] dari [Aisyah] radliallahu 'anha ia berkata: \"Apabila seorang wanita suci dari haid, hendaknya ia sertakan pakaian yang langsung menyentuh kulitnya, dan ia mencuci bagian yang terkena najis kemudian ia pergunakan shalat.\" "},"688":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ عَائِشَةَ قَالَتْ كَانَ يَكُونُ لِإِحْدَانَا الدِّرْعُ فِيهِ تَحِيضُ وَفِيهِ تُجْنِبُ ثُمَّ تَرَى فِيهِ الْقَطْرَةَ مِنْ دَمِ حَيْضَتِهَا فَتَقْصَعُهُ بِرِيقِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ibnu Abu Najih] dari ['Atha`] dari [Aisyah] radliallahu 'anha ia berkata: \"Dahulu salah seorang dari kami (para wanita) memiliki pakaian perang (yang ia kenakan) saat haid dan junub, kemudian ia melihat dalam pakaian perangnya beberapa tetesan darah haid, lalu ia bersihkan dengan ludahnya\". "},"689":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ عَنْ مُعَاذَةَ الْعَدَوِيَّةِ عَنْ عَائِشَةَ قَالَتْ إِذَا غَسَلَتْ الْمَرْأَةُ الدَّمَ فَلَمْ يَذْهَبْ فَلْتُغَيِّرْهُ بِصُفْرَةِ وَرْسٍ أَوْ زَعْفَرَانٍ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] dari [Mu'adzah Al 'Adawiyah] dari [Aisyah] radliallahu 'anha ia berkata: \"Apabila seorang wanita mencuci darah dan tidak juga hilang, hendaknya ia menghilangkan dengan kuning waras atau za'faran\"."},"690":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ الرِّشْكِ قَالَ سَمِعْتُ مُعَاذَةَ الْعَدَوِيَّةَ عَنْ عَائِشَةَ قَالَتْ لَهَا امْرَأَةٌ الدَّمُ يَكُونُ فِي الثَّوْبِ فَأَغْسِلُهُ فَلَا يَذْهَبُ فَأُقَطِّعُهُ قَالَتْ الْمَاءُ طَهُورٌ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar rabi'] telah menceritakan kepada kami [Syu'bah] dari [Yazid Ar Risyk] ia berkata: Aku pernah mendengar [Mu'adzah Al 'Adawiyah] dari [Aisyah] radliallahu 'anha Seorang wanita berkata kepadanya: \"Bila darah mengenai pakaian, lalu aku mencucinya (tetapi) tidak juga hilang, apakah harus aku potong?\", ia menjawab: \"Air itu suci, (tentu menyucikan) \". "},"691":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ حَدَّثَنِي جَابِرُ بْنُ صُبْحٍ قَالَ سَمِعْتُ خِلَاسَ بْنَ عَمْرٍو قَالَ سَمِعْتُ عَائِشَةَ تَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو الْقَاسِمِ يَكُونُ مَعِي فِي الشِّعَارِ الْوَاحِدِ وَأَنَا حَائِضٌ طَامِثٌ إِنْ أَصَابَهُ مِنِّي شَيْءٌ غَسَلَ مَا أَصَابَهُ لَمْ يَعْدُهُ إِلَى غَيْرِهِ وَصَلَّى فِيهِ ثُمَّ يَعُودُ وَإِنْ أَصَابَهُ مِنِّي شَيْءٌ فَعَلَ مِثْلَ ذَلِكَ غَسَلَ مَكَانَهُ لَمْ يَعْدُهُ إِلَى غَيْرِهِ وَصَلَّى فِيهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Yahya bin sa'id Al Qaththan] telah menceritakan kepadaku [Jabir bin Shubh] ia berkata: Aku pernah mendengar [Khilas bin 'Amr] ia berkata: Aku pernah mendengar [Aisyah] radliallahu 'anha ia berkata: \"Rasulullah shallallahu 'alaihi wasallam - alias Abu AlQasim- pernah bersamaku dalam satu pakaian dan (waktu itu) aku sedang haid, jika beliau terkena darah) dariku, beliau membersihkannya (bagian yang terkena darah saja) dan tidak melebar ke lainnya, lalu beliau shalat dengan pakaian itu, kemudian beliau mengulangi lagi, dan jika terkena sesuatu dariku, beliau lakukan kembali seperti itu, mencuci bagian yang terkena darah saja dan tidak melebar ke lainnya, lalu beliau shalat dengan pakaian tersebut\". "},"692":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ عَنْ مُجَاهِدٍ قَالَ الْمَرْأَةُ الْحَائِضُ تُصَلِّي فِي ثِيَابِهَا الَّتِي تَحِيضُ فِيهَا إِلَّا أَنْ يُصِيبَ شَيْئًا مِنْهَا دَمٌ فَتَغْسِلَ مَوْضِعَ الدَّمِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Utsman] dari [Mujahid] ia berkata: \"Seorang wanita yang (suci dari) haid, ia (boleh) shalat dengan bajunya sewaktu ia mengalami haid, kecuali jika baju itu terkena darah, ia mencuci bagian yang terkena darah\"."},"693":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحَيْضِ يُصِيبُ الثَّوْبَ قَالَ حُتِّيهِ ثُمَّ رُشِّيهِ بِالْمَاءِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Hisyam bin 'Urwah] dari [Fathimah binti Al Mundzir] dari [`Asma` binti Abu Bakar] ia berkata: \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang darah haid yang mengenai pakaian\", beliau menjawab: \"Keriklah, dan siramlah dengan air\"."},"694":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ هُوَ ابْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْ سَمِعْتُ امْرَأَةً تَسْأَلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَوْبِهَا إِذَا طَهُرَتْ مِنْ مَحِيضِهَا كَيْفَ تَصْنَعُ بِهِ قَالَ إِنْ رَأَيْتِ فِيهِ دَمًا فَحُكِّيهِ ثُمَّ اقْرُصِيهِ بِمَاءٍ ثُمَّ انْضَحِي فِي سَائِرِهِ فَصَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad Ibnu Ishaq], ia berkata: Telah menceritakan kepadaku [Fathimah binti Al Mundzir] dari [`Asma` binti Abu Bakar] ia berkata: \"Aku pernah mendengar seorang wanita bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang pakaiannya, jika telah suci dari haidnya, apa yang harus ia lakukan dengan pakaiannya tersebut?, beliau menjawab: 'Jika kamu melihat darah padanya, keriklah kemudian bersihkanlah dengan air dan siramlah ke seluruh bagian (yang terkena darah), dan shalatlah dengan (mengenakan) -nya' \"."},"695":{"ar":" أَخْبَرَنَا أَبُو عُبَيْدٍ الْقَاسِمُ بْنُ سَلَّامٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ ثَابِتٍ الْحَدَّادِ عَنْ عَدِيِّ بْنِ دِينَارٍ مَوْلَى أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ عَنْ أُمِّ قَيْسٍ قَالَتْ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ دَمِ الْحِيضَةِ يَكُونُ فِي الثَّوْبِ فَقَالَ اغْسِلِيهِ بِمَاءٍ وَسِدْرٍ وَحُكِّيهِ بِضِلَعٍ","id":"Telah mengabarkan kepada kami [Abu 'Ubaid Al Qasim bin Salam], telah menceritakan kepada kami [Abdur Raman bin Mahdi] dari [Sufyan] dari [Tsabit Al Haddad] dari ['Adi bin Dinar] -bekas budaknya Ummu Qais binti Mihshan-, dari [Ummu Qais] radliallahu 'anha ia berkata: \"Aku pernah bertanya Nabi shallallahu 'alaihi wasallam tentang darah haid yang mengenai pakaian, beliau menjawab: \"Cucilah dengan air dan sidr (sejenis tumbuhan-tumbuhan beraroma wangi yang ditumbuk dan dikeringkan, biasanya dipakai untuk campuran mencuci), dan keriklah dengan kayu (atau sejenisnya) \"."},"696":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ قَالَ سَمِعْتُ كَرِيمَةَ قالَتْ سَمِعْتُ عَائِشَةَ وَسَأَلَتْهَا امْرَأَةٌ فَقَالَتْ الْمَرْأَةُ يُصِيبُ ثَوْبَهَا مِنْ دَمِ حِيضَتِهَا فَقَالَتْ لِتَغْسِلْهُ بِالْمَاءِ قَالَتْ فَإِنَّا نَغْسِلُهُ فَيَبْقَى أَثَرُهُ قَالَتْ إِنَّ الْمَاءَ طَهُورٌ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] dari [Ali bin Al Mubarak] ia berkata: \"Aku pernah mendengar [Karimah] berkata: \"Aku mendengar [Aisyah] radliallahu 'anha, ada seorang wanita menyampaikan uneg-unegnya: 'Pakaiannya terkena darah haid', ia (Aisyah radliallahu 'anha) menjawab: \"Hendaknya ia mencucinya dengan air\", ia berkata lagi: \"Ia telah mencucinya, namun masih tersisa bekasnya\", Aisyah menjawab: \"Air itu suci (dan tentu mensucikan) \"."},"697":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ عَنْ عَبْدِ الْوَهَّابِ الثَّقَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ قَالَ سَأَلْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ الْجُنُبِ يَعْرَقُ فِي الثَّوْبِ ثُمَّ يَمْسَحُهُ بِهِ قَالَ لَا بَأْسَ بِهِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] dari [Abdul Wahab Ats Tsaqafi] dari [Abdullah bin Utsman bin Khutsaim] ia berkata: \"Aku pernah bertanya kepada [Sa'id bin Jubair], tentang seorang yang junub jika ia berkeringat pada pakaiannya kemudian ia usap dengan kain yang dikenakannya, ia menjawab: \"Tidak mengapa\"."},"698":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ كَانَ لَا يَرَى بِعَرَقِ الْجُنُبِ فِي الثَّوْبِ بَأْسًا","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair]: ia memandang keringat orang yang junub sebagai 'tidak masalah\". "},"699":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ الشَّعْبِيِّ أَنَّهُ كَانَ لَا يَرَى بِهِ بَأْسًا","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari ['Atha` bin As Sa`ib] dari [Asy Sya'bi]: Ia menganggap hal itu sebagai tidak masalah\"."},"700":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ قَالَ مَا كُلُّ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا يَجِدُونَ ثَوْبَيْنِ فَقَالَ إِذَا اغْتَسَلْتَ أَلَسْتَ تَلْبَسُهُ فَذَاكَ بِذَاكَ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Al Hasan] ia berkata: \"Tidak semua sahabat Nabi shallallahu 'alaihi wasallam memiliki dua buah baju\", ia juga berkata: \"Bukankah setelah kamu mandi, baju itu tetap kamu kenakan?, (dijawab ya), begitu juga sama\"."},"701":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ أَنَّ عَائِشَةَ سُئِلَتْ عَنْ الرَّجُلِ يُصِيبُ الْمَرْأَةَ ثُمَّ يَلْبَسُ الثَّوْبَ فَيَعْرَقُ فِيهِ فَلَمْ تَرَ بِهِ بَأْسًا","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Yahya bin Sa'id] dari [Al Qasim bin Muhammad]: \" [Aisyah] radliallahu 'anha ditanya tentang seorang laki-laki yang menggauli isterinya kemudian ia memakai bajunya dan berkeringat saat mengenakannya, ia (Aisyah radliallahu 'anha) menganggap tidak mengapa dalam masalah ini.\" "},"702":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ لَا بَأْسَ أَنْ يَعْرَقَ الْجُنُبُ وَالْحَائِضُ فِي الثَّوْبِ يُصَلَّى فِيهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Yahya bin Sulaim] dari [Ibnu Juraij] dari ['Atha`] ia berkata: \"Tidak mengapa seorang yang junub atau yang mengalami haid berkeringat (hingga membasahi badannya) kemudian ia pergunakan untuk shalat.\" "},"703":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي حَمْزَةَ عَنْ إِبْرَاهِيمَ فِي الْجُنُبِ يَعْرَقُ فِي ثَوْبِهِ قَالَ لَا يَضُرُّهُ وَلَا يَنْضَحُهُ بِالْمَاءِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Abu Al `Ahwash] dari [Abu Hamzah] dari [Ibrahim] tentang seorang yang junub, (jika) ia berkeringat di pakaiannya. Ia berkata: \"Ia tidak mengapa dan tidak perlu menyirami pakaiannya dengan air\"."},"704":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هِشَامٍ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ فِي الْحَائِضِ إِذَا عَرِقَتْ فِي ثِيَابِهَا فَإِنَّهُ يُجْزِئُهَا أَنْ تَنْضَحَهُ بِالْمَاءِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Hisyam] dari [Hammad] dari [Ibrahim] tentang seorang wanita yang mengalami haid, apabila ia berkeringat di pakaiannya: \"Ia cukup menyirami dengan air\"."},"705":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ كَانَ يَعْرَقُ فِي الثَّوْبِ وَهُوَ جُنُبٌ ثُمَّ يُصَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Abdullah bin Salamah] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu umar] radliallahu 'anhu Ia pernah berkeringat di bajunya saat ia tengah junub, (setelah bersuci) ia mengerjakan shalat dengan baju tersebut.\""},"706":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ يَحْيَى حَدَّثَنَا هُشَيْمٌ عَنْ هِشَامٍ هُوَ ابْنُ حَسَّانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ لَمْ يَكُنْ يَرَى بَأْسًا بِعَرَقِ الْحَائِضِ وَالْجُنُبِ","id":"Telah mengabarkan kepada kami [Yahya bin Yahya] telah menceritakan kepada kami [Husyaim] dari [Hisyam Ibnu Hassan], dari ['Ikrimah] dari [Ibnu Abbas] radliallahu 'anhu: \"Ia tidak menganggap masalah seorang yang junub atau haid bila berkeringat (di pakaian yang ia kenakan) \"."},"707":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَ سَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا يَحِلُّ لِي مِنْ امْرَأَتِي وَهِيَ حَائِضٌ قَالَ لِتَشُدَّ عَلَيْهَا إِزَارَهَا ثُمَّ شَأْنَكَ بِأَعْلَاهَا","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] ia berkata: \"Seorang laki-laki pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata: \"Apa yang dihalalkan bagiku terhadap isteriku saat ia sedang haid?\", beliau menjawab: \"Hendaklah kamu kencangkan sarungnya, kemudian dibolehkan bagimu bagian atasnya\"."},"708":{"ar":" أَخْبَرَنَا خَالِدٌ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ قَالَ أَرْسَلَ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ إِلَى عَائِشَةَ لِيَسْأَلَهَا هَلْ يُبَاشِرُ الرَّجُلُ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَتْ لِتَشُدَّ إِزَارَهَا عَلَى أَسْفَلِهَا ثُمَّ يُبَاشِرُهَا","id":"Telah mengabarkan kepada kami [Khalid] telah menceritakan kepada kami [Malik] dari [Nafi'] ia berkata: \"Abdullah bin Abdullah bin Umar mengutus (seseorang) kepada [Aisyah] radliallahu 'anha untuk bertanya kepadanya: 'Apakah boleh seorang laki-laki mencumbui isterinya sedang ia mengalami haid? ', ia menjawab: 'Hendaknya si (isteri) mengencangkan sarung bagian bawahnya, kemudian suami dibolehkan mencumbuinya' \"."},"709":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ قَالَ الْحَائِضُ يَأْتِيهَا زَوْجُهَا فِي مَرَاقِّهَا وَبَيْنَ فَخِذَيْهَا فَإِذَا دَفَقَ غَسَلَتْ مَا أَصَابَهَا وَاغْتَسَلَ هُوَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Al 'Ala` bin Al Musayyib] dari [Hammad] dari [Ibrahim] ia berkata: \"Seorang wanita yang haid, suaminya boleh mendatanginya pada bagian bawah perutnya (pusar) dan antara dua pahanya, apabila mani keluar, hendaknya ia (isteri) mencuci bagian yang terkena olehnya (mani) dan ia (suami) harus mandi\"."},"710":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ قَالَ سَأَلَ رَجُلٌ عَطَاءً عَنْ الْحَائِضِ فَلَمْ يَرَ بِمَا دُونَ الدَّمِ بَأْسًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Malik bin Mighwal] ia berkata: \"Seorang laki-laki bertanya kepada ['Atha`] tentang wanita yang haid, ia tidak menganggap masalah (mencumbui) di selain tempat keluarnya darah (kemaluan).\""},"711":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ كُنْتُ إِذَا حِضْتُ أَمَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَّزِرُ وَكَانَ يُبَاشِرُنِي","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al `Aswad] dari [Aisyah] radliallahu 'anha ia berkata: \"Jika aku mengalami haid, Nabi shallallahu 'alaihi wasallam memerintahkanku untuk memakai sarung, kemudian beliau mencumbuiku\". "},"712":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عُيَيْنَةُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ جَوْشَنٍ عَنْ مَرْوَانَ الْأَصْفَرِ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَ مَا يَحِلُّ لِلرَّجُلِ مِنْ امْرَأَتِهِ إِذَا كَانَتْ حَائِضًا قَالَتْ كُلُّ شَيْءٍ غَيْرُ الْجِمَاعِ قَالَ قَلْتُ فَمَا يَحْرُمُ عَلَيْهِ مِنْهَا إِذَا كَانَا مُحْرِمَيْنِ قَالَتْ كُلُّ شَيْءٍ غَيْرُ كَلَامِهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami ['Uyainah bin Abdur Rahman bin Jausyan] dari [Marwan Al `Ashfar] dari [Masruq] ia berkata: Aku bertanya kepada [Aisyah] radliallahu 'anha: \"Apa saja yang dihalalkan bagi seorang laki-laki terhadap isterinya yang sedang haid?\", ia menjawab: \"Segala sesuatu (boleh dilakukan) kecuali jima' (bersenggama) \", aku bertanya lagi: \" apa yang diharamkan atasnya dari isterinya tersebut, jika keduanya sedang malaksanakan ihram?\", ia menjawab: \"Segala sesuatu kecuali mengajaknya bicara\". "},"713":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ جَلْدِ بْنِ أَيُّوبَ عَنْ رَجُلٍ عَنْ عَائِشَةَ قَالَتْ لِإِنْسَانٍ اجْتَنِبْ شِعَارَ الدَّمِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al Jald bin Ayyub] dari [seorang laki-laki] dari [Aisyah] radliallahu 'anha ia berkata kepada orang-orang: \"Hindari pakaian yang menempel dengan darah (haid) \"."},"714":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ عَنْ الشَّعْبِيِّ قَالَ إِذَا كَفَّ الْأَذَى يَعْنِي الدَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Isma'il] dari [As Sya'bi] ia berkata: \"(Maksud dari ungkapan): 'Apabila penyakit itu telah berhenti', adalah berhentinya darah' \"."},"715":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْحَسَنُ بْنُ صَالِحٍ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ قَالَ يُقْبِلُ بِهِ وَيُدْبِرُ إِلَّا الدُّبُرَ وَالْمَحِيضَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Hasan bin Shalih] dari [Laits] dari [Mujahid] ia berkata: \"Suami boleh mencumbui isteri (saat haid) dari depan atau belakang kecuali dubur dan tempat keluarnya darah haid (kemaluannya) \"."},"716":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ وَيَزِيدُ بْنُ هَارُونَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْ كُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لِحَافٍ فَوَجَدْتُ مَا تَجِدُ النِّسَاءُ فَقُمْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَكِ أَنَفِسْتِ قُلْتُ وَجَدْتُ مَا تَجِدُ النِّسَاءُ قَالَ ذَاكَ مَا كَتَبَ اللَّهُ عَلَى بَنَاتِ آدَمَ قَالَتْ فَقُمْتُ فَأَصْلَحْتُ مِنْ شَأْنِي ثُمَّ رَجَعْتُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْخُلِي فِي اللِّحَافِ فَدَخَلْتُ","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] dan [Yazid bin Harun] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Ummu Salamah] radliallahu 'anha ia berkata: \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam satu selimut. Tiba-tiba haidhku datang, kontan aku pergi dan kupakai baju haidku. Beliau bertanya: 'Ada apa denganmu?, apakah kamu mengalami nifas? ', aku menjawab: 'Aku dapatkan kebiasaan yang dialami oleh para wanita wanita', beliau berkata: 'Itulah yang telah Allah subhanallahu wa ta'ala tetapkan untuk puteri-puteri Nabi Adam 'alaihissalaam. Ia berkata: ' aku bangkit dan aku bereskan kondisi tubuhku, lantas kutemui lagi Rasulullah shallallahu 'alaihi wasallam, beliau berkata: 'Masuklah ke dalam selimut', (Ummu Salamah radliallahu 'anha berkata): 'Aku pun masuk' \"."},"717":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كُنْتُ أُرَجِّلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] radliallahu 'anha ia berkata: \"Aku pernah menyisiri rambut Rasulullah shallallahu 'alaihi wasallam sedang aku (dalam keadaan) haid\"."},"718":{"ar":" أَخْبَرَنَا خَالِدٌ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ قَالَ كُنَّ جَوَارِي ابْنِ عُمَرَ يَغْسِلْنَ رِجْلَيْهِ وَهُنَّ حُيَّضٌ وَيُعْطِينَهُ الْخُمْرَةَ","id":"Telah mengabarkan kepada kami [Khalid] telah menceritakan kepada kami [Malik] dari [Nafi'] ia berkata: \"Para budak wanita [Ibnu Umar] radliallahu 'anhu mencuci kedua kakinya (Ibnu Umar), dan mereka sedang haid, dan mereka juga memberinya tikar untuk shalat\"."},"719":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْمِقْدَامِ بْنِ شُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ كُنْتُ أُوتَى بِالْإِنَاءِ فَأَضَعُ فَمِي فَأَشْرَبُ وَأَنَا حَائِضٌ فَيَضَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَهُ عَلَى الْمَكَانِ الَّذِي وَضَعْتُ فَيَشْرَبُ وَأُوتَى بِالْعَرْقِ فَأَنْتَهِسُ فَيَضَعُ فَاهُ عَلَى الْمَكَانِ الَّذِي وَضَعْتُ فَيَنْتَهِسُ ثُمَّ يَأْمُرُنِي فَأَتَّزِرُ وَأَنَا حَائِضٌ وَكَانَ يُبَاشِرُنِي","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al Miqdam bin Syuraih bin Hani`] dari [ayahnya] dari [Aisyah] radliallahu 'anha ia berkata: \"Aku pernah diberi sebuah wadah air (minum) aku menempelkan di bibirku dan saat itu sedang haid, Rasulullah shallallahu 'alaihi wasallam menempelkan ke bibir beliau di bagian yang aku tempelkan bibirku dan beliau meminumnya, kemudian aku diberi sepotong daging, maka aku gigit, beliau menempelkan bibirnya dibagian gigitanku, kemudian beliau menggigitnya, kemudian beliau memerintahkanku untuk mengenakan sarung (penutup) dan aku dalam keadaan haid, beliau mencumbuiku\". "},"720":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ كَانَ يُقَالُ الْحَائِضُ لَيْسَتْ الْحِيضَةُ فِي يَدِهَا تَغْسِلُ يَدَهَا وَتَعْجِنُ وَتَنْبِذُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Mughirah] dari [Ibrahim] ia berkata: \"Pernah dikatakan: 'Wanita yang sedang haid tidaklah mengalami haid di tangannya, ia dapat mencuci tangannya kemudian membuat masakan kue dan minuman juice\"."},"721":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا سُفْيَانُ عَنْ حَمَّادٍ قَالَ سَأَلْتُ إِبْرَاهِيمَ عَنْ مُصَافَحَةِ الْيَهُودِيِّ وَالنَّصْرَانِيِّ وَالْمَجُوسِيِّ وَالْحَائِضِ فَلَمْ يَرَ فِيهِ وُضُوءًا","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Sufyan] dari [Hammad] ia berkata: \"Aku pernah bertanya kepada [Ibrahim] tentang berjabat tangan dengan seorang (yang beragama) yahudi, nashrani, majusi dan wanita yang haid, maka ia berpendapat tidak harus berwudhu (setelah berjabat tangan) \"."},"722":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا إِسْمَعِيلُ السُّدِّيُّ عَنْ عَبْدِ اللَّهِ الْبَهِيِّ قَالَ حَدَّثَتْنِي عَائِشَةُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي الْمَسْجِدِ فَقَالَ لِلْجَارِيَةِ نَاوِلِينِي الْخُمْرَةَ قَالَتْ أَرَادَ أَنْ يَبْسُطَهَا وَيُصَلِّيَ عَلَيْهَا فَقَالَتْ إِنَّهَا حَائِضٌ فَقَالَ إِنَّ حِيضَتَهَا لَيْسَ فِي يَدِهَا","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Za`idah] telah menceritakan kepada kami [Isma'il As Suddi] dari [Abdullah Al Bahi] ia berkata: Telah menceritakan kepadaku [Aisyah] radliallahu 'anha: \"Rasulullah shallallahu 'alaihi wasallam pernah berada di masjid, beliau berkata kepada seorang pembantu perempuan: 'Ambilkan aku alas tikar untuk shalat', ia berkata: 'Beliau ingin membentangkannya dan shalat di atasnya', ia berkata: 'Dia (pembantu itu) sedang haid', beliau berkata: 'Haidnya tidak berada di tangannya' \"."},"723":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ كَانَ لَا يَرَى بَأْسًا أَنْ تُوَضِّئَ الْحَائِضُ الْمَرِيضَ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin `Asad] telah menceritakan kepada kami [Abu 'Awanah] dari [Mugirah] dari [Ibrahim]: \"Ia (berpendapat) Tidak mengapa seorang wanita yang sedang haid (membantu) membantu wudhu orang sakit\". "},"724":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ جَعْفَرِ بْنِ الْحَارِثِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ كُنْتُ أَغْسِلُ رَأْسَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ja'far bin Al Harits] dari [Manshur] dari [Ibrahim] dari [Al `Aswad] dari [Aisyah] radliallahu 'anha ia berkata: \"Aku pernah mengeramasi rambut Rasulullah shallallahu 'aliahi wa sallam sedang aku haid.\" "},"725":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا ال��أَعْمَشُ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ لَقَدْ كُنْتُ أَغْسِلُ رَأْسَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا حَائِضٌ وَهُوَ عَاكِفٌ","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Al A'masy] dari [Tamim bin Salamah] dari ['Urwah] dari [Aisyah] radliallahu 'anha ia berkata: \"Sungguh aku dulu pernah mengeramasi rambut Rasulullah shallallahu 'alaihi wasallam padahal (saat itu) aku haid dan beliau sedang beri'tikaf (di masjid) \"."},"726":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ سُلَيْمَانُ أَخْبَرَنِي عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهَا نَاوِلِينِي الْخُمْرَةَ قَالَتْ إِنِّي حَائِضٌ قَالَ إِنَّهَا لَيْسَتْ فِي يَدِكِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], telah berkata [Sulaiman] telah mengabarkan kepadaku dari [Tsabit bin 'Ubaid] dari [Al Qasim] dari [Aisyah] radliallahu 'anha ia berkata: \"Nabi shallallahu 'alaihi wasallam pernah berkata kepadanya: 'Ambilkan aku alas tikar (untuk shalat) ', ia berkata: 'Maaf aku sedang haid', beliau berkata: 'Haid itu bukan pada tanganmu' \"."},"727":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا مُغِيرَةُ عَنْ إِبْرَاهِيمَ وَيُونُسُ عَنْ الْحَسَنِ وَعَبْدُ الْمَلِكِ عَنْ عَطَاءٍ قَالَ مُحَمَّدٌ وَحَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ فِي الْحَائِضِ إِذَا طَهُرَتْ مِنْ الدَّمِ لَا يَقْرَبُهَا زَوْجُهَا حَتَّى تَغْتَسِلَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ مِثْلَهُ سَوَاءً","id":"Telah menceritakan kepada kami [Muhammad bin Isa], telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Mughirah] dari [Ibrahim] dan [Yunus] dari [Al Hasan] dan [Abdul Malik] dari ['Atha]. [Muhammad] juga berkata; Telah menceritakan kepadaku [Yahya bin Sa'id Al Qaththan] dari [Utsman bin Al `Aswad] dari [Mujahid] Tentang seorang wanita yang mengalami haid, apabila ia telah suci dari darah: \"Suaminya tidak boleh mendekatinya (menggaulinya) hingga ia mandi.\" Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Utsman bin Al `Aswad] dari [Mujahid] dengan redaksi yang sama. "},"728":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ سُئِلَ سُفْيَانُ أَيُجَامِعُ الرَّجُلُ امْرَأَتَهُ إِذَا انْقَطَعَ عَنْهَا الدَّمُ قَبْلَ أَنْ تَغْتَسِلَ فَقَالَ لَا فَقِيلَ أَرَأَيْتَ إِنْ تَرَكَتْ الْغُسْلَ يَوْمَيْنِ أَوْ أَيَّامًا قَالَ تُسْتَتَابُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] ia berkata: \" [Sufyan] pernah ditanya, apakah seorang laki-laki boleh menggauli isterinya jika darah (haidnya) Telah berhenti sebelum ia mandi?\", ia menjawab: \"Tidak boleh\", ditanyakan: \"Bagaimana pendapatmu jika ia meninggalkan mandi dua atau beberapa hari?\", ia menjawab: \"Hendaknya ia segera diminta untuk bertaubat\". "},"729":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَمَّنْ حَدَّثَهُ عَنْ مُجَاهِدٍ { وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ } قَالَ حَتَّى يَنْقَطِعَ الدَّمُ { فَإِذَا تَطَهَّرْنَ } قَالَ إِذَا اغْتَسَلْنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [seseorang yang menceritakan kepadanya] dari [Mujahid]: (Tentang ayat) \"WA LAA TAQRABUUHUNNA HATTAA YATHURNA\" (Dan janganlah kalian dekati mereka (wanita yang sedang haid) hingga ia suci) -Qs. Al Baqarah: 222-, ia berkata: \"(Maksudnya adalah) hingga darah (haidnya) berhenti\", dan \"FAIDZAA TATHAHHARNA\" (Dan apabila mereka telah suci) -Qs. Al Baqarah: 222-, ia berkata: \"(maksudnya adalah) jika mereka telah mandi.\""},"730":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { حَتَّى يَطْهُرْنَ } قَالَ إِذَا انْقَطَعَ الدَّمُ { فَإِذَا تَطَهَّرْنَ } قَالَ اغْتَسَلْنَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] \"HATTAA YATHHURNA\" (Hingga mereka suci) -Qs. Al Baqarah: 222-, ia berkata (makksudnya adalah): \"Jika darahnya benar-benar telah berhenti\", (sedang firman-Nya) \"FA IDZAA TATHAHHARNA\" (Dan apabila mereka telah bersuci) -Qs. Al Baqarah: 222-, ia berkata (maksudnya adalah): \"(jika) mereka telah mandi.\" "},"731":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى حَدَّثَنَا عُثْمَانُ بْنُ الْأَسْوَدِ قَالَ سَأَلْتُ مُجَاهِدًا عَنْ امْرَأَةٍ رَأَتْ الطُّهْرَ أَيَحِلُّ لِزَوْجِهَا أَنْ يَأْتِيَهَا قَبْلَ أَنْ تَغْتَسِلَ قَالَ لَا حَتَّى تَحِلَّ لَهَا الصَّلَاةُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] telah menceritakan kepada kami [Utsman bin Al `Aswad] ia berkata: \"Aku pernah bertanya kepada [Mujahid] tentang seorang wanita yang melihat (tanda-tanda) suci, apakah halal bagi suaminya untuk menggaulinya sebelum ia mandi?\", ia menjawab: \"Tidak boleh, hingga ia boleh melakukan shalat (yaitu setelah mandi) \"."},"732":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ هُوَ ابْنُ زِيَادٍ حَدَّثَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ قَالَ سَأَلْتُ عَطَاءً وَمَيْمُونَ بْنَ مِهْرَانَ وَحَدَّثَنِي حَمَّادٌ عَنْ إِبْرَاهِيمَ قَالُوا لَا يَغْشَاهَا حَتَّى تَغْتَسِلَ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin `Asad] telah menceritakan kepada kami [Abdul Wahid Ibnu Ziyad], telah menceritakan kepada kami [Al Hajjaj bin `Arthah] ia berkata: \"Aku pernah bertanya kepada ['Atha`] dan [Maimun bin Mihran], dan [Hammad] telah menceritakan kepadaku dari [Ibrahim], mereka berkata: \"Ia (sang suami) tidak boleh menggaulinya hingga ia (isteri) mandi (hadats) \". "},"733":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هِشَامٍ عَنْ الْحَسَنِ فِي الرَّجُلِ يَطَأُ امْرَأَتَهُ وَقَدْ رَأَتْ الطُّهْرَ قَبْلَ أَنْ تَغْتَسِلَ قَالَ هِيَ حَائِضٌ مَا لَمْ تَغْتَسِلْ وَعَلَيْهِ الْكَفَّارَةُ وَلَهُ أَنْ يُرَاجِعَهَا مَا لَمْ تَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Hisyam] dari [Al Hasan] Tentang seorang laki-laki yang menggauli isterinya dan ia (isterinya) benar-benar telah melihat (tanda-tanda) suci sebelum ia mandi (hadats), ia berkata: \"Ia masih berstatus haid selama belum mandi dan suami berkewajiban membayar kaffarah dan ia (suami) hendaknya meruju' isterinya selama ia belum mandi.\""},"734":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ قَالَ سَمِعْتُ يَزِيدَ بْنَ أَبِي حَبِيبٍ يَقُولُ قَالَ أَبُو الْخَيْرِ مَرْثَدُ بْنُ عَبْدِ اللَّهِ الْيَزَنِيُّ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُ وَاللَّهِ إِنِّي لَا أُجَامِعُ امْرَأَتِي فِي الْيَوْمِ الَّذِي تَطْهُرُ فِيهِ حَتَّى يَمُرَّ يَوْمٌ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kapada kami [Haiwah bin Syuraih] ia berkata: \"Aku pernah mendengar [Yazid bin Abu Habib] berkata: [Abul Khair] berkata: Telah berkata: [Martsad bin Abdullah Al Yazani]: Aku pernah mendengar ['Uqbah bin 'Amir Al Juhani] berkata: 'Demi Allah subhanallahu wa ta'ala, aku tidak menggauli isteriku pada hari ia suci hingga berlalu satu hari' \". "},"735":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الْمَرْأَةِ تَرَى الطُّهْرَ أَيَأْتِيهَا زَوْجُهَا قَبْلَ أَنْ تَغْتَسِلَ قَالَ لَا حَتَّى تَغْتَسِلَ","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Abdull Malik] dari ['Atha`] Tentang seorang wanita yang melihat (tanda-tanda) suci, apakah suaminya boleh menggaulinya sebelum ia mandi (hadats)?\", ia menjawab: \"Tidak boleh, hingga ia mandi.\""},"736":{"ar":" أَخْبَرَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ قَالَ سَمِعْتُ شَرِيكًا وَسَأَلَهُ رَجُلٌ فَقَالَ الْمَرْأَةُ يَنْقَطِعُ عَنْهَا الدَّمُ أَيَأْتِيهَا زَوْجُه��ا قَبْلَ أَنْ تَغْتَسِلَ فَقَالَ قَالَ عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ أَنَّهُ رَخَّصَ فِي ذَلِكَ لِلشَّبِقِ قَالَ أَبُو مُحَمَّد أَخَافُ أَنْ يَكُونَ ذَا خَطَأً أَخَافُ أَنْ يَكُونَ مِنْ حَدِيثِ لَيْثٍ لَا أَعْرِفُهُ مِنْ حَدِيثِ عَبْدِ الْمَلِكِ قَالَ أَبُو مُحَمَّد الشَّبِقُ الَّذِي يَشْتَهِي","id":"Telah mengabarkan kepada kami [Farwah bin Abu Al Maghra`] ia berkata: Aku pernah mendengar [Syarik], ada seorang laki-laki bertanya kepadanya, ia berkata: \"Seorang wanita yang telah berhenti darahnya, apakah suaminya boleh mendatanginya sebelum ia mandi?\", ia berkata: Telah berkata [Abdul Malik] dari ['Atha`]: 'Itu menjadi rukhshah sebab syahwat yang sudah membuncah\". Abu Muhammad berkata: \"Aku hawatir hal itu suatu kesalahan, aku hawatir itu pendapat Laits, aku tidak tahu hadits (seperti itu) dari Abdul Malik\", Abu Muhammad berkata: \"Asysyabiq itu adalah orang yang sedang berhasrat kuat\"."},"737":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى قَالَ زَعَمَ لَنَا هُشَيْمٌ عَنْ أَبِي حُرَّةَ وَاصِلِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الْحَسَنِ قَالَ رَأَيْتُ نِسَاءً مِنْ نِسَاءِ الْمَدِينَةِ يُصَلِّينَ فِي الْخِضَابِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] ia berkata: [Husyaim] menceritakan kepada kami dari [Abu Hurrah Washil bin Abdur Rahman], dari [Al Hasan] ia berkata: \"Aku pernah melihat para wanita penduduk Madinah shalat dalam keadaan rambut disemir\"."},"738":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَمَّنْ سَمِعَ عَائِشَةَ سُئِلَتْ عَنْ الْمَرْأَةِ تَمْسَحُ عَلَى الْخِضَابِ فَقَالَتْ لَأَنْ تُقْطَعَ يَدِي بِالسَّكَاكِينِ أَحَبُّ إِلَيَّ مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Ibnu Abu Najih] dari [seseorang] yang mendengar dari [Aisyah] radliallahu 'anha: Ia (Aisyah) ditanya tentang seorang wanita yang mengoles (rambutnya) dengan semir, ia menjawab: \"Kalau tanganku dipotong dengan pisau, itu lebih aku sukai dibandingkan hal itu.\""},"739":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ ابْنِ عَوْنٍ عَنْ أَبِي سَعِيدٍ أَنَّ امْرَأَةً سَأَلَتْ عَائِشَةَ تُصَلِّي الْمَرْأَةُ فِي الْخِضَابِ قَالَتْ اسْلُتِيهِ وَرَغْمًا قَالَ أَبُو مُحَمَّد أَبُو سَعِيدٍ هُوَ ابْنُ أَبِي الْعَنَبْسِ وَاسْمُ أَبِي الْعَنَبْسِ سَعِيدُ بْنُ كَثِيرِ بْنِ عُبَيْدٍ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Ibnu 'Aun] dari [Abu Sa'id] Bahwa ada seorang wanita bertanya kepada [Aisyah] radliallahu 'anha, (bagaimana hukumnya) seorang wanita shalat dan rambutnya ia semir?, ia menjawab: \"Hapuslah dan buanglah ke tanah\". Abu Mauhammad berkata: \"Abu Sa'id dia adalah Ibnu Abu Al 'Anbas, dan nama Abu Al 'Anbas adalah Sa'id bin Katsir bin 'Ubaid\"."},"740":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كُنَّ نِسَاؤُنَا يَخْتَضِبْنَ بِاللَّيْلِ فَإِذَا أَصْبَحْنَ فَتَحْنَهُ فَتَوَضَّأْنَ وَصَلَّيْنَ ثُمَّ يَخْتَضِبْنَ بَعْدَ الصَّلَاةِ فَإِذَا كَانَ عِنْدَ الظُّهْرِ فَتَحْنَهُ فَتَوَضَّأْنَ وَصَلَّيْنَ فَأَحْسَنَّ خِضَابَهُ وَلَا يَمْنَعُ مِنْ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Abu Mijlaz] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Isteri-isteri kami menyemir rambut mereka di malam hari, apabila waktu subuh menghampiri mereka, mereka membersihkannya, berwudhu, dan shalat, kemudian setelah shalat mereka menyemir kembali rambut mereka, dan apabila waktu dhuhur tiba mereka membersihkan semir tersebut dan berwudhu kemudian shalat, selanjutnya mereka memperbagus semirannya, dan (hal itu) tidak menghalangi shalat\". "},"741":{"ar":" حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ أَنَّ نِسَاءَ ابْنِ عُمَرَ كُنَّ يَخْتَضِبْنَ وَهُنَّ حُيَّضٌ","id":"Telah mengabarkan kepada kami [hajjaj] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi']; \"Isteri-isteri [Ibnu Umar] radliallahu 'anhu mereka terbiasa menyemir rambut mereka saat haid\"."},"742":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كُنَّ نِسَاؤُنَا إِذَا صَلَّيْنَ الْعِشَاءَ الْآخِرَةَ اخْتَضَبْنَ فَإِذَا أَصْبَحْنَ أَطْلَقْنَهُ وَتَوَضَّأْنَ وَصَلَّيْنَ وَإِذَا صَلَّيْنَ الظُّهْرَ اخْتَضَبْنَ فَإِذَا أَرَدْنَ أَنْ يُصَلِّينَ الْعَصْرَ أَطْلَقْنَهُ فَأَحْسَنَّ خِضَابَهُ وَلَا يَحْبِسُ عَنْ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Abu Mijlaz] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Para isteri kami apabila selesai shalat isya`, mereka menyemir rambut mereka, dan jika waktu subuh tiba, mereka bersihkan, berwudhu dan kemudian shalat, dan apabila mereka telah shalat dhuhur mereka menyemir kembali rambut mereka, jika mereka hendak shalat ashr, mereka membersihkannya (dan begitu selanjutnya) mereka perbagus cara penyemiran, dan mereka tidak terhalangi untuk shalat\". "},"743":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مُغِيرَةُ عَنْ إِبْرَاهِيمَ ح و أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَامِرٍ فِيمَنْ أَتَى أَهْلَهُ وَهِيَ حَائِضٌ قَالَا ذَنْبٌ أَتَاهُ يَسْتَغْفِرُ اللَّهَ وَيَتُوبُ إِلَيْهِ وَلَا يَعُودُ أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ الْمُثَنَّى عَنْ عَطَاءٍ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Mughirah] dari [Ibrahim]. (Dan dari Jalur yang lain;) Telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dari ['Amir] Tentang seorang suami yang menggauli isterinya sedang haid, keduanya berkata: \"Dosa yang telah ia lakukan, (hendaknya segeralah) ia meminta ampun kepada Allah subhanallahu wa ta'ala dan hendaknya pula ia bertaubat serta tidak mengulanginya kembali\". Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yahya bin Abu Za`idah] dari [Al Mutsanna] dari ['Atha`] dengan riwayat yang semisalnya\"."},"744":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَأَبُو النُّعْمَانِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يَعْقُوبَ بْنِ الْقَعْقَاعِ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ ذَنْبٌ أَتَاهُ وَلَيْسَ عَلَيْهِ كَفَّارَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] dan [Abu An Nu'man] keduanya berkata: Telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ya'qub bin Al Qa'qa'] dari [Muhammad bin Zaid] dari [Sa'id bin Jubair] ia berkata: \"Dosa telah ia kerjakan dan tidak ada kaffarah atasnya\". "},"745":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ أَنَّهُ سُئِلَ عَنْ الَّذِي يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَعْتَذِرُ إِلَى اللَّهِ وَيَتُوبُ إِلَى اللَّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ubaidullah bin Umar] dari [Abdur Raman bin Al Qasim] dari [ayahnya]: Bahwa ia pernah ditanya tentang seorang yang menggauli isterinya sedang ia haid, ia menjawab: \"Hendaknya ia memohon ampun kepada Allah subhanallahu wa ta'ala dan bertaubat kepada-Nya\"."},"746":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ تَسْتَغْفِرُ اللَّهَ وَلَيْسَ عَلَيْكَ شَيْءٌ يَعْنِي إِذَا وَقَعَ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha`] ia berkata: \"Hendaknya kamu memohon ampun kepada Allah subhanallahu wa ta'ala dan tidak ada kewajiban apapun atas kamu, (yakni apabila ia menggauli isterinya sedang ia haid) \"."},"747":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ مَالِكِ بْنِ الْخَطَّابِ الْعَنْبِرِيِّ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ سُئِلَ وَأَنَا أَسْمَعُ عَنْ الرَّجُلِ يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَسْتَغْفِرُ اللَّهَ","id":"Telah mengabarkan kepada kami [Utsman bin muhammad] telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dari [Malik bin Al Khaththab Al 'Anbari] dari [Ibnu Abu Mulaikah] ia berkata: \"Ia ditanya sedang (waktu itu) mendengarnya, tentang seorang laki-laki yang menggauli isterinya sedang haid, ia menjawab: \"Hendaknya ia memohon ampun kepada Allah subhanallahu wa ta'ala\". "},"748":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ أَنَّ رَجُلًا أَتَى أَبَا بَكْرٍ فَقَالَ رَأَيْتُ فِي الْمَنَامِ كَأَنِّي أَبُولُ دَمًا قَالَ تَأْتِي امْرَأَتَكَ وَهِيَ حَائِضٌ قَالَ نَعَمْ قَالَ اتَّقِ اللَّهَ وَلَا تَعُدْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah]: Ada seorang laki-laki datang menemui [Abu Bakar], ia berkata: \"Aku bermimpi seakan-akan aku kencing berupa darah\", ia bertanya: \"Apakah kamu menggauli isterimu saat ia tengah haid?\", ia menjawab: \"Ya, benar\", ia berkata: \"Takutlah kamu kepada Allah subhanallahu wa ta'ala, dan jangan kamu ulangi.\""},"749":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ فِي الَّذِي يَقَعُ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ قَالَ يَسْتَغْفِرُ اللَّهَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Muhammad bin Sirin] tentang seorang yang menggauli isterinya sedang ia haid, ia berkata: \"Hendaknya ia memohon ampun kepada Allah subhanallahu wa ta'ala.\""},"750":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ فِي الَّذِي يُفْطِرُ يَوْمًا مِنْ رَمَضَانَ قَالَ عَلَيْهِ عِتْقُ رَقَبَةٍ أَوْ بَدَنَةٌ أَوْ عِشْرِينَ صَاعًا لِأَرْبَعِينَ مِسْكِينًا وَفِي الَّذِي يَغْشَى امْرَأَتَهُ وَهِيَ حَائِضٌ مِثْلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Yazid bin Ibrahim] ia berkata: \"Aku pernah mendengar [Al Hasan] berkata tentang seorang yang berbuka sehari pada bulan ramadhan (tanpa ada sebab) ia berkata: 'Ia harus memerdekakan budak atau menyembelih seekor unta atau sedekah dua puluh sha' (makanan pokok) untuk empat puluh orang, dan bagi orang yang menggauli isterinya sedang ia tengah haid, maka serupa dengan itu (kaffarahnya). "},"751":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شَرِيكٌ عَنْ خُصَيْفٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِنِصْفِ دِينَارٍ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [syarik] dari [Khushaif] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam (bersabda) tentang seorang menggauli isterinya sedang ia tengah haid: \"Ia harus bersedekah dengan setengah dinar\". "},"752":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ الْحَمِيدِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ فِي الَّذِي يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِدِينَارٍ أَوْ نِصْفِ دِينَارٍ شَكَّ الْحَكَمُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdul Hamid] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu tentang seorang yang menggauli isterinya sedang ia haid: \"Ia harus bersedekah satu atau setengah dinar\", Al Hakam ragu kepastian setengah atau satu dinar dalam hal ini. "},"753":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْكَرِيمِ عَنْ رَجُلٍ عَنْ ابْنِ عَبَّاسٍ قَالَ إِذَا أَتَاهَا فِي دَمٍ فَدِينَارٌ وَإِذَا أَتَاهَا وَقَدْ انْقَطَعَ الدَّمُ فَنِصْفُ دِينَارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Abdul Karim] dari [seorang laki-laki] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Apabila ia menggaulinya sedang darah masih keluar, maka (kaffaratnya) satu dinar, dan jika ia menggaulinya setelah darah berhenti (tetapi belum mandi), maka setengah dinar\". "},"754":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ خُصَيْفٍ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَقَعُ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ يَتَصَدَّقُ بِنِصْفِ دِينَارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Khushaif] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: Telah bersabda Nabi shallallahu 'alaihi wasallam tentang seorang yang menggauli isterinya sedang ia tengah haid: \"Ia harus bersedekah setengah dinar\". "},"755":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَزِيدَ بْنِ أَبِي مَالِكٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ زَيْدِ بْنِ الْخَطَّابِ قَالَ كَانَ لِعُمَرَ بْنِ الْخَطَّابِ امْرَأَةٌ تَكْرَهُ الْجِمَاعَ فَكَانَ إِذَا أَرَادَ أَنْ يَأْتِيَهَا اعْتَلَّتْ عَلَيْهِ بِالْحَيْضِ فَوَقَعَ عَلَيْهَا فَإِذَا هِيَ صَادِقَةٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يَتَصَدَّقَ بِخُمُسَيْ دِينَارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] dari [Yazid bin Abu malik] dari [Abdul Hamid bin Zaid bin Al Khaththab] ia berkata: \"Umar bin Khaththab radliallahu 'anhu memiliki seorang isteri yang tidak suka bersenggama, maka jika ia hendak menggaulinya ia berpura-pura sedang haid, ia tetap menggaulinya dan ternyata ia jujur (waktu itu benar-benar haid), maka ia menemui Nabi shallallahu 'alaihi wasallam, beliau memerintahkan kepadanya untuk bersedekah dengan seperlima dinar\". "},"756":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا حَفْصٌ هُوَ ابْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ سُئِلَ عَنْ الَّذِي يَأْتِي امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِدِينَارٍ أَوْ بِنِصْفِ دِينَارٍ و قَالَ إِبْرَاهِيمُ يَسْتَغْفِرُ اللَّهَ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hafsh Ibnu Ghiyats], dari [Al A'masy] dari [Al hakam] dari [Miqsam] dari [Ibnu Abbas] radliallahu 'anhu; Bahwa ia ditanya tentang seorang yang menggauli isterinya sedang ia tengah haid, ia berkata: \"Ia harus bersedekah dengan satu dinar atau setengah dinar\". Dan Ibrahim berkata: 'Ia harus memohon ampun kepada Allah subhanallahu wa ta'ala\". "},"757":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ إِذَا وَقَعَ عَلَى امْرَأَتِهِ وَهِيَ حَائِضٌ فَعَلَيْهِ أَنْ يَتَصَدَّقَ بِدِينَارٍ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari [Ibnu Abu Laila] dari ['Atha`] dari [Ibnu Abbas] radliallahu 'anhu ia berkata: \"Apabila seorang menggauli isterinya sedang ia haid, ia harus bersedekah dengan satu dinar\"."},"758":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي رَجُلٍ جَامَعَ امْرَأَتَهُ وَهِيَ حَائِضٌ قَالَ يَتَصَدَّقُ بِدِينَارٍ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`]; Tentang seorang laki-laki yang menggauli isterinya sedang ia tengah haid, ia berkata: \"Ia harus bersedekah dengan satu dinar\". "},"759":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ سَعِيدٍ عَنْ شُعَيْبِ بْنِ إِسْحَقَ عَنْ الْأَوْزَاعِيِّ فِي رَجُلٍ يَغْشَى امْرَأَتَهُ وَهِيَ حَائِضٌ أَوْ رَأَتْ الطُّهْرَ وَلَمْ تَغْتَسِلْ قَالَ يَسْتَغْفِرُ اللَّهَ وَيَتَصَدَّقُ بِخُمُسَيْ دِينَارٍ","id":"Telah mengabarkan kepada kami [Wahab bin Sa'id] dari [Syu'aib bin Ishaq] dari [Al 'Auza'i] Tentang seorang laki-laki menggauli isterinya sedang ia tengah haid, atau ia melihat (tanda-tanda) suci dan ia belum mandi (hadats), ia berkata: \"Ia harus memohon ampun kepada Allah subhanallahu wa ta'ala dan bersedekah dengan seperlima dinar\"."},"760":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ ابْنِ سَابِطٍ قَالَ سَأَلْتُ حَفْصَةَ بِنْتَ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ أَبِي بَكْرٍ قُلْتُ لَهَا إِنِّي أُرِيدُ أَنْ أَسْأَلَكِ عَنْ شَيْءٍ وَأَنَا أَسْتَحْيِي أَنْ أَسْأَلَكِ عَنْهُ قَالَتْ سَلْ يَا ابْنَ أَخِي عَمَّا بَدَا لَكَ قَالَ أَسْأَلُكِ عَنْ إِتْيَانِ النِّسَاءِ فِي أَدْبَارِهِنَّ فَقَالَتْ حَدَّثَتْنِي أُمُّ سَلَمَةَ قَالَتْ كَانَتْ الْأَنْصَارُ لَا تُجَبِّي وَكَانَتْ الْمُهَاجِرُونَ تُجَبِّي فَتَزَوَّجَ رَجُلٌ مِنْ الْمُهَاجِرِينَ امْرَأَةً مِنْ الْأَنْصَارِ فَجَبَّاهَا فَأَبَتْ الْأَنْصَارِيَّةُ فَأَتَتْ أُمَّ سَلَمَةَ فَذَكَرَتْ ذَلِكَ لَهَا فَلَمَّا أَنْ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَحْيَتْ الْأَنْصَارِيَّةُ وَخَرَجَتْ فَذَكَرَتْ ذَلِكَ أُمُّ سَلَمَةَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْعُوهَا لِي فَدُعِيَتْ لَهُ فَقَالَ لَهَا { نِسَاؤُكُمْ حَرْثٌ لَكَمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } سِمَامًا وَاحِدًا وَالسِّمَامُ السَّبِيلُ الْوَاحِدُ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Ibnu Sabith] ia berkata: \"Aku pernah bertanya kepada [Hafshah binti Abdur Rahman Ibnu Abu Bakar], aku berkata kepadanya: Aku ingin bertanya kepada kamu perihal sesuatu yang sebenarnya aku malu menanyakannya kepadamu, ia berkata: \"Bertanyalah wahai keponakanku tentang hal yang mengganjal (di hatimu) \", ia bertanya: \"Aku bertanya kepada kamu tentang menggauli isteri-isteri dari dubur mereka?\", maka ia menjawab: \" [Ummu Salamah] radliallahu 'anha pernah menceritakan kepadaku, ia berkata: \"Dahulu orang-orang Anshar tidak pernah menggauli (isteri mereka) dari arah belakang, sedang orang-orang muhajirin biasa menggauli (isteri mereka) dari arah belakang, maka ada seorang laki-laki dari kaum muhajirin menikahi seorang wanita dari kaum anshar, ia menggaulinya dari arah belakang, maka wanita itu menolak, dan ia datang menemui Ummu Salamah radliallahu 'anha, ia menceritakan hal tersebut, maka tatkala Rasulullah shallallahu 'alaihi wasallam datang, wanita anshar itu malu dan keluar, maka Ummu Salamah radliallahu 'anha menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Panggillah wanita tadi untuk menemuiku\", maka dipanggillah ia untuk menemui beliau, kemudian beliau berkata: \"NISAA`UKUM HARTSUN LAKUM FA`TUU HARTSAKUM `ANNA SYI`TUM\" (Isteri-isteri kalian adalah sawah ladang kalian, maka datangilah sawah ladangmu itu bagaimana saja kamu kehendaki) -Qs. Al Baqarah: 223-, yaitu satu arah, maksud dari satu arah adalah dari arah mana saja kamu datangi asalkan sasarannya satu, yaitu kemaluan.\""},"761":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ أَبَانَ بْنِ صَالِحٍ عَنْ مُجَاهِدٍ قَالَ لَقَدْ عَرَضْتُ الْقُرْآنَ عَلَى ابْنِ عَبَّاسٍ ثَلَاثَ عَرَضَاتٍ أَقِفُ عِنْدَ كُلِّ آيَةٍ أَسْأَلُهُ فِيمَ أُنْزِلَتْ وَفِيمَ كَانَتْ فَقُلْتُ يَا ابْنَ عَبَّاسٍ أَرَأَيْتَ قَوْلَ اللَّهِ تَعَالَى { فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } قَالَ مِنْ حَيْثُ أَمَرَكُمْ أَنْ تَعْتَزِلُوهُنَّ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah memberitakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Aban bin Shalih] dari [Mujahid] ia berkata: \"Aku telah menunjukkan hafalan Al Qur`an kepada Ibnu Abbas radliallahu 'anhu sebanyak tiga kali, aku berhenti di setiap ayat dan aku menanyakan kepadanya tentang apa ayat tersebut turun? Dan dan di mana ia diturunkan?, aku bertanya: \"Wahai [Ibnu Abbas] radliallahu 'anhu, Bagaimana pendapatmu tentang firman Allah subhanallahu wa ta'ala: \"FAIDZAA TATHAHHARNA FA`TUHUNNA MIN HAITSU `AMARAKUMULLAHU\" (Maka apabila mereka telah suci, maka datangilah mereka dari arah yang perintahkan kepada kalian) -Qs. Al Baqarah: 222-, ia menjawab: \"Di tempat yang Ia perintahkan kepada kalian untuk dijauhi (ketika mereka sedang haid, yaitu kemaluan) \"."},"762":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ { فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } قَالَ أُمِرُوا أَنْ يَأْتُوا مِنْ حَيْثُ نُهُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Utsman bin Al Aswad] dari [Mujahid] ketika menafsirkan ayat: '(Maka datangilah mereka di tempat yang Allah subhanallahu wa ta'ala perintahkan kepada kalian) ' (Qs. Al Baqarah: 222), ia berkata: \"Mereka diperintahkan untuk mendatangi (isteri mereka) di tempat yang mereka dilarang untuk melakukannya (disaat haid) \"."},"763":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْبَزَّازُ حَدَّثَنَا شَرِيكٌ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ مُجَاهِدٍ { وَتَذَرُونَ مَا خَلَقَ لَكُمْ رَبُّكُمْ مِنْ أَزْوَاجِكُمْ } قَالَ هُوَ وَاللَّهِ الْقُبُلُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Bazzaz] telah menceritakan kepada kami [Syarik] dari [Ibrahim bin Muhajir] dari [Mujahid] (ketika menafsirkan ayat): '(Dan kalian tinggalkan apa yang Allah subhanallahu wa ta'ala ciptakan untuk kalian dari isteri-isteri kalian) ' (Qs. As Syu'ara`: 166), ia berkata: \"Demi Allah, itu adalah kemaluan.\" "},"764":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا خَالِدُ بْنُ رَبَاحٍ عَنْ عِكْرِمَةَ { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ إِنَّمَا هُوَ الْفَرْجُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Khalid bin Rabah] dari ['Ikrimah] (Ketika menafsirkan ayat): '(Isteri-isteri kalian (bagaikan) sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), ia berkata: \"Itu adalah kemaluan\"."},"765":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ { فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ ائْتِهَا مِنْ بَيْنِ يَدَيْهَا وَمِنْ خَلْفِهَا بَعْدَ أَنْ يَكُونَ فِي الْمَأْتَى","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] dari [Khalid bin Abdullah] dari ['Atha bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] (ketika menafsirkan ayat): '(Maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), ia berkata: \"Datangilah ia dari arah depan dan arah belakangnya selama masih di tempat kedatangan (kemaluan).\""},"766":{"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ قَالَ كَانَ أَهْلُ الْجَاهِلِيَّةِ يَصْنَعُونَ فِي الْحَائِضِ نَحْوًا مِنْ صَنِيعِ الْمَجُوسِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ } فَلَمْ يَزْدَدْ الْأَمْرُ فِيهِنَّ إِلَّا شِدَّةً","id":"Telah mengabarkan kepada kami [Khalifah bin Khayyath] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] ia berkata: \"Dahulu orang-orang jahiliyah berbuat terhadap wanita haid seperti yang dilakukan oleh orang-orang Majusi, hal itu kemudian disebutkan kepada Rasulullah shallallahu 'alaihi wasallam, maka turunlah ayat: '(Dan mereka bertanya tentang haid, katakanlah haid itu adalah kotoran, maka jauhilah isteri-isteri kalian di saat haid dan janganlah kalian dekati mereka hingga mereka suci) ' (Qs. Al Baqarah: 222), tidaklah urusan tentang mereka itu kecuali semakin tegas.\""},"767":{"ar":" أَخْبَرَنَا خَلِيفَةُ حَدَّثَنَا مُؤَمَّلٌ عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ { قُلْ هُوَ أَذًى } قَالَ هُوَ الدَّمُ","id":"Telah mengabarkan kepada kami [Khalifah] telah menceritakan kepada kami [Mu`ammal] dari [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] ketika mentafsirkan firman Allah: '(katakanlah haid itu adalah kotoran…) ' (Qs. Al Baqarah: 222), ia berkata, \"Maksudnya adalah darah.\""},"768":{"ar":" أَخْبَرَنَا خَلِيفَةُ بْنُ خَيَّاطٍ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ لَيْثًا حَدَّثَ عَنْ عِيسَى بْنِ قَيْسٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ { نِسَاؤُكُم�� حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَالَ إِنْ شِئْتَ فَاعْزِلْ وَإِنْ شِئْتَ فَلَا تَعْزِلْ","id":"Telah mengabarkan kepada kami [Khalifah bin Khayyath] telah menceritakan kepada kami [Al Mu'tamir] ia berkata: Aku pernah mendengar [Laits] menceritakan dari ['Isa bin Qais] dari [Sa'id bin Musayyib] firman Allah: '(Isteri-isteri kalian bagaikan sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ', (Qs. Al Baqarah: 223), ia berkata: \"Jika kamu berkehendak, maka jauhilah dia, dan jika kamu kehendaki, maka jangan kamu jauhi dia.\" "},"769":{"ar":" أَخْبَرَنَا خَلِيفَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ عَوْفٍ عَنْ الْحَسَنِ قَالَ كَيْفَ شِئْتَ يَعْنِي إِتْيَانَهَا فِي الْفَرْجِ","id":"Telah mengabarkan kepada kami [Khalifah] telah menceritakan kepada kami [Abdul Wahab] dari ['Auf] dari [Al Hasan] ia berkata: \"Terserah kepadamu, yakni mendatanginya pada kemaluan.\" "},"770":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ قَالَ مَنْ أَتَى امْرَأَتَهُ فِي دُبُرِهَا فَهُوَ مِنْ الْمَرْأَةِ مِثْلُهُ مِنْ الرَّجُلِ ثُمَّ تَلَا { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } أَنْ تَعْتَزِلُوهُنَّ فِي الْمَحِيضِ الْفَرْجَ ثُمَّ تَلَا { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ } قَائِمَةً وَقَاعِدَةً وَمُقْبِلَةً وَمُدْبِرَةً فِي الْفَرْجِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari [Mujahid] ia berkata: \"Barangsiapa menggauli isterinya pada duburnya, maka ia termasuk wanita yang semisalnya dari kalangan laki-laki, kemudian ia membaca ayat: '(Dan mereka bertanya kepada kamu tentang haid, maka katakanlah ia itu kotoran, maka jauhilah wanita-wanita yang tengah haid, dan jangan kalian dekati mereka hingga mereka suci, dan apabila mereka telah suci, maka datangilah mereka dari arah yang Allah subhanallahu wa ta'ala perintahkan kepada kalian) ' (Qs. Al Baqarah: 223), yakni hendaklah kalian jauhi kemaluan mereka ketika sedang haid. Kemudian ia membaca ayat: '(Isteri-isteri kalian bagaikan sawah ladang kalian, maka datangilah sawah ladang kalian sesuai kehendak kalian) ' (Qs. Al Baqarah: 223), yaitu baik berdiri, duduk, dari arah depan atau dari arah depan (tetapi tetap pada) kemaluannya.\""},"771":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ حَكِيمٍ الْأَثْرَمِ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى حَائِضًا أَوْ امْرَأَةً فِي دُبُرِهَا أَوْ كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] dari [Hammad bin Salamah] dari [Hakim Al Atsar] dari [Abu Tamimah Al hujaimi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam: \"Barangsiapa menggauli wanita yang tengah haid atau (menggauli) dari duburnya, atau mendatangi dukun lalu ia membenarkan apa yang dikatakannya, maka sungguh ia telah mengingkari apa yang telah diturunkan kepada Muhammad shallallahu 'alaihi wasallam.\""},"772":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبُو هِلَالٍ عَنْ أَبِي عَبْدِ اللَّهِ الشَّقَرِيِّ عَنْ أَبِي الْقَعْقَاعِ الْجَرْمِيِّ قَالَ جَاءَ رَجُلٌ إِلَى عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ آتِي امْرَأَتِي حَيْثُ شِئْتُ قَالَ نَعَمْ قَالَ وَمِنْ أَيْنَ شِئْتُ قَالَ نَعَمْ قَالَ وَكَيْفَ شِئْتُ قَالَ نَعَمْ فَقَالَ لَهُ رَجُلٌ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ هَذَا يُرِيدُ السُّوءَ قَالَ لَا مَحَاشُّ النِّسَاءِ عَلَيْكُمْ حَرَامٌ سُئِلَ عَبْد اللَّهِ تَقُولُ بِهِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abu Hilal] dari [Abu Abdullah As Syaqari] dari [Abu Al Qa'qa' Al Jarmi] ia berkata, \"Seorang laki-laki datang menemui [Abdullah bin Mas'ud] dan berkata: 'Wahai Abu 'Abdurrahman, apakah boleh aku menggauli isteriku dari arah yang aku kehendaki? ' Abdullah bin Mas'ud menjawab: \"Ya, boleh.\" Laki-laki itu berkata lagi, \"Sesuai kehendakku?\" Abdullah bin Mas'ud menjawab: 'Ya.\" Lalu seorang laki-laki berkata kepadanya: \"Wahai Abu 'Abdurrahman, sesungguhnya orang ini menginginkan kejelekan! \" Abdullah bin Mas'ud berkata: 'Tidak boleh sesukamu, dubur wanita haram atas kalian.\" Abdullah ditanya: \"Apakah kamu juga berkata demikian?\" ia menjawab: \"Ya.\""},"773":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا وُهَيْبٌ عَنْ دَاوُدَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ كَانَ يَكْرَهُ إِتْيَانَ الرَّجُلِ امْرَأَتَهُ فِي دُبُرِهَا وَيَعِيبُهُ عَيْبًا شَدِيدًا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Wuhaib] dari [Daud] dari ['Ikrimah] dari [Ibnu Abbas], bahwa ia tidak menyukai sesorang laki-laki mendatangi isterinya pada dubur dan mencelanya dengan celaan yang sangat.\""},"774":{"ar":" حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ عَمْرِو بْنِ دِينَارٍ { إِنَّكُمْ لَتَأْتُونَ الْفَاحِشَةَ مَا سَبَقَكُمْ بِهَا مِنْ أَحَدٍ مِنْ الْعَالَمِينَ } قَالَ مَا نَزَى ذَكَرٌ عَلَى ذَكَرٍ حَتَّى كَانَ قَوْمُ لُوطٍ","id":"Telah menceritakan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Isma'il bin 'Ulayyah] telah menceritakan kepada kami [Ibnu Abu Najih] dari ['Amru bin Dinar] firman Allah: '(Sesungguhnya kalian benar-benar mengerjakan satu kekejian yang belum pernah dilakukan oleh seorangpun sebelum kalian di alam ini) ' (Qs. Al Ankabut: 26), ia berkata: \"Tidak pernah ada kemaluan laki-laki menindih (menggauli) kemaluan laki-laki lainnya hingga ia menjadi (bagian dari) kaum Nabi Luth.\""},"775":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ الْحَارِثِ بْنِ مُخَلَّدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى امْرَأَتَهُ فِي دُبُرِهَا لَمْ يَنْظُرْ اللَّهُ تَعَالَى إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Suhail bin Abu Shalih] dari [Al Harits bin Al Mukhallad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menggauli isterinya pada duburnya, maka Allah subhanallahu wa ta'ala tidak akan melihatnya kelak pada hari kiamat.\""},"776":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عِيسَى بْنِ حِطَّانَ عَنْ مُسْلِمِ بْنِ سَلَّامٍ الْحَنَفِيِّ عَنْ عَلِيِّ بْنِ طَلْقٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَحْدَثَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَنْصَرِفْ وَلْيَتَوَضَّأْ ثُمَّ يُصَلِّي وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَأْتُوا النِّسَاءَ فِي أَدْبَارِهِنَّ فَإِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ سُئِلَ عَبْد اللَّهِ عَلِيُّ بْنُ طَلْقٍ لَهُ صُحْبَةٌ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Yahya] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] dari ['Ashim Al Ahwal] dari ['Isa bin Hiththan] dari [Muslim bin sallam Al Hanafi] dari [Ali bin Thalq] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Jika salah seorang dari kalian berhadats saat shalat hendaklah ia pergi wudlu, kemudian shalatlah kembali.\" Dan Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Janganlah kalian menggauli para wanita pada dubur-dubur mereka, sesungguhnya Allah subhanallahu wa ta'ala tidak pernah malu atas sebuah kebenaran.\" Abdullah ditanya, \"Apakah Ali bin Thalq memiliki isteri?\" ia menjawab: \"Ya.\""},"777":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي الْحَارِثُ بْنُ يَعْقُوبَ عَنْ سَعِيدِ بْنِ يَسَارٍ أَبِي الْحُبَابِ قَالَ قُلْتُ لِابْنِ عُمَرَ مَا تَقُولُ فِي الْجَوَارِي حِينَ أُحَمِّضُ بِهِنَّ قَالَ وَمَا التَّحْمِيضُ فَذَكَرْتُ الدُّبُرَ فَقَالَ هَلْ يَفْعَلُ ذَاكَ أَحَدٌ مِنْ الْمُسْلِمِينَ","id":"Telah menghabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Al Harits bin Ya'qub] dari [Sa'id bin yasar Abu Al Hubab] ia berkata, \"Aku pernah bertanya kepada [Ibnu Umar], \"Apa yang kamu katakan tentang para budak wanita yang aku gauli?\" ia balik bertanya, \"Apanya yang kamu gauli?\" lalu aku sebutkan, \"Dubur.\" Ia lalu berkata: \"Apakah ada seseorang dari kaum muslimin mengerjakan hal itu?.\""},"778":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا خُصَيْفٌ عَنْ مُجَاهِدٍ قَالَ كَانُوا يَجْتَنِبُونَ النِّسَاءَ فِي الْمَحِيضِ وَيَأْتُونَهُنَّ فِي أَدْبَارِهِنَّ فَسَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى { وَيَسْأَلُونَكَ عَنْ الْمَحِيضِ قُلْ هُوَ أَذًى فَاعْتَزِلُوا النِّسَاءَ فِي الْمَحِيضِ وَلَا تَقْرَبُوهُنَّ حَتَّى يَطْهُرْنَ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمْ اللَّهُ } فِي الْفَرْجِ وَلَا تَعْدُوهُ","id":"Telah menghabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Khushaif] dari [Mujahid] ia berkata, \"Dahulu mereka menjauhi para wanita di saat haid, dan menggauli mereka pada dubur-dubur mereka, lalu mereka bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal itu, maka Allah subhanallahu wa ta'ala menurunkan ayat: '(Dan mereka bertanya kepada kamu tentang haid, katakanlah ia itu kotor, maka jauhilah wanita yang tengah haid dan jangan kalian dekati mereka hingga mereka suci, dan jika mereka telah suci, maka datangilah mereka sesuai dengan yang Allah perintahkan) ' (Qs. Al Baqarah: 223), yakni pada lubang kemaluannya dan janganlah kalian menyimpang darinya.\""},"779":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنِي ابْنُ إِسْحَقَ حَدَّثَنِي أَبَانُ بْنُ صَالِحٍ عَنْ طَاوُسٍ وَسَعِيدٍ وَمُجَاهِدٍ وَعَطَاءٍ أَنَّهُمْ كَانُوا يُنْكِرُونَ إِتْيَانَ النِّسَاءِ فِي أَدْبَارِهِنَّ وَيَقُولُونَ هُوَ الْكُفْرُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid] telah menceritakan kepada kami [Yunus bin Bukair] ia berkata; telah menceritakan kepadaku [Ibnu Ishaq] ia berkata; telah menceritakan kepadaku [Aban bin Shalih] dari [Thawus] dan [Sa'id] dan [Mujahid] dan ['Atha], bahwa mereka sangat mengingkari menggauli para wanita pada dubur-dubur mereka, dan mereka mengatakan, \"Itu adalah sebuah kekufuran.\""},"780":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ حُذَيْفَةَ قَالَ لِامْرَأَتِهِ خَلِّلِي شَعْرَكِ بِالْمَاءِ قَبْلَ أَنْ تَخَلَّلَهُ نَارٌ قَلِيلَةُ الْبُقْيَا عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Syarik] dari [Al A'masy] dari [Ibrahim] dari [Hudzaifah] ia berkata kepada isterinya: \"Hendaklah kamu menyela-nyela rambutmu dengan air (ketika mandi hadats) sebelum ia disela-sela dengan api neraka untuk selamanya.\""},"781":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا زَائِدَةُ عَنْ صَدَقَةَ بْنِ سَعِيدٍ الْحَنَفِيِّ حَدَّثَنِي جُمَيْعُ بْنُ عُمَيْرٍ أَحَدُ بَنِي تَيْمِ اللَّهِ بْنِ ثَعْلَبَةَ قَالَ دَخَلْتُ مَعَ أُمِّي وَخَالَتِي عَلَى عَائِشَةَ فَسَأَلَتْهَا إِحْدَاهُمَا كَيْفَ تَصْنَعِينَ عِنْدَ الْغُسْلِ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَطَهَّرُ طُهُورَهُ لِلصَّلَاةِ وَيُفِيضُ عَلَى رَأْسِهِ ثَلَاثَ مَرَّاتٍ وَنَحْنُ نُفِيضُ عَلَى رُءُوسِنَا خَمْسًا مِنْ أَجْلِ الضَّفْرِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Za`idah] dari [Shadaqah bin Sa'id Al Hanafi] ia berkata; telah menceritakan kepadaku [Jumai' bin 'Umair] seorang dari Bani Tamimullah bin Tsa'labah, ia berkata, \"Pernah bersama ibu dan bibikku aku masuk menemui [Aisyah], lalu salah satu dari keduanya bertanya kepadanya, \"Apa yang kamu lakukan saat kamu mandi hadats?\" Aisyah menjawab, \"Rasulullah shallallahu 'alaihi wasallam memulai dengan berwudlu seperti wudlunya untuk shalat, lalu beliau menyiramkan air ke atas kepalanya sebanyak tiga kali, sedang kami menyiramkan ke atas kepala kami sebanyak lima kali agar sampai pangkal rambut.\" "},"782":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ يَزِيدَ بْنِ زَاذِي عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ سَأَلَ عَائِشَةَ عَنْ الْمَرْأَةِ تَغْتَسِلُ تَنْقُضُ شَعْرَهَا فَقَالَتْ بَخٍ وَإِنْ أَنْفَقَتْ فِيهِ أُوقِيَّةً إِنَّمَا يَكْفِيهَا أَنْ تُفْرِغَ عَلَى رَأْسِهَا ثَلَاثًا","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Yazid bin Zadzi] dari [Abu Zur'ah] dari [Abu Hurairah], bahwa ia pernah bertanya kepada [Aisyah] tentang seorang wanita yang mandi hadats, apakah ia harus mengurai rambutnya? Aisyah lalu menjawab, \"Waw…andai ia bersedekah dengan satu uqiyah (empat puluh dirhamm)! Sesungguhnya cukup baginya menuangkan ke atas kepalanya sebanyak tiga kali.\""},"783":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ حَجَّاجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ فِي الْحَائِضِ وَالْجُنُبِ يَصُبَّانِ الْمَاءَ صَبًّا وَلَا يَنْقُضَانِ شُعُورَهُمَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ حَجَّاجٍ عَنْ عَطَاءٍ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid] dari [Hajjaj] dari [Abu Az Zubair] dari [Jabir] tentang wanita yang haid dan orang yang junub, keduanya harus menyiramkan air (ke rambutnya saat mandi hadats) dan tidak perlu mengurai rambut mereka berdua.\" Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid] dari [Hajjaj] dari ['Atha] dengan riwayat yang semisalnya.\""},"784":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ قَالَ قَالَ إِبْرَاهِيمُ إِذَا بَلَّتْ أُصُولَهُ وَأَطْرَافَهُ لَمْ تَنْقُضْهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Manshur] ia berkata; [Ibrahim] berkata: \"Apabila ia telah membasahi pangkal dan ujung rambutnya maka ia tidak perlu mengurai rambutnya.\""},"785":{"ar":" حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أُمِّ مُحَمَّدٍ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْ لَا تَنْقُضْنَ عِقَصَكُنَّ مِنْ حَيْضٍ وَلَا مِنْ جَنَابَةٍ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid] dari [Ummu Muhammad] dari [Ummu Salamah], bahwa ia pernah berkata: \"Kalian tidak perlu melepas sanggul kalian (ketika mandi hadats) untuk haid atau junub.\" "},"786":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ جَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي أَشُدُّ ضَفْرَ رَأْسِي أَوْ عُقَدَهُ قَالَ احْفِنِي عَلَى رَأْسِكِ ثَلَاثَ حَفَنَاتٍ ثُمَّ اغْمِزِي عَلَى إِثْرِ كُلِّ حَفْنَةٍ غَمْزَةً","id":"Telah menceritakan kepada kami [Ubaidullah] dari [Usamah bin Zaid] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Seorang wanita datang menemui Nabi shallalahu 'alaihi wa sallam lalu berkata, \"Aku telah mengencangkan ikatan sanggulku?\" beliau menjawab: \"Guyurlah kepalamu sebanyak tiga kali guyuran, dan sela-selalah rambutmu (dengan menekan) pada setiap guyuran.\""},"787":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ حُذَيْفَةَ أَنَّهُ قَالَ لِامْرَأَتِهِ اسْتَأْصِلِي الشَّعْرَ لَا تَخَلَّلُهُ نَارٌ قَلِيلٌ بُقْيَاهَا عَلَيْهِ قَالَ مَنْصُورٌ يَعْنِي الْجَنَابَةَ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Za`idah] dari [Manshur] dari [Ibrahim] dari [Hammam bin Al Harits] dari [Hudzaifah], bahwa ia pernah berkata kepada isterinya: \"Alirkan air ke akar rambut, semoga ia kelak tidak disela-sela dengan api neraka.\" [Manshur] berkata, \"Yakni ketika mandi junub.\""},"788":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ إِذَا اغْتَسَلَتْ الْمَرْأَةُ مِنْ الْجَنَابَةِ فَلَا تَنْقُضْ شَعْرَهَا وَلَكِنْ تَصُبُّ الْمَاءَ عَلَى أُصُولِهِ وَتَبُلُّهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] dari [Khalid bin Abdullah] dari [Ibnu Abu Laila] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Jika seorang wanita mandi junub, maka ia tidak perlu mengurai rambutnya, tapi cukuplah ia menyiramkan air ke pangkal rambut dan membasahinya.\""},"789":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الْمَرْأَةِ تُصِيبُهَا الْجَنَابَةُ وَرَأْسُهَا مَعْقُوصٌ تَحُلُّهُ قَالَ لَا وَلَكِنْ تَصُبُّ عَلَى رَأْسِهَا الْمَاءَ صَبًّا حَتَّى تُرَوِّيَ أُصُولَ الشَّعْرِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha] tentang seorang wanita yang junub dan rambutnya bersanggul, apakah ia harus membukanya? ia menjawab: \" Tidak perlu, tetapi cukuplah ia menyiramkan air ke atas kepalanya dengan sekali siraman hingga membasahi pangkal rambut.\""},"790":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ لَا بَأْسَ أَنْ تَتَنَاوَلَ الْحَائِضُ مِنْ الْمَسْجِدِ الشَّيْءَ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin 'Asad] telah menceritakan kepada kami [Abu 'Awanah] dari [Mughirah] dari [Ibrahim] ia berkata: \"Tidak mengapa seorang wanita yang tengah haid mengambil sesuatu dari masjid.\""},"791":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ جَعْفَرِ بْنِ الْحَارِثِ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قَالَ تَتَنَاوَلُ الْحَائِضُ الشَّيْءَ مِنْ الْمَسْجِدِ وَلَا تَدْخُلُهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ja'far bin Al Harits] dari [Manshur] dari [Ibrahim] ia berkata, \"Seorang wanita yang tengah haid boleh mengambil sesuatu dari masjid, namun ia tidak boleh memasukinya.\""},"792":{"ar":" أَخْبَرَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ قَالَ الْجُنُبُ يَأْخُذُ مِنْ الْمَسْجِدِ وَلَا يَضَعُ فِيهِ","id":"Telah mengabarkan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] ia berkata, \"Seorang yang junub boleh mengambil sesuatu dari masjid, tetapi ia tidak boleh meletakkan (sesuatu) di dalamnya.\""},"793":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الْحَائِضِ تَنَاوَلُ مِنْ الْمَسْجِدِ الشَّيْءَ قَالَ نَعَمْ إِلَّا الْمُصْحَفَ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha] tentang seorang wanita yang tengah haid, (apakah ia boleh) mengambil sesuatu dari masjid? ' ia menjawab: \"Ya, kecuali Al-Qur'an.\" "},"794":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي مِجْلَزٍ عَنْ ابْنِ عَبَّاسٍ فِي قَوْلِهِ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ } قَالَ هُوَ الْمُسَافِرُ","id":"Telah mengabarkan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Abu Mijlaz] dari [Ibnu Abbas] tentang firman-Nya: '((jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. An Nisa: 43), ia berkata: \"Yaitu musafir.\" "},"795":{"ar":" أَخْبَرَنَا مُسْلِمٌ حَدَّثَنَا الْحَسَنُ بْنُ أَبِي جَعْفَرٍ حَدَّثَنَا سَلْمٌ الْعَلَوِيُّ عَنْ أَنَسٍ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ } قَالَ الْجُنُبُ يَجْتَازُ بِالْمَسْجِدِ وَلَا يَجْلِسُ فِيهِ","id":"Telah mengabarkan kepada kami [Muslim] telah menceritakan kepada kami [Al Hasan bin Abu Ja'far] telah menceritakan kepada kami [Salm Al 'Alawi] dari [Anas] ketika menafsirkan ayat: '(jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. Al An Nisa: 43), ia berkata, \"Orang yang sedang junub boleh melewati masjid, tetapi tidak boleh duduk (di dalamnya).\""},"796":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ وَأَبُو نُعَيْمٍ عَنْ شَرِيكٍ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ أَبِي عُبَيْدَةَ قَالَ الْجُنُبُ يَمُرُّ فِي الْمَسْجِدِ وَلَا يَقْعُدُ فِيهِ ثُمَّ قَرَأَ هَذِهِ الْآيَةَ { وَلَا جُنُبًا إِلَّا عَابِرِي سَبِيلٍ }","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] dan [Abu Nu'aim] dari [Syarik] dari [Abdul Karim Al Jazari] dari [Abu 'Ubaidah] ia berkata, \"Orang yang sedang junub boleh melewati masjid, tetapi ia tidak boleh duduk di dalamnya.\" Kemudian ia membaca ayat ini: '(jangan pula hampiri masjid) sedang ia dalam keadaan junub, kecuali sekedar berlalu saja) ' (Qs. An Nisaa: 43)."},"797":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ وَسَالِمٍ عَنْ سَعِيدٍ قَالَا يَمُرُّ وَلَا يَقْعُدُ فِيهِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Syarik] dari [Simak] dari ['Ikrimah] dan [Salim] dari [Sa'id] keduanya berkata, \"Orang yang junub boleh melewati (masjid) tetapi ia tidak boleh duduk di dalamnya.\""},"798":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي لَيْلَى عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كُنَّا نَمْشِي فِي الْمَسْجِدِ وَنَحْنُ جُنُبٌ لَا نَرَى بِذَلِكَ بَأْسًا","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Ibnu Abu Laila] dari [Abu Az Zubair] dari [Jabir] ia berkata: \"Dahulu kami terbiasa berjalan di masjid sedang kami tengah junub, dan kami tidak melihat itu sebagai masalah.\" "},"799":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ فِي الْمَرْأَةِ الْحَائِضِ فِي عُنُقِهَا التَّعْوِيذُ أَوْ الْكِتَابُ قَالَ إِنْ كَانَ فِي أَدِيمٍ فَلْتَنْزِعْهُ وَإِنْ كَانَ فِي قَصَبَةٍ مُصَاغَةٍ مِنْ فِضَّةٍ فَلَا بَأْسَ إِنْ شَاءَتْ وَضَعَتْ وَإِنْ شَاءَتْ لَمْ تَفْعَلْ قِيلَ لِعَبْدِ اللَّهِ تَقُولُ بِهَذَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Abdul Malik] dari ['Atha] tentang seorang wanita yang tengah haid dan di lehernya dapat at ta'widz (semacam jimat dari tulisan-tulisan Al-Qur'an) atau Al-Qur'an, ia berkata, \"Jika ia berada pada kulit, maka ia harus melepasnya, dan jika ia berada pada perhiasan dari perak, maka tidak mengapa. Jika mau ia dapat melepasnya, dan jika mau ia tidak perlu melakukan hal itu.\" Ditanyakan kepada Abdullah, \"Apakah kamu juga mengatakan demikian?\" ia menjawab: \"Ya.\""},"800":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا ضَمْرَةُ قَالَ عَبْدُ اللَّهِ بْنُ شَوْذَبٍ حَدَّثَنَا عَنْ مَطَرٍ قَالَ سَأَلْتُ الْحَسَنَ وَعَطَاءً عَنْ الرَّجُلِ تَكُونُ مَعَهُ امْرَأَتُهُ فِي سَفَرٍ فَتَحِيضُ ثُمَّ تَطْهُرُ وَلَا تَجِدُ الْمَاءَ قَالَا تَتَيَمَّمُ وَتُصَلِّي قَالَ قُلْتُ لَهُمَا يَطَؤُهَا زَوْجُهَا قَالَا نَعَمْ الصَّلَاةُ أَعْظَمُ مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid] telah menceritakan kepada kami [Dlamrah] berkata; [Abdullah bin Syaudzab] menceritakan kepada kami dari [Mathar] ia berkata, \"Aku pernah bertanya kepada [Al Hasan] dan ['Atha] tentang seorang laki-laki yang bepergian bersama isterinya, kemudian isterinya mengalami haid lalu suci namun tidak mendapati air.\" Keduanya menjawab, \"Hendaknya ia bertayammum lalu shalat.\" Aku bertanya lagi kepada keduanya, \"Apakah suaminya boleh menggauli isterinya?\" keduanya menjawab, \"Ya boleh, shalat lebih agung urusannya dibandingkan hal itu.\""},"801":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ ابْنِ الْمُبَارَكِ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ فِي الْمَرْأَةِ تَطْهُرُ وَلَا تَجِدُ الْمَاءَ قَالَ يُصِيبُهَا زَوْجُهَا إِذَا تَيَمَّمَتْ سُئِلَ عَبْد اللَّهِ تَقُولُ بِهَذَا قَالَ إِي وَاللَّهِ","id":"Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Ibnu Al Mubarak] dari [Ibnu Juraij] dari ['Atha] tentang seorang wanita yang suci (dari haid) tetapi ia tidak mendapatkan air, ia berkata, \"Suaminya boleh menggaulinya jika ia telah bertayammum.\" Abdullah ditanya, \"Apakah kamu juga berpendapat demikian?\" ia menjawab, \"Ya.\""},"802":{"ar":" أَخْبَرَنَا يَزِيدُ حَدَّثَنَا شَرِيكٌ عَنْ لَيْثٍ عَنْ طَاوُسٍ فِي اسْتِبْرَاءِ الْأَمَةِ إِنْ لَمْ تَكُنْ تَحِيضُ قَالَ خَمْسَةً وَأَرْبَعِينَ","id":"Telah mengabarkan kepada kami [Yazid] telah menceritakan kepada kami [Syarik] dari [Laits] dari [Thawus] tentang istibra` (masa untuk memastikan kehamilan) seorang budak wanita jika ia tidak lagi mengalami haid, ia berkata, \"Empat puluh lima hari.\" "},"803":{"ar":" أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا شَرِيكٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ قَالَ ثَلَاثَةُ أَشْهُرٍ","id":"Telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Syarik] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] ia berkata, \"Masa istibra` itu tiga bulan.\" "},"804":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ عَنْ عُمَرَ بْنِ عَبْدِ الْوَاحِدِ عَنْ الْأَوْزَاعِيِّ قَالَ سَأَلْتُ الزُّهْرِيَّ عَنْ الرَّجُلِ يَبْتَاعُ الْجَارِيَةَ لَمْ تَبْلُغْ الْمَحِيضَ وَلَا تَحْمِلُ مِثْلُهَا كَمْ يَسْتَبْرِئُهَا قَالَ ثَلَاثَةَ أَشْهُرٍ و قَالَ يَحْيَى بْنُ أَبِي كَثِيرٍ بِخَمْسَةٍ وَأَرْبَعِينَ يَوْمًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] dari [Umar bin Abdul Wahid] dari [Al 'Auza'i] ia berkata, \"Aku pernah bertanya kepada [Az Zuhri] tentang seorang laki-laki yang membeli seorang budak wanita yang belum mencapai usia haid dan hamil, berapa lamakah ia memastikan tidak adanya kehamilan?\" ia menjawab, \"Tiga bulan.\" [Yahya bin Abu Katsir] berkata, \"Empat puluh lima hari.\""},"805":{"ar":" أَخْبَرَنَا الْهَيْثَمُ بْنُ جَمِيلٍ عَنْ ابْنِ الْمُبَارَكِ عَنْ يَحْيَى بْنِ بِشْرٍ عَنْ عِكْرِمَةَ قَالَ بِشَهْرٍ سُئِلَ عَبْد اللَّهِ بِأَيِّهِمَا تَقُولُ قَالَ ثَلَاثَةُ أَشْهُرٍ أَوْثَقُ وَشَهْرٌ يَكْفِي","id":"Telah mengabarkan kepada kami [Al Haitsam bin Jamil] dari [Ibnu Al Mubarak] dari [Yahya bin Bisyr] dari ['Ikrimah] ia berkata, \"(Masa tunggunya adalah) satu bulan.\" Abdullah ditanya, \"Mana yang kamu pilih?\" ia menjawab, \"Yang tiga bulan lebih terpercaya, dan satu bulan sudah cukup.\""},"806":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الصَّلَوَاتِ الْمَكْتُوبَاتِ كَمَثَلِ نَهَرٍ جَارٍ عَذْبٍ عَلَى بَابِ أَحَدِكُمْ يَغْتَسِلُ مِنْهُ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami [Ya'la bin Ubaid] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Perumpamaan shalat wajib (lima waktu) bagaikan sebuah sungai berair tawar yang mengalir di depan pintu salah seorang dari kalian, lalu ia mandi di sungai tersebut setiap hari sebanyak lima kali.\""},"807":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَرَأَيْتُمْ لَوْ أَنَّ نَهَرًا بِبَابِ أَحَدِكُمْ يَغْتَسِلُ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍ مَاذَا تَقُولُونَ ذَلِكَ مُبْقِيًا مِنْ دَرَنِهِ قَالُوا لَا يُبْقِي مِنْ دَرَنِهِ قَالَ كَذَلِكَ مَثَلُ الصَّلَوَاتِ الْخَمْسِ يَمْحُو اللَّهُ بِهِنَّ الْخَطَايَا قَالَ عَبْد اللَّهِ حَدِيثُ أَبِي هُرَيْرَةَ عِنْدِي أَصَحُّ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] ia berkata; telah menceritakan kepadaku [Yazid bin Abdullah] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah], bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana menurut kalian kalau sekiranya ada sebuah sungai (mengalir) di depan pintu (rumah) salah seorang dari kalian, lalu ia mandi (di sungai tersebut) setiap harinya sebanyak lima kali, apa yang akan kalian katakan, apakah masih tersisa kotorannya?\" mereka menjawab, \"Tidak tersisa (sedikitpun) dari kotorannya.\" Beliau bersabda lagi: \"Begitulah perumpamaan shalat lima waktu, Allah subhanallahu wa ta'ala menghapus dengannya (shalat lima waktu tersebut) dosa-dosa.\""},"808":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَمْرِو بْنِ الْحَسَنِ بْنِ عَلِيٍّ قَالَ سَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فِي زَمَنِ الْحَجَّاجِ وَكَانَ يُؤَخِّرُ الصَّلَاةَ عَنْ وَقْتِ الصَّلَاةِ فَقَالَ جَابِرٌ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ حِينَ تَزُولُ الشَّمْسُ وَالْعَصْرَ وَهِيَ حَيَّةٌ أَوْ نَقِيَّةٌ وَالْمَغْرِبَ حِينَ تَجِبُ الشَّمْسُ وَالْعِشَاءَ رُبَّمَا عَجَّلَ وَرُبَّمَا أَخَّرَ إِذَا اجْتَمَعَ النَّاسُ عَجَّلَ وَإِذَا تَأَخَّرُوا أَخَّرَ وَالصُّبْحَ رُبَّمَا كَانُوا أَوْ كَانَ يُصَلِّيهَا بِغَلَسٍ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] ia berkata, \"Aku pernah mendengar [Muhammad bin 'Amru bin Al Hasan bin Ali] berkata, \"Kami pernah bertanya kepada [Jabir bin Abdullah] pada zaman Al Hajjaj -dan ia (Al Hajjaj) terbiasa mengahirkan shalat dari waktu semestinya-, maka Jabir berkata, \"Dahulu Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat zhuhur ketika matahari sudah tergelincir, dan shalat ashr ketika (matahari) hidup atau jernih, dan shalat maghrib ketika matahari tenggelam, shalat isya kadang-kadang beliau menyegerakan dan kadang mengakhirkannya, apabila orang-orang sudah berkumpul maka beliau segerakan dan apabila mereka terlambat datang beliau ahirkan, dan shalat shubuh barangkali mereka atau beliau biasa melaksanakannya ketika malam masih gelap.\" "},"809":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ الْحَنَفِيُّ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ أَنَّ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ أَخَّرَ الصَّلَاةَ يَوْمًا فَدَخَلَ عَلَيْهِ عُرْوَةُ بْنُ الزُّبَيْرِ فَأَخْبَرَهُ أَنَّ الْمُغِيرَةَ بْنَ شُعْبَةَ أَخَّرَ الصَّلَاةَ يَوْمًا فَدَخَلَ عَلَيْهِ أَبُو مَسْعُودٍ الْأَنْصَارِيُّ فَقَالَ مَا هَذَا يَا مُغِيرَةُ أَلَيْسَ قَدْ عَلِمْتَ أَنَّ جِبْرِيلَ نَزَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ بِهَذَا أُمِرْتَ قَالَ اعْلَمْ مَا تُحَدِّثُ يَا عُرْوَةُ أَوَ أَنَّ جِبْرِيلَ أَقَامَ وَقْتَ الصَّلَاةِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَذَلِكَ كَانَ بَشِيرُ بْنُ أَبِي مَسْعُودٍ يُحَدِّثُ عَنْ أَبِيهِ قَالَ عُرْوَةُ وَلَقَدْ حَدَّثَتْنِي عَائِشَةُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ وَالشَّمْسُ فِي حُجْرَتِهَا قَبْلَ أَنْ تَظْهَرَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid Al Hanafi] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab], bahwa Umar bin Abdul Aziz pernah pada suatu hari mengahirkan shalat, lalu ['Urwah bin Az Zubair] masuk menemuinya dan mengabarkan kepadanya, bahwa Al Mughirah bin Syu'bah pernah pada suatu hari mengahirkan shalat, lalu [Abu Mas'ud Al Anshari] masuk menemuinya dan berkata, \"Apa-apaan ini wahai Mughirah! Bukankah kamu sudah mengetahui bahwa malaikat Jibril 'alaihissalam telah turun kepada Rasulullah shallallahu 'alaihi wasallam, lalu ia shalat dan Rasulullah shallallahu 'alaihi wasallam ikut shalat, kemudian ia shalat dan Rasulullah shallallahu 'alaihi wasallam ikut shalat, lalu ia shalat dan Rasulullah shallallahu 'alaihi wasallam ikut shalat, lalu ia shalat dan Rasulullah shallallahu 'alaihi wasallam ikut shalat, lalu ia shalat dan Rasulullah shallallahu 'alaihi wasallam ikut shalat, kemudian beliau bertanya: \"Apakah begini kamu diperintahkan?\" Umar berkata, \"Hai Urwah, apa yang kamu ceritakan itu, apakah Jibril mengajarkan waktu shalat kepada Rasulullah shallallahu 'alaihi wasallam?\" 'Urwah menjawab, \"Demikianlah [Basyir bin Abu Mas'ud] menceritakan dari [ayahnya].\" ['Urwah] berkata, \"Sungguh, [Aisyah] pernah menceritakan kepadaku bahwa Nabi shallallahu 'alaihi wasallam pernah shalat ashr sedang (sinar) matahari masih berada di kamarnya sebelum (bayangan gelap) muncul.\""},"810":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا سَلَمَةُ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَقَ قَالَ وَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَدِمَهَا قَالَ أَبُو مُحَمَّد يَعْنِي الْمَدِينَةَ إِنَّمَا يُجْتَمَعُ إِلَيْهِ بِالصَّلَاةِ لِحِينِ مَوَاقِيتِهَا بِغَيْرِ دَعْوَةٍ فَهَمَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَجْعَلَ بُوقًا كَبُوقِ الْيَهُودِ الَّذِينَ يَدْعُونَ بِهِ لِصَلَاتِهِمْ ثُمَّ كَرِهَهُ ثُمَّ أَمَرَ بِالنَّاقُوسِ فَنُحِتَ لِيُضْرَبَ بِهِ لِلْمُسْلِمِينَ إِلَى الصَّلَاةِ فَبَيْنَمَا هُمْ عَلَى ذَلِكَ إِذْ رَأَى عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ عَبْدِ رَبِّهِ أَخُو بَلْحَارِثِ بْنِ الْخَزْرَجِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ طَافَ بِيَ اللَّيْلَةَ طَائِفٌ مَرَّ بِي رَجُلٌ عَلَيْهِ ثَوْبَانِ أَخْضَرَانِ يَحْمِلُ نَاقُوسًا فِي يَدِهِ فَقُلْتُ يَا عَبْدَ اللَّهِ أَتَبِيعُ هَذَا النَّاقُوسَ فَقَالَ وَمَا تَصْنَعُ بِهِ قُلْتُ نَدْعُو بِهِ إِلَى الصَّلَاةِ قَالَ أَفَلَا أَدُلُّكَ عَلَى خَيْرٍ مِنْ ذَلِكَ قُلْتُ وَمَا هُوَ قَالَ تَقُولُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ ��َكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ اسْتَأْخَرَ غَيْرَ كَثِيرٍ ثُمَّ قَالَ مِثْلَ مَا قَالَ وَجَعَلَهَا وِتْرًا إِلَّا أَنَّهُ قَالَ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ فَلَمَّا خُبِّرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا لَرُؤْيَا حَقٌّ إِنْ شَاءَ اللَّهُ فَقُمْ مَعَ بِلَالٍ فَأَلْقِهَا عَلَيْهِ فَإِنَّهُ أَنْدَى صَوْتًا مِنْكَ فَلَمَّا أَذَّنَ بِلَالٌ سَمِعَهَا عُمَرُ بْنُ الْخَطَّابِ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَجُرُّ إِزَارَهُ وَهُوَ يَقُولُ يَا نَبِيَّ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ رَأَيْتُ مِثْلَ مَا رَأَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلِلَّهِ الْحَمْدُ فَذَاكَ أَثْبَتُ قَالَ مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنِيهِ سَلَمَةُ قَالَ حَدَّثَنِيهِ ابْنُ إِسْحَقَ قَالَ حَدَّثَنِي هَذَا الْحَدِيثَ مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَبْدِ رَبِّهِ عَنْ أَبِيهِ بِهَذَا الْحَدِيثِ أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ زَيْدِ بْنِ عَبْدِ رَبِّهِ قَالَ حَدَّثَنِي أَبِي عَبْدُ اللَّهِ بْنُ زَيْدٍ قَالَ لَمَّا أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاقُوسِ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Salamah] ia berkata; telah menceritakan kepadaku [Muhammad bin Ishaq] ia berkata, \"Sungguh, ketika Rasulullah shallallahu 'aliahi wa sallam datang -Abu Muhammad berkata: Yaitu kota Madianah-, orang-orang dikumpulkan kepada beliau untuk melaksanakan shalat (berjama'ah) pada waktu-waktunya tanpa ada panggilan (khusus), lalu Rasulullah shallallahu 'alaihi wasallam menginginkan untuk membuat terompet seperti terompetnya orang-orang Yahudi yang mereka jadikan untuk mengundang saat mereka shalat, tetapi beliau membenci hal itu. Kemudian beliau memerintahkan untuk menggunakan lonceng, lalu dibuatkan untuk di tabuh memanggil kaum muslimin melaksanakan shalat, maka tatkala mereka masih (dalam kebingungan) dalam masalah tersebut, Abdullah bin Zaid bin Abdu Rabbih -saudaranya Balharits bin Al Khazraj-, datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, semalam ada seorang laki-laki mengelilingi aku, ada seseorang yang melewati aku ia mengenakan dua baju berwarna hijau, ia membawa lonceng di tangannya, maka aku bertanya, 'Wahai hamba Allah, apakah kamu hendak menjual lonceng ini? ' orang itu balik bertanya, 'Untuk apa? ' aku menjawab, 'Kami akan menggunakannya untuk memanggil shalat, ' orang itu berkata, 'Maukah kamu aku tunjukkan satu hal yang lebih baik dari itu? ' aku bertanya, 'Apakah itu? ' ia menjawab, \"ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAHU ASYHADU AN LAA ILAAHA ILLA ALLAHU, ASYHADU ANNA MUHAMMADAN RASULULLAH ASYHADU ANNA MUHAMMADAN RASULULLAH, HAYYA 'ALAS SHALAAT HAYYA 'ALAS SHALAAT, HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH, ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLA ALLAHU (Allah Maha Besar, Allah Maha Besar. Aku bersaksi bahwa tidak ada tuhan (yang berhak disembah) kecuali Allah, aku bersaksi bahwa tidak ada tuhan (yang berhak disembah) kecuali Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah, aku bersaksi bahwa Muhammad adalah utusan Allah. Marilah shalat, marilah shalat. Marilah menuju kemenangan, marilah menuju kemenangan. Allah Maha Besar, Allah Maha besar. Tidak ada tuhan (yang berhak disembah) kecuali Allah) '.\" Maka tatkala ia telah mengabarkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya itu adalah mimpi yang benar, jika Allah menghendaki maka bangkitlah bersama Bilal dan sampaikanlah kepadanya, karena suaranya lebih indah dibandingkan suaramu.\" Maka tatkala Bilal mengumandangkan adzan, Umar bin Khaththab mendengarnya dan ia masih berada di rumahnya, lalu ia keluar pun menuju menemui Rasulullah shallallahu 'alaihi wasallam -dan ia menjulurkan sarungnya-, ia berkata, \"Wahai Nabi Allah, demi Dzat yang mengutusmu dengan benar, sungguh aku telah bermimpi seperti apa yang ia mimpikan.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Puji syukur milik Allah subhanallahu wa ta'ala, itu lebih meyakinkan lagi.\" Telah berkata [Muhammad bin Humaid] telah menceritakannya kepadaku [Salamah] telah menceritakannya kepadaku [Ibnu Ishaq] telah menceritakan hadits ini kepadaku [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Muhammad bin Abdullah bin Zaid bin Abdu Rabbih] dari [Ayahnya] dengan hadits ini.\" Telah mengabarkan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] telah menceritakan kepada kami [Ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Muhammad bin Abdullah bin Zaid bin Abdu Rabbih] ia berkata: telah menceritakan kepadaku ayahku [Abdullah bin Zaid] -, ia berkata: \"Maka tatkala Rasulullah shallahu 'alihi wa sallam memerintahkan untuk menggunakan lonceng....lalu ia menyebutkan (riwayat) yang serupa.\""},"811":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ يَرْفَعُهُ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُؤَذِّنَ ابْنُ أُمِّ مَكْتُومٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Salim] dari [ayahnya] -Ibnu Umar radliallahu 'anhu-, ia meriwayatkan secara marfu', ia berkata: \"Sesungguhnya Bilal radhiallhu 'anhu mengumandangkan adzan pada malam hari, maka makan dan minumlah hingga Ibnu Ummi Maktu mengumandangkan adzan\"."},"812":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا عَبْدَةُ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَعَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْ كَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُؤَذِّنَانِ بِلَالٌ وَابْنُ أُمِّ مَكْتُومٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى تَسْمَعُوا أَذَانَ ابْنِ أ��مِّ مَكْتُومٍ فَقَالَ الْقَاسِمُ وَمَا كَانَ بَيْنَهُمَا إِلَّا أَنْ يَنْزِلَ هَذَا وَيَرْقَى هَذَا","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami ['Abdah] telah mengabarkan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari [Al Qasim] dari [Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam memiliki dua orang mu`adzdzin, Bilal dan Ibnu Ummi Maktum, Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya Bilal mengumandangkan adzan pada malam hari, maka makan dan minumlah (untuk sahur) hingga kalian mendengar adzan (yang dikumandangkan oleh) Ibnu Ummi Maktum.\" Al Qasim berkata, \"Dan tidaklah di antara mereka berdua, kecuali (bergantian) yang ini turun dan yang itu naik (tidak terlalu lama).\""},"813":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ بْنِ فَارِسٍ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ حَفْصِ بْنِ عُمَرَ بْنِ سَعْدٍ الْمُؤَذِّنِ أَنَّ سَعْدًا كَانَ يُؤَذِّنُ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَفْصٌ حَدَّثَنِي أَهْلِي أَنَّ بِلَالًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْذِنُهُ لِصَلَاةِ الْفَجْرِ فَقَالُوا إِنَّهُ نَائِمٌ فَنَادَى بِلَالٌ بِأَعْلَى صَوْتِهِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ فَأُقِرَّتْ فِي أَذَانِ صَلَاةِ الْفَجْرِ قَالَ أَبُو مُحَمَّد يُقَالُ سَعْدٌ الْقَرَظُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar bin Faris] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari [Hafsh bin Umar bin Sa'ad Al Mu`adzdzin], bahwa Sa'ad pernah mengumandangkan adzan di masjid Rasulullah shallallahu 'alaihi wasallam, lalu Hafsh berkata, \" [Keluargaku] mengabarkan kepadaku bahwa [Bilal] pernah datang menemui Rasulullah shallallahu 'alaihi wasallam untuk mengabarkan kepada beliau bahwa waktu shalat subuh telah tiba. Mereka pun berkata, \"Sesungguhnya beliau masih tidur.\" Maka Bilal pun mengumandangkan adzan dengan suara yang lantang, \"ASSAHALAATU KHAIRUN MIN AN NAUM (Shalat itu lebih baik dari pada tidur) ', lalu kalimat tersebut ditetapkan dalam adzan subuh.\" Abu Muhammad berkata, \"Sa'ad dikenal dengan sebutan Al Qarazh.\""},"814":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو جَعْفَرٍ عَنْ مُسْلِمٍ أَبِي الْمُثَنَّى عَنْ ابْنِ عُمَرَ أَنَّهُ قَالَ كَانَ الْأَذَانُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثْنَى مَثْنَى وَالْإِقَامَةُ مَرَّةً مَرَّةً غَيْرَ أَنَّهُ كَانَ إِذَا قَالَ قَدْ قَامَتْ الصَّلَاةُ قَالَهَا مَرَّتَيْنِ فَإِذَا سَمِعْنَا الْإِقَامَةَ تَوَضَّأَ أَحَدُنَا وَخَرَجَ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Ja'far] dari [Muslim Abu Al Mutsanna] dari [Ibnu Umar], bahwa ia pernah berkata, \"Adzan pada zaman Rasulullah shallallahu 'alaihi wasallam dua kali-dua kali dan iqamah itu satu kali-satu kali, hanya ketika mu`adzin mengucapkan: 'QAD QAAMATIS SHALAT (Sungguh shalat telah didirikan) ' itu dikumandangkan dua kali. Maka apabila kami mendengar iqamah, seseorang dari kami langsung berwudlu dan keluar (untuk shalat).\""},"815":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَعَفَّانُ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَ أُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَيُوتِرَ الْإِقَامَةَ","id":"Telah mengabarkan kepada kami [Abu Al Walid At Thayalisi] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Anas] ia berkata, \"Bilal diperintahkan untuk menggenapkan pada kalimat adzan (dua kali-dua kali) dan mengganjilkan iqamah.\" "},"816":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ سِمَاكِ بْنِ عَطِيَّةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَ أُمِرَ بِلَالٌ أَنْ يَشْفَعَ الْأَذَانَ وَيُوتِرَ الْإِقَامَةَ إِلَّا الْإِقَامَةَ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Simak bin 'Athiyyah] dari [Ayyub] dari [Abu Qilabah] dari [Anas] ia berkata; \"Bilal diperintahkan untuk menggenapkan kalimat adzan (dua kali-dua kali) dan mengganjilkan iqamah.\" Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Khalid] dari [Abu Qilabah] dari [Anas] dengan lafad sama."},"817":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هَمَّامٍ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ مَكْحُولٍ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ أَبِي مَحْذُورَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ نَحْوًا مِنْ عِشْرِينَ رَجُلًا فَأَذَّنُوا فَأَعْجَبَهُ صَوْتُ أَبِي مَحْذُورَةَ فَعَلَّمَهُ الْأَذَانَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَه إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ وَالْإِقَامَةَ مَثْنَى مَثْنَى","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Hammam] dari ['Amir Al 'Ahwal] dari [Makhul] dari [Ibnu Muhairiz] dari [Abu Mahdzurah], bahwa Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kepada sekitar dua puluh orang (untuk mengumandangkan adzan), lalu mereka mengumandangkannya dan beliau kagum pada suara Abu mahdzurah, maka beliau mengajarkan adzan kepadanya: 'ALLAHU AKBAR, ALLAHU AKBAR. ASYHADU AN LAA ILAAHA ILLA ALLAHU, ASYHADU AN LAA ILAAHA ILLA ALLAHU. ASYHADU ANNA MUHAMMADAN RASULULLAH, ASYHADU ANNA MUHAMMADAN RASULULLAH. HAYYA 'ALAS SHALAAT, HAYYA 'ALAS SHALAAT. HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH. ALLAHU AKBAR, ALLAHU AKBAR. LAA ILAAHA ILLA ALLAHU (Allah Maha Besar, Allah Maha Besar. Aku bersaksi bahwa tidak ada tuhan (yang patut disembah) kecuali Allah, aku bersaksi bahwa tidak ada tuhan (yang patut disembah) kecuali Allah. Aku bersaksi bahwa Muhammad adalah utusan Allah, aku bersaksi bahwa Muhammad adalah utusan Allah. Marilah shalat, marilah shalat. Mari kita menuju pada kemenangan, mari kita menuju pada kemenangan. Allah Maha Besar, Allah Maha Besar. Tidak ada tuhan (yang berhak disembah) kecuali Allah) '. Dan beliau memerintahkan iqamah diucapkan dua kali-dua kali.\""},"818":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَحَجَّاجُ بْنُ الْمِنْهَالِ قَالَا حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَامِرٌ الْأَحْوَلُ قَالَ حَجَّاجٌ فِي حَدِيثِهِ عَامِرُ بْنُ عَبْدِ الْوَاحِدِ قَالَ حَدَّثَنِي مَكْحُولٌ أَنَّ ابْنَ مُحَيْرِيزٍ حَدَّثَهُ أَنَّ أَبَا مَحْذُورَةَ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَهُ الْأَذَانَ تِسْعَ عَشْرَةَ كَلِمَةً وَالْإِقَامَةَ سَبْعَ عَشْرَةَ كَلِمَةً","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] dan [Hajjaj bin Minhal] keduanya berkata; telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Amir Al Ahwal], [Hajjaj] menyebutkan dalam haditsnya; ['Amir bin Abdul Wahid] ia berkata: telah menceritakan kepadaku [Makhul] bahwa [Ibnu Muhairiz] mengabarkan kepada kami, bahwa [Abu Mahdzurah] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengajarinya cara mengumandangkan adzan dengan sembilan belas kalimat, dan iqamah dengan tujuh belas kalimat.\""},"819":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ أَنَّهُ رَأَى بِلَالًا أَذَّنَ قَالَ فَجَعَلْتُ أَتْبَعُ فَاهُ هَاهُنَا وَهَاهُنَا بِالْأَذَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Aun bin Abu Juhaifah] dari [Ayahnya], bahwa ia pernah melihat [Bilal] mengumandangkan adzan, ia berkata, \"Akupun mengikuti mulutnya bergerak ke arah sini dan ke arah sana saat mengumandangkan adzan.\""},"820":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبَّادٌ عَنْ حَجَّاجٍ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ أَنَّ بِلَالًا رَكَزَ الْعَنَزَةَ ثُمَّ أَذَّنَ وَوَضَعَ أُصْبُعَيْهِ فِي أُذُنَيْهِ فَرَأَيْتُهُ يَدُورُ فِي أَذَانِهِ قَالَ عَبْد اللَّهِ حَدِيثُ الثَّوْرِيِّ أَصَحُّ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami ['Abbad] dari [Hajjaj] dari ['Aun bin Abu Juhaifah] dari [Ayahnya] bahwa [Bilal] pernah menancapkan tongkat kemudian ia mengumandangkan adzan dan ia meletakkan dua jarinya pada kedua telinganya, dan aku melihatnya berputar (memutar badannya ke kanan dan ke kiri).\" Abdullah berkata, \"Hadits Ats Tsauri lebih shahih.\""},"821":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُوسَى هُوَ ابْنُ يَعْقُوبَ الزَّمْعِيُّ قَالَ حَدَّثَنِي أَبُو حَازِمِ بْنُ دِينَارٍ قَالَ أَخْبَرَنِي سَهْلُ بْنُ سَعْدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثِنْتَانِ لَا تُرَدَّانِ أَوْ قَلَّ مَا تُرَدَّانِ الدُّعَاءُ عِنْدَ النِّدَاءِ وَعِنْدَ الْبَأْسِ حِينَ يُلْحِمُ بَعْضُهُ بَعْضًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Musa] -yaitu Ibnu Mas'ud Az Zam'i-, ia berkata: telah menceritakan kepadaku [Abu Hazim bin Dinar] ia berkata; telah mengabarkan kepadaku [Sahl bin Sa'ad] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua hal yang tidak akan tertolak, atau jarang tertolak; yaitu berdoa ketika adzan dan berdoa ketika masa perang saat sebagian orang membunuh sebagian yang lain.\""},"822":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ الْمُؤَذِّنَ فَقُولُوا مِثْلَ مَا يَقُولُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari ['Atha bin Yazid] dari [Abu Sa'id], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian mendengar mu`adzin, maka ucapkanlah seperti apa yang ia ucapkan.\" "},"823":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عِيسَى بْنِ طَلْحَةَ قَالَ دَخَلْنَا عَلَى مُعَاوِيَةَ فَنَادَى الْمُنَادِي فَقَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ فَقَالَ مُعَاوِيَةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ قَالَ أَشْهَدُ أَنْ لَا إِلَه إِلَّا اللَّهُ قَالَ وَأَنَا أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ وَأَنَا أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ يَحْيَى وَأَخْبَرَنِي بَعْضُ أَصْحَابِنَا أَنَّهُ لَمَّا قَالَ حَيَّ عَلَى الصَّلَاةِ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ ثُمَّ قَالَ مُعَاوِيَةُ سَمِعْتُ نَبِيَّكُمْ يَقُولُ هَذَا","id":"Telah mengbarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam Ad Dastawa`i] dari [Yahya] dari [Muhammad bin Ibrahim bin Al Harits] dari ['Isa bin Thalhah] ia berkata, \"Kami pernah masuk menemui [Mu'awiyah], lalu mu`adzin mengumandangkan adzan, saat mu`adzin mengucapkan; 'ALLAHU AKBAR (Allah Maha Besar), ' maka Mu'awiyah mengucapkan; 'ALLAHU AKBAR (Allah Maha Besar), ' mu`adzin mengucapkan; 'ASYHADU AN LAA ILAAHA ILLAHU (Aku bersaksi bahwa tidak ada tuhan (yang berhak disembah) kecuali Allah), ' Mu'awiyah berkata; 'Dan akupun juga bersaksi (demikian), ' mu`adzin mengucapan; \"ASYHADU ANNA MUHAMMADAN RASULULLAH (Aku bersaksi bahwa Muhammad adalah utusan Allah) ', Mu'awiyah berkata; \"Dan aku pun juga bersaksi (demikian).' Dan Yahya berkata; \"Dan sebagian sahabat kami pernah mengabarkan kepadaku bahwa ketika mu`adzin mengucapkan; \"HAYYA ALAS SHALAAT (Mari shalat) ', Mu'awiyah menjawab; \"LAA HAULA HAULA WA LAA QUWWATA ILLA BILLAHI (Tidak ada daya dan kekuatan kecuali (dengan kehendak) Allah) ', kemudian Mu'awiyah berkata; \"Aku telah mendengar Nabi kalian mengucapkan demikian.\""},"824":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ مُعَاوِيَةَ سَمِعَ الْمُؤَذِّنَ قَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ فَقَالَ مُعَاوِيَةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ فَقَالَ الْمُؤَذِّنُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ مُعَاوِيَةُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ الْمُؤَذِّنُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَقَالَ مُعَاوِيَةُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَقَالَ الْمُؤَذِّنُ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ فَقَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَقَالَ الْمُؤَذِّنُ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ فَقَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَقَالَ الْمُؤَذِّنُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ قَالَ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Ayahnya] dari [Kakeknya] bahwa [Mu'awiyah] pernah mendengar mu`adzin mengucapkan; \"ALLAHU AKBAR (Allah Maha besar), ' maka Mu'awiyah mengucapkan: \"ALLAHU AKBAR (Allah Maha Besar), ' mu`adzin mengucapkan; \"ASYHADU AN LAA ILAAHA ILLAHU (Aku bersaksi bahwa tidak ada tuhan (yang berhak disembah) kecuali Allah), ' maka Mu'awiyah mengucapkan; \"ASYHADU AN LAA ILAAHA ILLAHU (Aku bersaksi bahwa tidak ada tuhan (yang berhak disembah) kecuali Allah), ' mu`adzin mengucapkan; \"AYSHADU ANNA MUHAMMADAN RASULULLAH (Aku bersaksi bahwa Muhammad adalah utusan Allah), ' maka Mu'awiyah mengucapkan; \"ASYHADU ANNA MUHAMMAD RASULULLAH (Aku bersaksi bahwa Muhammad adalah utusan Allah), ' lalu mu`adzin mengucapkan; \"HAYYA ALA SHALAAT (Mari shalat), ' maka Mu'awiyah mengucapkan; \"LAA HAULA WA LAA QUWWATA ILLA BILLAHI (Tidak ada daya dan kekuatan kecuali dengan (kehendak) Allah), ' lalu mu`adzin mengucapkan; \"HAYYA ALAL FALAAH (Mari kita menuju pada kemenangan), ' maka Mu'awiyah mengucapkan; \"LAA HAULA WA LAA QUWWATA ILLA BILLAHI (Tidak ada daya dan kekuatan kecuali dengan (kehendak) Allah), ' lalu mu`adzin mengucapkan; \"ALLAHU AKBAR ALLAHU AKBAR LAA ILAAHA ILLAAHU (Allah Maha besar, Allah Maha Besar, tidak ada Tuhan (yang berhak disembah) kecuali Allah), ' maka Mu'awiyah mengucapkan: \"ALLAHU AKBAR ALLAHU AKBAR LAA ILAAHA ILLAHU (Allah Maha Besar, Allah Maha Besar, tidak ada tuhan (yang berhak disembah) kecuali Allah).' kemudian ia berkata: \"Demikianlah yang telah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam.\""},"825":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا نُودِيَ بِالصَّلَاةِ أَدْبَرَ الشَّيْطَانُ لَهُ ضُرَاطٌ حَتَّى لَا يَسْمَعَ الْأَذَانَ فَإِذَا قُضِيَ الْأَذَانُ أَقْبَلَ وَإِذَا ثُوِّبَ أَدْبَرَ فَإِذَا قُضِيَ التَّثْوِيبُ أَقْبَلَ حَتَّى يَخْطِرَ بَيْنَ الْمَرْءِ وَنَفْسِهِ فَيَقُولُ اذْكُرْ كَذَا وَكَذَا لِمَا لَمْ يَكُنْ يَذْكُرُ قَبْلَ ذَلِكَ قَالَ أَبُو مُحَمَّد ثُوِّبَ يَعْنِي أُقِيمَ","id":"Telah mengabarkan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila panggilan shalat dikumandangkan, maka setan akan lari terbirit-birit sambil terkentut-kentut hingga ia tidak lagi mendengar (suara) adzan tersebut, maka apabila adzan telah selesai dikumandangkan ia akan kembali, dan apabila iqamah dikumandangkan setan akan segera berpaling, jika iqamah telah selesai dikumandangkan ia akan kembali lagi (untuk mengganggu manusia) hingga ia membersitkan dalam hati seseorang dengan mengatakan 'Ingatlah hal ini dan itu' dari hal-hal yang sebelumnya tidak ia ingat.\" Abu Muhammad berkata; \"Tsuwwiba maksudnya adalah didirikan.\""},"826":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ أَبِي الشَّعْثَاءِ الْمُحَارِبِيِّ أَنَّ أَبَا هُرَيْرَةَ رَأَى رَجُلًا خَرَجَ مِنْ الْمَسْجِدِ بَعْدَ مَا أَذَّنَ الْمُؤَذِّنُ فَقَالَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Ibrahim bin Muhajir] dari [Abu Asy Sya'tsa` Al Muharibi] bahwa [Abu Hurairah] pernah melihat seorang laki-laki keluar dari masjid setelah mu`adzin mengumandangkan adzan, maka ia berkata, \"Orang ini, sungguh ia telah bermaksiat kepada Abu Qasim (Rasulullah) shallallahu 'alaihi wasallam.\""},"827":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ حِينَ زَاغَتْ الشَّمْسُ فَصَلَّى بِهِمْ صَلَاةَ الظُّهْرِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; telah mengabarkan kepadaku [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam pernah keluar ketika matahari agak condong, lalu beliau shalat zhuhur (berjama'ah) bersama mereka.\" "},"828":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اشْتَدَّ الْحَرُّ فَأَبْرِدُوا بِالصَّلَاةِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ قَالَ أَبُو مُحَمَّد هَذَا عِنْدِي عَلَى التَّأْخِيرِ إِذَا تَأَذَّوْا بِالْحَرِّ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Ibnu Syihab] dari [Sa'id bin Al Musayyib] dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila hawa panas sangat menyengat maka tunggulah hingga dingin (sejuk), sesungguhnya hawa panas yang menyengat adalah hembusan panas neraka jahannam.\" Abu Muhammad berkata; \"Inilah pendapatku, yaitu mengakhirkan shalat jika mereka terganggu dengan rasa panas.\" "},"829":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ ثُمَّ يَذْهَبُ الذَّاهِبُ إِلَى الْعَوَالِي فَيَأْتِيهَا وَالشَّمْسُ مُرْتَفِعَةٌ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat ashar, kemudian seseorang pergi ke Awali (tempat yang jaraknya sekitar delapan mil dari Madinah), ia pergi ke sana dan matahari masih agak tinggi.\""},"830":{"ar":" أَخْبَرَنَا إِسْحَقُ هُوَ ابْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَغْرِبَ سَاعَةَ تَغْرُبُ الشَّمْسُ إِذَا غَابَ حَاجِبُهَا","id":"Telah mengabarkan kepada kami [Ishaq] -yaitu Ibnu Ibrahim Al Hanzhali- telah mengabarkan kepada kami [Shafwan bin 'Isa] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] ia berkata, \"Nabi shallallahu 'alaihi wasallam mengerjakan shalat maghrib sesaat setelah matahari terbenam, setelah sebagian bagian akhir dari matahari tenggelam.\""},"831":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى عَنْ عَبَّادِ بْنِ الْعَوَّامِ عَنْ عُمَرَ بْنِ إِبْرَاهِيمَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ الْعَبَّاسِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزَالُ أُمَّتِي بِخَيْرٍ مَا لَمْ يَنْتَظِرُوا بِالْمَغْرِبِ اشْتِبَاكَ النُّجُومِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] dari ['Abbad bin Al 'Awwam] dari [Umar bin Ibrahim] dari [Qatadah] dari [Al Hasan] dari [Al Ahnaf bin Qais] dari [Al 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Umatku akan senantiasa dalam kebaikan selama mereka tidak menunggu maghrib hingga munculnya bintang-bintang.\""},"832":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ بَشِيرِ بْنِ ثَابِتٍ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَ وَاللَّهِ إِنِّي لَأَعْلَمُ النَّاسِ بِوَقْتِ هَذِهِ الصَّلَاةِ يَعْنِي صَلَاةَ الْعِشَاءِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهَا لِسُقُوطِ الْقَمَرِ لِثَالِثَةٍ قَالَ يَحْيَى أَمَلَّهُ عَلَيْنَا مِنْ كِتَابِهِ عَنْ بَشِيرِ بْنِ ثَابِتٍ","id":"Telah mengabarkan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Basyir bin Tsabit] dari [Habib bin Salim] dari [An Nu'man bin Basyir] ia berkata, \"Demi Allah, sesungguhnya aku adalah orang yang paling mengetahui tentang waktunya shalat ini, yakni shalat 'isya, Rasulullah shallallahu 'alaihi wasallam mengerjakannya pada saat jatuhnya bulan di (bagian malam) yang ke tiga.\" Yahya berkata, \"Ia mendiktekan hadits ini kepada kami, dari kitabnya, dari Basyir bin Tsabit.\""},"833":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ وَعَمْرُو بْنُ عَاصِمٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ أَخَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعِشَاءِ ذَاتَ لَيْلَةٍ حَتَّى كَادَ أَنْ يَذْهَبَ ثُلُثُ اللَّيْلِ أَوْ قَرِيبُهُ فَجَاءَ وَالنَّاسُ رُقَّدٌ وَهُمْ عِزُونَ وَهِيَ حِلَقٌ فَغَضِبَ فَقَالَ لَوْ أَنَّ رَجُلًا نَدَى النَّاسَ وَقَالَ عَمْرٌو نَدَبَ النَّاسَ إِلَى عَرْقٍ أَوْ مِرْمَاتَيْنِ لَأَجَابُوا إِلَيْهِ وَهُمْ يَتَخَلَّفُونَ عَنْ هَذِهِ الصَّلَاةِ لَهَمَمْتُ أَنْ آمُرَ رَجُلًا لِيُصَلِّيَ بِالنَّاسِ ثُمَّ أَتَخَلَّفَ عَلَى أَهْلِ هَذِهِ الدُّورِ الَّذِينَ يَتَخَلَّفُونَ عَنْ هَذِهِ الصَّلَاةِ فَأُضْرِمَهَا عَلَيْهِمْ بِالنِّيرَانِ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] dan ['Amru bin 'Ashim] keduanya berkata: telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ashim bin Bahdalah] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada suatu malam penah mengahirkan shalat 'isya hingga hampir berlalu sepertiga malam atau sekitar itu, lalu beliau datang sedang orang-orang tengah tidur dan berpencar berkelompok-kelompok, beliau lalu marah seraya bersabda: \"Kalau sekiranya seseorang memanggil orang-orang, \" 'Amru menyebutkan, \"menyeru manusia untuk menghadiri hidangan makanan daging pada tulang atau daging paha, niscaya mereka akan datang padanya, sedang mereka meninggalkan shalat ini. Sungguh, aku berkeinginan untuk memerintahkan seseorang shalat bersama orang-orang (mengimami mereka), kemudian aku menuju rumah orang-orang yang tidak ikut shalat ini (dengan berjama'ah) kemudian membakarnya.\" "},"834":{"ar":" أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ أَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعِشَاءِ حَتَّى نَادَاهُ عُمَرُ بْنُ الْخَطَّابِ قَدْ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَيْسَ أَحَدٌ مِنْ أَهْلِ الْأَرْضِ يُصَلِّي هَذِهِ الصَّلَاةَ غَيْرَكُمْ وَلَمْ يَكُنْ أَحَدٌ يُصَلِّي يَوْمَئِذٍ غَيْرَ أَهْلِ الْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mengakhirkan shalat 'isya hingga Umar bin Al Khaththab berseru, \"Para wanita dan anak-anak telah tidur! \" maka Rasulullah shallallahu 'alaihi wasallam pun keluar seraya bersabda: \"Sesungguhnya tidak ada seorangpun dari penduduk bumi selain kalian yang mengerjakan shalat ini, dan pada saat itu tidak ada seorangpun yang mengerjakannya kecuali penduduk Madinah.\" "},"835":{"ar":" حَدَّثَنَا إِسْحَقُ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنَا الْمُغِيرَةُ بْنُ حَكِيمٍ أَنَّ أُمَّ كُلْثُومٍ بِنْتَ أَبِي بَكْرٍ أَخْبَرَتْهُ عَنْ عَائِشَةَ قَالَتْ أَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ حَتَّى ذَهَبَ عَامَّةُ اللَّيْلِ وَرَقَدَ أَهْلُ الْمَسْجِدِ فَخَرَجَ فَصَلَّاهَا فَقَالَ إِنَّهَا لَوَقْتُهَا لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami [Muhammad bin bakar] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepada kami [Al Mughirah bin Hakim] bahwa [Ummu Kultsum binti Abu Bakar] mengabarkan kepadanya dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pada suatu malam pernah mengakhirkan (shalat 'isya) hingga berlalu sebagian besar waktu malam, dan orang-orang yang berada di masjid (mereka) telah tertidur. Beliau lalu keluar dan mengerjakannya (dengan berjama'ah), lalu beliau bersabda: \"Sungguh, inilah waktunya (yang tepat), kalau saja aku tidak memberatkan umatku.\" "},"836":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ ح وَابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَّرَ الصَّلَاةَ ذَاتَ لَيْلَةٍ فَقِيلَ يَا رَسُولَ اللَّهِ الصَّلَاةَ نَامَ النِّسَاءُ وَالْوِلْدَانُ فَخَرَجَ وَهُوَ يَمْسَحُ الْمَاءَ عَنْ شِقِّهِ وَهُوَ يَقُولُ هُوَ الْوَقْتُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari ['Atha] dari [Ibnu Abbas]. (dalam jalur lain disebutkan) dan [Ibnu Juraij] dari ['Atha] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam pada suatu malam pernah mengakhirkan shalat ('isya), maka dikatakan kepada beliau, \"Wahai Rasulullah, para wanita dan anak-anak telah tertidur.\" Beliau lalu keluar sambil mengusap tetesan air wudlu yang ada di sebagian anggota wudlunya, beliau bersabda: \"Inilah waktunya (yang tepat) kalau saja aku tidak memberatkan umatku.\" "},"837":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي عُرْوَةُ عَنْ عَائِشَةَ قَالَتْ كُنَّ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّينَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ ثُمَّ يَرْجِعْنَ مُتَلَفِّعَاتٍ بِمُرُوطِهِنَّ قَبْلَ أَنْ يُعْرَفْنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al 'Auza'i] telah menceritakan kepadaku [Az Zuhri] telah menceritakan kepadaku ['Urwah] dari [Aisyah] ia berkata, \"Dahulu para isteri Nabi shallallahu 'alaihi wasallam mengerjakan shalat subuh bersama Nabi shallallahu 'alaihi wasallam, kemudian mereka kembali dengan bertutupkan kain sebelum mereka dikenal.\""},"838":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْفِرُوا بِصَلَاةِ الصُّبْحِ فَإِنَّهُ أَعْظَمُ لِلْأَجْرِ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ishaq] dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ahirkanlah shalat subuh hingga cahaya subuh merekah, karena itu lebih utama.\" "},"839":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَوِّرُوا بِصَلَاةِ الْفَجْرِ فَإِنَّهُ أَعْظَمُ لِلْأَجْرِ أَخْبَرَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ ابْنِ عَجْلَانَ نَحْوَهُ أَوْ أَسْفِرُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu 'Ajlan] dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Kerjakanlah shalat subuh hingga cahaya subuh terlihat, karena sesungguhnya itu lebih besar pahala (nya).\" Telah mengabarkan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Ibnu 'Ajlan] seperti itu, atau dengan lafadz 'ashfiruu'.\" "},"840":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ صَلَاةٍ رَكْعَةً فَقَدْ أَدْرَكَهَا أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al 'Auza'i] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mendapati satu rakaat shalat, maka sungguh ia telah mendapatkannya.\" Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] telah menceritakan kepadaku [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan redaksi yang sama.\""},"841":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ وَعَنْ بُسْرِ بْنِ سَعِيدٍ وَعَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ يُحَدِّثُونَهُ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصُّبْحِ رَكْعَةً قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ مِنْ الْعَصْرِ رَكْعَةً قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَهَا","id":"Telah mengabarkan kepada kami [Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dan [Busr bin Sa'id] serta ['Abdurrahman Al A'raaj] mereka menceritakannya dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa mendapatkan satu rakaat dari shalat subuh sebelum terbitnya matahari, maka ia telah mendapatkannya (shalat subuh), dan barangsiapa mendapatkan satu rakaat dari shalat ashar sebelum matahari terbenam, maka ia telah mendapatkannya (shalat ashar).\""},"842":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ الرَّجُلَ يَعْتَادُ الْمَسَاجِدَ فَاشْهَدُوا لَهُ بِالْإِيمَانِ فَإِنَّ اللَّهَ يَقُولُ { إِنَّمَا يَعْمُرُ مَسَاجِدَ اللَّهِ مَنْ آمَنَ بِاللَّهِ }","id":"Telah mengabarkan kepada kami [Abdullah bin Az Zubair Al Humaidi] telah menceritakan kepada kami [Abdullah bin Wahb] dari ['Amru bin Al Harits] dari [Darraj Abu As Samah] dari [Abu Al Haitsam] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila kalian melihat seorang laki-laki yang terbiasa mendatangi masjid maka bersaksilah atas keimanannya, sesungguhnya Allah berfirman: '(Sesungguhnya hanyalah yang memakmurkan masjid itu adalah orang-orang yang beriman kepada Allah) ' (Qs. At Taubah: 18)."},"843":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي سَهْلٍ قَالَ ح و أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ عُثْمَانَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى الْعِشَاءَ فِي جَمَاعَةٍ كَانَ كَقِيَامِ نِصْفِ لَيْلَةٍ وَمَنْ صَلَّى الْفَجْرَ فِي جَمَاعَةٍ كَانَ كَقِيَامِ لَيْلَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abu Sahl] ia berkata: (dalam jalur lain disebutkan) Dan telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Utsman bin Hakim] dari ['Abdurrahman bin Abu 'Amrah] dari [Utsman] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengerjakan shalat 'isya dengan berjama'ah maka ia seperti beribadah setengah malam, dan barangsiapa mengerjakan shalat subuh dengan berjama'ah maka ia seperti beribadah satu malam penuh.\""},"844":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ الْوَلِيدُ بْنُ عَيْزَارٍ أَخْبَرَنِي قَالَ سَمِعْتُ أَبَا عَمْرٍو الشَّيْبَانِيَّ يَقُولُ حَدَّثَنِي صَاحِبُ هَذِهِ الدَّارِ وَأَوْمَأَ بِيَدِهِ إِلَى دَارِ عَبْدِ اللَّهِ أَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَفْضَلُ أَوْ أَحَبُّ إِلَى اللَّهِ قَالَ الصَّلَاةُ عَلَى مِيقَاتِهَا","id":"Telah mengabarkan kepada kami [Abu Al Walid At Thayalisi] telah menceritakan kepada kami [Syu'bah] ia berkata: telah mengabarkan kepadaku [Al Walid bin 'Aizar] ia berkata: Aku pernah mendengar [Abu 'Amru As Syaibani] berkata, \"Pemilik rumah ini telah menceritakan kepadaku -dan ia menunjukkan dengan tangannya ke rumah [Abdullah] -, bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, 'Amalan apakah yang paling dicintai oleh Allah? ' beliau menjawab: \"Shalat pada waktunya.\" "},"845":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ النُّعْمَانِ الْأَنْصَارِيُّ حَدَّثَنِي سَعْدُ بْنُ إِسْحَقَ بْنِ كَعْبِ بْنِ عُجْرَةَ الْأَنْصَارِيُّ عَنْ أَبِيهِ عَنْ كَعْبٍ قَالَ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي الْمَسْجِدِ سَبْعَةٌ مِنَّا ثَلَاثَةٌ مِنْ عَرَبِنَا وَأَرْبَعَةٌ مِنْ مَوَالِينَا أَوْ أَرْبَعَةٌ مِنْ عَرَبِنَا وَثَلَاثَةٌ مِنْ مَوَالِينَا قَالَ فَخَرَجَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَعْضِ حُجَرِهِ حَتَّى جَلَسَ إِلَيْنَا فَقَالَ مَا يُجْلِسُكُمْ هَاهُنَا قُلْنَا انْتِظَارُ الصَّلَاةِ قَالَ فَنَكَتَ بِإِصْبَعِهِ فِي الْأَرْضِ وَنَكَسَ سَاعَةً ثُمَّ رَفَعَ إِلَيْنَا رَأْسَهُ فَقَالَ هَلْ تَدْرُونَ مَا يَقُولُ رَبُّكُمْ قَالَ قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ إِنَّهُ يَقُولُ مَنْ صَلَّى الصَّلَاةَ لِوَقْتِهَا فَأَقَامَ حَدَّهَا كَانَ لَهُ بِهِ عَلَيَّ عَهْدٌ أُدْخِلُهُ الْجَنَّةَ وَمَنْ لَمْ يُصَلِّ الصَّلَاةَ لِوَقْتِهَا وَلَمْ يُقِمْ حَدَّهَا لَمْ يَكُنْ لَهُ عِنْدِي عَهْدٌ إِنْ شِئْتُ أَدْخَلْتُهُ النَّارَ وَإِنْ شِئْتُ أَدْخَلْتُهُ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Abdurrahman] -yaitu Ibnu An Nu'man Al Anshari-, telah menceritakan kepadaku [Sa'ad bin Ishaq bin Ka'ab bin 'Ujzah Al Anshari] dari [Ayahnya] dari [Ka'ab] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah keluar menemui kami sedang kami bertujuh tengah berada di masjid, tiga di antara kami adalah orang Arab dan yang empat adalah bekas budak-budak kami, atau empat di antara kami adalah orang Arab, dan yang tiga adalah bekas budak-budak kami.\" Ka'ab, \"Rasulullah shallallahu 'alaihi wasallam kemudian keluar dari salah satu kamarnya dan duduk di dekat kami, lalu beliau bertanya: \"Apa yang membuat kalian duduk-duduk di sini (masjid)?\" maka kami menjawab, \"Menunggu shalat.\" Ka'ab berkata, \"Beliau menggaris-garis tanah dengan jari beliau, beliau sedikit mengangguk-anggukkan kepala kemudian mengangkatnya memandang kami, beliau lantas bersabda: 'Apakah kalian mengetahui apa yang sedang dikatakan oleh Rabb kalian? ' Ka'ab berkata, \"Kami menjawab: \"Allah dan Rasul-Nya yang lebih tahu.\" Beliau bersabda: \"Sesungguhnya Allah berfirman: 'Barangsiapa menunaikan shalat tepat pada waktunya lalu menjaga batas-batasnya, maka dengan perbuatannya ini Aku telah menjanjikan untuknya untuk memasukkannya ke dalam surga. Dan barangsiapa tidak mengerjakan shalat tepat pada waktunya dan menjaga batas-batasnya maka tidak ada janji dari-Ku, jika Aku berkehendak maka Aku akan masukkan ia ke neraka, dan jika Aku kehendaki (pula) akan Aku masukkan ia ke dalam surga'.\""},"846":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ بُدَيْلٍ عَنْ أَبِي الْعَالِيَةِ الْبَرَّاءِ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ كَيْفَ أَنْتَ إِذَا بَقِيتَ فِي قَوْمٍ يُؤَخِّرُونَ الصَّلَاةَ عَنْ وَقْتِهَا قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ صَلِّ الصَّلَاةَ لِوَقْتِهَا وَاخْرُجْ فَإِنْ أُقِيمَتْ الصَّلَاةُ وَأَنْتَ فِي الْمَسْجِدِ فَصَلِّ مَعَهُمْ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Budail] dari [Abu Al 'Aliyah Al Barra`] dari [Abdullah bin Ash Shamit] dari [Abu Dzar], bahwa Nabi shallallahu 'alaihi wasallam pernah bertanya kepadanya: \"Bagaimana keadaan kamu jika kamu berada di tengah-tengah suatu kaum yang mengakhirkan shalat dari waktunya?\" ia menjawab: \"Allah dan Rasul-Nya lebih tahu.\" Beliau bersabda: \"Hendaknya kamu laksanakan shalat pada waktunya lalu hendaknya kamu keluar, jika iqamah dikumandangkan sedang kamu berada di masjid maka shalatlah bersama mereka.\""},"847":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا ذَرٍّ كَيْفَ تَصْنَعُ إِذَا أَدْرَكْتَ أُمَرَاءَ يُؤَخِّرُونَ الصَّلَاةَ عَنْ وَقْتِهَا قُلْتُ مَا تَأْمُرُنِي يَا رَسُولَ اللَّهِ قَالَ صَلِّ الصَّلَاةَ لِوَقْتِهَا وَاجْعَلْ صَلَاتَكَ مَعَهُمْ نَافِلَةً قَالَ أَبُو مُحَمَّد ابْنُ الصَّامِتِ هُوَ ابْنُ أَخِي أَبِي ذَرٍّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] telah menceritakan kepada kami [Abu 'Imran Al Jauni] dari [Abdullah bin Ash Shamit] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah bertanya: \"Wahai Abu Dzar, apa yang akan kamu lakukan apabila kamu mendapatkan para pemimpin mengakhirkan (pelaksanaan) shalat dari waktunya?\" aku berkata, \"Apa yang engkau perintahkan kepadaku wahai Rasulullah?\" beliau bersabda: \"Shalatlah pada waktunya dan jadikan shalat kamu (berjama'ah) bersama mereka sebagai nafilah (sunnah).\" Abu Muhammad berkata: \"Ibnu Ash Shamit adalah putera dari saudara Abu Dzar.\""},"848":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَسِيَ صَلَاةً أَوْ نَامَ عَنْهَا فَلْيُصَلِّهَا إِذَا ذَكَرَهَا إِنَّ اللَّهَ تَعَالَى يَقُولُ { أَقِمْ الصَّلَاةَ لِذِكْرِي }","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Sa'id] dari [Qatadah] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa lupa melakukan shalat atau tertidur dari melakukan shalat, maka hendaknya ia melakukannya apabila telah ingat. Sesungguhnya Allah Ta'ala berfirman: '(Dirikanlah shalat untuk mengingat-Ku) ' (Qs. Thaahaa: 14) "},"849":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ يَرْفَعُهُ قَالَ إِنَّ الَّذِي تَفُوتُهُ الصَّلَاةُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Salim] dari [Ayahnya] dan ia memarfu'kannya, ia berkata, \"Sesungguhnya orang yang tertinggal melakukan shalat -yaitu shalat Ashar-, maka seolah-olah ia terampas keluarga dan hartanya.\""},"850":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَاتَتْهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَوَلَدَهُ قَالَ أَبُو مُحَمَّد أَوْ مَالَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ketinggalan melakukan shalat Ashar maka seolah-olah ia terampas keluarga atau hartanya.\""},"851":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْخَنْدَقِ مَلَأَ اللَّهُ قُبُورَهُمْ وَبُيُوتَهُمْ نَارًا كَمَا حَبَسُونَا عَنْ صَلَاةِ الْوُسْطَى حَتَّى غَابَتْ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam bin Hassan] dari [Muhammad] dari ['Abidah] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda pada saat perang Khandaq: \"Semoga Allah memenuhi kuburan mereka dan rumah mereka dengan Api sebagaimana mereka menahan kami dari melakukan shalat Ashar hingga matahari tenggelam.\""},"852":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنَا أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرًا يَقُولُ أَوْ قَالَ جَابِرٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بَيْنَ الْعَبْدِ وَبَيْنَ الشِّرْكِ وَبَيْنَ الْكُفْرِ إِلَّا تَرْكُ الصَّلَاةِ قَالَ لِي أَبُو مُحَمَّد الْعَبْدُ إِذَا تَرَكَهَا مِنْ غَيْرِ عُذْرٍ وَعِلَّةٍ وَلَا بُدَّ مِنْ أَنْ يُقَالَ بِهِ كُفْرٌ وَلَمْ يَصِفْ بِالْكُفْرِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] telah menceritakan kepada kami [Abu Az Zubair], bahwa ia mendengar [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada penghalang antara seorang hamba dengan kesyirikan serta kekafiran selain meninggalkan shalat.\" Abu Muhammad berkata kepadaku, \"Seorang hamba apabila meninggalkan shalat tanpa ada udzur dan alasan, maka harus dikatakan bahwa padanya terdapat sifat kekafiran. Dan ia tidak boleh mensifatinya sebagai orang kafir.\" "},"853":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ بَيْنَمَا النَّاسُ فِي صَلَاةِ الْفَجْرِ فِي قُبَاءٍ جَاءَهُمْ رَجُلٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنْزِلَ عَلَيْهِ الْقُرْآنُ وَأُمِرَ أَنْ يَسْتَقْبِلَ الْكَعْبَةَ فَاسْتَقْبِلُوهَا وَكَانَ وُجُوهُ النَّاسِ إِلَى الشَّامِ فَاسْتَدَارُوا فَوَجَّهُوا إِلَى الْكَعْبَةِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata, \"Ketika orang-orang sedang melakukan shalat di Quba`, tiba-tiba seorang laki-laki datang kepada mereka dan berkata, 'Sesungguhnya telah diturunkan Al Qur'an kepada Rasulullah shallallahu 'alaihi wasallam, beliau diperintahkan agar menghadap ke Ka'bah, maka hendaknya kalian menghadap ke Ka'bah.' Saat itu wajah mereka menghadap ke Syam, kemudian mereka pun memutar dan menghadap ke Ka'bah.\""},"854":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ قِيلَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ الَّذِينَ مَاتُوا وَهُمْ يُصَلُّونَ إِلَى بَيْتِ الْمَقْدِسِ فَأَنْزَلَ اللَّهُ تَعَالَى { وَمَا كَانَ اللَّهُ لِيُضِيعَ إِيمَانَكُمْ }","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya, 'Wahai Rasulullah, bagaimana pendapat anda mengenai orang-orang yang mati dalam keadaan melakukan shalat menghadap ke Baitul Maqdis? ' Kemudian Allah menurunkan wahyu: '(Dan tidaklah Allah menyia-nyiakan keimanan kalian….) ' (Qs.?Al Baqarah: 143)."},"855":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ حَدَّثَنَا بُدَيْلٌ الْعُقَيْلِيُّ عَنْ أَبِي الْجَوْزَاءِ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتَتِحُ الصَّلَاةَ بِالتَّكْبِيرِ وَيَفْتَتِحُ الْقِرَاءَةَ بِالْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ وَيَخْتِمُهَا بِالتَّسْلِيمِ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Sa'id bin Abu 'Arubah] telah menceritakan kepada kami [Budail Al 'Uqali] dari [Abu Al Jauza`] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membuka shalat dengan bertakbir, membuka bacaan dengan membaca ALHAMDULILLAAHI RABBIL 'AALAMIIN, dan menutup shalat dengan membaca salam.\""},"856":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ الْحَنَفِيُّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَقُومُ إِلَى الصَّلَاةِ إِلَّا رَفَعَ يَدَيْهِ مَدًّا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Al Majid Al Hanafi] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Muhammad bin 'Amru bin 'Atha`] dari [Muhammad bin 'Abdurrahman bin Tsauban] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam tidak berdiri melakukan shalat melainkan beliau mengangkat kedua tangannya dengan tinggi.\" "},"857":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَمِّهْ الْمَاجِشُونَ عَنْ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ كَبَّرَ ثُمَّ قَالَ وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ حَنِيفًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ { إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا أَوَّلُ الْمُسْلِمِينَ } اللَّهُمَّ أَنْتَ الْمَلِكُ لَا إِلَهَ إِلَّا أَنْتَ أَنْتَ رَبِّي وَأَنَا عَبْدُكَ ظَلَمْتُ نَفْسِي وَاعْتَرَفْتُ بِذَنْبِي فَاغْفِرْ لِي ذُنُوبِي جَمِيعًا لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ وَاهْدِنِي لِأَحْسَنِ الْأَخْلَاقِ لَا يَهْدِي لِأَحْسَنِهَا إِلَّا أَنْتَ وَاصْرِفْ عَنِّي سَيِّئَهَا لَا يَصْرِفُ سَيِّئَهَا إِلَّا أَنْتَ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ كُلُّهُ فِي يَدَيْكَ وَالشَّرُّ لَيْسَ إِلَيْكَ أَنَا بِكَ وَإِلَيْكَ تَبَارَكْتَ وَتَعَالَيْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah] dari pamannya [Al Majisyun] dari [Al A'raj] dari ['Ubaidullah bin Rafi'] dari [Ali bin Abu Thalib radliallahu 'anhu] ia berkata, \" Rasulullah shallallahu 'alaihi wasallam apabila membuka shalat maka beliau bertakbir kemudian membaca: \"Wajjahtu wajhiya lilladzii fatharas samaawaati wal ardha haniifan wa maa ana minal musyrikiin, inna shalaatii wa nusukii wa mahyaaya wa mamaatii lillaahi rabbil 'aalamiin laa syariikalahu wa bidzaalika umirtu wa ana awwalul muslimiin. Allaahumma antal maliku laa ilaaha illaa anta, anta rabbii wa ana 'abduka, zhalamtu nafsii laa yahdii liahsanihaa illaa anta washrif 'annii wayyiahaa laa yashrifu sayyiahaa illaa anta. Laabbaika wa sa'daika wal khairu kulluhu fii yadaika wasy syarru laisa ilaika, ana bika wa ana ilaika, tabarakta wa ta'alait, wa astaghfirka wa atuubu ilaika.\""},"858":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ عَلِيِّ بْنِ عَلِيٍّ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ فَكَبَّرَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ أَعُوذُ بِاللَّهِ السَّمِيعِ الْعَلِيمِ مِنْ الشَّيْطَانِ الرَّجِيمِ مِنْ هَمْزِهِ وَنَفْثِهِ وَنَفْخِهِ ثُمَّ يَسْتَفْتِحُ صَلَاتَهُ قَالَ جَعْفَرٌ وَفَسَّرَهُ مَطَرٌ هَمْزُهُ الْمُوتَةُ وَنَفْثُهُ الشِّعْرُ وَنَفْخُهُ الْكِبْرُ","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Ali bin Ali] dari [Abu Al Mutawalli] dari [Abu Sa'id] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam apabila berdiri untuk melakukan shalat malam, maka beliau bertakbir dan mengucapkan: \"ALLAAHUMMA WA BIHAMDIKA WA TABAARAKAS MUKA WA TA'AALAA JADDUKA WA LAA ILAAHA GHAIRUKA. A'UUDZU BILLAAHIS SAMII'IL 'ALIIM MINASY SYAITHAANR RAJIIM MIN HAMZIHI WA NAFTSIHI WA NAFKHIHI.\" Kemudian beliau membuka shalatnya.\" Ja'far berkata, \"Mathar menjelaskan bahwa HAMZUHU adalah kematian, WA NAFTSUHU adalah sya'irnya, dan NAFKHUHU adalah kesombaongannya.\" "},"859":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ كَانُوا يَفْتَتِحُونَ الْقِرَاءَةَ بِ { الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ } قَالَ أَبُو مُحَمَّد بِهَذَا نَقُولُ وَلَا أَرَى الْجَهْرَ بِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ","id":"Telah mengabarkan kepada kami [Muslim bin Ibraihim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakr, Umar dan Utsman membuka bacaan shalat dengan ALHAMDULILLAAHI RABBIL 'AALAMIIN.\" Abu Muhammad berkata, \"Pendapat inilah yang kami ambil, dan saya tidak berpendapat untuk mengeraskan lafazh BISMILLAAHIR RAHMAANIR RAHIIM.\""},"860":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَضَعُ يَدَهُ الْيُمْنَى عَلَى الْيُسْرَى قَرِيبًا مِنْ الرُّسْغِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Abdul Jabbar bin Wail] dari [Ayahnya] ia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam meletakkan tangan kanannya di atas tangan kiri dekat dengan ruas tangan.\""},"861":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَقْرَأْ بِأُمِّ الْقُرْآنِ فَلَا صَلَاةَ لَهُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin Ash Shamit], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak membaca Al Fatihah maka tidak ada shalat baginya.\""},"862":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْكُتُ سَكْتَتَيْنِ إِذَا دَخَلَ فِي الصَّلَاةِ وَإِذَا فَرَغَ مِنْ الْقِرَاءَةِ فَأَنْكَرَ ذَلِكَ عِمْرَانُ بْنُ حُصَيْنٍ فَكَتَبُوا إِلَى أُبَيِّ بْنِ كَعْبٍ فَكَتَبَ إِلَيْهِمْ أَنْ قَدْ صَدَقَ سَمُرَةُ قَالَ أَبُو مُحَمَّد كَانَ قَتَادَةُ يَقُولُ ثَلَاثُ سَكَتَاتٍ وَفِي الْحَدِيثِ الْمَرْفُوعِ سَكْتَتَانِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Al Hasan] dari [Samrah bin Jundab], bahwa Rasulullah shallallahu 'alaihi wasallam diam dua kali, yaitu apabila telah memasuki shalat dan apabila selesai membaca surat.\" Kemudian Imran bin Hushain mengingkari hal tersebut. Maka mereka menulis surat kepada [Ubai bin Ka'b], lalu Ubai menulis balasan kepada mereka bahwa pendapat Samurah adalah benar.\" Abu Muhammad berkata, \"Qatadah menyebutkan tiga kali diam.\" Dan dalam hadits Marfu' disebutkan dua kali diam.\" "},"863":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ آدَمَ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرٍو عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْكُتُ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ إِسْكَاتَةً حَسِبْتُهُ قَالَ هُنَيَّةً فَقُلْتُ لَهُ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِسْكَاتَتَكَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ مَا تَقُولُ قَالَ أَقُولُ اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ نَقِّنِي مِنْ خَطَايَايَ كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ اللَّهُمَّ اغْسِلْنِي مِنْ خَطَايَايَ بِالثَّلْجِ وَالْمَاءِ الْبَارِدِ","id":"Telah mengabarkan kepada kami [Bisyr bin Adam] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin 'Amru] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam diam di antara takbir dan bacaan surat dengan satu kali diam -Saya mengira ia mengatakan- diam sejenak. Kemudian saya berkata kepadanya, \"Wahai Rasulullah, demi bapak dan ibuku! Bagaimana ketika engkau diam di antara takbir dan membaca surat, apa yang engkau ucapkan? Beliau bersabda: \"Saya mengucapkan: 'ALLAAHUMMA BAA'ID BAINI WA BAINA KHATHAAYAAYA KAMAA BAA'ATTA BAINAL MASYRIQI WAL MAGHRIBI, ALLAAHUMMA NAQQINII MIN GHATHAAYAAYA KAMAA YUNAQQATS TSAUBUL ABYADHU MINAD DANAS. ALLAAHUMMAGHSILNII MIN KHATHAAYAAYA BITS TSALJI WAL MAAIL BAARID.\" "},"864":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ الْقَارِئُ { غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ } فَقَالَ مَنْ خَلْفَهُ آمِينَ فَوَافَقَ ذَلِكَ أَهْلَ السَّمَاءِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang membaca; GHAIRIL MAGHDHUUBI 'ALAIHIM WA LADHDHAALLIIN, kemudian orang yang dibelakangnya mengucapkan; AAMIIN lalu bacaan tersebut bersamaan dengan penduduk langit, maka akan diampuni dosanya yang telah lalu.\""},"865":{"ar":" أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ { غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ } فَقُولُوا آمِينَ فَإِنَّ الْمَلَائِكَةَ تَقُولُ آمِينَ وَإِنَّ الْإِمَامَ يَقُولُ آمِينَ فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab], dan [Abu Salamah] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila seorang imam mengucapkan: GHAIRIL MAGHDHUUBI 'ALAIHIM WA LADHDHAALLIIN, maka ucapkanlah: AAMIIN. Sesungguhnya Malaikat mengucapkan; AAMIIN, dan imam mengucapkan; AAMIIN. Barangsiapa yang ucapan AAMIIN-nya bersamaan dengan Malaikat maka akan dimaafkan dosanya yang telah lalu..\""},"866":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ بْنُ سَعِيدٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجْرِ بْنِ الْعَنْبَسِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَرَأَ { وَلَا الضَّالِّينَ } قَالَ آمِينَ وَيَرْفَعُ بِهَا صَوْتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan bin Sa'id] dari [Salamah bin Kuhail] dari [Hujr bin Al 'Anbasi] dari [Wail bin Hujr] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam apabila membaca; WALADH DHALLIIN, maka beliau mengucapkan AAMIIN, dan beliau mengeraskan suaranya.\" "},"867":{"ar":" أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ وَعَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُمَا صَلَّيَا خَلْفَ أَبِي هُرَيْرَةَ فَلَمَّا رَكَعَ كَبَّرَ فَلَمَّا رَفَعَ رَأْسَهُ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَالَ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ سَجَدَ وَكَبَّرَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ ثُمَّ كَبَّرَ حِينَ قَامَ مِنْ الرَّكْعَتَيْنِ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَقْرَبُكُمْ شَبَهًا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَ هَذِهِ صَلَاتُهُ حَتَّى فَارَقَ الدُّنْيَا","id":"Telah mengabarkan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Abu Bakr bin 'Abdurrahman] dan dari [Abu Salamah] dari [Abu Hurairah], bahwa keduanya melakukan shalat di belakang Abu Hurairah, tatkala melakukan rukuk ia bertakbir, dan tatkala mengangkat kepala ia mengucapkan: 'SAMI'ALLAAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya). Kemudian ia mengucapkan: RABBANAA WALAKAL HAMDU (Wahai Rabb kami, kepada-Mu lah segala pujian). Kemudian ia sujud dan membaca takbir, kemudian mengangkat kepalanya dan membaca takbir, kemudian ia membaca takbir lagi saat akan berdiri dari dua rakaat. Kemudian Abu Hurairah berkata, \"Demi Dzat yang jiwaku ada di tangan-Nya, sungguh aku adalah orang yang paling mirip shalatnya dengan Rasulullah shallallahu 'alaihi wasallam, seperti inilah shalatnya hingga beliau meninggal dunia.\""},"868":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ أَخْبَرَنَا أَبُو خَيْثَمَةَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ وَعَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي كُلِّ رَفْعٍ وَوَضْعٍ وَقِيَامٍ وَقُعُودٍ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah mengabarkan kepada kami [Abu Khaitsamah] telah menceritakan kepada kami [Abu Ishaq] dari ['Abdurrahman bin Al Aswad] dari [bapaknya] dan dari ['Alqamah] dari [Abdullah] ia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam bertakbir pada setiap rukuk dan sujud, berdiri dan duduk.\" "},"869":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ الصَّلَاةَ كَبَّرَ وَرَفَعَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَإِذَا رَكَعَ كَبَّرَ وَرَفَعَ يَدَيْهِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَلَا يَرْفَعُ بَيْنَ السَّجْدَتَيْنِ أَوْ فِي السُّجُودِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Malik] dari [Az Zuhri] dari [Salim] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam apabila melakukan shalat beliau bertakbir dan mengangkat kedua tangannya sejajar dengan kedua pundaknya, apabila rukuk beliau bertakbir dan mengangkat kedua tangannya, dan apabila mengangkat kepalanya dari rukuk beliau melakukan seperti itu dan tidak mengangkatnya ketika duduk di antara dua sujud, atau ketika bersujud.\""},"870":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَبَّرَ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ أُذُنَيْهِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits], bahwa Nabi shallallahu 'alaihi wasallam apabila bertakbir, rukuk dan mengangkat kepalanya dari rukuk, maka beliau mengangkat kedua tangannya hingga sejajar dengan kedua telinganya.\""},"871":{"ar":" أَخْبَر��نَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ حَدَّثَنِي أَبُو الْبَخْتَرِيِّ عَنْ عَبْدِ الرَّحْمَنِ الْيَحْصُبِيِّ عَنْ وَائِلٍ الْحَضْرَمِيِّ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ يُكَبِّرُ إِذَا خَفَضَ وَإِذَا رَفَعَ وَيَرْفَعُ يَدَيْهِ عِنْدَ التَّكْبِيرِ وَيُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ قَالَ قُلْتُ حَتَّى يَبْدُوَ وَضَحُ وَجْهِهِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] telah menceritakan kepadaku [Abu Al Bakhtari] dari ['Abdurrahman Al Yahshubi] dari [Wail Al Hadlrami], bahwa ia pernah melakukan shalat bersama Rasulullah shallallahu 'alaihi wasallam. Beliau bertakbir apabila turun dan mengangkat kepala, mengangkat kedua tangannya ketika bertakbir, dan mengucapkan salam ke kanan dan ke kiri.\" 'Abdurrahman berkata; Saya katakan, \"Apakah hingga terlihat putih wajahnya? Ia menjawab, \"Ya.\" "},"872":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ قَوْمِي وَنَحْنُ شَبَبَةٌ فَأَقَمْنَا عِنْدَهُ عِشْرِينَ لَيْلَةً وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَفِيقًا فَلَمَّا رَأَى شَوْقَنَا إِلَى أَهْلِينَا قَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَكُونُوا فِيهِمْ فَمُرُوهُمْ وَعَلِّمُوهُمْ وَصَلُّوا كَمَا رَأَيْتُمُونِي أُصَلِّي وَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ ثُمَّ لِيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Wuhaib bin Khalid] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Malik bin Al Huwairits] ia berkata, \"Saya datang menemui Rasulullah shallallahu 'alaihi wasallam di antara beberapa orang dari kaumku, dan kami adalah para pemuda. Kami tinggal bersama beliau selama dua puluh malam. Rasulullah shallallahu 'alaihi wasallam adalah orang yang sangat lembut. Tatkala beliau melihat rasa rindu kami kepada keluarga, maka beliau bersabda: \"Kembalilah kepada keluarga kalian, dan tinggallah bersama mereka, perintahkan dan ajarilah mereka, serta lakukanlah shalat sebagaimana kalian melihatku melakukan shalat. Apabila telah datang waktu shalat, maka hendaknya salah seorang di antara kalian mengumandangkan adzan, kemudian orang tertua di antara kalian menjadi imam bagi kalian.\""},"873":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اجْتَمَعَ ثَلَاثَةٌ فَلْيَؤُمَّهُمْ أَحَدُهُمْ وَأَحَقُّهُمْ بِالْإِمَامَةِ أَقْرَؤُهُمْ","id":"Telah mengabarkan kepada kami [Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila terdapat tiga orang yang berkumpul, maka hendaknya salah seorang di antara mereka menjadi imam, dan orang paling berhak menjadi imam adalah orang yang paling baik bacaannya.\""},"874":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَ كُنْتُ عِنْدَ خَالَتِي مَيْمُونَةَ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الْعِشَاءِ فَصَلَّى أَرْبَعَ رَكَعَاتٍ ثُمَّ قَامَ فَقَالَ أَنَامَ الْغُلَيِّمُ أَوْ كَلِمَةً نَحْوَهَا فَقَامَ فَصَلَّى فَجِئْتُ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ بِيَدِي فَجَعَلَنِي عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata; saya mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] ia berkata, \"Saya pernah berada di sisi bibiku, Maimunah. Kemudian Nabi shallallahu 'alaihi wasallam datang setelah shalat Isya`, beliau lalu shalat empat rakaat, kemudian beliau berdiri seraya berkata: \"Apakah anak kecil itu sudah tidur?\" Atau ungkapan yang semisal. Kemudian beliau berdiri shalat, maka saya pun ikut berdiri dan shalat di sisi kirinya, lantas beliau memegang tanganku dan menggeserku ke sisi kanannya.\" "},"875":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْن�� عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ فَرَسًا فَصُرِعَ عَنْهُ فَجُحِشَ شِقُّهُ الْأَيْمَنُ فَصَلَّى صَلَاةً مِنْ الصَّلَوَاتِ وَهُوَ جَالِسٌ فَصَلَّيْنَا مَعَهُ جُلُوسًا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَلَا تَخْتَلِفُوا عَلَيْهِ فَإِذَا صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ وَإِنْ صَلَّى قَاعِدًا فَصَلُّوا قُعُودًا أَجْمَعُونَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam mengendarai kuda kemudian beliau terjatuh dari kuda tersebut hingga tubuh bagian kanannya sobek. Beliau lalu melakukan beberapa shalat dalam keadaan duduk, maka kamipun shalat dalam keadaan duduk bersamanya. Selesai shalat beliau mengatakan: \"Sesungguhnya dijadikannya imam agar diikuti, maka janganlah kalian menyelisihinya. Apabila ia melakukan shalat dalam keadaan berdiri maka lakukanlah shalat dalam keadaan berdiri, jika ia rukuk maka rukuklah, jika ia bangkit dari rukuk maka bangkitlah, dan jika ia shalat dalam keadaan duduk maka shalatlah kalian semua dalam keadaan duduk.\" "},"876":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا مُوسَى بْنُ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَ دَخَلْتُ عَلَى عَائِشَةَ فَقُلْتُ لَهَا أَلَا تُحَدِّثِينِي عَنْ مَرَضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ بَلَى ثَقُلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصَلَّى النَّاسُ قُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ فَقَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ قَالَتْ فَفَعَلْنَا فَاغْتَسَلَ ثُمَّ ذَهَبَ لِيَنُوءَ فَأُغْمِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَقَالَ أَصَلَّى النَّاسُ فَقُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ فَقَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ فَفَعَلْنَا ثُمَّ ذَهَبَ لِيَنُوءَ فَأُغْمِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَقَالَ أَصَلَّى النَّاسُ فَقُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ قَالَتْ وَالنَّاسُ عُكُوفٌ فِي الْمَسْجِدِ يَنْتَظِرُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصَلَاةِ الْعِشَاءِ الْآخِرَةِ قَالَتْ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ قَالَتْ فَأَتَاهُ الرَّسُولُ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ بِأَنْ تُصَلِّيَ بِالنَّاسِ فَقَالَ أَبُو بَكْرٍ وَكَانَ رَجُلًا رَقِيقًا يَا عُمَرُ صَلِّ بِالنَّاسِ فَقَالَ لَهُ عُمَرُ أَنْتَ أَحَقُّ بِذَلِكَ قَالَتْ فَصَلَّى بِهِمْ أَبُو بَكْرٍ تِلْكَ الْأَيَّامَ قَالَتْ ثُمَّ إِنَّ رَسُولَ اللَّهِ وَجَدَ مِنْ نَفْسِهِ خِفَّةً فَخَرَجَ بَيْنَ رَجُلَيْنِ أَحَدُهُمَا الْعَبَّاسُ لِصَلَاةِ الظُّهْرِ وَأَبُو بَكْرٍ يُصَلِّي بِالنَّاسِ فَلَمَّا رَآهُ أَبُو بَكْرٍ ذَهَبَ لِيَتَأَخَّرَ فَأَوْمَأَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَتَأَخَّرَ وَقَالَ لَهُمَا أَجْلِسَانِي إِلَى جَنْبِهِ فَأَجْلَسَاهُ إِلَى جَنْبِ أَبِي بَكْرٍ قَالَتْ فَجَعَلَ أَبُو بَكْرٍ يُصَلِّي وَهُوَ قَائِمٌ بِصَلَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ أَبِي بَكْرٍ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ قَالَ عُبَيْدُ اللَّهِ فَدَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ فَقُلْتُ لَهُ أَلَا أَعْرِضُ عَلَيْكَ مَا حَدَّثَتْنِي عَائِشَةُ عَنْ مَرَضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَاتِ فَعَرَضْتُ حَدِيثَهَا عَلَيْهِ فَمَا أَنْكَرَ مِنْهُ شَيْئًا غَيْرَ أَنَّهُ قَالَ أَسَمَّتْ لَكَ الرَّجُلَ الَّذِي كَانَ مَعَ الْعَبَّاسِ قُلْتُ لَا فَقَالَ هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zaidah] telah menceritakan kepada kami [Musa bin Abu Aisyah] dari ['Ubaidullah bin Abdullah] ia berkata; saya menemui [Aisyah] dan mengatakan kepadanya, \"Maukah engkau ceritakan kepadaku mengenai sakitnya Rasulullah shallallahu 'alaihi wasallam? Aisyah lalu menjawab, \"Ya. Rasulullah shallallahu 'alaihi wasallam merasakan kondisi yang sangat berat, kemudian beliau bersabda: \"Apakah orang-orang sudah melaksanakan shalat? Lalu kami katakan, \"Belum, mereka menunggumu wahai Rasulullah! Beliau lalu bersabda: \"Ambilkan untukku air dalam bejana! \" Aisyah berkata, \"Lalu kami pun melakukannya. Beliau kemudian mandi, namun ketika hendak berdiri beliau pingsan, kemudian sadar lagi dan berkata: \"Apakah orang-orang telah melaksanakan shalat?\" Lalu kami katakan, 'Belum, mereka menunggumu wahai Rasulullah! ' Beliau bersabda: \"Ambilkan untukku air dalam bejana! \" Lalu kami pun melakukannya. Kemudian beliau berdiri dan pingsan lagi, saat tersadar beliau bertanya: \"Apakah orang-orang telah melaksanakan shalat? ' Lalu kami katakan, \"Belum, mereka menunggumu wahai Rasulullah! Aisyah berkata, \"Orang-orang sedang berada di masjid menunggu Rasulullah shallallahu 'alaihi wasallam untuk melaksanakan shalat Isya`.\" Aisyah melanjutkan, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mengutus seseorang menemui Abu Bakr agar ia melaksanakan shalat bersama orang-orang. Kemudian utusan tersebut mendatanginya dan berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkanmu untuk memimpin orang-orang melaksanakan shalat. Kemudian Abu Bakr yang berperasaan lembut berkata, \"Wahai Umar, shalatlah bersama orang-orang! ' Lalu Umar berkata kepadanya, 'Engkau lebih berhak terhadap hal tersebut.' Aisyah berkata, \"Abu Bakr lalu memimpin orang-orang melaksanakan shalat dalam beberapa hari. Kemudian Rasulullah shallallahu 'alaihi wasallam mendapatkan rasa ringan pada dirinya, lalu beliau keluar dengan dipapah oleh dua orang laki-laki, salah satunya adalah Al Abbas, untuk melakukan shalat zhuhur, sementara Abu Bakr sedang memimpin orang-orang melakukan shalat. Ketika Abu Bakr melihat beliau maka ia berkeinginan mundur, tetapi Nabi shallallahu 'alaihi wasallam memberikan isyarat kepadanya agar ia tidak mundur. Kemudian beliau berkata kepada dua orang yang memapahnya: \"Dudukkan aku di sampingnya.\" Lalu mereka mendudukkannya di samping Abu Bakr.\" Aisyah melanjutkan ceritanya, \"Lalu Abu Bakr melakukan shalat dalam keadaan berdiri mengikuti shalat Nabi shallallahu 'alaihi wasallam, sementara orang-orang melakukan shalat mengikuti shalat Abu Bakr, dan saat itu Nabi shallallahu 'alaihi wasallam melakukan shalat dalam keadaan duduk.\" 'Ubaidullah berkata, \"Kemudian saya menemui [Abdullah bin Abbas] dan mengatakan kepadanya, 'Maukah aku sampaikan kepadamu apa yang telah diceritakan Aisyah kepadaku mengenai sakitnya Rasulullah shallallahu 'alaihi wasallam? Lalu ia menjawab, \"katakan! \" Kemudian saya sampaikan cerita Aisyah itu kepadanya, dan ia tidak mengingkari sedikitpun dari cerita tersebut, hanya saja ia berkata, 'Apakah ia menyebutkan kepadamu orang yang bersama Al Abbas? Maka saya katakan, \"Tidak.\" Ia lalu berkata, \"Laki-laki itu adalah Ali bin Abu Thalib.\" "},"877":{"ar":" أَخْبَرَنَا أَبُو مَعْمَرٍ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَسَ عَلَى الْمِنْبَرِ فَكَبَّرَ فَكَبَّرَ النَّاسُ خَلْفَهُ ثُمَّ رَكَعَ وَهُوَ عَلَى الْمِنْبَرِ ثُمَّ رَفَعَ رَأْسَهُ فَنَزَلَ الْقَهْقَرَى فَسَجَدَ فِي أَصْلِ الْمِنْبَرِ ثُمَّ عَادَ حَتَّى فَرَغَ مِنْ آخِرِ صَلَاتِهِ قَالَ أَبُو مُحَمَّد فِي ذَلِكَ رُخْصَةٌ لِلْإِمَامِ أَنْ يَكُونَ أَرْفَعَ مِنْ أَصْحَابِهِ وَقَدْرُ هَذَا الْعَمَلِ فِي الصَّلَاةِ أَيْضًا","id":"Telah mengabarkan kepada kami [Abu Ja'far Isma'il bin Ibrahim] dari [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Sahl bin Sa'd] ia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam duduk di atas mimbar, kemudian beliau bertakbir dan orang-orang bertakbir di belakangnya. Beliau kemudian rukuk di atas mimbar, kemudian mengangkat kepala lalu turun dan mundur ke belakang, lalu beliau sujud di lantai sebelah mimbir tingkat yang paling bawah. Setelah itu beliau kembali lagi ke mimbar, hingga selesai dari shalatnya.\" Abu Muhammad berkata, \"Hadits itu menunjukkan adanya keringanan bagi seorang imam untuk berada lebih tinggi daripada orang lain, dan ini juga berlaku dalam shalat.\" "},"878":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنِّي لَأَتَأَخَّرُ عَنْ صَلَاةِ الْغَدَاةِ مِمَّا يُطِيلُ بِنَا فِيهَا فُلَانٌ فَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ غَضَبًا فِي مَوْعِظَةٍ مِنْهُ يَوْمَئِذٍ فَقَالَ أَيُّهَا النَّاسُ إِنَّ مِنْكُمْ مُنَفِّرِينَ فَمَنْ صَلَّى بِالنَّاسِ فَلْيَتَجَوَّزْ فَإِنَّ فِيهِمْ الْكَبِيرَ وَالضَّعِيفَ وَذَا الْحَاجَةِ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Isma'il bin Abu Khalid] dari [Qais] dari [Abu Mas'ud Al Anshari] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya saya tidak jadi ikut melaksanakan shalat subuh karena lamanya shalat yang dilakukan oleh Fulan bersama kami.\" Maka saya tidak pernah melihat Nabi shallallahu 'alaihi wasallam marah melebihi kemarahannya pada saat itu ketika sedang memberikan nasihat. Beliau bersabda: \"Wahai manusia, sesungguhnya di antara kalian ada orang-orang yang membuat lari orang lain, maka barangsiapa shalat bersama manusia (sebagai Imam), maka hendaknya ia meringankannya. Sebab di antara mereka ada orang yang telah tua, orang lemah, dan orang yang memiliki keperluan.\" "},"879":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يَقُولُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَفَّ النَّاسِ صَلَاةً فِي تَمَامٍ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ia berkata; saya mendengar [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam adalah orang yang paling ringan dan sempurna dalam melakukan shalat.\" "},"880":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ قَالَ كَتَبَ إِلَيَّ يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نُودِيَ لِلصَّلَاةِ فَلَا تَقُومُوا حَتَّى تَرَوْنِي","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] ia berkata, [Yahya bin Abu Katsir] telah menulis surat kepadaku dari [Abdullah bin Abu Qatadah] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila telah dikumandangkan seruan untuk melakukan shalat maka janganlah kalian berdiri hingga kalian melihatku.\""},"881":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَقُومُوا حَتَّى تَرَوْنِي","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Hammam] telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepada kami [Abdullah bin Abu Qatadah] bahwa [Ayahnya] telah menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila dikumandangkan iqamah maka janganlah kalian berdiri hingga melihatku.\" "},"882":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ وَسَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَوُّوا صُفُوفَكُمْ فَإِنَّ تَسْوِيَةَ الصَّفِّ مِنْ تَمَامِ الصَّلَاةِ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] dan [Sa'id bin 'Amir] dari [Syu'bah] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luruskan barisan kalian, sesungguhnya lurusnya barisan termasuk dari kesempurnaan shalat.\""},"883":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي طَلْحَةُ بْنُ مُصَرِّفٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَوْسَجَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ سَوُّوا صُفُوفَكُمْ لَا تَخْتَلِفُ قُلُوبُكُمْ قَالَ وَكَانَ يَقُولُ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الصَّفِّ الْأَوَّلِ أَوْ الصُّفُوفِ الْأُوَلِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Thalhah bin Musharrif] ia berkata, saya mendengar ['Abdurrahman bin 'Ausajah] dari [Al Barra` bin 'Azib], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luruskan barisan kalian, janganlah hati kalian berselisih.\" Al Barra` berkata, \"Beliau pernah bersabda: \"Sesungguhnya Allah dan Malaikat-Nya mengucapkan shalawat kepada shaf yang pertama.\""},"884":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ عِرْبَاضِ بْنِ سَارِيَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَغْفِرُ لِلصَّفِّ الْأَوَّلِ ثَلَاثًا وَلِلصَّفِّ الثَّانِي مَرَّةً أَخْبَرَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى الْأَشْيَبُ عَنْ شَيْبَانَ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ عِرْبَاضِ بْنِ سَارِيَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Muhammad bin Ibrahim] dari [Khalid bin Ma'dan] dari ['Irbadh bin Sariyah], bahwa Rasulullah shallallahu 'alaihi wasallam memintakan ampunan untuk shaf yang pertama sebanyak tiga kali, dan untuk shaf yang kedua sebanyak satu kali.\" Telah mengabarkan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Al Hasan bin Musa Al Asyyab] dari [Syaiban] dari [Yahya] dari [Muhammad bin Ibrahim] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari ['Irbadh bin Sariyah] dari Nabi shallallahu 'alaihi wasallam sama seperti itu.\""},"885":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ مَنَاكِبَنَا فِي الصَّلَاةِ وَيَقُولُ لَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ لِيَلِيَنِّي مِنْكُمْ أُولُو الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ قَالَ أَبُو مَسْعُودٍ فَأَنْتُمْ الْيَوْمَ أَشَدُّ اخْتِلَافًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dari [Abu Mas'ud Al Anshari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mengusap pundak kami ketika hendak melakukan shalat, lalu bersabda: \"Janganlah kalian berselisih sehingga hati kalian pun berselisih. Hendaknya yang menempati posisi setelahku di antara kalian adalah orang-orang yang sabar dan berakal, kemudian orang yang setelahnya, kemudian orang yang setelahnya.\" Abu Mas'ud berkata, \"Hari ini perselisihan kalian lebih nampak.\" "},"886":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَلِيَنِّي مِنْكُمْ أُولُو الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ وَلَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ وَإِيَّاكُمْ وَهَوْشَاتِ الْأَسْوَاقِ","id":"Telah mengabarkan kepada kami [Zakaria bin 'Adi] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid] dari [Abu Ma'syar] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya yang menempati posisi setelahku di antara kalian adalah orang-orang yang sabar dan berakal, kemudian orang yang setelahnya, kemudian orang yang setelahnya. Janganlah kalian berselisih sehingga hati kalian pun berselisih, dan jauhilah perselisihan dan kekacauan di pasar.\""},"887":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ صُفُوفِ الرِّجَالِ أَوَّلُهَا وَشَرُّهَا آخِرُهَا وَخَيْرُ صُفُوفِ النِّسَاءِ آخِرُهَا وَشَرُّهَا أَوَّلُهَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari ['Ajlan] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik shaf laki-laki adalah yang paling pertama dan yang paling buruk adalah yang paling terakhir. Dan sebaik-baik shaf wanita adalah yang paling terakhir dan yang paling buruk adalah yang paling pertama.\""},"888":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ أَشَاهِدٌ فُلَانٌ قَالُوا لَا فَقَالَ أَشَاهِدٌ فُلَانٌ فَقَالُوا لَا لِنَفَرٍ مِنْ الْمُنَافِقِينَ لَمْ يَشْهَدُوا الصَّلَاةَ فَقَالَ إِنَّ هَاتَيْنِ الصَّلَاتَيْنِ أَثْقَلُ الصَّلَاةِ عَلَى الْمُنَافِقِينَ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا قَالَ أَبُو مُحَمَّد عَبْدُ اللَّهِ بْنُ أَبِي بَصِيرٍ قَالَ حَدَّثَنِي أَبِي عَنْ أُبَيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعْتُهُ مِنْ أُبَيٍّ أَخْبَرَنَا أَبُو غَسَّانَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ خَالِدِ بْنِ مَيْمُونٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ubai bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat subuh, kemudian menghadap kepada kami dengan wajahnya seraya mengatakan: \"Apakah Fulan hadir?\" Mereka mengatakan, \"Tidak.\" Lalu beliau bersabda lagi: \"Apakah Fulan hadir?\" Mereka menjawab, \"Tidak.\" Yaitu beberapa orang-orang Munafik yang tidak ikut menghadiri shalat. Kemudian beliau bersabda: \"Sesungguhnya dua shalat ini (yaitu Subuh dan Isya`) paling berat bagi orang-orang munafik, seandainya mereka mengetahui apa yang ada pada keduanya niscaya mereka mendatanginya walaupun dengan merangkak.\" Abu Muhammad [Abdullah bin Bashir] berkata; telah menceritakan kepadaku [Ayahku] dari [Ubai] dari Nabi shallallahu 'alaihi wasallam, dan saya mendengarnya dari Ubai.\" Telah mengabarkan kepada kami [Abu Ghassan] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ayahnya] dari [Ubai bin Ka'b] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" Telah mengabarkan kami [Sa'id bin 'Amir] dari [Sa'id Abu 'Arubah] dari [Khalid bin Maimun] dari [Abu Ishaq] dari [Abdullah bin Abu Bashir] dari [Ayah] dari [Ubai bin Ka'b] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"889":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ مِنْ صَلَاةٍ أَثْقَلُ عَلَى الْمُنَافِقِينَ مِنْ صَلَاةِ الْعِشَاءِ الْآخِرَةِ وَصَلَاةِ الْفَجْرِ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah mengabarkan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya tidak ada shalat yang lebih berat bagi orang-orang munafik dari pada shalat Isya` dan shalat Subuh. Seandainya mereka mengetahui apa yang ada pada keduanya, niscaya mereka akan mendatanginya walaupun dengan merangkak.\""},"890":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ هَمَمْتُ أَنْ آمُرَ فِتْيَانِي فَيَجْمَعُوا حَطَبًا فَآمُرَ رَجُلًا يُصَلِّي بِالنَّاسِ ثُمَّ أُخَالِفَ إِلَى أَقْوَامٍ يَتَخَلَّفُونَ عَنْ هَذِهِ الصَّلَاةِ فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ لَوْ كَانَ عَرْقًا سَمِينًا أَوْ مُعَرَّقَتَيْنِ لَشَهِدُوهَا وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu 'Ajlan] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah berkeinginan memerintahkan beberapa pemuda untuk mengumpulkan kayu bakar, kemudian aku perintahkan seseorang agar memimpin orang-orang melaksanakan shalat. Kemudian aku menemui orang-orang yang tidak menghadiri shalat ini, lalu membakar rumah mereka. Seandainya salah seorang dari mereka mengetahui bahwa ia akan mendapatkan satu atau dua tulang yang berdaging banyak, niscaya mereka akan menghadirinya. Sungguh, seandainya mereka mengetahui apa yang ada pada keduanya (shalat isya dan subuh), niscaya mereka akan mendatanginya walaupun dengan merangkak.\""},"891":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ نَزَلَ بِضَجْنَانَ فِي لَيْلَةٍ بَارِدَةٍ فَأَمَرَ مُنَادِيًا فَنَادَى الصَّلَاةُ فِي الرِّحَالِ ثُمَّ أَخْبَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَانَ فِي سَفَرٍ فِي لَيْلَةٍ بَارِدَةٍ أَوْ الْمَطَرِ أَمَرَ مُنَادِيًا فَنَادَى الصَّلَاةُ فِي الرِّحَالِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar], bahwa ia pernah singgah di Dlajnan pada malam yang dingin, kemudian beliau memerintahkan seseorang agar mengumandangkan adzan seraya menyerukan, 'Shalat di rumah! ' Kemudian ia mengabarkan bahwa Nabi shallallahu 'alaihi wasallam apabila sedang dalam perjalanan pada malam yang dingin, atau ketika turun hujan, maka beliau memerintahkan seseorang agar mengumandangkan adzan seraya menyerukan, 'Shalat di rumah! \""},"892":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ قَالَ قُلْتُ لِسَعِيدِ بْنِ الْمُسَيَّبِ رَجُلٌ صَلَّى فِي بَيْتِهِ ثُمَّ أَدْرَكَ الْإِمَامَ وَهُوَ يُصَلِّي أَيُصَلِّي مَعَهُ قَالَ نَعَمْ قُلْتُ بِأَيَّتِهِمَا يَحْتَسِبُ قَالَ بِالَّتِي صَلَّى مَعَ الْإِمَامِ فَإِنَّ أَبَا هُرَيْرَةَ حَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الرَّجُلِ فِي الْجَمِيعِ تَزِيدُ عَلَى صَلَاتِهِ وَحْدَهُ بِضْعًا وَعِشْرِينَ جُزْءًا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Daud bin Abu Hindun] ia berkata, saya bertanya kepada [Sa'id bin Al Musayyab], \"Ada seorang laki-laki telah melakukan shalat di rumahnya, kemudian ia menjumpai imam sedang melakukan shalat, apakah ia melakukan shalat bersamanya? Ia menjawab, \"Ya.\" Saya bertanya lagi, \"Shalat manakah yang ia hitung? Ia menjawab, \"Shalat yang ia lakukan bersama imam, karena sesungguhnya [Abu Hurairah] telah menceritakan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatnya seorang laki-laki dalam berjama'ah lebih utama dengan shalat yang ia kerjakan sendirian dengan dua puluh sekian derajat.\" "},"893":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الرَّجُلِ فِي جَمَاعَةٍ تَزِيدُ عَلَى صَلَاتِهِ وَحْدَهُ سَبْعًا وَعِشْرِينَ دَرَجَةً","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Abdullah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalatnya seorang laki-laki dalam jama'ah melebihi shalatnya yang dilakukan sendirian sebanyak dua puluh tujuh derajat.\""},"894":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَأْذَنَتْ أَحَدَكُمْ زَوْجَتُهُ إِلَى الْمَسْجِدِ فَلَا يَمْنَعْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila isteri salah seorang dari kalian meminta izin untuk pergi ke masjid, maka janganlah ia melarangnya.\""},"895":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَمْنَعُوا إِمَاءَ اللَّهِ مَسَاجِدَ اللَّهِ وَلْيَخْرُجْنَ إِذَا خَرَجْنَ تَفِلَاتٍ أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو بِإِسْنَادِ هَذَا الْحَدِيثِ قَالَ قَالَ سَعِيدُ بْنُ عَامِرٍ التَّفِلَةُ الَّتِي لَا طِيبَ لَهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melarang para wanita untuk menuju ke masjid, hendaklah mereka keluar jika tidak memakai minyak wangi.\" Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Muhammad bin 'Amru] dengan sanad hadits ini. Ia berkata, [Sa'id bin 'Amir] berkata, \"At tafilah adalah wanita yang tidak memakai minyak wangi.\" "},"896":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَ الْعَشَاءُ وَحَضَرَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [Ayahnya] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila makan malam telah dihidangkan lalu hadir waktu shalat, maka dahulukan makan malam.\""},"897":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ وَسُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَضَرَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dan [Sulaiman bin Katsir] dari [Az Zuhri] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila makan malam telah sedia, lalu shalat dikumandangkan maka mulailah dengan makan malam.\" "},"898":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَيْتُمْ الصَّلَاةَ فَلَا تَأْتُوهَا تَسْعَوْنَ وَأْتُوهَا تَمْشُونَ وَعَلَيْكُمْ السَّكِينَةُ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَأَتِمُّوا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kalian datang untuk melakukan shalat maka janganlah kalian mendatanginya dengan berlari, datangilah shalat dengan berjalan kaki, dan hendaknya kalian bersikap tenang. Laksanakanlah shalat yang kalian dapatkan dan sempurnakanlah shalat yang kalian tertinggal.\" "},"899":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَيْتُمْ الصَّلَاةَ فَعَلَيْكُمْ بِالسَّكِينَةِ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا سُبِقْتُمْ فَأَتِمُّوا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendatangi shalat maka datangilah dengan tenang, laksanakanlah shalat yang kalian dapatkan dan sempurnakanlah apa yang kalian tertinggal.\" "},"900":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ كَانَ رَجُلٌ بِالْمَدِينَةِ لَا أَعْلَمُ بِالْمَدِينَةِ مَنْ يُصَلِّي إِلَى الْقِبْلَةِ أَبْعَدَ مَنْزِلًا مِنْ الْمَسْجِدِ مِنْهُ وَكَانَ يَشْهَدُ الصَّلَوَاتِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ لَوْ ابْتَعْتَ حِمَارًا تَرْكَبُهُ فِي الرَّمْضَاءِ وَالظَّلْمَاءِ قَالَ وَاللَّهِ مَا يَسُرُّنِي أَنَّ مَنْزِلِي بِلِزْقِ الْمَسْجِدِ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ يَا رَسُولَ اللَّهِ كَيْمَا يُكْتَبَ أَثَرِي وَخُطَايَ وَرُجُوعِي إِلَى أَهْلِي وَإِقْبَالِي وَإِدْبَارِي أَوْ كَمَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْطَاكَ اللَّهُ ذَلِكَ كُلَّهُ وَأَعْطَاكَ مَا احْتَسَبْتَ أَجْمَعَ أَوْ كَمَا قَالَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [At Taimi] dari [Abu Utsman] dari [Ubai bin Ka'b] ia berkata, \"Di Madinah ada seorang laki-laki, dan aku tidak mengetahui di kota Madinah ada orang yang shalat menghadap kiblat, rumahnya paling jauh dari masjid kecuali dia. Ia selalu menghadiri shalat bersama Rasulullah shallallahu 'alaihi wasallam. Kemudian ada yang mengatakan kepadanya, \"Sekiranya engkau membeli seekor keledai hingga engkau bisa menungganginya melewati gurun dan gelapnya malam, maka itu akan lebih baik.\" Laki-laki itu lalu berkata, \"Demi Allah, bukan berarti aku senang jika rumahku dekat dengan masjid.\" Maka dikabarkanlah hal itu kepada Nabi shallallahu 'alaihi wasallam, sehingga beliau bertanya kepada orang itu mengenai hal tersebut. Laki-laki itu lalu berkata, \"Wahai Rasulullah, agar setiap jejak langkahku saat pergi dan kembali kepada keluargaku ditulis sebagai pahala.\" Atau sebagaimana yang ia katakan. Lalu Rasulullah shallallahu 'alaihi wasallam pun bersabda: 'Semoga Allah memberimu semua itu dan memberikan kepadamu seluruh pahala yang engkau harapkan.' Atau sebagaimana yang beliau katakan.\" "},"901":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو زُبَيْدٍ هُوَ عَبْثَرُ بْنُ الْقَاسِمِ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يَسَافٍ قَالَ أَخَذَ بِيَدِي زِيَادُ بْنُ أَبِي الْجَعْدِ فَأَقَامَنِي عَلَى شَيْخٍ مِنْ بَنِي أَسَدٍ يُقَالُ لَهُ وَابِصَةُ بْنُ مَعْبَدٍ فَقَالَ حَدَّثَنِي هَذَا وَالرَّجُلُ يَسْمَعُ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ صَلَّى خَلْفَهُ رَجُلٌ وَلَمْ يَتَّصِلْ بِالصُّفُوفِ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ الصَّلَاةَ قَالَ أَبُو مُحَمَّد كَانَ أَحْمَدُ بْنُ حَنْبَلٍ يُثْبِتُ حَدِيثَ عَمْرِو بْنِ مُرَّةَ وَأَنَا أَذْهَبُ إِلَى حَدِيثِ يَزِيدَ بْنِ زِيَادِ بْنِ أَبِي الْجَعْدِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Zubaid] -yaitu 'Abtsar bin Al Qasim- dari [Hushain] dari [Hilal bin Yasaf] ia berkata; [Ziyad bin Abu Al Ja'd] menggandeng tanganku dan membawaku kepada orang yang telah tua dari Bani Asad yang dipanggil dengan nama [Wabishah bin Ma'bad], Kemudian ia berkata, \"Orang ini (Wabishah) telah menceritakan kepadaku -dan orang tersebut mendengar- bahwa ia melihat Rasulullah shallallahu 'alaihi wasallam yang dibelakangnya ada seorang laki-laki melaksanakan shalat dan tidak masuk ke dalam barisan (shalat sendirian). Lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan agar dia mengulangi shalat.\" Abu Muhammad berkata, \"Ahmad bin Hanbal menetapkan hadits 'Amru bin Murrah, sedangkan saya berpendapat dengan hadits Yazid bin Ziyad bin Abu Al Ja'd.\" "},"902":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ حَدَّثَنَا يَزِيدُ بْنُ زِيَادٍ عَنْ عُبَيْدِ بْنِ أَبِي الْجَعْدِ عَنْ زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ وَابِصَةَ بْنِ مَعْبَدٍ أَنَّ رَجُلًا صَلَّى خَلْفَ الصُّفُوفِ وَحْدَهُ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ قَالَ أَبُو مُحَمَّد أَقُولُ بِهَذَا","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Daud] telah menceritakan kepada kami [Yazid bin Ziyad] dari ['Ubaid bin Abu Al Ja'd] dari [Ziyad bin Abu Al Ja'd] dari [Wabishah bin Ma'bad], bahwa ada seorang laki-laki shalat di belakang shaf sendirian, lalu Nabi shallallahu 'alaihi wasallam memerintahkan dia agar mengulangi shalatnya.\" Abu Muhammad berkata, \"Saya berpendapat dengan hal ini.\" "},"903":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَتْهُ فَأَكَلَ ثُمَّ قَالَ قُومُوا فَلِأُصَلِّيَ بِكُمْ قَالَ أَنَسٌ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لُبِسَ فَنَضَحْتُهُ بِمَاءٍ فَقَامَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْتُ أَنَا وَالْيَتِيمُ وَرَاءَهُ وَالْعَجُوزُ وَرَاءَنَا فَصَلَّى لَنَا رَكْعَتَيْنِ ثُمَّ انْصَرَفَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], bahwa neneknya, Mulaikah, mengundang Rasulullah shallallahu 'alaihi wasallam untuk menyantap makanan yang telah ia buat. Beliau kemudian memakannya dan bersabda: \"Berdirilah sehingga aku melakukan shalat bersama kalian.\" Anas berkata, \"Lalu saya berdiri menuju tikar kami yang telah menghitam karena telah lama dipakai, kemudian saya memercikinya dengan air. Rasulullah shallallahu 'alaihi wasallam lantas berdiri, lalu saya dan seorang anak yatim membuat shaf di belakang beliau, sedangkan wanita tua di belakang kami. Lalu beliau melakukan shalat bersama kami dua rakaat kemudian pergi.\" "},"904":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ الْوَلِيدِ أَبِي بِشْرٍ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُومُ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ الظُّهْرِ قَدْرَ ثَلَاثِينَ آيَةً وَفِي الْأُخْرَيَيْنِ عَلَى قَدْرِ النِّصْفِ مِنْ ذَلِكَ وَفِي الْعَصْرِ عَلَى قَدْرِ الْأُخْرَيَيْنِ مِنْ الظُّهْرِ وَفِي الْأُخْرَيَيْنِ عَلَى قَدْرِ النِّصْفِ مِنْ ذَلِكَ أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا هُشَيْمٌ عَنْ مَنْصُورٍ عَنْ الْوَلِيدِ أَبِي بِشْرٍ عَنْ أَبِي الصِّدِّيقِ عَنْ أَبِي سَعِيدٍ بِنَحْوِهِ وَزَادَ قَدْرَ قِرَاءَةِ الم تَنْزِيلُ السَّجْدَةِ","id":"Telah mengabarkan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Uwanah] dari [Manshur bin Zadan] dari [Al Walid Abu Bisyr] dari [Abu Ash Shiddiq An Naji] dari [Abu Sa'id], bahwa Nabi shallallahu 'alaihi wasallam berdiri pada dua rakaat pertama shalat zhuhur kira-kira sekadar bacaan tiga puluh ayat, dan pada dua dua rakaat yang lainnya kira-kira setengah dari yang pertama. Sedangkan pada shalat asar seukuran dua rakaat terakhir dari shalat zhuhur, dan pada dua rakaat yang terakhir setengah dari itu.\" Telah mengabarkan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Husyaim] dari [Manshur] dari [Al Walid Abu Bisyr] dari [Abu Ash Shiddiq] dari [Abu Sa'id] sama seperti itu. Hanya ia menambahkan, \"Seukuran bacaan surat As Sajdah.\""},"905":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ بِالسَّمَاءِ وَالطَّارِقِ وَالسَّمَاءِ ذَاتِ الْبُرُوجِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Jabir bin Samurah], bahwa Nabi shallallahu 'alaihi wasallam pada shalat zhuhur dan asar membaca surat Ath Thariq dan surat Al Buruj.\""},"906":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ بِأُمِّ الْقُرْآنِ وَبِسُورَتَيْنِ مَعَهَا فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ وَصَلَاةِ الْعَصْرِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطَوِّلُ فِي الرَّكْعَةِ الْأُولَى أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بِإِسْنَادِهِ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam membaca Al Fatihah dan dua surat pada dua rakaat pertama shalat zhuhur dan asar. Terkadang beliau memperdengarkan bacaan ayat kepada kami, dan beliau memanjangkan bacaan pada rakaat pertama.\" Telah mengabarkan kepada kami [Abu 'Ashim] dari [Al Auza'i] dari [Yahya] dengan sanadnya sama seperti hadits itu.\" "},"907":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هَمَّامٌ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ بِأُمِّ الْكِتَابِ وَبِسُورَتَيْنِ وَفِي الْأُخْرَيَيْنِ بِأُمِّ الْكِتَابِ وَكَانَ يُسْمِعُنَا الْآيَةَ وَكَانَ يُطِيلُ فِي الرَّكْعَةِ الْأُولَى مَا لَا يُطِيلُ فِي الثَّانِيَةِ وَهَكَذَا فِي صَلَاةِ الْعَصْرِ وَهَكَذَا فِي صَلَاةِ الْغَدَاةِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammam] telah menceritakan kepada kami [Yahya bin Abu Katsir] telah menceritakan kepada kami [Abdullah bin Abu Qatadah] bahwa [Ayahnya] telah menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pada dua rakaat pertama shalat zhuhur membaca surat Al Fatihah dan dua surat yang lain, sedangkan pada dua rakaat yang terakhir membaca surat Al Fatihah saja. Terkadang beliau memperdengarkan bacaan ayat kepada kami, beliau juga memanjangkan bacaan pada rakaat pertama yang tidak beliau panjangkan pada rakaat yang kedua. Seperti inilah beliau melakukannya pada shalat asar dan shalat subuh.\" "},"908":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ أُمِّ الْفَضْلِ أَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالْمُرْسَلَاتِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] dari [Ummu Al Fadll], bahwa ia mendengar Nabi shallallahu 'alaihi wasallam membaca surat Al Mursalat saat melaksanakan shalat Maghrib.\" "},"909":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالطُّورِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Ayahnya], bahwa ia mendengar Nabi shallallahu 'alaihi wasallam membaca surat Ath Thuur dalam shalat Maghrib.\""},"910":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ مُعَاذًا كَانَ يُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَأْتِي قَوْمَهُ فَيُصَلِّي بِهِمْ فَجَاءَ ذَاتَ لَيْلَةٍ فَصَلَّى الْعَتَمَةَ وَقَرَأَ الْبَقَرَةَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَصَلَّى ثُمَّ ذَهَبَ فَبَلَغَهُ أَنَّ مُعَاذًا يَنَالُ مِنْهُ فَشَكَا ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمُعَاذٍ فَاتِنًا فَاتِنًا فَاتِنًا أَوْ فَتَّانًا فَتَّانًا فَتَّانًا ثُمَّ أَمَرَهُ بِسُورَتَيْنِ مِنْ وَسَطِ الْمُفَصَّلِ قَالَ أَبُو مُحَمَّد نَأْخُذُ بِهَذَا","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari ['Amru bin Dinar] dari [Jabir bin Abdullah], bahwa Mu'adz pernah melakukan shalat bersama Rasulullah shallallahu 'alaihi wasallam, kemudian ia datang kepada kaumnya dan melakukan shalat bersama mereka. Pada suatu malam ia datang dan melakukan shalat Isya` dengan membaca Surat Al Baqarah, kemudian seorang laki-laki Anshar datang melaksanakan shalat dan langsung pergi. Maka sampailah kepadanya kabar bahwa Mu'adz telah mencelanya, maka ia mengadukan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda kepada Mu'adz: \"Apakah engkau akan menjadi tukang fitnah? Apakah engkau akan menjadi tukang fitnah? Apakah engkau akan menjadi tukang fitnah?\" Kemudian beliau memerintahkan agar ia membaca dua surat yang sedang.\" Abu Muhammad berkata, \"Kami mengambil pendapat ini.\" "},"911":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَمِّي يَقُولُ إِنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَهُ يَقْرَأُ فِي إِحْدَى الرَّكْعَتَيْنِ مِنْ الصُّبْحِ وَالنَّخْلَ بَاسِقَاتٍ قَالَ شُعْبَةُ وَسَأَلْتُهُ مَرَّةً أُخْرَى قَالَ سَمِعْتُهُ يَقْرَأُ بْ ق","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Alqamah] ia berkata; Saya mendengar [Pamanku] berkata, bahwa ia pernah melakukan shalat bersama Nabi shallallahu 'alaihi wasallam. Ia mendengar beliau membaca: 'WAN NAKHLA BAASIQAATIN (dan pohon kurma yang tinggi-tinggi…) (Qs. Qaaf: 10) pada salah satu rakaat shalat Subuh.\" Syu'bah berkata, \"Sekali waktu aku bertanya lagi kepadanya, lalu ia berkata, 'Saya mendengar beliau membaca surat Qaaf.\" "},"912":{"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ قُطْبَةَ بْنِ مَالِكٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ فِي الرَّكْعَةِ الْأُولَى وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ","id":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ziyad bin 'Alqamah] dari [Quthbah bin Malik] ia berkata, \"Saya mendengar Nabi shallallahu 'alaihi wasallam pada rakaat pertama shalat Subuh membaca: 'WAN NAKHLA BAASIQAATIN LAHAA THAL'UN NADHIID (dan pohon kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun-susun) ' (Qs. Qaaf: 10)."},"913":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ الْوَلِيدِ بْنِ سَرِيعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي صَلَاةِ الصُّبْحِ إِذَا الشَّمْسُ كُوِّرَتْ فَلَمَّا انْتَهَى إِلَى هَذِهِ الْآيَةِ { وَاللَّيْلِ إِذَا عَسْعَسَ } جَعَلْتُ أَقُولُ فِي نَفْسِي مَا اللَّيْلُ إِذَا عَسْعَسَ أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ الْوَلِيدِ عَنْ عَمْرِو بْنِ حُرَيْثٍ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Mas'udi] dari [Al Walid bin Sari'] dari ['Amru bin Huraits], bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam pada shalat Subuh membaca: IDZASY SYAMSU KUWWIRAT kemudian setelah sampai pada ayat WALLAILI IDZAA 'AS'AS (demi malam apabila telah hampir meninggalkan gelapnya) (Qs. At Takwir: 17), maka saya berkata dalam hati, 'Apakah malam yang apabila telah hampir meninggalkan gelapnya itu?.\" Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari [Al Walid] dari ['Amru bin Huraits] seperti hadits tersebut.\" "},"914":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا عَوْفٌ عَنْ سَيَّارِ بْنِ سَلَامَةَ قَالَ دَخَلْتُ مَعَ أَبِي عَلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ وَهُوَ عَلَى عِلْوٍ مِنْ قَصَبٍ فَسَأَلَهُ أَبِي عَنْ وَقْتِ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ يُصَلِّي الْهَجِيرَ الَّتِي تَدْعُونَ الظُّهْرَ إِذَا دَحَضَتْ الشَّمْسُ وَكَانَ يُصَلِّي الْعَصْرَ ثُمَّ يَنْطَلِقُ أَحَدُنَا إِلَى أَهْلِهِ فِي أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ قَالَ وَنَسِيتُ مَا ذَكَرَ فِي الْمَغْرِبِ وَكَانَ يَسْتَحِبُّ أَنْ يُؤَخِّرَ مِنْ صَلَاةِ الْعِشَاءِ الَّتِي تَدْعُونَ الْعَتَمَةَ وَكَانَ يَنْصَرِفُ مِنْ صَلَاةِ الصُّبْحِ وَالرَّجُلُ يَعْرِفُ جَلِيسَهُ وَكَانَ يَقْرَأُ فِيهَا مِنْ السِّتِّينَ إِلَى الْمِائَةِ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami ['Auf] dari [Sayyar bin Salamah] ia berkata, \"Saya bersama ayahku menemui [Abu Barzah Al Aslami] yang saat itu berada di atas loteng yang terbuat dari kayu. Ayahku lalu bertanya kepadanya tentang waktu shalat yang dilakukan Rasulullah shallallahu 'alaihi wasallam. Ia lalu menjawab, \"Beliau melakukan shalat siang hari yang kalian sebut zhuhur saat matahari telah bergeser ke Barat, dan beliau melakukan shalat asar saat salah seorang dari kami menemui keluarganya di ujung Madinah, sementara matahari dalam keadaan putih dan sangat panas -Sayyar berkata, 'Dan saya lupa apa yang ia sebutkan mengenai shalat Maghrib-. Dan beliau senang mengakhirkan shalat Isya` yang kalian sebut 'Atamah. Beliau beranjak dari shalat Subuh ketika seseorang mengetahui siapa orang yang duduk di sebelahnya, dan pada shalat tersebut (subuh) beliau membaca antara enam puluh hingga seratus ayat.\" "},"915":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ خَلِيلٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ أَخْبَرَنَا الْأَعْمَشُ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ وَقَدْ رَفَعُوا أَبْصَارَهُمْ فِي الصَّلَاةِ فَقَالَ لَتَنْتَهُنَّ أَوْ لَا تَرْجِعُ إِلَيْكُمْ أَبْصَارُكُمْ","id":"Telah mengabarkan kepada kami [Isma'il bin Khalil] telah menceritakan kepada kami [Ali bin Mushir] telah mengabarkan kepada kami [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Tamim bin Tharafah] dari [Jabir bin Samurah] ia berkata, \"Nabi shallallahu 'alaihi wasallam memasuki masjid, sementara para sahabat mengangkat pandangannya saat melaksanakan shalat, maka beliau pun bersabda: \"Sungguh, kalian segera berhenti dari perbuatan seperti itu atau pandangan kalian tidak akan kembali kepada kalian! \""},"916":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا بَالُ أَقْوَامٍ يَرْفَعُونَ أَبْصَارَهُمْ إِلَى السَّمَاءِ فِي صَلَاتِهِمْ فَاشْتَدَّ قَوْلُهُ فِي ذَلِكَ حَتَّى قَالَ لَتَنْتَهُنَّ عَنْ ذَلِكَ أَوْ لَيَخْطَفَنَّ اللَّهُ أَبْصَارَكُمْ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Muhammad bin Bisyr] [Sa'id] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Kenapa orang-orang mengangkat pandangan mereka ke atas ketika melakukan shalat?\" Ucapan beliau dalam hal tersebut sangat keras hingga beliau bersabda: \"Sungguh, kalian segera berhenti dari perbuatan itu atau Allah membutakan pandangan kalian?\" "},"917":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو يَعْفُورٍ الْعَبْدِيُّ حَدَّثَنِي مُصْعَبُ بْنُ سَعْدٍ قَالَ كَانَ بَنُو عَبْدِ اللَّهِ بْنِ مَسْعُودٍ إِذَا رَكَعُوا جَعَلُوا أَيْدِيَهُمْ بَيْنَ أَفْخَاذِهِمْ فَصَلَّيْتُ إِلَى جَنْبِ سَعْدٍ فَصَنَعْتُهُ فَضَرَبَ يَدِي فَلَمَّا انْصَرَفَ قَالَ يَا بُنَيَّ اضْرِبْ بِيَدَيْكَ رُكْبَتَيْكَ ثُمَّ فَعَلْتُهُ مَرَّةً أُخْرَى بَعْدَ ذَلِكَ بِيَوْمٍ فَصَلَّيْتُ إِلَى جَنْبِهِ فَضَرَبَ يَدِي فَلَمَّا انْصَرَفَ قَالَ كُنَّا نَفْعَلُ هَذَا وَأُمِرْنَا أَنْ نَضْرِبَ بِالْأَكُفِّ عَلَى الرُّكَبِ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ مُصْعَبٍ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Israil] telah menceritakan kepada kami [Abu Ya'fur Al 'Abdi] telah menceritakan kepadaku [Mush'ab bin Sa'd] ia berkata, \"Anak-anak Abdullah bin Mas'ud apabila melakukan rukuk, maka mereka meletakkan tangan-tangan mereka di antara paha. Maka saat aku shalat di sisi [Sa'ad] dan aku melakukan hal tersebut, ia pun memukul tanganku. Selesai shalat ia berkata, \"Wahai anakku, letakkan kedua tanganmu pada kedua lututmu.\" Setelah berlalu, maka pada suatu hari saat aku shalat di sisinya dan aku tetap melakukan hal yang sama, ia memukul tanganku. Selesai shalat ia berkata, \"(Dahulu) kami melakukannya seperti ini, kami diperintahkan agar meletakkan telapak tangan di atas lutut.\" Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Israil] dari [Abu Ishaq] dari [Mush'ab] dengan sanadnya seperti hadits tersebut.\" "},"918":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ سَالِمٍ الْبَرَّادِ قَالَ وَكَانَ أَوْثَقَ عِنْدِي مِنْ نَفْسِي قَالَ قَالَ لَنَا أَبُو مَسْعُودٍ الْأَنْصَارِيُّ أَلَا أُصَلِّي بِكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَبَّرَ وَرَكَعَ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَفَرَّجَ بَيْنَ أَصَابِعِهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Atha' bin As Sa`ib] dari [Salim Al Barrad] -berkata; bagiku ia lebih tsiqah daripada diriku- ia berkata; [Abu Mas'ud Al Anshari] berkata kepada kami, \"Maukah kuperlihatkan kepada kalian bagaimana shalatnya Rasulullah shallallahu 'alaihi wasallam? Salim berkata, \"Kemudian ia bertakbir, lalu rukuk dan meletakkan kedua tangannya di atas kedua lututnya. Ia merenggangkan jari-jarinya hingga segala anggota badannya menempati posisinya.\" "},"919":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا مُوسَى بْنُ أَيُّوبَ حَدَّثَنِي عَمِّي إِيَاسُ بْنُ عَامِرٍ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُ لَمَّا نَزَلَتْ { فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيمِ } قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلُوهَا فِي رُكُوعِكُمْ فَلَمَّا نَزَلَتْ { سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى } قَالَ اجْعَلُوهَا فِي سُجُودِكُمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Musa bin Ayyub] telah menceritakan kepadaku pamanku [Iyas bin 'Amir] ia berkata, saya mendengar ['Uqbah bin 'Amir] berkata, \"Tatkala turun ayat: 'FASABBIH BISMIRABBIKAL 'AZHIIM (Maka bertasbihlah dengan (menyebut) nama Rabbmu Yang Maha Besar) ' (Qs.?Al Waaqi'ah: 74), Rasulullah shallallahu 'alaihi wasallam berkata kepada kami: \"Jadikanlah ayat tersebut ada dalam rukuk kalian.\" Kemudian setelah turun ayat: 'SABBIHISMA RABBIKAL A'LAA (Sucikanlah nama Tuhanmu Yang Maha Tinggi) ' (Qs.?Al A'laa: 1), beliau bersabda: \"Jadikanlah ayat tersebut ada dalam sujud kalian.\""},"920":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ الْمُسْتَوْرِدِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَفِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى وَمَا أَتَى عَلَى آيَةِ رَحْمَةٍ إِلَّا وَقَفَ عِنْدَهَا فَسَأَلَ وَمَا أَتَى عَلَى آيَةِ عَذَابٍ إِلَّا تَعَوَّذَ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Sulaiman] dari [Al Mustaurid] dari [Shilah bin Zufar] dari [Hudzaifah], bahwa ia pernah melaksanakan shalat bersama Nabi shallallahu 'alaihi wasallam pada suatu malam, dalam rukuknya beliau membaca: 'SUBHAANA RABBIYAL 'AZHIIM (Maha Suci Allah, Rabb yang Maha Agung), dan dalam sujudnya membaca: SUBHAANA RABBIYAL A'LAA (Maha Suci Allah, Rabb Yang Maha Tinggi). Dan tidaklah beliau membaca ayat yang berisi mengenai rahmat melainkan beliau berhenti padanya dan berdoa, dan tidaklah beliau membaca ayat mengenai adzab melainkan beliau meminta perlindungan.\""},"921":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عَبَّاسِ بْنِ سَهْلٍ قَالَ اجْتَمَعَ مُحَمَّدُ بْنُ مَسْلَمَةَ وَأَبُو أُسَيْدٍ وَأَبُو حُمَيْدٍ وَسَهْلُ بْنُ سَعْدٍ فَذَكَرُوا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو حُمَيْدٍ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَكَبَّرَ وَرَفَعَ يَدَيْهِ ثُمَّ رَفَعَ يَدَيْهِ حِينَ كَبَّرَ لِلرُّكُوعِ ثُمَّ رَكَعَ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ كَأَنَّهُ قَابِضٌ عَلَيْهِمَا وَوَتَرَ يَدَيْهِ فَنَحَّاهُمَا عَنْ جَنْبَيْهِ وَلَمْ يُصَوِّبْ رَأْسَهُ وَلَمْ يُقْنِعْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Abu 'Amir Al 'Aqadi] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Abbas bin Sahl] ia berkata, \"Muhammad bin Maslamah, Abu Usaid, Abu Humaid, dan Sahl bin Sa'd berkumpul menjadi satu, kemudian mereka menyebutkan shalat Rasulullah shallallahu 'alaihi wasallam. [Abu Humaid] berkata, \"Saya adalah orang yang lebih mengetahui di antara kalian mengenai shalat Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam berdiri lalu takbir dan mengangkat kedua tangannya, kemudian kembali mengangkat kedua tangannya saat takbir untuk rukuk, kemudian beliau rukuk dan meletakkan kedua tangannya pada lutut, seolah-olah beliau menggenggam keduanya. Beliau meregangkan kedua tangan dan menjauhkannya dari kedua sisi badannya, tidak merendahkan kepala dan tidak mengangkatnya.\" "},"922":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ فَإِذَا رَكَعَ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ وَلَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya] ia berkata, \"Nabi shallallahu 'alaihi wasallam apabila memulai shalat beliau mengangkat kedua tangannya sejajar dengan kedua pundak, beliau juga akan melakukan seperti itu jika akan rukuk dan mengangkat kepala dari rukuk, sambil mengucapkan: 'SAMI'ALLAHU LIMAN HAMIDAH, ALLAHUMMA RABBANAA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Ya Allah Rabb kami, kepada-Mu lah semua pujian). Dan beliau tidak mengangkat kedua tangannya ketika akan bersujud.\" Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Malik bin Anas] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. Hanya saja ia menyebutkan: 'RABBANAA WALAKAL HAMDU(Ya Rabb kami, kepada-Mu lah segala pujian).\""},"923":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَإِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Apabila imam mengucapkan; 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya) maka ucapkanlah; 'RABBANAA WA LAKAL HAMDU (Ya Rabb kami, kepada-Mu lah segala pujian) \"."},"924":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ وَإِذَا صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا أَجْمَعُونَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dijadikannya imam adalah agar ia diikuti, apabila ia bertakbir maka bertakbirlah, apabila ia rukuk maka rukuklah, apabila ia sujud maka sujudlah, apabila ia mengucapkan; 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya), maka ucapkanlah; 'RABBANAA LAKAL HAMDU (Ya Rabb kami, kepada-Mu lah segala pujian). Dan apabila ia melakukan shalat dengan berdiri maka shalatlah dengan berdiri, apabila ia melakukan shalat dengan duduk maka shalatlah dengan duduk semua.\" "},"925":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ عَنْ أَبِي مُوسَى أَنَّهُ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا فَعَلَّمَنَا صَلَاتَنَا وَسَنَّ لَنَا سُنَّتَنَا قَالَ أَحْسَبُهُ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلْيَؤُمَّكُمْ أَحَدُكُمْ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَالَ { غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ } فَقُولُوا آمِينَ يُجِبْكُمْ اللَّهُ وَإِذَا كَبَّرَ وَرَكَعَ فَكَبِّرُوا وَارْكَعُوا فَإِنَّ الْإِمَامَ يَرْكَعُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ أَوْ قَالَ رَبَّنَا لَكَ الْحَمْدُ فَإِنَّ اللَّهَ قَالَ عَلَى لِسَانِ نَبِيِّهِ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Yunus bin Jubair] dari [Hiththan bin Abdullah Ar Raqasyi] dari [Abu Musa], bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, lalu beliau mengajarkan shalat dan menetapkan sunah kami.\" Perawi berkata, \"Saya mengira beliau bersabda: \"Jika shalat telah dikumandangkan, maka hendaklah salah seorang dari kalian menjadi imam. Jika imam bertakbir maka bertakbirlah, jika ia mengucapkan; 'GHAIRIL MAGHDHUUBI 'ALAIHIM WA LADHDHAALLIIN (bukan (jalan) mereka yang dimurkai dan bukan (pula jalan) mereka yang sesat), maka ucapkanlah; AAMIIN (Semoga Allah mengabulkan). Sehingga Allah akan mengabulkan doamu. Jika ia takbir dan rukuk maka takbir dan rukuklah kalian. Sesungguhnya imam melakukan rukuk sebelum kalian dan mengangkat kepala sebelum kalian.\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Saat rukuk yang itu sama kadarnya dengan saat rukuk yang itu. Dan jika ia mengucapkan; 'SAMI'ALLAHU LIMAN HAMIDAH (Semoga Allah mendengar pujian orang yang memuji-Nya) ', maka ucapkanlah; 'ALLAHUMMA RABBANAA LAKAL HAMDU (Ya Allah Rabb kami, kepada-Mu lah segala pujian) -atau beliau mengatakan- 'RABBANAA LAKAL HAMDU (Ya Rabb kami, kepada-Mu lah segala pujian). Sesungguhnya Allah berfirman melalui perantara lisan Nabi-Nya; 'SAMI'ALLAHU LIMAN HAMIDAH.\" "},"926":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ عَطِيَّةَ بْنِ قَيْسٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى ال��َّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ أَهْلَ الثَّنَاءِ وَالْمَجْدِ أَحَقُّ مَا قَالَ الْعَبْدُ وَكُلُّنَا لَكَ عَبْدٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sa'id bin Abdul Aziz] dari ['Athiyah bin Qais] dari [Qazarah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam apabila mengangkat kepala dari rukuk beliau mengucapkan: 'RABBANAA LAKAL HAMDU MIL AS SAMAAWAATI WA MIL Al ARDLI WA MIL A MAA SYI'TA MIN SYAI`IN BA'DU, AHLATS TSANAA`I WAL MAJDI AHAQQU MAA QAALAL 'ABDU WA KULLUNAA LAKA 'ABDUN. ALLAAHUMMA LAA MAANI'A LIMAA A'THAITA WA LAA MU'THIYA LIMAA MANA'TA WA LAA YANFA'U MINKAL JADDU.\""},"927":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ عَمِّهْ الْمَاجِشُونَ عَنْ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَالْأَرْضِ وَمِلْءَ مَا بَيْنَهُمَا وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ قِيلَ لِعَبْدِ اللَّهِ تَأْخُذُ بِهِ قَالَ لَا وَقِيلَ لَهُ تَقُولُ هَذَا فِي الْفَرِيضَةِ قَالَ عَسَى وَقَالَ كُلُّهُ طَيِّبٌ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] dari pamannya [Al Majisyun] dari [Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam apabila mengangkat kepala dari rukuk beliau mengucapkan: SAMI'ALLAAHU LIMAN HAMIDAH RABBANAA LAKAL HAMDU MIL AS SAMAAWAATI WA MIL Al ARDLI WA MIL`A MAA BAINAHUMAA WA MIL`A MAA SYI'TA MIN SYAI`IN BA'DU.\" Abdullah lalu ditanya, \"Apakah engkau mengambilnya? Ia berkata, \"Tidak.\" Ia ditanya lagi, \"Apakah engkau mengatakan hal ini dalam shalat fardlu? Ia menjawab, \"Mungkin. Dan semuanya adalah baik.\" "},"928":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ مُعَاوِيَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي قَدْ بَدَّنْتُ فَلَا تَسْبِقُونِي بِالرُّكُوعِ وَلَا بِالسُّجُودِ فَإِنِّي مَهْمَا أَسْبِقُكُمْ حِينَ أَرْكَعُ تُدْرِكُونِي حِينَ أَرْفَعُ وَمَهْمَا أَسْبِقُكُمْ حِينَ أَسْجُدُ تُدْرِكُونِي حِينَ أَرْفَعُ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Muhammad bin 'Ajlan] dari [Muhammad bin Yahya bin Habban] dari [Ibnu Muhairiz] dari [Mu'awiyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku telah tua dan gemuk, maka janganlah kalian mendahuluiku melakukan rukuk dan sujud. Sesungguhnya bagaimanapun saya mendahului kalian ketika melakukan rukuk, kalian akan dapat mengejarku ketika aku mengangkat kepala dari rukuk, dan bagaimanapun saya mendahului kalian ketika sujud, kalian akan dapat mengejarku ketika aku mengangkat kepala dari sujud.\""},"929":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا يَخْشَى أَحَدُكُمْ أَوْ أَلَا يَخْشَى أَحَدُكُمْ إِذَا رَفَعَ رَأْسَهُ قَبْلَ الْإِمَامِ أَنْ يَجْعَلَ اللَّهُ رَأْسَهُ رَأْسَ حِمَارٍ أَوْ صُورَتَهُ صُورَةَ حِمَارٍ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] ia berkata, saya mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah salah seorang di antara kalian merasa takut Allah akan mengubah kepalanya menjadi kepala himar, atau bentuknya menjadi bentuk himar jika ia mengangkat kepalanya sebelum imam?\""},"930":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا الْمُخْتَارُ بْنُ فُلْفُلٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَثَّهُمْ عَلَى الصَّلَاةِ وَنَهَاهُمْ أَنْ يَسْبِقُوهُ إِذَا كَانَ يَؤُمُّهُمْ بِالرُّكُوعِ وَالسُّجُودِ وَأَنْ يَنْصَرِفُوا قَبْلَ انْصِرَافِهِ مِنْ الصَّلَاةِ وَقَالَ إِنِّي أَرَاكُمْ مِنْ خَلْفِي وَأَمَامِي","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Zaidah] telah menceritakan kepada kami [Al Mukhtar bin Fulful] dari [Anas bin Malik], bahwa Nabi shallallahu 'alaihi wasallam menganjurkan mereka untuk melakukan shalat dan melarang mereka dari mendahului beliau saat menjadi imam. Yaitu ketika rukuk, sujud dan beranjak dari tempat shalat sebelum beliau beranjak pergi. Beliau bersabda: \"Aku bisa melihat kalian dari belakang sebagaimana aku melihat kalian dari depan.\""},"931":{"ar":" أَخْبَرَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ طَاوُسًا يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَ أُمِرَ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةٍ وَأُمِرَ أَنْ لَا يَكُفَّ شَعَرًا وَلَا ثَوْبًا قَالَ شُعْبَةُ وَحَدَّثَنِيهِ مَرَّةً أُخْرَى قَالَ أُمِرْتُ بِالسُّجُودِ وَلَا أَكُفَّ شَعَرًا وَلَا ثَوْبًا","id":"Telah mengabarkan kepada kami [Abu An Nadlr Hasyim Al Qasim] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar] ia berkata, Saya mendengar [Thawus] menceritakan dari [Ibnu Abbas] ia berkata, \"Nabi kalian shallallahu 'alaihi wasallam telah diperintahkan agar sujud di atas tujuh anggota badan. Dan diperintahkan agar tidak menahan rambut dan baju.\""},"932":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ وَيَحْيَى بْنُ حَسَّانَ قَالَا حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ الْجَبْهَةِ قَالَ وُهَيْبٌ وَأَشَارَ بِيَدِهِ إِلَى أَنْفِهِ وَالْيَدَيْنِ وَالرُّكْبَتَيْنِ وَأَطْرَافِ الْقَدَمَيْنِ وَلَا نَكُفَّ الثِّيَابَ وَلَا الشَّعَرَ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] dan [Yahya bin Hassan] mereka berkata; telah menceritakan kepada kami [Wuhaib] ia berkata, telah menceritakan kepada kami [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku diperintahkan untuk sujud di atas tujuh tulang; kening.. [Wuhaib] menyebutkan, \"Beliau lalu menunjukkan dengan tangannya ke hidung, kedua tangan, kedua lutut, dan ujung telapak kaki. Dan kami tidak menahan kain dan rambut.\" "},"933":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ يَضَعُ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا نَهَضَ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Syarik] dari ['Ashim bin Kulaib] dari [Ayahnya] dari [Wail bin Hujr] ia berkata, \"Saya melihat Rasulullah shallallahu 'alaihi wasallam apabila bersujud meletakkan kedua lutut sebelum ke dua tangan, dan apabila berdiri beliau mengangkat ke dua tangan sebelum kedua lutut.\""},"934":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ فَلَا يَبْرُكْ كَمَا يَبْرُكُ الْبَعِيرُ وَلْيَضَعْ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ قِيلَ لِعَبْدِ اللَّهِ مَا تَقُولُ قَالَ كُلُّهُ طَيِّبٌ وَقَالَ أَهْلُ الْكُوفَةِ يَخْتَارُونَ الْأَوَّلَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Muhammad bin Abdullah bin Al Hasan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian melakukan shalat maka janganlah ia sujud seperti unta menderum, hendaklah ia meletakkan kedua tangannya sebelum kedua lututnya.\" Abdullah ditanya, \"Apa pendapat anda?\" Ia menjawab, \"Semuanya baik.\" Dan ia berkata, \"Penduduk Kufah memilih yang pertama.\" "},"935":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ وَسَعِيدُ بْنُ الرَّبِيعِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَدِلُوا فِي الرُّكُوعِ وَالسُّجُودِ وَلَا يَبْسُطْ أَحَدُكُمْ ذِرَاعَيْهِ بِسَاطَ الْكَلْبِ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] dan [Sa'id bin Ar Rabi'] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ia berkata, Saya mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seimbanglah saat kalian rukuk dan sujud, dan janganlah salah seorang di antara kalian membentangkan kedua sikunya seperti anjing\""},"936":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ أَبِيهِ عَنْ تَمِيمِ بْنِ مَحْمُودٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ الْأَنْصَارِيِّ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ افْتِرَاشِ السَّبُعِ وَنَقْرَةِ الْغُرَابِ وَأَنْ يُوطِنَ الرَّجُلُ الْمَكَانَ كَمَا يُوطِنُ الْبَعِيرُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] dari [Ayahnya] dari [Tamim bin Mahmud] dari ['Abdurrahman bin Syibl Al Anshari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang membentangkan kedua siku layaknya binatang buas, sujud seperti burung gagak mematuk (tergesa-gesa), dan seorang laki-laki yang mengkhususkan tempat untuk shalat seperti seekor unta mengkhususkan tempat untuk menderum.\""},"937":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ طَلْحَةَ بْنِ يَزِيدَ الْأَنْصَارِيِّ عَنْ حُذَيْفَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ بَيْنَ السَّجْدَتَيْنِ رَبِّ اغْفِرْ لِي فَقِيلَ لِعَبْدِ اللَّهِ تَقُولُ هَذَا قَالَ رُبَّمَا قُلْتُ وَرُبَّمَا سَكَتُّ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Al 'Ala` bin Al Musayyab] dari ['Amru bin Murrah] dari [Thalhah bin Yazid Al Anshari] dari [Hudzaifah], bahwa Nabi shallallahu 'alaihi wasallam di antara dua sujud mengucapkan: 'RABBIGHFIRLII (Ya Allah, ampunilah aku) \". Abdullah ditanya, \"Anda mengucapkan ini juga?\" Ia berkata, \"Terkadang aku mengucapkan dan terkadang diam.\" "},"938":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ كَشَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السِّتَارَةَ وَالنَّاسُ صُفُوفٌ خَلْفَ أَبِي بَكْرٍ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّهُ لَمْ يَبْقَ مِنْ مُبَشِّرَاتِ النُّبُوَّةِ إِلَّا الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ أَلَا إِنِّي نُهِيتُ أَنْ أَقْرَأَ رَاكِعًا أَوْ سَاجِدًا فَأَمَّا الرُّكُوعُ فَعَظِّمُوا رَبَّكُمْ وَأَمَّا السُّجُودُ فَاجْتَهِدُوا فِي الدُّعَاءِ فَقَمِنٌ أَنْ يُسْتَجَابَ لَكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Sulaiman bin Suhaim] dari [Ibrahim bin Abdullah bin Ma'bad] dari [Ayahnya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah membuka korden dan orang-orang sedang berbaris di belakang Abu Bakr, kemudian beliau bersabda: \"Wahai manusia, sesungguhnya tidak tersisa lagi kabar-kabar gembira kenabian selain mimpi yang baik yang dilihat oleh seorang muslim, atau beliau mengatakan, 'diperlihatkan kepadanya. Ketahuilah, aku dilarang membaca Al Qur'an ketika sedang rukuk atau sujud. Jika rukuk maka agungkanlah Tuhan kalian, dan jika sujud maka bersungguh-sungguhlah dalam berdoa karena lebih memungkinkan dikabulkan doa kalian.\""},"939":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ وَإِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي نُهِيتُ أَنْ أَقْرَأَ وَأَنَا رَاكِعٌ أَوْ سَاجِدٌ فَأَمَّا الرُّكُوعُ فَعَظِّمُوا فِيهِ الرَّبَّ وَأَمَّا السُّجُودُ فَاجْتَهِدُوا فِي الدُّعَاءِ فَقَمِنٌ أَنْ يُسْتَجَابَ لَكُمْ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dan [Isma'il bin Ja'far] dari [Sulaiman bin Suhaim] dari [Ibraihim bin Abdullah bin Ma'bad bin Abbas] dari [Bapaknya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku dilarang untuk membaca Al Qur'an ketika sedang rukuk atau sujud. Jika rukuk maka agungkanlah Tuhan kalian, dan jika sujud maka bersungguh-sungguhlah dalam berdoa karena lebih memungkinkan dikabulkan doa kalian.\""},"940":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ هُوَ ابْنُ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةٌ لَا يُقِيمُ الرَّجُلُ فِيهَا صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Al A'masy] dari ['Umarah] -yaitu Ibnu 'Umair- dari [Abu Ma'mar] dari [Abu Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah sah shalat seseorang yang tidak meluruskan tulang punggungnya disaat rukuk dan sujud.\" "},"941":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْوَأُ النَّاسِ سَرِقَةً الَّذِي يَسْرِقُ صَلَاتَهُ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ يَسْرِقُ صَلَاتَهُ قَالَ لَا يُتِمُّ رُكُوعَهَا وَلَا سُجُودَهَا","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pencuri yang paling buruk adalah orang yang mencuri shalatnya.\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana ia mencuri shalatnya?\" Beliau menjawab: \"Ia tidak menyempurnakan rukuk dan sujudnya.\" "},"942":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ عَنْ أَبِيهِ عَنْ عَمِّهِ رِفَاعَةَ بْنِ رَافِعٍ وَكَانَ رِفَاعَةُ وَمَالِكُ ابْنَيْ رَافِعٍ أَخَوَيْنِ مِنْ أَهْلِ بَدْرٍ قَالَ بَيْنَمَا نَحْنُ جُلُوسٌ حَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ وَنَحْنُ حَوْلَهُ شَكَّ هَمَّامٌ إِذْ دَخَلَ رَجُلٌ فَاسْتَقْبَلَ الْقِبْلَةَ فَصَلَّى فَلَمَّا قَضَى الصَّلَاةَ جَاءَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى الْقَوْمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ الرَّجُلُ فَصَلَّى وَجَعَلْنَا نَرْمُقُ صَلَاتَهُ لَا نَدْرِي مَا يَعِيبُ مِنْهَا فَلَمَّا قَضَى صَلَاتَهُ جَاءَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى الْقَوْمِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ قَالَ هَمَّامٌ فَلَا أَدْرِي أَمَرَهُ بِذَلِكَ مَرَّتَيْنِ أَوْ ثَلَاثًا قَالَ الرَّجُلُ مَا أَلَوْتُ فَلَا أَدْرِي مَا عِبْتَ عَلَيَّ مِنْ صَلَاتِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَا تَتِمُّ صَلَاةُ أَحَدِكُمْ حَتَّى يُسْبِغَ الْوُضُوءَ كَمَا أَمَرَهُ اللَّهُ عَزَّ وَجَلَّ فَيَغْسِلُ وَجْهَهُ وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ وَيَمْسَحُ بِرَأْسِهِ وَرِجْلَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ يُكَبِّرُ اللَّهَ وَيَحْمَدُهُ ثُمَّ يَقْرَأُ مِنْ الْقُرْآنِ مَا أَذِنَ اللَّهُ عَزَّ وَجَلَّ لَهُ فِيهِ ثُمَّ يُكَبِّرُ فَيَرْكَعُ فَيَضَعُ كَفَّيْهِ عَلَى رُكْبَتَيْهِ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ وَتَسْتَرْخِيَ وَيَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَيَسْتَوِي قَائِمًا حَتَّى يُقِيمَ صُلْبَهُ فَيَأْخُذَ كُلُّ عَظْمٍ مَأْخَذَهُ ثُمَّ يُكَبِّرُ فَيَسْجُدُ فَيُمَكِّنُ وَجْهَهُ قَالَ هَمَّامٌ وَرُبَّمَا قَالَ جَبْهَتَهُ مِنْ الْأَرْضِ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ وَتَسْتَرْخِيَ ثُمَّ يُكَبِّرُ فَيَسْتَوِي قَاعِدًا عَلَى مَقْعَدِهِ وَيُقِيمُ صُلْبَهُ فَوَصَفَ الصَّلَاةَ هَكَذَا أَرْبَعَ رَكَعَاتٍ حَتَّى فَرَغَ لَا تَتِمُّ صَلَاةُ أَحَدِكُمْ حَتَّى يَفْعَلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Ishaq bin Abdullah] dari [Ali bin Yahya bin Khallad] dari [Ayahnya] dari pamannya [Rifa'ah bin Rafi'] -Rifa'ah dan Malik adalah anak Rafi', dan keduanya termasuk ahli badar-. Ia berkata, \"Ketika kami sedang duduk-duduk di sekitar Rasulullah shallallahu 'alaihi wasallam, atau ketika Rasulullah shallallahu 'alaihi wasallam sedang duduk dan kami berada di sekitar beliau -Hammam merasa ragu-, tiba-tiba ada seorang laki-laki masuk, lalu menghadap kiblat dan mengerjakan shalat. Selesai shalat ia datang dan mengucapkan salam kepada Rasulullah shallallahu 'alaihi wasallam dan orang-orang. Lalu Rasulullah shallallahu 'alaihi wasallam mengatakan: \"Celaka kamu! Kembali dan kerjakanlah shalat, sesungguhnya engkau belum melakukan shalat.\" Maka orang tersebut kembali dan melakukan shalat, kami memperhatikan shalatnya dan tidak mengetahui apa yang beliau cela dari shalatnya tersebut. Selesai shalat ia ia kembali datang dan mengucapkan salam kepada Rasulullah shallallahu 'alaihi wasallam dan orang-orang. Lalu Rasulullah shallallahu 'alaihi wasallam mengatakan: \"Celaka kamu! Kembali dan kerjakanlah shalat, sesungguhnya kamu belum melakukan shalat.\" Hammam berkata, \"Saya tidak tahu beliau memerintahkan hal tersebut dua atau tiga kali. Orang itu akhirnya berkata, \"Saya tidak mengurangi dan tidak mengetahui apa yang anda cela atas shalatku.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Sesungguhnya tidaklah sempurna shalat salah seorang dari kalian hingga ia menyempurnakan wudlu sebagaimana yang Allah 'azza wajalla perintahkan. Ia cuci wajah dan kedua tangannya hingga kedua siku, mengusap kepala dan kedua kakinya hingga kedua mata kaki. Kemudian takbir dan memuji Allah, lalu membaca sebagian dari Al Qur'an yang Allah 'azza wajalla izinkan padanya. Kemudian takbir dan rukuk, lalu ia letakkan kedua telapak tangannya di atas kedua lutut hingga persendiannya tenang dan rileks. Lalu membaca; SAMI'ALLAHU LIMAN HAMIDAHU(Semoga Allah mendengar pujian orangyang memuji-Nya) hingga tegak berdiri dan lurus tulang sulbinya. Dan setiap tulang persendiannya kembali ke tempatnya semula. Kemudian takbir, lalu sujud dan menempelkan wajahnya -Hammam berkata; terkadang beliau mengatakan 'wajahnya'- di tanah hingga persendiannya menjadi tenang dan rileks. Kemudian takbir hingga duduk dengan tegak di atas tempat duduknya, dan lurus tulang sulbinya.\" Beliau kemudian menyebutkan sifat shalat -empat rakaat- tersebut seperti ini hingga selesai. Dan tidaklah sempurna shalat salah seorang di antara kalian hingga melakukan hal tersebut.\" "},"943":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا جَعْفَرُ بْنُ بُرْقَانَ حَدَّثَنَا يَزِيدُ بْنُ الْأَصَمِّ عَنْ مَيْمُونَةَ بِنْتِ الْحَارِثِ قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ جَافَى حَتَّى يَرَى مَنْ خَلْفَهُ وَضَحَ إِبِطَيْهِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ja'far bin Burqan] telah menceritakan kepada kami [Yazid bin Al Asham] dari [Maimunah binti Al Harits] ia berkata, \"Nabi shallallahu 'alaihi wasallam apabila sujud merenggangkan tangan hingga orang yang di belakangnya melihat putihnya ketiak beliau.\" "},"944":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ وَإِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَصَمِّ عَنْ عَمِّهِ يَزِيدَ بْنِ الْأَصَمِّ عَنْ مَيْمُونَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ جَافَى حَتَّى لَوْ شَاءَتْ بَهْمَةٌ تَمُرُّ تَحْتَهُ لَمَرَّتْ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dan [Isma'il bin Zakaria] dari ['Ubaidullah bin Abdullah bin Al Asham] dari pamannya [Yazid bin Al Asham] dari [Maimunah] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam sujud, maka beliau merenggangkan tangan hingga apabila hewan ternak hendak lewat di bawahnya niscaya ia dapat melewatinya.\""},"945":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مَرْوَانُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ الْأَصَمِّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ خَوَّى بِيَدَيْهِ يَعْنِي جَنَّحَ حَتَّى يُرَى وَضَحُ إِبْطَيْهِ مِنْ وَرَائِهِ وَإِذَا قَعَدَ اطْمَأَنَّ عَلَى فَخِذِهِ الْيُسْرَى","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Marwan] telah menceritakan kepada kami ['Ubaidullah bin Abdullah bin Al Asham] dari [Yazid bin Al Asham] dari [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam sujud, maka beliau mengosongkan dengan kedua tangannya, membentangkan kedua sikunya seperti sayap hingga dari belakang terlihat putihnya kedua ketiak beliau. Jika duduk maka beliau duduk dengan tenang di atas paha kirinya.\" "},"946":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى حَدَّثَنِي الْبَرَاءُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ رُكُوعُهُ إِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَسُجُودُهُ وَبَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] telah menceritakan kepadaku [Al Barra`], bahwa jika Rasulullah shallallahu 'alaihi wasallam melakukan rukuk, atau beliau mengangkat kepalanya dari rukuk, atau saat sujud dan di antara dua sujud, maka lamanya hampir sama.\" "},"947":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ هِلَالِ بْنِ حُمَيْدٍ الْوَزَّانِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ قَالَ رَمَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاتِهِ فَوَجَدْتُ قِيَامَهُ وَرَكْعَتَهُ وَاعْتِدَالَهُ بَعْدَ الرَّكْعَةِ فَسَجْدَتَهُ فَجِلْسَتَهُ بَيْنَ السَّجْدَتَيْنِ فَسَجْدَتَهُ فَجِلْسَتَهُ بَيْنَ التَّسْلِيمِ وَالِانْصِرَافِ قَرِيبًا مِنْ السَّوَاءِ قَالَ أَبُو مُحَمَّد هِلَالُ بْنُ حُمَيْدٍ أُرَى أَبُو حُمَيْدٍ الْوَزَّانُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Abu 'Awanah] dari [Hilal bin Humaid Al Wazzan] dari ['Abdurrahman bin Abu Laila] dari [Al Barra`] ia berkata, \"Saya memperhatikan Rasulullah shallallahu 'alaihi wasallam ketika melakukan shalat, maka saya dapati berdirinya, rukuknya dan I'tidalnya setelah rukuk, kemudian sujudnya, duduknya di antara dua sujud, sujudnya, duduknya di antara salam dan beranjak pergi adalah hampir sama lamanya.\" Abu Muhammad Hilal bin Humaid berkata, \"Saya diperlihatkan oleh Abu Humaid Al Wazzan.\""},"948":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبَّادُ بْنُ زِيَادٍ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ وَحَمْزَةَ بْنِ الْمُغِيرَةِ أَنَّهُمَا سَمِعَا الْمُغِيرَةَ بْنَ شُعْبَةَ يُخْبِرُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبَلَ وَأَقْبَلَ مَعَهُ الْمُغِيرَةُ بْنُ شُعْبَةَ حَتَّى وَجَدُوا النَّاسَ قَدْ أَقَامُوا الصَّلَاةَ صَلَاةَ الْفَجْرِ وَقَدَّمُوا عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ يُصَلِّي بِهِمْ فَصَلَّى بِهِمْ عَبْدُ الرَّحْمَنِ رَكْعَةً مِنْ صَلَاةِ الْفَجْرِ قَبْلَ أَنْ يَأْتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَفَّ مَعَ النَّاسِ وَرَاءَ عَبْدِ الرَّحْمَنِ فِي الرَّكْعَةِ الثَّانِيَةِ فَلَمَّا سَلَّمَ عَبْدُ الرَّحْمَنِ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَلَّى فَفَزِعَ النَّاسُ لِذَلِكَ وَأَكْثَرُوا التَّسْبِيحَ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ لِلنَّاسِ قَدْ أَصَبْتُمْ أَوْ قَدْ أَحْسَنْتُمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits bin Sa'd] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Abbad bin Ziyad] dari ['Urwah bin Al Mughirah] dan [Hamzah bin Al Mughirah] bahwa keduanya telah mendengar [Al Mughirah bin Syu'bah] mengabarkan, bahwa Rasulullah shallallahu 'alaihi wasallam datang bersama Al Mughirah bin Syu'bah dan mendapati orang-orang telah mendirikan shalat subuh. Orang-orang itu (para sahabat) telah menunjuk Abdurrahman bin 'Auf untuk menjadi imam, maka Abdurrahman pun shalat bersama mereka satu rakaat shalat subuh sebelum Rasulullah shallallahu 'alaihi wasallam datang. Kemudian Rasulullah shallallahu 'alaihi wasallam datang dan berbaris di shaf bersama orang-orang di belakang Abdurrahman bin 'Auf pada rakaat kedua. Lalu ketika Abdurrahman bin 'Auf mengucapkan salam, Rasulullah shallallahu 'alaihi wasallam berdiri kemudian melakukan shalat. Maka orang-orang pun kaget karena hal tersebut hingga mereka memperbanyak mengucapkan kalimat tasbih. Kemudian tatkala Rasulullah shallallahu 'alaihi wasallam menyelesaikan shalatnya beliau berkata kepada orang-orang: \"Sungguh kalian telah benar, atau kalian telah berbuat baik.\""},"949":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ حَدَّثَنَا بَكْرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ حَمْزَةَ بْنِ الْمُغِيرَةِ عَنْ أَبِيهِ أَنَّهُ قَالَ فَانْتَهَيْنَا إِلَى الْقَوْمِ وَقَدْ قَامُوا إِلَى الصَّلَاةِ يُصَلِّي بِهِمْ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ وَقَدْ رَكَعَ بِهِمْ فَلَمَّا أَحَسَّ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَهَبَ يَتَأَخَّرُ فَأَوْمَى إِلَيْهِ بِيَدِهِ فَصَلَّى بِهِمْ فَلَمَّا سَلَّمَ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْتُ فَرَكَعْنَا الرَّكْعَةَ الَّتِي سُبِقْنَا قَالَ أَبُو مُحَمَّد أَقُولُ فِي الْقَضَاءِ بِقَوْلِ أَهْلِ الْكُوفَةِ أَنْ يَجْعَلَ مَا فَاتَهُ مِنْ الصَّلَاةِ قَضَاءً","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Humaid Ath Thawil] telah menceritakan kepada kami [Bakr bin Abdullah Al Muzani] dari [Hamzah bin Al Mughirah] dari [Ayahnya] bahwa ia berkata, \"Kemudian kami sampai kepada orang-orang sementara mereka telah berdiri melakukan shalat dengan Abdurrahman bin 'Auf sebagai imamnya, dan 'Abdurrahman telah mendapatkan satu rakaat bersama mereka. Kemudian tatkala ia merasakan kehadiran Nabi shallallahu 'alaihi wasallam maka ia mundur, tetapi beliau memberi isyarat kepadanya dengan tangannya (agar tetap shalat bersama mereka), maka ia pun tetap shalat bersama mereka. Ketika 'Abdurrahman salam, Nabi shallallahu 'alaihi wasallam berdiri dan akupun berdiri, kemudian kami melakukan rukuk untuk rakaat kami yang telah tertinggal.\" Abu Muhammad berkata, \"Dalam masalah mengqadla shalat aku berpendapat seperti pendapat penduduk Kufah, yaitu menjadikan apa yang tertinggal sebagai qadla.\""},"950":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا غَالِبٌ الْقَطَّانُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسٍ قَالَ كُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شِدَّةِ الْحَرِّ فَإِذَا لَمْ يَسْتَطِعْ أَحَدُنَا أَنْ يُمَكِّنَ جَبْهَتَهُ مِنْ الْأَرْضِ بَسَطَ ثَوْبَهُ فَصَلَّى عَلَيْهِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami [Ghalib Al Qaththan] dari [Bakr bin Abdullah] dari [Anas] ia berkata, \"Kami pernah melakukan shalat bersama Rasulullah shallallahu 'alaihi wasallam pada waktu yang sangat panas, apabila salah seorang di antara kami tidak mampu menempelkan keningnya di tanah maka ia menghamparkan kain dan melakukan shalat di atasnya.\" "},"951":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ ابْنِ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو هَكَذَا فِي الصَّلَاةِ وَأَشَارَ ابْنُ عُيَيْنَةَ بِأُصْبُعِهِ وَأَشَارَ أَبُو الْوَلِيدِ بِالسَّبَّاحَةِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ibnu 'Ajlan] dari ['Amir bin Abdullah bin Az Zubair] dari [Ayahnya] ia berkata, \"Saya melihat Nabi shallallahu 'alaihi wasallam berdoa demikian di dalam shalat.\" Ibnu 'Uyainah memberikan isyarat menggunakan jari-jarinya, dan Abu Al Walid berisyarat menggunakan jari telunjuk.\""},"952":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَعَدَ فِي آخِرِ الصَّلَاةِ وَضَعَ يَدَهُ الْيُسْرَى عَلَى رُكْبَتِهِ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُمْنَى عَلَى رُكْبَتِهِ الْيُمْنَى وَنَصَبَ إِصْبَعَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam apabila duduk di akhir shalat, beliau meletakkan tangan kirinya di atas lutut kiri dan meletakkan tangan kanannya di atas lutut kanan serta menegakkan jari-jarinya.\""},"953":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَ كُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا السَّلَامُ عَلَى اللَّهِ قَبْلَ عِبَادِهِ السَّلَامُ عَلَى جِبْرِيلَ السَّلَامُ عَلَى مِيكَائِيلَ السَّلَامُ عَلَى إِسْرَافِيلَ السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ قَالَ فَأَقْبَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ تَعَالَى هُوَ السَّلَامُ فَإِذَا جَلَسْتُمْ فِي الصَّلَاةِ فَقُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّكُمْ إِذَا قُلْتُمُوهَا أَصَابَتْ كُلَّ عَبْدٍ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ لِيَتَخَيَّرْ مَا شَاءَ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] ia berkata, \"Dahulu jika kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam, maka kami mengucapkan, 'Semoga keselamatan bagi Allah sebelum para hamba-Nya, semoga keselamatan bagi Jibril, semoga keselamatan bagi Mikail, semoga keselamatan bagi Israfil, semoga keselamatan bagi fulan dan fulan'.\" Abdullah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam menghadap ke arah kami dan mengatakan: \"Sesungguhnya Allah Ta'ala adalah As Salam (Maha Sejahtera), maka apabila kalian duduk dalam shalat maka ucapkanlah: AT TAHIYYAATU LILLAAHI WASH SHALAWAATU WATH THAYYIBAATU, AS SALAAMU 'ALAIKA AYYUHAN NABIYYU WA RAHMATULLAAHI WA BARAKAATUH, AS SALAAMU 'ALAINAA WA 'ALAA 'IBAADILLAAHISH SHAALIHIIN (Segala ucapan selamat milik Allah, shalawat serta segala kebaikan. Semoga keselamatan bagimu wahai Nabi dan rahmat Allah serta berkah-Nya. Semoga keselamatan bagi hamba-hamba Allah yang shalih), sesungguhnya apabila kalian mengucapkan hal tersebut maka kalian kalimat tersebut telah mencakup seluruh hamba yang shalih di langit dan bumi. ASYHADU AN LAA ILAAHA ILLALLAAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya). Kemudian hendaknya ia memilih (doa) yang ia kehendaki.\""},"954":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ الْحَسَنِ بْنِ حُرٍّ حَدَّثَنِي الْقَاسِمُ بْنُ مُخَيْمِرَةَ قَالَ أَخَذَ عَلْقَمَةُ بِيَدِي فَحَدَّثَنِي أَنَّ عَبْدَ اللَّهِ أَخَذَ بِيَدِهِ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِ عَبْدِ اللَّهِ فَعَلَّمَهُ التَّشَهُّدَ فِي الصَّلَاةِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ قَالَ زُهَيْرٌ أُرَاهُ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَيْضًا شَكَّ فِي هَاتَيْنِ الْكَلِمَتَيْنِ إِذَا فَعَلْتَ هَذَا أَوْ قَضَيْتَ فَقَدْ قَضَيْتَ صَلَاتَكَ إِنْ شِئْتَ أَنْ تَقُومَ فَقُمْ وَإِنْ شِئْتَ أَنْ تَقْعُدَ فَاقْعُدْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Al Hasan bin Hurr] telah menceritakan kepadaku [Al Qasim bin Mukhaimarah] ia berkata, ['Alqamah] menggandeng tanganku kemudian menceritakan kepadaku bahwa [Abdullah] telah menggandeng tangannya, bahwa Rasulullah shallallahu 'alaihi wasallam menggandeng tangan Abdullah kemudian mengajarkan kepadanya tasyahud dalam shalat: \"AT TAHIYYAATU LILLAAHI WASH SHALAWAATU WATH THAYYIBAATU, AS SALAAMU 'ALAIKA AYYUHAN NABIYYU WA RAHMATULLAAHI WA BARAKAATUH, AS SALAAMU 'ALAINAA WA 'ALAA 'IBAADILLAAHISH SHAALIHIIN (Segala ucapan selamat milik Allah, shalawat serta segala kebaikan. Semoga keselamatan bagimu wahai Nabi dan rahmat Allah serta berkah-Nya. Semoga keselamatan bagi hamba-hamba Allah yang shalih).\" Zuhair berkata, \"Menurutku beliau mengucapkan: \"ASYHADU AN LAA ILAAHA ILLALLAAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya) -Zuhair masih merasa ragu antara dua kalimat ini-. Apabila engkau melakukan hal ini atau menyelesaikannya sungguh engkau telah menyelesaikan shalatmu. Apabila engkau ingin berdiri maka berdirilah, dan apabila engkau ingin duduk maka duduklah.\""},"955":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ الْحَكَمُ أَخْبَرَنِي قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى يَقُولُ لَقِيَنِي كَعْبُ بْنُ عُجْرَةَ فَقَالَ أَلَا أُهْدِي لَكَ هَدِيَّةً إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْنَا فَقُلْنَا قَدْ عَلِمْنَا السَّلَامَ عَلَيْكَ فَكَيْفَ نُصَلِّي قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thalisi] telah menceritakan kepada kami [Syu'bah] ia berkata; [Al Hakam] telah mengabarkan kepadaku, ia berkata; aku mendengar [Ibnu Abu Laila] berkata; [Ka'b bin 'Ujrah] bertemu denganku dan berkata, \"Maukah kamu aku beri hadiah? Sesungguhnya Rasulullah shallallahu 'alaihi wasallam keluar menemui kami, kemudian kami berkata, \"Kami telah tahu cara mengucapkan salam kepada anda, lalu bagaimana kami bershalawat? Beliau lalu berkata: \"Ucapkanlah: 'ALLAAHUMMA SHALLI 'ALAA MUHAMMADIN WA 'ALAA AALI MUHAMMADIN KAMAA SHALLAITA 'ALAA AALI IBRAAHIIMA, INNAKA HAMIIDUN MAJIID, WA BAARIK 'ALAA MUHAMMADIN WA 'ALAA AALI MUHAMMADIN KAMAA BAARAKTA 'ALAA AALI IBRAAHIIMA INNAKA HAMIIDUN MAJIID (Ya Allah, limpahkanlah shalawat kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau melimpahkan shalawat kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji dan Maha Pemurah. Berilah berkah kepada Muhammad dan keluarga Muhammad sebagaimana Engkau memberikan berkah kepada keluarga Ibrahim. Sesungguhnya Engkau Maha terpuji dan Maha Pemurah).\""},"956":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ نُعَيْمٍ الْمُجْمِرِ مَوْلَى عُمَرَ بْنِ الْخَطَّابِ أَنَّ مُحَمَّدَ بْنَ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْأَنْصَارِيَّ الَّذِي كَانَ أُرِيَ النِّدَاءَ بِالصَّلَاةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ أَنَّ أَبَا مَسْعُودٍ الْأَنْصَارِيَّ قَالَ أَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ مَعَنَا فِي مَجْلِسِ سَعْدِ بْنِ عُبَادَةَ فَقَالَ لَهُ بَشِيرُ بْنُ سَعْدٍ وَهُوَ أَبُو النُّعْمَانِ بْنُ بَشِيرٍ أَمَرَنَا اللَّهُ أَنْ نُصَلِّيَ عَلَيْكَ يَا رَسُولَ اللَّهِ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ فَصَمَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمَنَّيْنَا أَنَّهُ لَمْ يَسْأَلْهُ ثُمَّ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَالسَّلَامُ كَمَا قَدْ عَلِمْتُمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Nu'aim Al Mujmir] mantan budak Umar bin Al Khathab, bahwa [Muhammad bin Abdullah bin Zaid Al Anshari] yang bermimpi mengenai seruan adzan untuk shalat pada masa Rasulullah shallallahu 'alaihi wasallam mengabarkan kepadanya, bahwa [Abu Mas'ud Al Anshari] berkata, \"Rasulullah shallallahu 'alaihi wasallam datang menemui kami lalu duduk bersama kami di dalam majelis Sa'd bin 'Ubadah. Kemudian Basyir bin Sa'd -Abu An Nu'man bin Basyir- berkata kepada beliau, 'Wahai Rasulullah, Allah telah memerintahkan kami untuk bershalawat kepada anda, lalu bagaimana kami bershalawat kepada anda? ' Abu Mas'ud berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam diam hingga kami berangan-angan bahwa ia tidak bertanya kepada beliau. Beliau kemudian berkata: \"Ucapkanlah; 'ALLAAHUMMA SHALLI 'ALAA MUHAMMADIN WA 'ALAA AALI MUHAMMADIN KAMAA SHALLAITA 'ALAA IBRAAHIIMA, WA BAARIK 'ALAA MUHAMMADIN WA 'ALAA AALI MUHAMMADIN KAMAA BAARAKTA 'ALAA AALI IBRAAHIIMA FIL 'AALAMIINA INNAKA HAMIIDUN MAJIID (Ya Allah, limpahkanlah shalawat kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau melimpahkan shalawat kepada Ibrahim, berilah berkah kepada Muhammad dan keluarga Muhammad sebagaimana Engkau memberikan berkah kepada keluarga Ibrahim di seluruh alam sesungguhnya Engkau Maha terpuji dan Maha Pemurah).sedangkan salam sebagaimana kalian telah ketahui.\""},"957":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَائِشَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَرَغَ أَحَدُكُمْ مِنْ التَّشَهُّدِ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ أَرْبَعٍ مِنْ عَذَابِ جَهَنَّمَ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَشَرِّ الْمَسِيحِ الدَّجَّالِ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Hassan] dari [Muhammad bin Abu Aisyah] ia berkata; aku mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata: \"Apabila salah seorang di antara kalian telah selesai bertasyahud, maka hendaknya ia berlindung kepada Allah dari empat perkara; dari adzab Jahannam, adzab kubur, fitnah kehidupan dan kamatian serta kejahatan Al Masih Dajjal.\" Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] seperti itu.\" "},"958":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلِّمُ عَنْ يَمِينِهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ ثُمَّ يُسَلِّمُ عَنْ يَسَارِهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Abdullah bin Ja'far] dari [Isma'il bin Muhammad bin Sa'd] dari ['Amir bin Sa'd] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengucapkan salam ke samping kanan hingga kelihatan putih pipinya, kemudian mengucapkan salam ke kirinya hingga terlihat putih pipinya.\" "},"959":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ الْحَكَمِ وَمَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ قَالَ صَلَّيْتُ خَلْفَ رَجُلٍ بِمَكَّةَ فَسَلَّمَ تَسْلِيمَتَيْنِ فَذَكَرْتُ ذَلِكَ لِعَبْدِ اللَّهِ فَقَالَ أَنَّى عَلِقَهَا وَقَالَ الْحَكَمُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Al Hakam] dan [Manshur] dari [Mujahid] dari [Abu Ma'mar] ia berkata, \"Aku pernah shalat di belakang seseorang di Makkah, kemudian ia mengucapkan dua kali salam. Lalu hal itu aku ceritakan kepada [Abdullah], maka ia pun berkata, \"Dari mana ia mendapatkan sunah tersebut? Al Hakam berkata, \"Dahulu Nabi shallallahu 'alaihi wasallam melakukannya.\""},"960":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمٌ عَنْ أَبِي الْوَلِيدِ هُوَ عَبْدُ اللَّهِ بْنُ الْحَارِثِ عَنْ عَائِشَةَ قَالَتْ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْلِسُ بَعْدَ الصَّلَاةِ إِلَّا قَدْرَ مَا يَقُولُ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim] dari [Abu Al Walid] -yaitu Abdullah bin Al Harits- dari [Aisyah] ia berkata, \"Tidaklah Nabi shallallahu 'alaihi wasallam duduk setelah shalat kecuali seukuran mengucapkan 'ALLAAHUMMA ANTAS SALAAM WA MINKAS SALAAM TABAARAKTA YAA DZAL JALAALI WAL IKRAAM (Ya Allah, Engkau adalah As Salaam (Yang Maha Sejahtera), dari-Mu lah datang keselamatan, Maha Suci Engkau wahai Dzat Yang memiliki kemuliaan) '.\" "},"961":{"ar":"أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ شَدَّادٍ أَبِي عَمَّارٍ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنْصَرِفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Syaddad Abu 'Ammar] dari [Abu Asma` Ar Rahabi] dari [Tsauban] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam apabila hendak beranjak dari shalatnya, maka beliau beristighfar tiga kali kemudian mengucapkan: 'ALLAAHUMMA ANTAS SALAAM WA MINKAS SALAAM TABAARAKTA YAA DZAL JALAALI WAL IKRAAM (Ya Allah, Engkau adalah As Salaam (Yang Maha Sejahtera), dari-Mu lah datang keselamatan, Maha Suci Engkau wahai Dzat Yang memiliki kemuliaan) '.\""},"962":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ أَمْلَى عَلَيَّ الْمُغِيرَةُ بْنُ شُعْبَةَ فِي كِتَابٍ إِلَى مُعَاوِيَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي دُبُرِ كُلِّ صَلَاةٍ مَكْتُوبَةٍ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin 'Umair] dari [Warrad] penulis Al Mughirah bin Syu'bah, ia berkata, \" [Al Mughirah bin Syu'bah] mendektekan kepadaku ketika menulis surat kepada Mu'awiyah, bahwa Rasulullah shallallahu 'alaihi wasallam dahulu setiap selesai shalat wajib mengucapkan: 'LAA ILAAHA ILLAAHA ILLALLAAHU WAHDAHU LAA SYARIIKA LAHU LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI`IN QADIIR, ALLAAHUMMA LAA MAANI'A LIMAA A'THAITA WA LAA MU'THIYA LIMAA MANA'TA WA LAA YANFA'U DZAL JADDI MINKAL JADDU (Tidak ada tuhan yang berhak disembah kecuali Allah semata, tidak ada sekutu bagi-Nya, segala kerajaan milik-Nya serta segala puji bagi-Nya, dan Dia Maha Mampu Melakukan segala sesuatu. Ya Allah, tidak ada yang dapat menahan apa yang Engkau berikan dan tidak ada yang dapat memberi apa yang Engkau tahan, dan tidak bermanfaat dari-Mu kekayaan bagi orang yang memiliki kekayaan).\""},"963":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَ لَا يَجْعَلْ أَحَدُكُمْ لِلشَّيْطَانِ نَصِيبًا مِنْ صَلَاتِهِ يَرَى أَنَّ حَقًّا عَلَيْهِ أَنْ لَا يَنْصَرِفَ إِلَّا عَنْ يَمِينِهِ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَثِيرًا يَنْصَرِفُ عَنْ يَسَارِهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari ['Umarah] dari [Al Aswad] dari [Abdullah] ia berkata, \"Janganlah salah seorang di antara kalian menjadikan bagi setan bagian dari shalatnya, ia melihat bahwa kewajibannya adalah tidak beranjak (pergi) kecuali dari sisi kanannya. Sungguh, aku sering melihat Rasulullah shallallahu 'alaihi wasallam beranjak ke sisi sebelah kirinya.\" "},"964":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ السُّدِّيِّ قَالَ سَمِعْتُ أَنَسًا يَقُولُ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْصَرِفُ عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [As Suddi] ia berkata; aku mendengar [Anas] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam beranjak pergi dari sisi sebelah kanannya.\" "},"965":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ السُّدِّيِّ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَ انْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ يَمِينِهِ يَعْنِي فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [As Suddi] ia berkata, \"Aku mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam beranjak pergi dari sisi sebelah kanannya, yakni saat shalat.\" "},"966":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا هِقْلٌ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي حَسَّانُ بْنُ عَطِيَّةَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي عَائِشَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ أَبُو ذَرٍّ يَا رَسُولَ اللَّهِ ذَهَبَ أَصْحَابُ الدُّثُورِ بِالْأُجُورِ يُصَلُّونَ كَمَا نُصَلِّي وَيَصُومُونَ كَمَا نَصُومُ وَلَهُمْ فُضُولُ أَمْوَالٍ يَتَصَدَّقُونَ بِهَا وَلَيْسَ لَنَا مَا نَتَصَدَّقُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَلَا أُعَلِّمُكَ كَلِمَاتٍ إِذَا أَنْتَ قُلْتَهُنَّ أَدْرَكْتَ مَنْ سَبَقَكَ وَلَمْ يَلْحَقْكَ مَنْ خَلَفَكَ إِلَّا مَنْ عَمِلَ بِمِثْلِ عَمَلِكَ قَالَ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ تُسَبِّحُ دُبُرَ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدُهُ ثَلَاثًا وَثَلَاثِينَ وَتُكَبِّرُهُ ثَلَاثًا وَثَلَاثِينَ وَتَخْتِمُهَا بِلَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Hiql] dari [Al Auza'i] ia berkata, telah menceritakan kepadaku [Hassan bin 'Athiyyah] ia berkata, telah menceritakan kepadaku [Muhammad bin Abu 'Aisyah] dari [Abu Hurairah] ia berkata, Abu Dzar berkata, \"Wahai Rasulullah, orang-orang kaya telah pergi dengan membawa pahala, mereka shalat sebagaimana kami shalat, berpuasa sebagaimana kami berpuasa dan mereka memiliki kelebihan harta yang mereka sedekahkan, sedang kami tidak memiliki sesuatu yang kami sedekahkan?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku ajarkan kepadamu beberapa kalimat, apabila engkau ucapkan maka engkau akan dapat menyusul orang-orang yang telah mendahuluimu, dan tidak ada orang setelahmu yang dapat mengejarmu kecuali orang yang melakukan seperti apa yang engkau lakukan?\" Abu Dzar berkata, \"Maka aku katakan, \"Wahai Rasulullah, baiklah.\" Beliau lalu bersabda: \"Bertasbih setiap selesai shalat sebanyak tiga puluh tiga kali, bertahmid tiga puluh tiga kali, bertakbir tiga puluh tiga kali dan engkau tutup dengan ucapan LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKA LAHU, LAHUL MULKU WA LAHUL HAMDU WA HUWA 'ALAA KULLI SYAI`IN QADIIR (Tidak ada tuhan yang berhak disembah kecuali Allah semata, tidak ada sekutu bagi-Nya, milik-Nya seluruh kerajaan dan bagi-Nya seluruh pujian, dan ia Dia Maha Mampu melakukan segala sesuatu).\""},"967":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ كَثِيرِ بْنِ أَفْلَحَ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ أُمِرْنَا أَنْ نُسَبِّحَ فِي دُبُرِ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَنَحْمَدَهُ ثَلَاثًا وَثَلَاثِينَ وَنُكَبِّرَ أَرْبَعًا وَثَلَاثِينَ فَأُتِيَ رَجُلٌ أَوْ أُرِيَ رَجُلٌ مِنْ الْأَنْصَارِ فِي الْمَنَامِ فَقِيلَ أَمَرَكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُسَبِّحُوا اللَّهَ فِي دُبُرِ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدُوا ثَلَاثًا وَثَلَاثِينَ وَتُكَبِّرُوا أَرْبَعًا وَثَلَاثِينَ قَالَ نَعَمْ قَالَ فَاجْعَلُوهَا خَمْسًا وَعِشْرِينَ خَمْسًا وَعِشْرِينَ وَاجْعَلُوا مَعَهَا التَّهْلِيلَ فَأُخْبِرَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ افْعَلُوهَا","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Katsir bin Aflah] dari [Zaid bin Tsabit] ia berkata, \"Kami diperintahkan agar bertasbih setiap selesai shalat tiga puluh tiga kali, bertahmid tiga puluh tiga kali, dan bertakbir tiga puluh empat. Kemudian seorang laki-laki dari kalangan anshar didatangkan, atau bermimpi, lalu dikatakan kepadanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kalian agar bertasbih kepada Allah setiap selesai shalat sebanyak tiga puluh tiga kali, bertahmid tiga puluh tiga kali, dan bertakbir tiga puluh empat kali? Ia berkata, \"Ya.\" Orang yang bertanya itu berkata, \"Jadikan kalimat-kalimat tersebut dua puluh lima kali, dua puluh lima kali, dan jadikan bersamanya tahlil.\" Kemudian Nabi shallallahu 'alaihi wasallam diberitahu mengenai hal tersebut, maka beliau berkata: \"Lakukan.\""},"968":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ تَمِيمٍ الدَّارِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ مَا يُحَاسَبُ بِهِ الْعَبْدُ الصَّلَاةُ فَإِنْ وَجَدَ صَلَاتَهُ كَامِلَةً كُتِبَتْ لَهُ كَامِلَةً وَإِنْ كَانَ فِيهَا نُقْصَانٌ قَالَ اللَّهُ تَعَالَى لِمَلَائِكَتِهِ انْظُرُوا هَلْ لِعَبْدِي مِنْ تَطَوُّعٍ فَأَكْمِلُوا لَهُ مَا نَقَصَ مِنْ فَرِيضَتِهِ ثُمَّ الزَّكَاةُ ثُمَّ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ قَالَ أَبُو مُحَمَّد لَا أَعْلَمُ أَحَدًا رَفَعَهُ غَيْرَ حَمَّادٍ قِيلَ لِأَبِي مُحَمَّدٍ صَحَّ هَذَا قَالَ إِي","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Daud bin Abu Hindun] dari [Zurarah bin Aufa] dari [Tamim Ad Dari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pertama kali yang akan dihisab dari seorang hamba adalah shalat, jika shalatnya sempurna maka akan ditulis sempurna untuknya. Apabila padanya terdapat kekurangan, maka Allah Ta'ala berfirman kepada para malaikat-Nya: 'Lihatlah apakah hamba-Ku memiliki amalan sunah? Lalu sempurnakanlah apa yang kurang sempurna dari ibadah wajibnya.' Kemudian zakat, kemudian amalan-amalan lain juga seperti itu (perhitungannya).\" Abu Muhammad berkata, \"Aku tidak mengetahui seseorang yang memarfu'kan hadits tersebut selain Hammad.\" Abu Muhammad ditanya, \"Apakah hadits ini benar? Ia menjawab, \"Ya.\" "},"969":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ السَّاعِدِيَّ فِي عَشَرَةٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَدُهُمْ أَبُو قَتَادَةَ قَالَ أَنَا أَعْلَمُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا لِمَ فَمَا كُنْتَ أَكْثَرَنَا لَهُ تَبَعَةً وَلَا أَقْدَمَنَا لَهُ صُحْبَةً قَالَ بَلَى قَالُوا فَاعْرِضْ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ رَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ كَبَّرَ حَتَّى يَقَرَّ كُلُّ عَظْمٍ فِي مَوْضِعِهِ ثُمَّ يَقْرَأُ ثُمَّ يُكَبِّرُ وَيَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ ثُمَّ يَرْكَعُ وَيَضَعُ رَاحَتَيْهِ عَلَى رُكْبَتَيْهِ حَتَّى يَرْجِعَ كُلُّ عَظْمٍ إِلَى مَوْضِعِهِ وَلَا يُصَوِّبُ رَأْسَهُ وَلَا يُقْنِعُ ثُمَّ يَرْفَعُ رَأْسَهُ فَيَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ يَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ يَظُنُّ أَبُو عَاصِمٍ أَنَّهُ قَالَ حَتَّى يَرْجِعَ كُلُّ عَظْمٍ إِلَى مَوْضِعِهِ مُعْتَدِلًا ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ ثُمَّ يَهْوِي إِلَى الْأَرْضِ فَيُجَافِي يَدَيْهِ عَنْ جَنْبَيْهِ ثُمَّ يَسْجُدُ ثُمَّ يَرْفَعُ رَأْسَهُ فَيَثْنِي رِجْلَهُ الْيُسْرَى فَيَقْعُدُ عَلَيْهَا وَيَفْتَحُ أَصَابِعَ رِجْلَيْهِ إِذَا سَجَدَ ثُمَّ يَعُودُ فَيَسْجُدُ ثُمَّ يَرْفَعُ رَأْسَهُ فَيَقُولُ اللَّهُ أَكْبَرُ وَيَثْنِي رِجْلَهُ الْيُسْرَى فَيَقْعُدُ عَلَيْهَا مُعْتَدِلًا حَتَّى يَرْجِعَ كُلُّ عَظْمٍ إِلَى مَوْضِعِهِ مُعْتَدِلًا ثُمَّ يَقُومُ فَيَصْنَعُ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ فَإِذَا قَامَ مِنْ السَّجْدَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا فَعَلَ عِنْدَ افْتِتَاحِ الصَّلَاةِ ثُمَّ يَصْنَعُ مِثْلَ ذَلِكَ فِي بَقِيَّةِ صَلَاتِهِ حَتَّى إِذَا كَانَتْ السَّجْدَةُ أَوْ الْقَعْدَةُ الَّتِي يَكُونُ فِيهَا التَّسْلِيمُ أَخَّرَ رِجْلَهُ الْيُسْرَى وَجَلَسَ مُتَوَرِّكًا عَلَى شِقِّهِ الْأَيْسَرِ قَالَ قَالُوا صَدَقْتَ هَكَذَا كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [Muhammad bin 'Amru bin 'Atha`] ia berkata; saya mendengar [Abu Humaid As Sa'idi] di antara sepuluh orang para sahabat Nabi shallallahu 'alaihi wasallam, yang salah seorang di antara mereka adalah Abu Qatadah, berkata, \"Aku adalah orang yang paling mengetahui shalat Rasulullah shallallahu 'alaihi wasallam. Kemudian mereka berkata, \"Kenapa bisa? Padahal engkau bukanlah orang yang lebih banyak mengikuti beliau, dan bukan orang yang paling lama menyertai Rasulullah shallallahu 'alaihi wasallam di antara kami?\" Ia mengatakan, \"Benar.\" Mereka berkata, \"Jelaskan! \" Abu Humaid lalu berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam berdiri untuk melakukan shalat, beliau mengangkat kedua tangannya hingga sejajar kedua pundaknya, kemudian takbir hingga setiap tulang menempati tempatnya, lalu membaca surat. Kemudian takbir dan mengangkat kedua tangannya hingga sejajar kedua pundak, kemudian rukuk dan meletakkan kedua telapak tangannya di atas kedua lutut hingga setiap tulang kembali ke tempatnya, beliau tidak menundukkan kepala dan tidak menengadahkan. Kemudian mengangkat kepalanya seraya mengucapkan: 'SAMI'ALLAAHU LIMAN HAMIDAHU (Semoga Allah mendengar orang yang memuji-Nya).' Kemudian mengangkat kedua tangannya hingga sejajar kedua pundaknya.\" Menurut Abu 'Ashim Abu Humaid berkata, \"Hingga setiap tulang kembali kepada tempatnya dalam keadaan lurus, kemudian beliau mengucapkan: 'Allaahu akbar (Allah Maha Besar).' Kemudian turun ke lantai dan merenggangkan kedua tangannya dari kedua sisi badannya, kemudian bersujud, kemudian mengangkat kepalanya. Kemudian beliau membengkokkan kaki kirinya dan duduk di atasnya seraya membuka jari-jari kedua kakinya apabila sujud, kemudian kembali dan sujud, kemudian mengangkat kepalanya sambil mengaucapkan: 'ALLAAHU AKBAR dan membengkokkan kaki kiri dan duduk di atasnya dengan lurus hingga setiap tulang kembali kepada tempatnya secara seimbang. Kemudian beliau berdiri dan melakukan rakaat yang lain seperti itu pula. Apabila berdiri dari dua sujud, beliau takbir dan mengangkat kedua tangannya hingga sejajar kedua pundak sebagaimana beliau melakukan di saat permulaan shalat. Kemudian melakukan seperti itu pada sisa shalatnya hingga pada saat sujud atau duduk yang padanya terdapat salam, beliau memundurkan kaki kirinya dan duduk dalam keadaan tawarruk (posisi duduk dengan meletakkan kedua pantat di atas lantai) miring ke sisi kiri.\" Perawi berkata, \"Orang-orang berkata, \"Engkau benar demikianlah shalat Rasulullah shallallahu 'alaihi wasallam.\""},"970":{"ar":" حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ بْنُ قُدَامَةَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ أَخْبَرَنِي أَبِي أَنَّ وَائِلَ بْنَ حُجْرٍ أَخْبَرَهُ قَالَ قُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُصَلِّي فَنَظَرْتُ إِلَيْهِ فَقَامَ فَكَبَّرَ فَرَفَعَ يَدَيْهِ حَتَّى حَاذَتَا بِأُذُنَيْهِ وَوَضَعَ يَدَهُ الْيُمْنَى عَلَى ظَهْرِ كَفِّهِ الْيُسْرَى قَالَ ثُمَّ لَمَّا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ مِثْلَهَا وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ ثُمَّ رَفَعَ رَأْسَهُ فَرَفَعَ يَدَيْهِ مِثْلَهَا ثُمَّ سَجَدَ فَجَعَلَ كَفَّيْهِ بِحِذَاءِ أُذُنَيْهِ ثُمَّ قَعَدَ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ كَفَّهُ الْيُسْرَى عَلَى فَخِذِهِ وَرُكْبَتِهِ الْيُسْرَى وَجَعَلَ مِرْفَقَهُ الْأَيْمَنَ عَلَى فَخْذِهِ الْيُمْنَى ثُمَّ قَبَضَ ثِنْتَيْنِ فَحَلَّقَ حَلْقَةً ثُمَّ رَفَعَ أُصْبُعَهُ فَرَأَيْتُهُ يُحَرِّكُهَا يَدْعُو بِهَا قَالَ ثُمَّ جِئْتُ بَعْدَ ذَلِكَ فِي زَمَانٍ فِيهِ بَرْدٌ فَرَأَيْتُ عَلَى النَّاسِ جُلَّ الثِّيَابِ يُحَرِّكُونَ أَيْدِيَهُمْ مِنْ تَحْتِ الثِّيَابِ","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Zaidah bin Qudamah] telah menceritakan kepada kami ['Ashim bin Kulaib] telah mengabarkan kepadaku [Ayahku] bahwa [Wail bin Hujr] telah mengabarkan kepadanya, ia berkata, \"Aku katakan, \"Sungguh, aku akan memperhatikan shalat Rasulullah shallallahu 'alaihi wasallam, bagaimana beliau melakukan shalat.\" Kemudian aku memperhatikan Rasulullah, beliau berdiri dan takbir, lalu mengangkat kedua tangannya hingga sejajar kedua telinga, dan meletakkan tangan kanannya di atas punggung telapak tangan kirinya.\" Wail bin Hujr berkata, \"Kemudian saat akan rukuk beliau mengangkat kedua tangannya seperti itu dan meletakkan kedua tangannya di atas kedua lututnya, kemudian mengangkat kepalanya dan mengangkat kedua tangannya seperti itu. Baru setelah itu beliau sujud dan menjadikan kedua telapak tangannya sejajar dengan kedua telinganya, kemudian duduk dan menyilangkan kaki kirinya, lalu meletakkan telapak tangan kirinya di atas paha serta lutut kirinya dan menjadikan siku kanannya berada di atas paha kanannya, Beliau menggenggam dua jarinya dan membuat lingkaran dengan mengangkat satu jari (telunjuk) nya, dan aku melihat beliau menggerakkan jari tersebut sambl membaca berdoa.\" Wail bin Hujr berkata, \"Setelah itu aku kepada mereka saat musim dingin, dan aku lihat mereka memakai pakaian besar dan menggerakkan tangan mereka dari bawah pakaian.\""},"971":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ قَالَ صَلَّى بِنَا أَبُو مُوسَى إِحْدَى صَلَاتَيْ الْعَشِيِّ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أُقِرَّتْ الصَّلَاةُ بِالْبِرِّ وَالزَّكَاةِ فَلَمَّا قَضَى أَبُو مُوسَى الصَّلَاةَ قَالَ أَيُّكُمْ الْقَائِلُ كَلِمَةَ كَذَا وَكَذَا فَأَرَمَّ الْقَوْمُ فَقَالَ لَعَلَّكَ يَا حِطَّانُ قُلْتَهَا قَالَ مَا أَنَا قُلْتُهَا وَقَدْ خِفْتُ أَنْ تَبْكَعَنِي بِهَا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَنَا قُلْتُهَا وَمَا أَرَدْتُ بِهَا إِلَّا الْخَيْرَ فَقَالَ أَبُو مُوسَى أَوَ مَا تَعْلَمُونَ مَا تَقُولُونَ فِي صَلَاتِكُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا فَعَلَّمَنَا صَلَاتَنَا وَبَيَّنَ لَنَا سُنَّتَنَا قَالَ أَحْسَبُهُ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلْيَؤُمَّكُمْ أَحَدُكُمْ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَالَ { غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ } فَقُولُوا آمِينَ يُجِبْكُمْ اللَّهُ فَإِذَا كَبَّرَ وَرَكَعَ فَكَبِّرُوا وَارْكَعُوا فَإِنَّ الْإِمَامَ يَرْكَعُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ فَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ أَوْ قَالَ رَبَّنَا وَلَكَ الْحَمْدُ فَإِنَّ اللَّهَ قَالَ عَلَى لِسَانِ نَبِيِّهِ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَإِذَا كَبَّرَ وَسَجَدَ فَكَبِّرُوا وَاسْجُدُوا فَإِنَّ الْإِمَامَ يَسْجُدُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ فَإِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ أَوَّلِ قَوْلِ أَحَدِكُمْ التَّحِيَّاتُ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ السَّلَامُ أَوْ سَلَامٌ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ أَوْ سَلَامٌ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Yunus bin Jubair] dari [Hiththan bin Abdullah Ar Raqasyi] ia berkata, \" [Abu Musa] melakukan shalat bersama kami salah satu shalat di waktu malam (Shalat Maghrib atau Isya`). Kemudian seorang laki-laki berkata, \"Shalat diiringi dengan perbuatan baik dan zakat.\" Maka ketika Abu Musa menyelesaikan shalatnya ia berkata, \"Siapakah di antara kalian yang mengatakan perkataan demikian dan demikian?\" Orang-orang pun diam. Abu Musa lalu berkata, \"Kemungkinan engkau yang mengatakannya wahai Hiththan.\" Ia menjawab, \"Bukan aku yang mengatakannya. Sungguh aku telah khawatir engkau akan mencelaku karenanya.\" Kemudian seorang laki-laki di antara orang-orang tersebut berkata, \"Aku yang mengatakannya, dan tidak ada yang aku inginkan dengan kata-kata itu kecuali kebaikan.\" Lalu Abu Musa berkata, \"Tidakkah kalian mengetahui apa yang kalian ucapkan dalam shalat kalian? Rasulullah shallallahu 'alaihi wasallam pernah berkhutbah di hadapan kami, beliau mengajarkan kami shalat dan menjelaskan sunah kepada kami.\" Perawi berkata, \"Aku mengira beliau mengatakan: \"Jika shalat telah diserukan maka hendaklah salah seorang dari kalian menjadi imam bagi yang lain. Kemudian apabila imam takbir maka bertakbirlah, jika ia mengucapkan; 'GHAIRIL MAGHDHUUBI 'ALAIHIM WA LADLAALLIIN, maka ucapkan; AAMIIN, maka Allah akan mengabulkan kalian. Jika ia takbir dan rukuk maka takbir dan rukuklah, karena sesungguhnya Imam sujud sebelum kalian dan rukuk sebelum kalian.\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Waktu itu (waktu imam) sama dengan waktu itu (makmum). Jika ia mengucapkan; SAMI'ALLAHU LIMAN HAMIDAHU (Semoga Allah mendengar pujian orang yang memuji-Nya) maka ucapkanlah; ALLAHUMMA RABBANAA LAKAL HAMDU (Ya Allah, Rabb kami, segala puji hanya milik-Mu), atau beliau mengatakan; RABBANAA WA LAKAL HAMDU (Ya Rabb kami, dan bagi-Mu lah segala pujian). Sebab Allah telah berfirman melalui lisan Nabi-Nya; SAMI'ALLAHU LIMAN HAMIDAHU. Dan jika ia takbir dan sujud maka takbir dan sujudlah, sebab imam itu sujud dan rukuk sebelum kalian.\" Nabi shallallahu 'alaihi wasallam kemudian \"Waktu itu (waktu imam) sama dengan waktu itu (makmum). Jika telah duduk, maka jadikanlah pertama kali yang salah seorang dari kalian ucapkan adalah; 'AT TAHIYYAATUTH THAYYIBAATUSH SHALAWAATU LILLAAH, AS SALAAMU, atau SALAAMUN 'ALAIKA AYYUHAN NABIIYU WA RAHMATULLAAHI WA BARAKAATUH. AS SALAAMU 'ALAINAA WA 'ALAA 'IBAADILLAAHISH SHAALIHIIN. ASYHADU AN LAA ILAAHA ILLALLAAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH (Segala ucapan selamat yang baik dan seluruh shalawat adalah milik Allah, semoga keselamatan, rahmat serta berkah terlimpahkan kepadamu wahai Nabi, semoga keselamatan terlimpahkan kepada kami dan para hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah semata, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya).\""},"972":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ هُوَ النَّبِيلُ عَنْ ابْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يُصَلِّي وَقَدْ حَمَلَ عَلَى عُنُقِهِ أَوْ عَاتِقِهِ أُمَامَةَ بِنْتَ زَيْنَبَ فَإِذَا رَكَعَ وَضَعَهَا وَإِذَا قَامَ حَمَلَهَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] -yaitu An Nabil- dari ['Ajlan] dari [Al Maburi] dari ['Amru bin Sulaim] dari [Abu Qatadah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah keluar untuk melaksanakan shalat sementara di pundaknya beliau menggendong Umamah binti Zainab. Apabila rukuk, maka beliau meletakkannya dan apabila berdiri maka beliau menggendongnya.\" "},"973":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَ الْأَنْصَارِيِّ قَالَ حَمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَامَةَ بِنْتَ زَيْنَبَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَإِذَا سَجَدَ وَضَعَهَا وَإِذَا قَامَ حَمَ��َهَا","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari ['Amir bin Abdullah bin Az Zubair] dari ['Amru bin Sulaim Az Zuraqi] dari [Abu Qatadah Al Anshari] ia berkata, \"Saat shalat Rasulullah shallallahu 'alaihi wasallam menggendong Umamah binti Zainab binti Rasulullah shallallahu 'alaihi wasallam. Jika sujud, maka beliau meletakkannya dan jika berdiri maka beliau menggendongnya.\" "},"974":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ أَخْبَرَنِي بُكَيْرٌ هُوَ ابْنُ الْأَشَجِّ عَنْ نَابِلٍ صَاحِبِ الْعَبَاءِ عَنْ ابْنِ عُمَرَ عَنْ صُهَيْبٍ قَالَ مَرَرْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ وَهُوَ يُصَلِّي فَرَدَّ إِلَيَّ إِشَارَةً قَالَ لَيْثٌ أَحْسَبُهُ قَالَ بِأُصْبُعِهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thalisi] telah menceritakan kepada kami [Laits bin Sa'd] telah mengabarkan kepadaku [Bukair] -yaitu Ibnu Al Asyaj- dari [Nabil pemilik Al 'Aba`] dari [Ibnu Umar] dari [Shuhaib] ia berkata, \"Aku melewati Rasulullah shallallahu 'alaihi wasallam yang sedang melaksanakan shalat, lalu aku mengucapkan salam kepada beliau. Maka beliau pun menjawab salamku dengan isyarat.\" Latis berkata, \"Aku mengira ia berkata, \"Menggunakan jari-jari.\""},"975":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَسْجِدَ بَنِي عَمْرِو بْنِ عَوْفٍ فَدَخَلَ النَّاسُ يُسَلِّمُونَ عَلَيْهِ وَهُوَ فِي الصَّلَاةِ قَالَ فَسَأَلْتُ صُهَيْبًا كَيْفَ كَانَ يَرُدُّ عَلَيْهِمْ قَالَ هَكَذَا وَأَشَارَ بِيَدِهِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Zaid bin Aslam] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam memasuki masjid Bani 'Amru bin 'Auf, kemudian orang-orang masuk dan mengucapkan salam kepada beliau sementara beliau sedang melakukan shalat.\" Ibnu Umar, \"Kemudian aku bertanya kepada Shuhaib, \"Bagaimana beliau menjawab salam mereka?\" Ia menjawab, \"Seperti ini.\" lalu ia berisyarat dengan tangannya.\" "},"976":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bertasbih untuk laki-laki dan tepuk tangan untuk untuk wanita.\""},"977":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَابَكُمْ فِي صَلَاتِكُمْ شَيْءٌ فَلْيُسَبِّحْ الرِّجَالُ وَلْتُصَفِّحْ النِّسَاءُ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْجُمَحِيُّ وَعَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ وَعَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ وَسُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Hazim] dari [Sahl bin Sa'd], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika dalam shalat kalian terjadi sesuatu, maka hendaknya laki-laki bertasbih dan wanita bertepuk tangan.\" Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sa'id? bin Abdurrahman Al Jumahi] dan [Abdul Aziz bin Muhammad] dan [Abdul Aziz bin Abu Hazim] serta [Sufyan bin 'Uyainah] dari [Abu Hazim] dari [Sahl bin Sa'd] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut.\" "},"978":{"ar":" أَخْبَرَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَيْكُمْ بِالصَّلَاةِ فِي بُيُوتِكُمْ فَإِنَّ خَيْرَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الْجَمَاعَةَ","id":"Telah mengabarkan kepada kami [Makki bin Ibrahim] telah menceritakan kepada kami [Abdullah bin Sa'id bin Abu Hindun] dari [Abu An Nadlr] dari [Busr bin Sa'id] dari [Zaid bin Tsabit], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian melakukan shalat di rumah kalian, sesungguhnya sebaik-baik shalat seseorang adalah di rumahnya kecuali shalat jama'ah.\""},"979":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ قَالَ سَمِعْتُ جَابِرَ بْنَ يَزِيدَ بْنِ الْأَسْوَدِ السُّوَائِيَّ يُحَدِّثُ عَنْ أَبِيهِ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ قَالَ فَإِذَا رَجُلَانِ حِينَ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدَانِ فِي نَاحِيَةٍ لَمْ يُصَلِّيَا قَالَ فَدَعَا بِهِمَا فَجِيءَ بِهِمَا تُرْعَدُ فَرَائِصُهُمَا قَالَ مَا مَنَعَكُمَا أَنْ تُصَلِّيَا قَالَا صَلَّيْنَا فِي رِحَالِنَا قَالَ فَلَا تَفْعَلَا إِذَا صَلَّيْتُمَا فِي رِحَالِكُمَا ثُمَّ أَدْرَكْتُمَا الْإِمَامَ فَصَلِّيَا فَإِنَّهَا لَكُمَا نَافِلَةٌ قَالَ فَقَامَ النَّاسُ يَأْخُذُونَ بِيَدِهِ يَمْسَحُونَ بِهَا وُجُوهَهُمْ قَالَ فَأَخَذْتُ بِيَدِهِ فَمَسَحْتُ بِهَا وَجْهِي فَإِذَا هِيَ أَبْرَدُ مِنْ الثَّلْجِ وَأَطْيَبُ رِيحًا مِنْ الْمِسْكِ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha`] ia berkata, saya mendengar [Jabir bin Yazid bin Al Aswad As Suwai] menceritakan dari [Ayahnya], bahwa ia pernah shalat subuh bersama Nabi shallallahu 'alaihi wasallam. Ia berkata, \"Tiba-tiba saat Nabi shallallahu 'alaihi wasallam melaksanakan shalat ada dua orang laki-laki yang sedang duduk di pojok masjid, mereka tidak ikut mengerjakan shalat. Maka beliau minta agar keduanya dipanggil, maka dibawalah mereka berdua ke hadapan beliau dengan bergetar. Beliau lantas bertanya: \"Apakah yang menghalangi kalian untuk melakukan shalat?\" Keduanya menjawab, \"Kami telah melakukan shalat di perjalanan kami.\" Beliau berkata: \"Jangan kalian melakukan hal itu, apabila kalian telah melakukan shalat di perjalanan, kemudian mendapati imam maka lakukanlah shalat, karena shalat tersebut bagi kalian sebagai shalat sunah.\" Kemudian orang-orang memegang tangan beliau dan mengusapkannya ke wajah mereka.\" Yazid (perawi) berkata, \"Kemudian aku memegang tangan beliau dan mengusapkan ke wajahku, ternyata tangan beliau lebih dingin daripada salju, dan lebih harum daripada minyak kasturi.\" "},"980":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا سُلَيْمَانُ الْأَسْوَدُ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُصَلِّي وَحْدَهُ فَقَالَ أَلَا رَجُلٌ يَتَصَدَّقُ عَلَى هَذَا فَيُصَلِّي مَعَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Sulaiman Al Aswad] dari [Abu Al Mutawakkil An Naji] dari [Abu Sa'id], bahwa Nabi shallallahu 'alaihi wasallam melihat seorang laki-laki melakukan shalat sendirian, kemudian beliau bersabda: \"Tidakkah ada seseorang yang bersedekah kepada orang ini, hingga ia melakukan shalat bersamanya?\""},"981":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا سُلَيْمَانُ الْأَسْوَدُ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ وَقَدْ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا رَجُلٌ يَتَصَدَّقُ عَلَى هَذَا فَيُصَلِّي مَعَهُ قَالَ عَبْد اللَّهِ يُصَلِّي صَلَاةَ الْعَصْرِ وَيُصَلِّي الْمَغْرِبَ وَلَكِنْ يَشْفَعُ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Sulaiman Al Aswad] dari [Abu Al Mutawakkil An Naji] dari [Abu Sa'id Al Khudri], bahwa seorang laki-laki masuk ke dalam masjid sementara Nabi shallallahu 'alaihi wasallam telah melaksanakan shalat. Kemudian beliau berkata: \"Tidakkah ada seseorang yang bersedekah kepada orang ini sehingga ia melakukan shalat bersamanya?\" Abdullah berkata, \"Ia shalat asar dan maghrib, tetapi harus genap.\" "},"982":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَيُصَلِّي الرَّجُلُ فِي الثَّوْبِ الْوَاحِدِ قَالَ أَوَ كُلُّكُمْ يَجِدُ ثَوْبَيْنِ أَوْ لِكُلِّكُمْ ثَوْبَانِ","id":"Telah mengabarkan kepada kami [Sa'id? bin 'Amir] dari [Hisyam] dari [Muhammad] dari [Abu Hurairah], bahwa seorang laki-laki berkata, \"Wahai Rasulullah, apakah seorang laki-laki boleh melakukan shalat dengan memakai satu pakaian? Beliau berkata: \"Apakah setiap kalian mendapatkan dua pakaian?\" Atau beliau mengatakan: \"Apakah setiap kalian memiliki dua pakaian?\""},"983":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى وَمُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّيَنَّ أَحَدُكُمْ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى عَاتِقِهِ مِنْهُ شَيْءٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dan [Muhammad bin Yusuf] dari [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata: \"Janganlah salah seorang di antara kalian melakukan shalat dengan memakai satu pakaian yang tidak ada sesuatu yang menutupi pundaknya! \""},"984":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ أَنْ يَحْتَبِيَ أَحَدُكُمْ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ بَيْنَ فَرْجِهِ وَبَيْنَ السَّمَاءِ شَيْءٌ وَعَنْ الصَّمَّاءِ اشْتِمَالِ الْيَهُودِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari dua cara berpakaian; salah seorang dari kalian berihtiba` dengan mengenakan satu kain, antara kemaluan dan langit tidak ada yang menutupinya. Dan pakaian shamma` Yahudi (yang tidak ada tempat keluar untuk kedua tangannya).\" "},"985":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ وَأَبُو الْوَلِيدِ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah mengabarkan kepada kami [Sa'id? bin 'Amir] dan [Abu Al Walid] dari [Syu'bah] dari [Sulaiman Asy Syaibani] dari [Abdullah bin Syaddad] dari [Maimunah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah melakukan shalat di atas khumrah (tikar kecil untuk muka).\" "},"986":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ وَعَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَا حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى حَصِيرٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] dan [Abdullah bin Maslamah] mereka berkata; telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat di atas tikar.\""},"987":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ أَنَّهُ سَأَلَ أُمَّ حَبِيبَةَ هَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الَّذِي يُضَاجِعُكِ فِيهِ قَالَتْ نَعَمْ إِذَا لَمْ يَرَ فِيهِ أَذًى","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] dari [Yazid bin Abu Habib] dari [Mu'awiyah bin Hudaij] dari [Mu'awiyah bin Abu Sufyan], bahwa ia bertanya kepada [Ummu] Habibah, \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah melakukan shalat dengan memakai pakaian yang beliau gunakan di saat menggaulimu?\" Ia menjawab, \"Ya. Jika beliau tidak melihat najis padanya.\" "},"988":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُخْتِهِ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَأَلَهَا هَلْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي الثَّوْبِ الَّذِي يُجَامِعُهَا فِيهِ قَالَتْ نَعَمْ إِذَا لَمْ يَرَ فِيهِ أَذًى","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Hudaij] dari [Mu'awiyah bin Abu Sufyan] dari saudarinya [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ia bertanya kepadanya, \"Apakah Nabi shallallahu 'alaihi wasallam pernah melakukan shalat dengan memakai pakaian yang beliau pakai di saat menggaulinya?\" Ummu Habibah menjawab, \"Ya. Jika tidak melihat najis padanya.\" "},"989":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي مَسْلَمَةَ هُوَ سَعِيدُ بْنُ يَزِيدَ الْأَزْدِيُّ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْهِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Syu'bah] dari [Abu Maslamah] -yaitu Sa'id bin Yazid Al Azdi- ia berkata, aku pernah bertanya kepada [Anas bin Malik], \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan memakai kedua sandal beliau?\" Ia menjawab, \"Ya.\" "},"990":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ وَأَبُو النُّعْمَانِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي نَعَامَةَ السَّعْدِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ بَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِأَصْحَابِهِ إِذْ خَلَعَ نَعْلَيْهِ فَوَضَعَهُمَا عَنْ يَسَارِهِ فَخَلَعُوا نِعَالَهُمْ فَلَمَّا قَضَى صَلَاتَهُ قَالَ مَا حَمَلَكُمْ عَلَى إِلْقَائِكُمْ نِعَالَكُمْ قَالُوا رَأَيْنَاكَ خَلَعْتَ فَخَلَعْنَا قَالَ إِنَّ جِبْرِيلَ أَتَانِي أَوْ آتٍ فَأَخْبَرَنِي أَنَّ فِيهِمَا أَذًى أَوْ قَذَرًا فَإِذَا جَاءَ أَحَدُكُمْ الْمَسْجِدَ فَلْيُقَلِّبْ نَعْلَيْهِ فَإِنْ رَأَى فِيهِمَا أَذًى فَلْيُمِطْ وَلْيُصَلِّ فِيهِمَا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] dan [Abu An Nu'man] mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Na'amah As Sa'di] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam melakukan shalat bersama para sahabatnya tiba-tiba beliau melepas kedua sandalnya dan meletakkannya di samping kirinya. Maka mereka pun ikut melepas sandal mereka. Selesai shalat beliau berkata: \"Apa yang mendorong kalian untuk melepaskan sandal kalian?\" Mereka berkata, \"Kami melihat anda melepas sandal maka kami pun melepas sandal.\" Beliau bersabda: \"Sesungguhnya Jibril telah datang kepadaku dan memberitahuku bahwa pada kedua sandal tersebut terdapat najis atau kotoran, maka apabila salah seorang di antara kalian datang ke masjid hendaknya ia membalikkan kedua sandalnya, jika ia melihat padanya terdapat najis maka hendaknya ia menghilangkannya dan melakukan shalat dengan memakai keduanya.\""},"991":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ عِسْلٍ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ كَرِهَ السَّدْلَ وَرَفَعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sa'id? bin 'Amir] dari [Sa'id? bin Abu 'Arubah] dari ['Isl] dari ['Atha`] dari [Abu Hurairah], bahwa ia tidak suka untuk membiarkan kain hingga menyentuh tanah.\" Ia menyandarkan hal tersebut kepada Nabi shallallahu 'alaihi wasallam. "},"992":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مِخْوَلٍ عَنْ أَبِي سَعِيدٍ عَنْ أَبِي رَافِعٍ قَالَ رَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا سَاجِدٌ وَقَدْ عَقَصْتُ شَعْرِي أَوْ قَالَ عَقَدْتُ فَأَطْلَقَهُ","id":"Telah mengabarkan kepada kami [Sa'id? bin 'Amir] dari [Syu'bah] dari [Mikhwal] dari [Abu Sa'id] dari [Abu Rafi'] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melihatku dalam keadaan sujud, sementara aku telah menjalin atau mengikat rambutku, kemudian beliau melepaskannya.\" "},"993":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي بَكْرٌ هُوَ ابْنُ مُضَرَ عَنْ عَمْرٍو يَعْنِي ابْنَ الْحَارِثِ عَنْ بُكَيْرٍ أَنَّ كُرَيْبًا مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَهُ أَنَّ ابْنَ عَبَّاسٍ رَأَى عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُصَلِّي وَرَأْسُهُ مَعْقُوصٌ مِنْ وَرَائِهِ فَقَامَ وَرَاءَهُ فَجَعَلَ يَحُلُّهُ وَأَقَرَّ لَهُ الْآخَرُ ثُمَّ انْصَرَفَ إِلَى ابْنِ عَبَّاسٍ فَقَالَ مَا لَكَ وَرَأْسِي قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا مَثَلُ هَذَا كَمَثَلِ الَّذِي يُصَلِّي وَهُوَ مَكْتُوفٌ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Bakr] -yaitu Ibnu Mudlar- dari ['Amru] -yaitu Ibnu Al Harits- dari [Bukair] bahwa [Kuraib mantan budak Ibnu Abbas] menceritakan kepadanya, bahwa [Ibnu Abbas] melihat Abdullah bin Al Harits melakukan shalat sementara rambut kepalanya di jalin pada bagian belakang. Maka Ibnu Abbas berdiri di belakangnya dan melepaskan jalinan tersebut. Sementara orang lain (yang melihatnya) membiarkannya. Kemudian Abdullah bin Al Harits berkata, \"Apa urusanmu dengan rambutku?\" Ibnu Abbas menjawab, \"Sesungguhnya aku telah mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Sungguh, permisalan orang yang melakukan ini seperti orang yang shalat sementara tangannya terikat ke pundaknya.\""},"994":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ هُوَ ابْنُ مُحَمَّدٍ عَنْ سُهَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَثَاءَبَ أَحَدُكُمْ فَلْيَشُدَّ يَدَهُ فَإِنَّ الشَّيْطَانَ يَدْخُلُ قَالَ أَبُو مُحَمَّد يَعْنِي عَلَى فِيهِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz] -yaitu Ibnu Muhammad- dari [Suhail] dari [Abdurrahman bin Abu Sa'id] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang di antara kalian menguap hendaknya menutupkan tangannya, karena setan akan masuk.\" Abu Muhammad berkata, \"(Yakni) ke mulutnya.\" "},"995":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَجَدَ أَحَدُكُمْ النَّوْمَ وَهُوَ يُصَلِّي فَلْيَنَمْ حَتَّى يَذْهَبَ نَوْمُهُ فَإِنَّهُ عَسَى يُرِيدُ أَنْ يَسْتَغْفِرَ فَيَسُبَّ نَفْسَهُ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah di antara kalian mengantuk saat shalat hendaknya ia tidur hingga hilang kantuknya, karena bisa jadi ia hendak beristighfar namun ia mencela dirinya.\""},"996":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا جَعْفَرٌ هُوَ ابْنُ الْحَارِثِ عَنْ مَنْصُورٍ عَنْ هِلَالٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ بَلَغَنِي أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الرَّجُلِ جَالِسًا نِصْفُ الصَّلَاةِ قَالَ فَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي جَالِسًا فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ بَلَغَنِي أَنَّكَ قُلْتَ صَلَاةُ الرَّجُلِ جَالِسًا نِصْفُ الصَّلَاةِ وَأَنْتَ تُصَلِّي جَالِسًا قَالَ أَجَلْ وَلَكِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Ja'far] -yaitu Ibnu Al Harits- dari [Manshur] dari [Hilal] dari [Abu Yahya] dari [Abdullah bin 'Amru] ia berkata, \"Telah sampai kepadaku berita bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat seorang laki-laki dengan duduk pahalanya setengah shalat.\" Abdullah berkata, \"Kemudian aku menemui Nabi shallallahu 'alaihi wasallam sementara beliau shalat dalam keadaan duduk. Aku lalu berkata, \"Wahai Rasulullah! Telah sampai kabar kepadaku bahwa tuan mengatakan, 'Shalat seorang laki-laki dengan duduk pahalanya setengah shalat', tetapi kenapa tuan sendiri shalat dengan duduk. Beliau lalu menjawab: \"Benar, tetapi aku tidak seperti salah seorang diantara kalian.\""},"997":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي السَّائِبُ بْنُ يَزِيدَ عَنْ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ أَنَّ حَفْصَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي سُبْحَتِهِ وَهُوَ جَالِسٌ حَتَّى كَانَ قَبْلَ أَنْ يُتَوَفَّى بِعَامٍ وَاحِدٍ أَوْ عَامَيْنِ فَرَأَيْتُهُ يُصَلِّي فِي سُبْحَتِهِ وَهُوَ جَالِسٌ فَيُرَتِّلُ السُّورَةَ حَتَّى تَكُونَ أَطْوَلَ مِنْ أَطْوَلَ مِنْهَا أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ عَنْ حَفْصَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku [As Sa`ib bin Yazid] dari [Al Muththalib bin Abu Wada'ah] bahwa [Hafshah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukan shalat sunah dalam keadaan duduk hingga satu atau dua tahun sebelum beliau meninggal. Kemudian aku melihat beliau melakukan shalat sunah dalam keadaan duduk, beliau membaca surat dengan tartil hingga menjadi surat yang paling panjang daripada surat yang paling panjang.\" Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Malik] dari [Az Zuhri] dari [As Saib bin Yazid] dari [Al Muththalib bin Abu Wada'ah] dari [Hafshah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini.\""},"998":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ حَدَّثَنِي مُعَيْقِيبٌ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهُ فِي الْمَسْحِ فِي الْمَسْجِدِ قَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَوَاحِدَةً قَالَ هِشَامٌ أُرَاهُ قَالَ مَسْحِ الْحَصَا","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah] telah menceritakan kepadaku [Mu'aiqib], bahwa Rasulullah shallallahu 'alaihi wasallam ditanya mengenai mengusap pasir (saat shalat) di masjid. Beliau lalu menjawab: \"Apabila engkau harus melakannya maka lakukanlah satu kali.\" Hisyam berkata, \"Menurutku ia menyebutkan, \"Mengusap pasir.\" "},"999":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ إِلَى الصَّلَاةِ فَإِنَّ الرَّحْمَةَ تُوَاجِهُهُ فَلَا يَمْسَحْ الْحَصَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Abu Al Ahwash] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian berdiri untuk melakukan shalat maka sesungguhnya rahmat berhadapan dengannya, maka janganlah ia mengusap pasir.\""},"1000":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا سَيَّارٌ قَالَ سَمِعْتُ يَزِيدَ الْفَقِيرَ يَقُولُ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُعْطِيتُ خَمْسًا لَمْ يُعْطَهُنَّ نَبِيٌّ قَبْلِي كَانَ النَّبِيُّ يُبْعَثُ إِلَى قَوْمِهِ خَاصَّةً وَبُعِثْتُ إِلَى النَّاسِ كَافَّةً وَأُحِلَّتْ لِيَ الْمَغَانِمُ وَحُرِّمَتْ عَلَى مَنْ كَانَ قَبْلِي وَجُعِلَتْ لِيَ الْأَرْضُ طَيِّبَةً مَسْجِدًا وَطَهُورًا وَيَرْعَبُ مِنَّا عَدُوُّنَا مَسِيرَةَ شَهْرٍ وَأُعْطِيتُ الشَّفَاعَةَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Sayyar] ia berkata, saya mendengar [Yazid Al Faqir] berkata, saya mendengar [Jabir bin Abdullah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diberi lima perkara yang tidak diberikan kepada seorang nabi pun sebelumnya; setiap nabi diutus khusus kepada kaumnya dan aku diutus untuk manusia secara menyeluruh, dihalalkan bagiku harta rampasan perang dan diharamkan atas orang sebelumku, bumi dijadikan bagiku sebagai tempat sujud dan bersuci, musuh merasa takut kepada kami sejauh perjalanan satu bulan, dan aku diberi syafa'at.\""}};
